insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (424, '12', '치매 대상자의 운동을 돕는 방법으로 옳은 것은?', '["걷는 시간을 서서히 늘린다.", "운동 시간을 매일 다르게 한다.", "산책로는 자주 바꾸어 지루하지 않게 한다.", "다리 운동에서 목 운동으로 진행하게 한다.", "팔다리 관절을 빠르게 움직이며 운동하게 한다."]'::jsonb, 1, NULL, NULL, '{"1": "걷는 시간을 서서히 늘리는 것은 적절한 방법으로, 치매 대상자가 안전하게 운동을 지속할 수 있도록 돕습니다.\n[정답]", "2": "운동 시간을 매일 다르게 하는 것은 일관성을 줄이므로 바람직하지 않습니다.", "3": "산책로를 자주 바꾸면 대상자가 혼란스러울 수 있어 그다지 좋지 않습니다.", "4": "다리 운동에서 목 운동으로 진행하는 것은 적절한 연결이 아닙니다.", "5": "팔다리 관절을 빠르게 움직이는 것은 치매 대상자에게 위험할 수 있습니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí", "def_ko": "기억력과 인지 능력이 감소하는 질병", "def_vi": "Bệnh suy giảm trí nhớ và khả năng nhận thức"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (423, '12', '치매 대상자의 옷 입기를 돕는 방법으로 옳은 것은?', '["색깔이 요란하고 장식이 많은 옷을 선택한다.", "시간이 걸리면 요양보호사가 입혀준다.", "옷 입기를 거부하면 목욕 시간을 이용하여 갈아입힌다.", "단추가 많이 달린 옷을 제공한다.", "자신의 옷이 아니라고 하면 다른 옷을 구입한다."]'::jsonb, 3, NULL, NULL, '{"1": "색깔이 요란하고 장식이 많은 옷을 선택하는 것은 치매 환자에게 혼란을 줄 수 있어 바람직하지 않다.\n[정답]", "2": "시간이 걸리면 요양보호사가 입혀주는 것은 자율성을 침해할 수 있다.", "3": "옷 입기를 거부하면 목욕 시간을 이용하여 갈아입히는 것은 치매 대상자의 스트레스를 최소화할 수 있는 방법이다.", "4": "단추가 많이 달린 옷은 치매 환자가 입기 힘들 수 있다.", "5": "자신의 옷이 아니라고 하면 다른 옷을 구입하는 것은 개인의 정체성과 감정을 고려하지 않는 방법이다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억 및 사고 기능의 저하로 인한 질병", "def_vi": "Bệnh do suy giảm chức năng trí nhớ và tư duy"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (422, '12', '목욕을 시키기 위해 치매 대상자의 옷을 벗기려 하자 거칠게 거부할 때 돕는 방법으로 옳은 것은?', '["욕실 내 혼자 머무르게 한다.", "행동을 신속하게 제지한다.", "목욕하기 싫은 이유를 물어본다.", "여러 요양보호사와 함께 목욕을 시킨다.", "목욕을 중지하고 조용한 방에서 쉬게 한다."]'::jsonb, 5, NULL, NULL, '{"1": "욕실 내 혼자 머무르게 한다는 것은 치매 대상자의 불안감을 증가시킬 수 있다.\n[정답]", "5": "목욕을 중지하고 조용한 방에서 쉬게 하는 것은 대상자의 스트레스를 줄이고 향후 목욕 시간을 다시 시도할 수 있는 여지를 제공한다.", "2": "행동을 신속하게 제지하는 것은 상황을 악화시킬 수 있다.", "3": "목욕하기 싫은 이유를 물어보는 것은 필요하지만, 이 상황에서는 적절하지 않다.", "4": "여러 요양보호사와 함께 목욕을 시키는 것은 혼란스러움을 야기할 수 있다."}'::jsonb, '[{"term_ko": "목욕", "term_vi": "Tắm", "def_ko": "씻는 것(한국어)", "def_vi": "Rửa"}, {"term_ko": "치매", "term_vi": "Sa sút trí tuệ", "def_ko": "기억 및 인지 기능의 저하(한국어)", "def_vi": "Sự suy giảm chức năng ghi nhớ và nhận thức"}, {"term_ko": "대상자", "term_vi": "Đối tượng", "def_ko": "치료나 보호를 받는 사람(한국어)", "def_vi": "Người được điều trị hoặc chăm sóc"}, {"term_ko": "거부", "term_vi": "Từ chối", "def_ko": "원하지 않는다고 말하거나 행동하는 것(한국어)", "def_vi": "Nói hoặc hành động nói rằng không muốn"}, {"term_ko": "스트레스", "term_vi": "Căng thẳng", "def_ko": "긴장이나 압박감을 느끼는 상태(한국어)", "def_vi": "Trạng thái cảm thấy căng thẳng hoặc áp lực"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (421, '12', '치매 대상자를 목욕시키는 방법으로 옳은 것은?', '["목욕을 싫어해도 개인위생을 위해 억지로 시킨다.", "부드럽게 유도하거나 시간을 미루어 다시 시도한다.", "나이가 들면 피부의 탄력을 잃기 때문에 통목욕을 자주 한다.", "개인위생을 위해 목욕 시간은 1시간 이상 꼼꼼히 한다.", "지루하지 않게 목욕 과정을 길고 복잡하게 한다."]'::jsonb, 2, NULL, NULL, '{"1": "목욕을 억지로 시키는 것은 부정적인 경험을 줄 수 있습니다.\n[정답]", "2": "부드럽게 유도하거나 시간을 미루는 것은 치매 환자의 심리적 안정을 돕습니다.", "3": "피부의 탄력과 목욕 빈도는 나이와 관계없이 개별적으로 다룬다.", "4": "목욕 시간은 개인의 상태에 맞추어 적절히 조정해야 합니다.", "5": "긴 목욕 과정은 오히려 환자에게 스트레스를 유발할 수 있습니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh Alzheimer", "def_ko": "기억과 사고 기능의 감소로 인한 상태", "def_vi": "Một trạng thái giảm khả năng ghi nhớ và tư duy"}, {"term_ko": "부드럽게", "term_vi": "Nhẹ nhàng", "def_ko": "부드러운 방법으로", "def_vi": "Bằng cách nhẹ nhàng"}, {"term_ko": "유도하다", "term_vi": "Đưa ra hướng dẫn", "def_ko": "어떤 방향으로 이끌다", "def_vi": "Hướng dẫn một cách chủ động"}, {"term_ko": "목욕", "term_vi": "Tắm", "def_ko": "청결을 위한 물과 비누 활용", "def_vi": "Sử dụng nước và xà phòng để giữ vệ sinh"}, {"term_ko": "개인위생", "term_vi": "Vệ sinh cá nhân", "def_ko": "개인의 청결 유지", "def_vi": "Duy trì sự sạch sẽ của cơ thể cá nhân"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (420, '12', '치매 대상자의 부적절한 배설행동에 대한 돕기 방법으로 옳은 것은?', '["배변시간에는 대상자 혼자 있도록 한다.", "반복하여 화장실에 갈 경우 수분섭취량을 줄인다.", "대소변을 손으로 만지더라도 아무렇지 않은 것처럼 뒤처리를 한다.", "화장실과 먼 곳에 방을 배치한다.", "대소변처리가 쉽도록 화장실 환경을 바꾸어본다."]'::jsonb, 3, NULL, NULL, '{"1": "대상자가 혼자 있도록 하면 안전 문제와 불안감을 초래할 수 있다.\n[정답]", "3": "대소변을 손으로 만지더라도 이를 수용하고 정상적인 반응으로 대처한다.", "2": "수분섭취량을 줄이는 것은 건강에 악영향을 미칠 수 있다.", "4": "화장실과 먼 거리에 방을 배치하면 접근성이 떨어진다.", "5": "화장실 환경을 개선하는 것은 긍정적인 영향을 미친다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Sa sút trí tuệ", "def_ko": "기억과 사고 능력이 저하되는 질환", "def_vi": "Bệnh giảm khả năng nhớ và suy nghĩ"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (419, '12', '다음과 같은 상황이 있을 때 요양보호사의 돕는 방법으로 옳은 것은?', '["시설장에게 즉시 보고한다.", "상황을 기록하고 기저귀를 채운다.", "수치심을 유발하지 않게 모른 척한다.", "뒤처리 후 더러워진 옷을 갈아입힌다.", "재가서비스가 어려우므로 시설 입소를 권한다."]'::jsonb, 4, NULL, NULL, '{"1": "상황에 따라 즉시 보고해야 할 경우도 있지만, 이 경우 환자의 긴급한 도움이 우선입니다.\n[정답]", "2": "단순히 상황을 기록하는 것으로는 환자에게 필요한 도움을 주지 못합니다.", "3": "수치심을 유발하지 않게 하는 것이 중요하지만, 모른 척하는 것은 환자에게 도움이 되지 않습니다.", "4": "뒤처리를 통해 청결을 유지하고 환자의 편안함을 보장하는 것이 중요한 대응입니다.", "5": "상황과 필요에 따라 결정해야 하며, 즉각적인 도움을 제공하는 것이 우선입니다."}'::jsonb, '[{"term_ko": "요양보호사", "term_vi": "Nhân viên chăm sóc", "def_ko": "노인을 돌보는 전문 직업", "def_vi": "Nghề chuyên chăm sóc người cao tuổi"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (418, '12', '스스로 음식을 먹을 수 있는 치매 대상자의 식사를 돕는 방법으로 옳은 것은?', '["투명한 유리 제품에 음식을 보기 좋게 담는다.", "식전에 사탕을 제공하여 식욕을 돋운다.", "약간 무거운 숟가락을 쥐어준다.", "소금이나 간장은 식탁 위에 두고 사용하게 한다.", "식사 시간에 졸려 하더라도 제시간에 먹게 한다."]'::jsonb, 3, NULL, NULL, '{"1": "투명한 유리 제품에 음식을 보기 좋게 담는 것은 시각적 자극을 제공해 도움이 될 수 있다. 그러나 직접적인 도움과는 관련이 없다.\n[정답]", "2": "식전에 사탕을 제공하여 식욕을 돋우는 것은 도움이 될 수 있지만 의도한 식사 도움의 방법이 아니다.", "3": "약간 무거운 숟가락을 쥐어주는 것은 그들이 스스로 음식을 먹는 데 필요한 힘을 제공하여 유용하다.", "4": "소금이나 간장은 식탁 위에 두고 사용하게 하는 것이 자율성을 부여하지만, 이 방법은 직접적으로 식사를 돕는 것이 아니다.", "5": "식사 시간에 졸려 하더라도 제시간에 먹게 하는 것은 식사의 규칙성을 제공하지만, 스스로 먹는 것을 돕는 것이 아니라 강요하는 행위가 될 수 있다."}'::jsonb, '[{"term_ko": "스스로", "term_vi": null, "def_ko": "스스로(자기 자신으로부터)", "def_vi": null}, {"term_ko": "음식", "term_vi": null, "def_ko": "음식(đồ ăn)", "def_vi": null}, {"term_ko": "치매", "term_vi": null, "def_ko": "치매(bệnh sa sút trí tuệ)", "def_vi": null}, {"term_ko": "대상자", "term_vi": null, "def_ko": "대상자(nhân vật)", "def_vi": null}, {"term_ko": "식사", "term_vi": null, "def_ko": "식사(bữa ăn)", "def_vi": null}, {"term_ko": "도움", "term_vi": null, "def_ko": "도움(hỗ trợ)", "def_vi": null}, {"term_ko": "방법", "term_vi": null, "def_ko": "방법(phương pháp)", "def_vi": null}, {"term_ko": "소금", "term_vi": null, "def_ko": "소금(muối)", "def_vi": null}, {"term_ko": "간장", "term_vi": null, "def_ko": "간장(xì dầu)", "def_vi": null}, {"term_ko": "졸리다", "term_vi": null, "def_ko": "졸리다(buồn ngủ)", "def_vi": null}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (417, '12', '치매 대상자의 식사를 돕는 방법은?', '["휴대전화로 영상을 보여주며 식사한다.", "음식을 부드럽게 조리하여 제공한다.", "간장을 이용해 스스로 간을 맞추게 한다.", "가벼운 숟가락과 젓가락을 사용하게 한다.", "처방된 비타민은 음식에 섞어서 먹게 한다."]'::jsonb, 2, NULL, NULL, '{"1": "휴대전화로 영상을 보여주는 것은 주의 집중을 해칠 수 있어 적절하지 않습니다.\n[정답]", "2": "음식을 부드럽게 조리하여 제공하는 것은 치매 환자의 씹는 능력을 고려한 좋은 방법입니다.", "3": "간장을 스스로 간을 맞추게 하는 것은 혼란을 초래할 수 있어 좋지 않습니다.", "4": "가벼운 숟가락과 젓가락을 사용하는 것은 도와줄 수 있으나, 직접적으로 식사 지원과는 관련이 적습니다.", "5": "처방된 비타민을 음식에 섞는 것은 알 수 없으므로 주의가 필요합니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Chứng mất trí", "def_ko": "기억력과 사고 능력이 감소하는 상태", "def_vi": "Tình trạng giảm trí nhớ và khả năng suy nghĩ"}, {"term_ko": "식사", "term_vi": "Bữa ăn", "def_ko": "음식을 먹는 행위", "def_vi": "Hành động ăn uống"}, {"term_ko": "부드럽게", "term_vi": "Mềm", "def_ko": "아프지 않게, 쉽게 씹을 수 있게 하는 것", "def_vi": "Không đau, dễ nhai"}, {"term_ko": "간장", "term_vi": "Nước tương", "def_ko": "한식에서 사용되는 간단한 양념", "def_vi": "Gia vị đơn giản trong ẩm thực Hàn Quốc"}, {"term_ko": "비타민", "term_vi": "Vitamin", "def_ko": "몸에 필요한 영양소", "def_vi": "Chất dinh dưỡng cần thiết cho cơ thể"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (416, '12', '최근 시설에 입소한 치매 대상자가 자신의 방을 청소하겠다고 할 때 돕는 방법으로 옳은 것은?', '["청소기 사용법을 자세하게 설명한다.", "담당 청소 직원이 한다고 설명한다.", "무리하지 않는 범위 내에서 청소하게 한다.", "당분간 침상에서 절대 안정을 취하라고 말한다.", "청소는 낙상 위험이 있으므로 하지 말라고 한다."]'::jsonb, 3, NULL, NULL, '{"1": "청소기 사용법을 자세하게 설명하면 대상자가 혼란스러워할 수 있다.\n[정답]", "3": "무리하지 않는 범위 내에서 청소하게 함으로써 자율성을 존중하고 안전을 확보할 수 있다.", "2": "담당 청소 직원이 한다고 설명하면 대상자의 자율성을 침해할 수 있다.", "4": "당분간 침상에서 절대 안정을 취하라고 하면 청소를 할 수 없게 된다.", "5": "청소는 낙상 위험이 있으므로 하지 말라고 하면 대상자의 자율성을 부정하는 것이다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh Alzheimer", "def_ko": "기억력과 사고 능력에 문제가 생기는 질환", "def_vi": "Bệnh có vấn đề về trí nhớ và khả năng suy nghĩ"}, {"term_ko": "청소", "term_vi": "Dọn dẹp", "def_ko": "공간을 깨끗하게 만들기 위한 작업", "def_vi": "Hoạt động làm sạch không gian"}, {"term_ko": "자율성", "term_vi": "Tự chủ", "def_ko": "스스로 결정하고 행동할 수 있는 능력", "def_vi": "Khả năng tự quyết định và hành động"}, {"term_ko": "안전", "term_vi": "An toàn", "def_ko": "위험이 없는 상태", "def_vi": "Trạng thái không có nguy hiểm"}, {"term_ko": "낙상", "term_vi": "Ngã", "def_ko": "넘어짐", "def_vi": "Rơi xuống"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (415, '12', '치매 대상자의 일상생활 지원의 목적으로 옳은 것은?', '["대상자의 상태를 정확히 파악한다.", "정신기능 활동을 위해 새로운 학습활동을 한다.", "현재의 신체기능을 유지한다.", "새로운 환경을 조성한다.", "새로운 일을 배우는 능력을 기른다."]'::jsonb, 1, NULL, NULL, '{"1": "대상자의 상태를 정확히 파악한다. [정답] 이는 치매 대상자가 필요한 지원을 적절하게 제공하기 위한 기초가 된다.", "2": "정신기능 활동을 위해 새로운 학습활동을 한다. 이는 치매 환자에게 도전이 될 수 있으나 기본적으로 상태 파악이 우선이다.", "3": "현재의 신체기능을 유지한다. 중요하지만, 상태 파악이 선행되어야 한다.", "4": "새로운 환경을 조성한다. 환경 변화는 스트레스를 유발할 수 있으므로 신중해야 한다.", "5": "새로운 일을 배우는 능력을 기른다. 이는 목표가 아닐 수 있다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Sa sút trí tuệ", "def_ko": "기억력, 사고, 행동의 기능에 장애가 생기는 질병", "def_vi": "Bệnh làm suy giảm chức năng trí nhớ, tư duy, và hành vi"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (414, '12', '처방약이 변경된 후 대상자가 초조한 듯 집안을 왔다 갔다 하고 있다. 요양보호사의 돕는 방법으로 옳은 것은?', '["약물의 용량을 늘려서 제공한다.", "이전에 복용하던 치매 약을 준다.", "증상을 메모하여 병원 갈 때 가지고 간다.", "대상자에게 부작용의 증상을 물어본다.", "약이 바뀌면 흔하게 나타나는 증상이라고 말한다."]'::jsonb, 3, NULL, NULL, '{"1": "약물의 용량을 늘리는 것은 잘못된 방법입니다.\n[정답]", "3": "증상을 메모하고 병원에 갈 때 가지고 가는 것은 의사와의 소통에 도움이 됩니다.", "2": "이전에 복용하던 약을 주는 것은 치료에 도움이 되지 않습니다.", "4": "대상자에게 부작용의 증상을 물어보는 것은 필요하지만, 질문을 통해 바로 해결하지는 못합니다.", "5": "번화한 증상이 흔하다고 말하는 것은 대상자의 불안감을 경감시키지 못할 수 있습니다."}'::jsonb, '[{"term_ko": "처방약", "term_vi": "Thuốc theo chỉ định", "def_ko": "의사의 지시에 따라 환자가 복용하는 약", "def_vi": "Thuốc mà bệnh nhân sử dụng theo chỉ dẫn của bác sĩ"}, {"term_ko": "초조한", "term_vi": "Lo âu", "def_ko": "불안하거나 긴장하거나 차분하지 않은 상태", "def_vi": "Tình trạng không yên tâm hoặc căng thẳng"}, {"term_ko": "증상", "term_vi": "Triệu chứng", "def_ko": "질환이나 상태의 나타남", "def_vi": "Biểu hiện của bệnh tật hoặc trạng thái"}, {"term_ko": "부작용", "term_vi": "Tác dụng phụ", "def_ko": "약물이나 치료에 의해 나타나는 원치 않는 증상", "def_vi": "Các triệu chứng không mong muốn xuất hiện do thuốc hoặc điều trị"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (413, '12', '치매 대상자의 약물 복용을 돕는 방법으로 옳은 것은?', '["인지개선제는 병의 완치를 위해 투여한다.", "약물을 복용한 후 침상에서 절대 안정시킨다.", "증상의 변화에 따라 약의 양을 조절한다.", "약물 부작용이 나타나면 메모하여 병원 진료 시 알린다.", "복용량을 줄이고자 할 때는 기관장의 허락을 받는다."]'::jsonb, 4, NULL, NULL, '{"1": "인지개선제는 병의 완치를 위해 투여하는 것이 아니라 증상을 완화하기 위해 사용됩니다.\n[정답]", "4": "약물 부작용이 나타나면 반드시 메모하여 병원 진료 시 의사에게 알리는 것이 중요합니다.", "2": "약물을 복용한 후 침상에서 절대 안정시키는 것은 비효율적이며, 오히려 활동을 권장할 수 있습니다.", "3": "증상의 변화에 따라 약의 양을 조절하는 것은 전문의의 판단이 필요하므로, 독단적으로 변경해서는 안 됩니다.", "5": "복용량을 줄이고자 할 때는 기관장의 허락을 받아야 하는 것이 아니라 전문의와 상담 후 결정해야 합니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh Alzheimer", "def_ko": "질병(한국어)", "def_vi": "Bệnh gây mất trí nhớ(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (412, '12', '치매 대상자의 병원 방문을 도울 때 의사소통하는 방법으로 옳은 것은?', '["대상자 스스로가 치매 대상자임을 인식시킨다.", "요양보호사가 동행한다고 말해주며 안심시킨다.", "대상자가 병원 방문 이유를 알고 있는지 확인한다.", "병원에서 검사 후 진료를 받고 약을 탈 것이라고 설명한다.", "치매의 정도가 심해졌을 수도 있다고 분명하게 말해둔다."]'::jsonb, 2, NULL, NULL, '{"1": "대상자가 스스로 치매임을 인식하는 것은 어렵기 때문에 효과적이지 않습니다.\n[정답]", "2": "요양보호사가 동행한다고 말해주며 안심시키는 것이 가장 적절한 방법입니다.", "3": "병원 방문 이유를 확인하는 것은 중요하지만 긴장감이 높아질 수 있습니다.", "4": "병원에서 검사 후 진료 및 약을 탈 것이라고 설명하는 것은 필요하지만, 치매 대상자에게는 복잡할 수 있습니다.", "5": "치매의 정도가 심해질 수도 있다고 말하는 것은 불안감을 초래할 수 있습니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Sa sút trí tuệ", "def_ko": "기억력과 인지 기능의 감소가 있는 상태", "def_vi": "Tình trạng suy giảm trí nhớ và chức năng nhận thức"}, {"term_ko": "대상자", "term_vi": "Đối tượng", "def_ko": "치료를 받는 환자", "def_vi": "Bệnh nhân nhận điều trị"}, {"term_ko": "요양보호사", "term_vi": "Người chăm sóc", "def_ko": "노인이나 장애인을 도와주는 사람", "def_vi": "Người hỗ trợ người già hoặc người khuyết tật"}, {"term_ko": "병원", "term_vi": "Bệnh viện", "def_ko": "환자가 치료를 받는 장소", "def_vi": "Nơi bệnh nhân nhận điều trị"}, {"term_ko": "정신적 지지", "term_vi": "Hỗ trợ tinh thần", "def_ko": "심리적인 도움", "def_vi": "Sự giúp đỡ về tâm lý"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (411, '11', '치매노인이 생활하는데 안전한 주거 환경으로 옳은 것은?', '["깔끔한 환경을 위해 공간 이름표 등을 제거하여 혼란을 줄인다.", "망상 및 배회를 줄이기 위해 창문이 없는 공간에서 생활한다.", "낙상예방을 위해 요양보호사들이 일상생활 활동을 대신한다.", "새소리, 음식 끓는 소리 등의 환경적 자극은 제한한다.", "불쾌한 악취 등의 냄새는 조정한다."]'::jsonb, 5, NULL, NULL, '{"1": "공간 이름표 등을 제거하면 오히려 혼란을 초래할 수 있으며, 치매환자의 기억에 도움을 줄 수 있습니다.\n[정답]", "5": "불쾌한 악취 등의 냄새를 조정하는 것은 치매환자의 편안함과 안전을 위한 중요한 조치입니다.", "2": "창문이 없는 공간은 치매환자에게 오히려 불안과 혼란을 줄 수 있습니다.", "3": "요양보호사가 모든 활동을 대신하는 것은 환자의 자립성을 감소시킬 수 있습니다.", "4": "환경적 자극을 제한하는 것은 부적절하며, 적절한 자극은 좋습니다."}'::jsonb, '[{"term_ko": "주거 환경", "term_vi": "Môi trường sống", "def_ko": "생활 공간(한국어)", "def_vi": "Không gian sinh hoạt(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (410, '11', '재가대상자가 요구한 물건을 구매했더니 마음에 들지 않는다며 불평을 할 때 대처 방법으로 옳은 것은?', '["해결방안을 시설장과 상의하여 처리한다.", "비슷한 물건이니 그냥 쓰라고 설득한다.", "앞으로 물건 대행은 어렵겠다고 말한다.", "구매한 물건을 대상자와 함께 교환하러 간다.", "원하는 물건은 대상자가 직접 구매하게 한다."]'::jsonb, 4, NULL, NULL, '{"1": "해결방안을 시설장과 상의하여 처리한다.\n시설장과 상의하는 것은 좋은 방법이지만, 즉각적인 대처가 아니라서 직접적인 해결책이 아닙니다.\n[정답]", "4": "구매한 물건을 대상자와 함께 교환하러 간다.\n대상자의 불만을 해결하고, 그들의 의견을 존중하는 방법입니다.", "3": "앞으로 물건 대행은 어렵겠다고 말한다.\n대상자의 요청을 무시하는 것으로, 긍정적인 방법이 아닙니다.", "2": "비슷한 물건이니 그냥 쓰라고 설득한다.\n대상자의 만족도를 고려하지 않는 비효율적인 접근입니다.", "5": "원하는 물건은 대상자가 직접 구매하게 한다.\n대상자의 편의를 고려하지 않는 방법입니다."}'::jsonb, '[{"term_ko": "재가대상자", "term_vi": "Người phục vụ tại nhà", "def_ko": "집에서 돌봄을 받는 대상자", "def_vi": "Người nhận sự chăm sóc tại nhà"}, {"term_ko": "불평", "term_vi": "Phàn nàn", "def_ko": "불만 또는 불만의 표현", "def_vi": "Sự không hài lòng hoặc biểu hiện sự không hài lòng"}, {"term_ko": "교환", "term_vi": "Đổi", "def_ko": "바꾸다", "def_vi": "Thay đổi đồ vật hoặc món hàng"}, {"term_ko": "해결", "term_vi": "Giải quyết", "def_ko": "문제를 없애다", "def_vi": "Loại bỏ vấn đề"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (409, '11', '재가대상자가 요양보호사의 차를 이용하여 외출하고자 할 때 대처방법으로 옳은 것은?', '["외출은 주말에만 할 수 있다고 말한다.", "외출하기 전에 주유비를 미리 청구한다.", "시설장에게 직접 허락을 받아달라고 한다.", "요양보호사의 차를 이용할 수 없다고 말한다.", "요양보호사의 차의 뒷자석에 대상자를 앉혀 이동한다."]'::jsonb, 4, NULL, NULL, '{"1": "외출은 주말에만 할 수 있다고 말한다: 적절하지 않은 답변입니다. 외출은 주말에만 제한되지 않습니다.\n[정답]", "2": "외출하기 전에 주유비를 미리 청구한다: 통상적으로 이런 방식은 사용되지 않아 적절하지 않습니다.", "3": "시설장에게 직접 허락을 받아달라고 한다: 불필요한 절차로, 적절한 방법이 아닙니다.", "4": "요양보호사의 차를 이용할 수 없다고 말한다: 이는 요양보호사가 외출에 대한 관리 책임이 있음을 나타내므로 적절합니다.", "5": "요양보호사의 차의 뒷자석에 대상자를 앉혀 이동한다: 안전을 고려했을 때 적절하지 않은 방법입니다."}'::jsonb, '[{"term_ko": "재가대상자", "term_vi": "Người nhận dịch vụ chăm sóc tại nhà", "def_ko": "집에서 외부의 도움을 받는 사람", "def_vi": "Người nhận sự giúp đỡ từ bên ngoài tại nhà"}, {"term_ko": "외출", "term_vi": "Ra ngoài", "def_ko": "집을 떠나 나가는 것", "def_vi": "Rời khỏi nhà"}, {"term_ko": "주유비", "term_vi": "Chi phí xăng", "def_ko": "차량 연료비", "def_vi": "Chi phí cho nhiên liệu của xe"}, {"term_ko": "시설장", "term_vi": "Giám đốc cơ sở", "def_ko": "시설의 책임자", "def_vi": "Người đứng đầu cơ sở"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (408, '11', '대상자가 진료를 위해 병원을 방문하고자 할 때 동행하는 방법으로 옳은 것은?', '["요양보호사의 일정에 맞게 병원 예약을 정한다.", "보호자의 자가용을 운전하여 이동한다.", "대상자의 귀중품은 소지하고 가게 한다.", "대상자에게 필요한 경비를 미리 확인한다.", "외출 전에 하루 용량의 약을 복용하게 한다."]'::jsonb, 4, NULL, NULL, '{"1": "요양보호사의 일정에 맞게 병원 예약을 정하는 것은 아니라는 점에서 부적절하다.\n[정답]", "4": "대상자에게 필요한 경비를 미리 확인하는 것은 병원 방문에 필수적인 준비 사항이므로 옳다.", "2": "보호자의 자가용을 운전하여 이동하는 것이 꼭 필요한 방법은 아니다.", "3": "대상자의 귀중품은 소지하고 가게 하는 것은 안전을 위해 피하는 것이 좋다.", "5": "외출 전에 하루 용량의 약을 복용하게 하는 것은 적절한 시점이 아닐 수 있다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người tham gia", "def_ko": "환자", "def_vi": "Bệnh nhân"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (407, '11', '거동이 불편한 재가 서비스 대상자와 외출을 할 때 동행방법으로 옳은 것은?', '["보호자를 통해 이동보조 기구 및 장비를 점검시킨다.", "계단을 오를 때 몇 번씩 쉬면서 천천히 이동한다.", "차량 이용 시 요양보호사는 운전자 옆자리에 앉고, 대상자 스스로 오르내리게 격려한다.", "외출 후 돌아와 낮잠을 푹 자게 한다.", "만족스러웠는지 보호자에게 확인한다."]'::jsonb, 2, NULL, NULL, '{"1": "보호자를 통해 이동보조 기구 및 장비를 점검하는 것은 중요하지만, 동행 방법으로는 적절하지 않습니다.\n[정답]", "2": "계단을 오를 때 몇 번씩 쉬면서 천천히 이동하는 것은 안전한 동행 방법입니다.", "3": "차량 이용 시 요양보호사가 운전자의 옆자리에 앉고, 대상자 스스로 오르내리게 격려하는 것은 바람직하지 않은 방법입니다.", "4": "외출 후 돌아와 낮잠을 푹 자게 하는 것은 건강 관리의 일환이지만, 동행 방법과는 관련이 없습니다.", "5": "만족스러웠는지 보호자에게 확인하는 것은 사후 평가에 해당하며, 동행 방법으로는 부적절합니다."}'::jsonb, '[{"term_ko": "거동", "term_vi": "거 động", "def_ko": "움직임(한국어)", "def_vi": "di chuyển(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (406, '11', '다음과 같은 표시기호가 있는 의복의 다림질 방법으로 옳은 것은?(그림)#252', '["80~120˚C 이상의 온도로 다림질한다.", "80~120˚C의 물로 분무한 후 다림질한다.", "80~120˚C로 다림질한 후 펴서 보관한다.", "80~120˚C로 다림질한 후 완전히 말린다.", "원단 위에 천을 덮고 80~120˚C로 다림질한다."]'::jsonb, 5, NULL, NULL, '{"1": "80~120˚C 이상의 온도로 다림질하면 소재 손상이 일어날 수 있습니다.", "2": "물로 분무한 후 다림질하는 것은 적절한 방법이지만, 80~120˚C 범위에 해당하는 것이 아니라서 틀립니다.\n[정답]", "5": "원단 위에 천을 덮고 80~120˚C로 다림질하는 것이 올바른 방법입니다.", "3": "다림질한 후 펴서 보관하는 것은 잘못된 방법입니다.", "4": "다림질한 후 완전히 말리는 것은 필요 없고, 오히려 다림질과 동시에 수분이 남아 있어야 합니다."}'::jsonb, '[{"term_ko": "다림질", "term_vi": "Ủi", "def_ko": "옷을 펴게 하는 과정(한국어)", "def_vi": "quá trình làm phẳng quần áo(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (405, '11', '다음의 그림에 해당하는 설명으로 옳은 것은?(그림)#252', '["청바지 - 색이 바래지 않게 뒤집어서 건조", "색깔 있는 니트 - 통기성이 좋은 곳에서 채 반등에 펴서 건조", "노란색 나일론 블라우스 - 옷걸이에 걸어서 그늘에 건조", "흰색 면직물 - 햇볕에 건조", "합성섬유 - 뉘어서 그늘에 건조"]'::jsonb, 3, NULL, NULL, '{"1": "청바지는 색이 바래지 않게 뒤집어서 건조해야 합니다.\n[정답]", "2": "색깔 있는 니트는 통기성이 좋은 곳에서 채 반듯이 펴서 건조해야 합니다.", "3": "노란색 나일론 블라우스는 옷걸이에 걸어서 그늘에 건조하는 것이 맞습니다.", "4": "흰색 면직물은 자외선에 의해 노란색으로 변할 수 있으므로 햇볕에 건조하면 안 됩니다.", "5": "합성섬유는 보통 뉘어서 그늘에서 건조하는 것이 좋습니다."}'::jsonb, '[{"term_ko": "청바지", "term_vi": "Quần bò", "def_ko": "찢어진 바지(바지)", "def_vi": "Quần có vết rách"}, {"term_ko": "색깔", "term_vi": "Màu sắc", "def_ko": "색(명사)", "def_vi": "Màu"}, {"term_ko": "니트", "term_vi": "Đồ len", "def_ko": "뜨개질한 옷(명사)", "def_vi": "Quần áo đan"}, {"term_ko": "통기성", "term_vi": "Tính thông gió", "def_ko": "공기가 통과하는 성질(명사)", "def_vi": "Tính chất cho không khí đi qua"}, {"term_ko": "흰색", "term_vi": "Màu trắng", "def_ko": "색상이 없는(형용사)", "def_vi": "Không có màu sắc"}, {"term_ko": "면직물", "term_vi": "Vải cotton", "def_ko": "면으로 된 직물(명사)", "def_vi": "Vải làm từ bông"}, {"term_ko": "합성섬유", "term_vi": "Sợi tổng hợp", "def_ko": "인공 섬유(명사)", "def_vi": "Sợi nhân tạo"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (404, '11', '방충제를 넣어 보관해야 하는 의류로 옳은 것은?', '["비닐 장갑(모자)", "나일론 양말", "합성섬유 바지", "모직 자켓", "폴리에스테르 티셔츠"]'::jsonb, 4, NULL, NULL, '{"1": "비닐 장갑(모자)은 방충제가 필요하지 않습니다.\n[정답]", "4": "모직 자켓은 방충제를 넣어 보관해야 합니다.", "2": "나일론 양말은 방충제가 필요하지 않습니다.", "3": "합성섬유 바지는 방충제가 필요하지 않습니다.", "5": "폴리에스테르 티셔츠는 방충제가 필요하지 않습니다."}'::jsonb, '[{"term_ko": "방충제", "term_vi": "Thuốc chống côn trùng", "def_ko": "해충을 방지하는 약품", "def_vi": "Thuốc ngăn côn trùng"}, {"term_ko": "의류", "term_vi": "Trang phục", "def_ko": "입는 옷", "def_vi": "Quần áo"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (403, '11', '다음 그림의 세탁표시에 따른 세탁 방법을 옳게 설명한 것은?(그림)#251', '["약하게 짜면 안됨", "다림질을 약한 온도로 함", "드라이클리닝을 약하게 함", "산소계표백제를 적게 사용함", "세탁기에서는 단시간에 짜야함"]'::jsonb, 5, NULL, NULL, '{"1": "약하게 짜면 안됨: 세탁표시의 요구사항을 충족하지 않음.\n[정답]", "2": "다림질을 약한 온도로 함: 세탁 후 다림질에 대한 요구사항이 아님.", "3": "드라이클리닝을 약하게 함: 드라이클리닝과 세탁 방법과는 무관함.", "4": "산소계표백제를 적게 사용함: 세탁표시와 관련된 내용 아님.", "5": "세탁기에서는 단시간에 짜야함: 세탁기 사용 시 짜는 것에 대한 정확한 설명."}'::jsonb, '[{"term_ko": "세탁", "term_vi": "Giặt", "def_ko": "세금(한국어)", "def_vi": "Giặt giũ(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (402, '11', '세탁 후 관리하는 방법으로 옳은 것은?', '["다림질은 다리미가 앞으로 나갈 때는 앞부분에 힘을 준다.", "풀 먹인 천을 다릴 때는 분무기로 물을 뿌리고 다린다.", "거풍할 때는 건조하고 맑게 갠 날 바람이 잘 통하는 그늘에서 한다.", "실리카겔은 분홍색으로 변색되면 사용할 수 없다.", "방충제는 공기보다 무거우므로 보관용기의 아래 구석에 넣어둔다."]'::jsonb, 3, NULL, NULL, '{"1": "다림질은 다리미가 앞으로 나갈 때는 앞부분에 힘을 준다는 설명이 부정확합니다.\n[정답]", "2": "풀 먹인 천을 다릴 때는 분무기로 물을 뿌리고 다려야 효과적입니다.", "3": "거풍할 때는 건조하고 맑게 갠 날 바람이 잘 통하는 그늘에서 해야 합니다.", "4": "실리카겔은 분홍색으로 변색되면 사용할 수 없습니다.", "5": "방충제는 공기보다 가벼우므로 보관할 때 주의가 필요합니다."}'::jsonb, '[{"term_ko": "세탁", "term_vi": "관리", "def_ko": "세탁(giặt)", "def_vi": "관리(quan lý)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (401, '11', '대상자의 면 속옷을 삶을 때 세탁방법으로 옳은 것은?', '["면직물 속옷은 줄어들기 때문에 주의해야 한다.", "먼저 삶은 후 세탁한다.", "삶을 때는 뚜껑을 열고 삶는다.", "색이 빠질 우려가 있는 제품은 절대 삶지 않는다.", "비눗물에 세탁물이 반쯤 잠길 정도로 넣고 삶는다."]'::jsonb, 5, NULL, NULL, '{"1": "면직물 속옷이 줄어든다는 점은 맞으나, 이 보기는 세탁 방법에 대한 질문이므로 정답이 아닙니다.\n[정답]", "5": "비눗물에서 반쯤 잠기도록 세탁하는 것이 올바른 방법입니다.", "2": "삶은 후 세탁하는 것은 일반적이지 않으므로 옳지 않습니다.", "3": "삶을 때 뚜껑을 열고 삶는 것은 안전하지 않으므로 적절하지 않습니다.", "4": "색이 빠질 우려가 있는 제품은 세탁법에 맞게 다르게 처리해야 하므로 잘못된 정보입니다."}'::jsonb, '[{"term_ko": "면", "term_vi": "Cotton", "def_ko": "면직물(한국어)", "def_vi": "Vải cotton"}, {"term_ko": "삶다", "term_vi": "Nấu", "def_ko": "끓이는 행위(한국어)", "def_vi": "Hành động đun sôi"}, {"term_ko": "세탁", "term_vi": "Giặt", "def_ko": "세탁(한국어)", "def_vi": "Giặt"}, {"term_ko": "제품", "term_vi": "Sản phẩm", "def_ko": "제품(한국어)", "def_vi": "Sản phẩm"}, {"term_ko": "우려", "term_vi": "Lo lắng", "def_ko": "걱정하는 상태(한국어)", "def_vi": "Tình trạng lo lắng"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (400, '11', '변실금으로 오염된 대상자의 속옷을 세탁하는 방법으로 옳은 것은?', '["뚜껑을 열고 삶는다.", "본 세탁 전에 애벌빨래를 한다.", "오염된 부위는 아세톤으로 세탁한다.", "얼룩을 제거하고 섬유유연제에 오래 담가 둔다.", "식초물에 여러 번 담갔다가 헹구어 건조한다."]'::jsonb, 2, NULL, NULL, '{"1": "뚜껑을 열고 삶는 것은 위생적이지 않으며, 잘못된 접근입니다.\n[정답]", "2": "본 세탁 전에 애벌빨래를 하는 것이 가장 적절한 방법입니다.", "3": "아세톤으로 세탁하는 것은 적합하지 않습니다.", "4": "섬유유연제에 오래 담가 두는 것은 필요하지 않으며, 알맞지 않은 방법입니다.", "5": "식초물에 담갔다가 헹구는 방법은 하지만, 일반적으로 선호되는 방법은 아닙니다."}'::jsonb, '[{"term_ko": "변실금", "term_vi": "Tiêu chảy", "def_ko": "대변의 제어를 잃는 질환", "def_vi": "Mất kiểm soát phân"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (399, '11', '대상자의 세탁물을 처리하는 방법으로 옳은 것은?', '["수선이 필요한 경우 세탁 후 수선한다.", "오염이 심한 세탁물은 드라이클리닝을 한다.", "립스틱은 클렌징 폼으로 얼룩을 살살 문질러 따뜻한 물에 헹군다.", "혈액얼룩은 더운물로 닦고 찬물에 헹군다.", "속옷은 뚜껑을 열고 삶는다."]'::jsonb, 3, NULL, NULL, '{"1": "수선이 필요한 경우 세탁 후 수선하기 보다는, 수선이 이루어져야 할 경우 수선 후 세탁하는 것이 일반적이다.\n[정답]", "2": "드라이클리닝은 소량의 더러움을 제거하는 데 적합하지 않다.", "3": "립스틱 얼룩은 클렌징 폼으로 문질러 따뜻한 물에 헹구는 것이 적절한 방법이다.", "4": "혈액얼룩은 따뜻한 물이 아닌 찬물로 처리해야 얼룩이 퍼지지 않는다.", "5": "속옷은 삶을 때 뚜껑을 열어서는 안전하지 않으며, 닫아서 삶아야 한다."}'::jsonb, '[{"term_ko": "세탁물", "term_vi": "Đồ giặt", "def_ko": "세탁하기 위한 의류", "def_vi": "Quần áo cần được giặt"}, {"term_ko": "오염", "term_vi": "Ô nhiễm", "def_ko": "더러움", "def_vi": "Bẩn"}, {"term_ko": "드라이클리닝", "term_vi": "Giặt khô", "def_ko": "화학약품으로 세탁하는 방법", "def_vi": "Phương pháp giặt sử dụng hóa chất"}, {"term_ko": "얼룩", "term_vi": "Vết bẩn", "def_ko": "더러운 흔적", "def_vi": "Dấu vết bẩn"}, {"term_ko": "속옷", "term_vi": "Đồ lót", "def_ko": "몸에 직접 닿는 의류", "def_vi": "Quần áo tiếp xúc trực tiếp với cơ thể"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (398, '11', '대상자의 침구류(A)와 선택 시 고려사항(B)으로 옳은 것은?', '["이불 따뜻하고 가벼우며 보습성이 있는 것", "이불 커버 거칠고 모직물로 된 것", "베개 목침처럼 딱딱한 베개", "시트 풀을 먹이고 재봉선이 있는 것", "매트리스 푹신하고 습기를 흡수하는 것"]'::jsonb, 1, NULL, NULL, '{"1": "이불이 따뜻하고 가벼우며 보습성이 있다는 것은 대상자의 편안함을 높여줍니다.\n[정답]", "2": "이불 커버가 거칠고 모직물로 된 것은 적절하지 않습니다.", "3": "딱딱한 베개는 목에 부담을 줄 수 있어 바람직하지 않습니다.", "4": "시트에 풀을 먹이고 재봉선이 있는 것은 오히려 불편할 수 있습니다.", "5": "푹신한 매트리스는 좋으나 너무 습기를 흡수하면 건강에 좋지 않을 수 있습니다."}'::jsonb, '[{"term_ko": "침구류", "term_vi": "Đồ đạc trên giường", "def_ko": "침대에 사용하는 모든 종류의 패브릭", "def_vi": "Tất cả các loại vải sử dụng trên giường"}, {"term_ko": "보습성", "term_vi": "Tính giữ ẩm", "def_ko": "습기를 유지하는 성질", "def_vi": "Đặc tính duy trì độ ẩm"}, {"term_ko": "거칠다", "term_vi": "Thô ráp", "def_ko": "표면이 부드럽지 않고 거친 상태", "def_vi": "Tình trạng bề mặt không mịn màng"}, {"term_ko": "딱딱하다", "term_vi": "Cứng", "def_ko": "단단한 상태", "def_vi": "Tình trạng chắc chắn"}, {"term_ko": "풀", "term_vi": "Keo", "def_ko": "접착제를 의미", "def_vi": "Có nghĩa là chất dính"}, {"term_ko": "재봉선", "term_vi": "Đường may", "def_ko": "천을 꿰매어 연결하는 선", "def_vi": "Dấu hiệu kết nối vải lại với nhau"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (397, '11', '대상자의 침구를 관리하는 방법으로 옳은 것은?', '["매트리스는 푹신한 소재를 선택한다.", "오리털 이불은 햇볕에 말린다.", "재봉선이 없는 시트를 사용한다.", "습기를 흡수하는 베갯속을 선택한다.", "침대 커버는 한 달에 한 번 세탁한다."]'::jsonb, 3, NULL, NULL, '{"1": "매트리스는 딱딱한 소재가 건강에 좋다.\n[정답]", "3": "재봉선이 없는 시트를 사용하면 세균 번식을 줄일 수 있다.", "2": "오리털 이불은 햇볕에 말리면 오히려 손상될 수 있다.", "4": "습기를 흡수하는 베갯속은 방지해주는 것이 좋다.", "5": "침대 커버는 1주일마다 세탁하는 것이 바람직하다."}'::jsonb, '[{"term_ko": "침구", "term_vi": "Bộ đồ giường", "def_ko": "침대와 관련된 모든 품목", "def_vi": "Tất cả các mặt hàng liên quan đến giường"}, {"term_ko": "매트리스", "term_vi": "Nệm", "def_ko": "침대의 뼈대", "def_vi": "Khung của giường"}, {"term_ko": "재봉선", "term_vi": "Đường khâu", "def_ko": "꿰매는 선", "def_vi": "Đường may"}, {"term_ko": "습기", "term_vi": "Độ ẩm", "def_ko": "물이 많은 상태", "def_vi": "Trạng thái có nhiều nước"}, {"term_ko": "세탁", "term_vi": "Giặt", "def_ko": "세척하다", "def_vi": "Rửa"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (396, '11', '재가 대상자의 주방을 위생적으로 관리하는 방법으로 옳은 것은?', '["냉장고는 계절별로 청소한다.", "냉장고 청소는 손을 씻고 변색된 음식을 버린다.", "냉장고 선반은 젖은 행주로 닦는다.", "손의 보습을 위해 고무장갑은 습기를 유지한다.", "쓰레기통은 자주 세척하고 건조한 후 사용한다."]'::jsonb, 5, NULL, NULL, '{"1": "냉장고는 계절별로 청소해야 하나, 청소 빈도가 중요하다.\n[정답]", "5": "쓰레기통은 자주 세척하고 건조한 후 사용하는 것이 위생적으로 관리하는 올바른 방법이다.", "2": "냉장고 청소 시 손을 씻고 변색된 음식을 버리는 것은 중요하지만 전반적인 위생 관리 방법에 포함되지 않는다.", "3": "냉장고 선반은 젖은 행주로 닦는 것보다는 마른 행주로 닦는 것이 바람직하다.", "4": "고무장갑의 사용 목적은 보습이 아닌 위생적인 작업을 돕기 위한 것이다."}'::jsonb, '[{"term_ko": "주방", "term_vi": "Nhà bếp", "def_ko": "부엌", "def_vi": "Nơi nấu ăn"}, {"term_ko": "위생", "term_vi": "Vệ sinh", "def_ko": "청결 상태", "def_vi": "Tình trạng sạch sẽ"}, {"term_ko": "청소", "term_vi": "Dọn dẹp", "def_ko": "더러운 것을 제거하는 행동", "def_vi": "Hành động loại bỏ sự bẩn"}, {"term_ko": "쓰레기통", "term_vi": "Thùng rác", "def_ko": "쓰레기를 담는 용기", "def_vi": "Bình chứa rác"}, {"term_ko": "세척", "term_vi": "Vệ sinh", "def_ko": "깨끗하게 하는 것", "def_vi": "Làm sạch"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (395, '11', '재가 대상자의 식기 및 주방을 위생적으로 관리하는 방법으로 옳은 것은?', '["기름기가 많은 그릇은 물로 세척한다.", "유통기한이 지난 음식은 빨리 조리한다.", "그물 모양 수세미보다 스펀지로 된 수세미를 사용한다.", "일반쓰레기와 음식물 쓰레기통을 함께 사용한다.", "삶을 수 없는 수세미는 소독제를 희석한 물에 담근다."]'::jsonb, 5, NULL, NULL, '{"1": "기름기가 많은 그릇은 물로 세척하면 기름이 잘 제거되지 않아 위생에 문제가 발생할 수 있다.", "2": "유통기한이 지난 음식은 빨리 조리해서도 먹으면 안 되며, 폐기해야 한다.", "3": "그물 모양 수세미는 표면이 거칠어서 위생적으로 좋지 않으므로 스펀지 수세미가 더 적합하다.\n[정답]", "4": "일반쓰레기와 음식물 쓰레기통은 분리해서 사용해야 위생적이다.", "5": "삶을 수 없는 수세미는 소독제를 희석한 물에 담가서 소독할 수 있다."}'::jsonb, '[{"term_ko": "재가 대상자", "term_vi": "Người nhận chăm sóc tại nhà", "def_ko": "가정에서 돌봄을 받는 사람", "def_vi": "Người được chăm sóc tại nhà"}, {"term_ko": "식기", "term_vi": "Chén dĩa", "def_ko": "식사 시 사용하는 그릇", "def_vi": "Đồ dùng ăn"}, {"term_ko": "위생", "term_vi": "Vệ sinh", "def_ko": "건강을 위해 깨끗하게 관리하는 것", "def_vi": "Quản lý sạch sẽ cho sức khỏe"}, {"term_ko": "주방", "term_vi": "Nhà bếp", "def_ko": "음식을 준비하는 곳", "def_vi": "Nơi chuẩn bị thực phẩm"}, {"term_ko": "수세미", "term_vi": "Bọt biển", "def_ko": "그릇을 씻는 도구", "def_vi": "Dụng cụ rửa chén"}, {"term_ko": "유통기한", "term_vi": "Hạn sử dụng", "def_ko": "식품의 소비 기한", "def_vi": "Thời gian tiêu thụ thực phẩm"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (394, '11', '수확한 뒤 상온에서 일정기간 보관했다가 먹으면 영양가가 더 좋아지는 과일로 옳은 것은?', '["토마토", "수박", "한라봉", "딸기", "블루베리"]'::jsonb, 1, NULL, NULL, '{"1": "수확 후 숙성이 진행되어 맛과 영양가가 증가합니다.\n[정답]", "2": "상온 보관 시 수분이 빠져나가 영양가가 감소할 수 있습니다.", "3": "수확 후 바로 소비하는 것이 좋습니다.", "4": "상온에서 보관해도 큰 변화가 없습니다.", "5": "다른 과일에 비해 숙성에 유리하지 않습니다."}'::jsonb, '[{"term_ko": "수확", "term_vi": "Thu hoạch", "def_ko": "수확하다(한국어)", "def_vi": "thu hoạch(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (393, '11', '대상자가 유효기간이 지난 영양제를 버리지 못하게 할 때 요양보호사의 대처방법으로 옳은 것은?', '["최대한 빨리 드시라고 말한다.", "냉동실에 보관하여 드시라고 한다.", "영양제 대신 다른 약을 넣어둔다.", "보호자가 지켜보는 앞에서 정리한다.", "가족에게 새로운 영양제 구입비용을 청구한다."]'::jsonb, 4, NULL, NULL, '{"1": "최대한 빨리 드시라고 말한다: 대상자의 안전을 고려하지 않은 비효율적인 방법입니다.\n[정답]", "4": "보호자가 지켜보는 앞에서 정리한다: 보호자의 동의와 지켜보는 상황에서 정리하는 것이 안전하고 바람직한 대처입니다.", "2": "냉동실에 보관하여 드시라고 한다: 잘못된 보관 방법입니다.", "3": "영양제 대신 다른 약을 넣어둔다: 안전하지 않으며 비윤리적인 방법입니다.", "5": "가족에게 새로운 영양제 구입비용을 청구한다: 문제가 해결되지 않고 불필요한 부담을 줄 수 있습니다."}'::jsonb, '[{"term_ko": "유효기간", "term_vi": "Hạn sử dụng", "def_ko": "특정 제품이 안전하게 사용될 수 있는 기간", "def_vi": "Thời gian mà sản phẩm có thể sử dụng an toàn"}, {"term_ko": "대상자", "term_vi": "Đối tượng", "def_ko": "돌봄을 받는 사람", "def_vi": "Người nhận sự chăm sóc"}, {"term_ko": "요양보호사", "term_vi": "Người chăm sóc", "def_ko": "노인을 돌보는 전문인", "def_vi": "Chuyên gia chăm sóc người già"}, {"term_ko": "보호자", "term_vi": "Người giám hộ", "def_ko": "환자를 담당하는 가족 또는 친척", "def_vi": "Gia đình hoặc người thân chăm sóc bệnh nhân"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (392, '11', '재가대상자의 식사를 도울 때 식중독을 예방할 수 있는 방법으로 옳은 것은?', '["야채굴죽은 50˚c에서 조리한다.", "냉동식품은 실온에서 해동한다.", "달걀은 조리 직전에 씻어서 사용한다.", "채소는 물에 1분 정도 담갔다 먹는다.", "해동 후 남은 어패류는 다시 냉동한다."]'::jsonb, 3, NULL, NULL, '{"1": "야채굴죽은 50˚c에서 조리하면 낮은 온도에서 조리되므로 식중독을 유발할 수 있는 세균이 살지 않을 가능성이 큽니다.\n[정답]", "2": "냉동식품은 실온에서 해동하면 식중독 세균이 성장할 수 있는 위험이 있습니다.", "3": "달걀은 조리 직전에 씻어서 사용하면 외부 오염물을 제거할 수 있어서 안전하게 사용할 수 있습니다.", "4": "채소는 물에 1분 정도 담갔다 먹으면 충분히 세척되지 못할 수 있어 도리어 위험할 수 있습니다.", "5": "해동 후 남은 어패류는 다시 냉동하는 것은 품질 저하와 식중독 위험을 높일 수 있습니다."}'::jsonb, '[{"term_ko": "재가대상자", "term_vi": "Người nhận dịch vụ tại nhà", "def_ko": "가정에서 요양받는 사람", "def_vi": "Người nhận dịch vụ chăm sóc sức khỏe tại nhà"}, {"term_ko": "식중독", "term_vi": "Ngộ độc thực phẩm", "def_ko": "식사나 음식을 통해 감염되는 질병", "def_vi": "Bệnh truyền qua thực phẩm"}, {"term_ko": "조리", "term_vi": "Nấu ăn", "def_ko": "음식 만드는 과정", "def_vi": "Quá trình chế biến thức ăn"}, {"term_ko": "세균", "term_vi": "Vi khuẩn", "def_ko": "미생물의 일종", "def_vi": "Một loại vi sinh vật"}, {"term_ko": "위험", "term_vi": "Nguy hiểm", "def_ko": "위험한 상황", "def_vi": "Tình huống nguy hiểm"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (391, '11', '치아 손실이 있는 재가대상자의 식사를 조리하는 방법으로 옳은 것은?', '["삼치는 바싹 튀겨 소금을 뿌린다.", "오징어는 물을 붓고 오랫동안 삶는다.", "흰떡은 큼직하게 썰어 기름에 볶는다.", "양배추는 센 불로 익힌 후 약불로 줄여서 찐다.", "소고기는 납작하게 저며서 말려 육포로 만든다."]'::jsonb, 4, NULL, NULL, '{"1": "삼치는 바싹 튀겨 소금을 뿌리면, 경도가 높아 씹기 힘들 수 있습니다.\n[정답]", "2": "오징어는 물을 붓고 오랫동안 삶으면 부드러워져 쉽게 먹을 수 있습니다.", "3": "흰떡은 큼직하게 썰어 기름에 볶으면 소화에 부담을 줄 수 있습니다.", "4": "양배추는 센 불로 익힌 후 약불로 줄여서 찌면 부드럽고 소화가 잘 됩니다.", "5": "소고기는 납작하게 저며서 말려 육포로 만들면 식사에 적합하지 않을 수 있습니다."}'::jsonb, '[{"term_ko": "치아", "term_vi": "Răng", "def_ko": "이(한국어)", "def_vi": "Răng"}, {"term_ko": "손실", "term_vi": "Mất", "def_ko": "잃다(한국어)", "def_vi": "Thua lỗ"}, {"term_ko": "재가대상자", "term_vi": "Người chăm sóc tại nhà", "def_ko": "재가에서 관리받는 사람(한국어)", "def_vi": "Người nhận sự chăm sóc tại nhà"}, {"term_ko": "식사", "term_vi": "Bữa ăn", "def_ko": "먹는 일(한국어)", "def_vi": "Bữa ăn"}, {"term_ko": "조리", "term_vi": "Nấu ăn", "def_ko": "음식을 만드는 일(한국어)", "def_vi": "Nấu ăn"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (390, '11', '삼킴장애 대상자의 식사 시 주의사항으로 옳은 것은?', '["떠먹는 요구르트보다 마시는 요구르트를 제공한다.", "밥을 국이나 물에 말아 먹인다.", "참외를 숫가락으로 긁어서 먹인다.", "채소는 레몬소스를 뿌려 먹인다.", "계란은 반숙보다 완숙으로 먹는다."]'::jsonb, 3, NULL, NULL, '{"1": "떠먹는 요구르트보다 마시는 요구르트를 제공하는 것은 삼킴장애에 좋지 않습니다. 마시는 요구르트는 넘어질 위험이 높습니다.\n[정답]", "3": "참외를 숫가락으로 긁어서 먹이는 것은 안전한 방법입니다. 삼킴장애가 있는 분들에게 알맞은 식사를 제공합니다.", "2": "밥을 국이나 물에 말아 먹이는 것은 삼킴장애를 악화시킬 수 있습니다.", "4": "채소는 레몬소스를 뿌려 먹이지 않는 것이 좋습니다. 소스가 넘치는 위험이 있습니다.", "5": "계란은 반숙보다 완숙으로 먹이는 것이 일반적으로 안전하지만, 삼킴장애의 경우에는 과도한 조리 방법이 필요할 수 있습니다."}'::jsonb, '[{"term_ko": "삼킴장애", "term_vi": "Rối loạn nuốt", "def_ko": "음식이나 액체를 삼키는 데 어려움이 있는 상태", "def_vi": "Tình trạng khó khăn trong việc nuốt thức ăn hoặc chất lỏng"}, {"term_ko": "안전", "term_vi": "An toàn", "def_ko": "위험이 없는 상태", "def_vi": "Tình trạng không có nguy cơ"}, {"term_ko": "식사", "term_vi": "Bữa ăn", "def_ko": "음식을 먹는 행위", "def_vi": "Hành động ăn uống"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (389, '11', '고혈압 대상자에게 혈압을 낮추기 위해 제공할 수 있는 칼륨이 많이 함유된 식품으로 옳은 것은?', '["깻잎 장아찌", "조개젓", "강된장", "찐 감자", "마른 오징어"]'::jsonb, 4, NULL, NULL, '{"1": "깻잎 장아찌: 칼륨 함량이 낮고, 나트륨이 많이 포함되어 있기 때문에 고혈압에 적합하지 않습니다.\n[정답]", "4": "찐 감자: 칼륨이 풍부하여 혈압을 낮추는 데 도움이 됩니다.", "2": "조개젓: 나트륨 함량이 매우 높아 고혈압에는 좋지 않습니다.", "3": "강된장: 나트륨이 많아 고혈압에 적합하지 않습니다.", "5": "마른 오징어: 칼륨 함량이 낮고 나트륨이 많아 부적합합니다."}'::jsonb, '[{"term_ko": "고혈압", "term_vi": "Tăng huyết áp", "def_ko": "고혈압(한국어)", "def_vi": "Tăng huyết áp(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (388, '11', '당뇨병 대상자의 혈당 관리에 도움이 되는 혈당지수 낮은 식품으로 옳은 것은?', '["미역", "고구마", "수박", "흰 식빵", "떡"]'::jsonb, 1, NULL, NULL, '{"1": "미역은 혈당 지수가 낮아 당뇨병 환자에게 좋은 식품입니다.\n[정답]", "2": "고구마는 혈당 지수가 상대적으로 낮지만, 미역보다 혈당 관리에 덜 효과적일 수 있습니다.", "3": "수박은 혈당 지수가 높은 편입니다.", "4": "흰 식빵은 혈당 지수가 높아 당뇨병 환자에게 피해야 할 식품입니다.", "5": "떡은 일반적으로 혈당 지수가 높아 당뇨병 환자에게 적합하지 않습니다."}'::jsonb, '[{"term_ko": "혈당 관리", "term_vi": "Quản lý đường huyết", "def_ko": "혈 đường 수치를 조절하는 것", "def_vi": "Điều chỉnh mức đường trong máu"}, {"term_ko": "당뇨병", "term_vi": "Bệnh tiểu đường", "def_ko": "만성 질환으로 인슐린의 분비나 작용이 부족.", "def_vi": "Bệnh mãn tính do thiếu hụt sự bài tiết hoặc tác động của insulin"}, {"term_ko": "혈당 지수", "term_vi": "Chỉ số đường huyết", "def_ko": "식품이 혈당에 끼치는 영향의 척도", "def_vi": "Thước đo ảnh hưởng của thực phẩm đến đường huyết"}, {"term_ko": "식품", "term_vi": "Thực phẩm", "def_ko": "음식, thực phẩm", "def_vi": "Thực phẩm"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (387, '11', '대상자의 식사를 준비하기 위해 장을 볼 때 고려할 사항으로 옳은 것은?', '["한 번에 많은 양의 식품을 구입한다.", "장을 본 후 결과에 만족하는지를 확인한다.", "장보기 후 경비 결산은 시설장에게 한다.", "가족이 먹고 싶은 음식을 확인하여 구입한다.", "요양보호사 자신에게 필요한 물품을 함께 구입한다."]'::jsonb, 2, NULL, NULL, '{"1": "한 번에 많은 양의 식품을 구입하는 것은 식품의 신선도를 떨어뜨릴 수 있으므로 바람직하지 않습니다.\n[정답]", "2": "장을 본 후 결과에 만족하는지를 확인하는 것은 올바른 행동입니다. 식품의 질이나 양을 체크해야 합니다.", "3": "장보기 후 경비 결산은 일반적으로 요양보호사가 아닌 다른 책임자가 해야 합니다.", "4": "가족이 먹고 싶은 음식을 확인하여 구입하는 것도 중요하지만, 대상자의 건강 상태를 우선 고려해야 합니다.", "5": "요양보호사 자신에게 필요한 물품을 함께 구입하는 것은 업무의 초점을 흐릴 수 있습니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người được chăm sóc", "def_ko": "환자", "def_vi": "Bệnh nhân"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (386, '11', '재가 대상자의 식사를 준비하는 방법으로 옳은 것은?', '["음식이 뜨거울 때 간을 맞춘다.", "무, 버섯으로 만든 채수로 국물을 만든다.", "생선은 오래 굽고 육류는 기름에 튀긴다.", "엿과 설탕 같은 단당류로 음식을 조리한다.", "음식은 한꺼번에 만들어 두고 조금씩 제공한다."]'::jsonb, 2, NULL, NULL, '{"1": "음식이 뜨거울 때 간을 맞추면 균형 잡힌 맛을 내기 어렵다. \n[정답]", "2": "무와 버섯으로 만든 채수는 건강한 국물 대신으로 적합하다.", "3": "생선을 너무 오래 굽는 것은 질감을 떨어뜨리고 육류를 기름에 튀기는 것은 건강에 좋지 않다.", "4": "엿과 설탕처럼 단당류는 과다 섭취 시 건강에 문제를 일으킬 수 있다.", "5": "음식은 신선하게 제공하는 것이 좋으며, 미리 만들어야 할 경우 적절한 보관이 필요하다."}'::jsonb, '[{"term_ko": "재가 대상자", "term_vi": "Đối tượng chăm sóc tại nhà", "def_ko": "가정에서 요양을 받는 환자", "def_vi": "Người bệnh nhận sự chăm sóc tại nhà"}, {"term_ko": "식사", "term_vi": "Bữa ăn", "def_ko": "음식을 준비하고 제공하는 행위", "def_vi": "Hành động chuẩn bị và phục vụ thức ăn"}, {"term_ko": "채수", "term_vi": "Nước dùng", "def_ko": "채소를 우려낸 물", "def_vi": "Nước được chiết xuất từ rau củ"}, {"term_ko": "단당류", "term_vi": "Đường đơn", "def_ko": "단순당으로 구성된 당분", "def_vi": "Loại đường cấu thành từ các đường đơn giản"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (385, '11', '식사를 준비하면서 재가대상자에게 설명한 것으로 옳은 것은?', '["\"반찬을 만들고 남은 재료는 제가 가져갈게요.\"", "\"야채 사고 남은 돈은 아들에게 주었어요.\"", "\"어르신은 편찮으시니까 죽만 드시는 것이 좋겠어요.\"", "\"냉장고에 있던 과일은 오래된 것 같아서 버렸어요.\"", "\"혈당이 높으니 어르신이 좋아하는 잡곡밥을 해드릴게요.\""]'::jsonb, 5, NULL, NULL, '{"1": "식사 준비 과정에서 재료를 가져가는 것은 불필요한 소통이다.\n[정답]", "5": "어르신의 건강 상태에 맞춰 잡곡밥을 제공하는 것이 적절하다.", "2": "개인적인 사정을 언급하는 것은 전문적인 의사소통이 아니다.", "3": "어르신의 건강을 고려한 발언이지만, 메시지가 명확하지 않다.", "4": "과일 소실에 대한 무책임한 언급으로서 부적절하다."}'::jsonb, '[{"term_ko": "식사", "term_vi": "준비", "def_ko": "식사(한국어), bữa ăn(베트남어)", "def_vi": "준비(한국어), chuẩn bị(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (384, '10', '자세 변환용 쿠션을 선택할 때 고려해야 할 사항으로 옳은 것은?', '["부착된 지퍼가 노출되어 있어야 한다.", "내부 충진재가 커버 밖으로 나와 있어야 한다.", "견고하고 딱딱한 재질이어야 한다.", "커버는 분리되지 않아야 한다.", "변질되지 않는 것이어야 한다."]'::jsonb, 5, NULL, NULL, '{"1": "부착된 지퍼가 노출되어 있는 것은 안전하지 않으므로 바람직하지 않습니다.\n[정답]", "5": "변질되지 않는 것이어야 하며, 이는 쿠션의 지속적인 사용을 위해 중요합니다.", "3": "견고하고 딱딱한 재질은 편안함을 제공하지 않을 수 있습니다.", "4": "커버가 분리되지 않는 것은 관리 측면에서 불편할 수 있습니다.", "2": "내부 충진재가 커버 밖으로 나와 있는 것은 안전 문제가 발생할 수 있습니다."}'::jsonb, '[{"term_ko": "자세", "term_vi": "Tư thế", "def_ko": "태도(한국어)", "def_vi": "Thái độ(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (383, '10', '신체압력을 분산시켜 욕창을 예방하며 보온성, 통풍성이 용이한 것을 선택해야 하는 대여 복지용구로 옳은 것은?', '["침대형 휠체어", "욕창예방 매트리스", "욕창예방 방석", "전동 침대", "자세변환 쿠션"]'::jsonb, 2, NULL, NULL, '{"1": "침대형 휠체어는 이동성을 제공하지만 압력 분산 효과가 낮다.\n[정답]", "2": "욕창예방 매트리스는 압력을 잘 분산시켜 욕창 예방에 효과적이다.", "3": "욕창예방 방석은 특정 부위에 초점을 맞추지만 전체적인 보온성과 통풍성은 부족할 수 있다.", "4": "전동 침대는 기능성이 뛰어나나 압력 분산에 제한적이다.", "5": "자세변환 쿠션은 주로 자세를 바꾸는 데 사용되며 압력 분산 효과가 매트리스보다 낮다."}'::jsonb, '[{"term_ko": "신체압력", "term_vi": "Áp lực cơ thể", "def_ko": "압력이 신체에 미치는 영향", "def_vi": "Ảnh hưởng của áp lực lên cơ thể"}, {"term_ko": "욕창", "term_vi": "Loét do tì đè", "def_ko": "피부가 손상되는 질환", "def_vi": "Bệnh gây tổn thương da"}, {"term_ko": "예방", "term_vi": "Ngăn ngừa", "def_ko": "방지하거나 예방하는 것", "def_vi": "Ngăn chặn hoặc phòng ngừa"}, {"term_ko": "복지용구", "term_vi": "Thiết bị hỗ trợ", "def_ko": "장애인을 돕기 위한 도구", "def_vi": "Công cụ giúp người khuyết tật"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (382, '10', '이동욕조 선정이나 사용 시 고려할 사항으로 옳은 것은?', '["배수구가 막혀져 있는 것을 사용한다.", "욕조 안이 미끄러워야 한다.", "공기 주입 및 조립이 복잡해야 한다.", "팽창상태에서 변형이 가능해야 한다.", "평평하고 이물질이 없는 장소에서 사용한다."]'::jsonb, 5, NULL, NULL, '{"1": "배수구가 막혀져 있는 것은 안전상 문제를 일으킬 수 있으므로 옳지 않다.", "2": "욕조 안이 미끄러우면 안전사고의 위험이 높아진다.", "3": "공기 주입 및 조립이 복잡하면 사용이 불편해진다.\n[정답]", "5": "평평하고 이물질이 없는 장소에서 사용하는 것이 안전에 중요하다.", "4": "팽창상태에서 변형이 가능해야 할 필요는 없다."}'::jsonb, '[{"term_ko": "이동욕조", "term_vi": "Bồn tắm di động", "def_ko": "이동이 가능한 욕조", "def_vi": "Bồn tắm có thể di chuyển"}, {"term_ko": "배수구", "term_vi": "Cống thoát nước", "def_ko": "물이 빠지는 구멍", "def_vi": "Lỗ để nước chảy ra"}, {"term_ko": "미끄러움", "term_vi": "Trơn trượt", "def_ko": "미끄러운 상태", "def_vi": "Trạng thái trơn trượt"}, {"term_ko": "이물질", "term_vi": "Chất lạ", "def_ko": "원하지 않는 물체", "def_vi": "Vật thể không mong muốn"}, {"term_ko": "평평하다", "term_vi": "Bằng phẳng", "def_ko": "고른 표면을 가지다", "def_vi": "Có bề mặt phẳng"}, {"term_ko": "변형", "term_vi": "Biến dạng", "def_ko": "형태가 바뀌다", "def_vi": "Thay đổi hình dạng"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (381, '10', '목욕리프트 선정 시 고려사항으로 옳은 것은?', '["등받이가 각도가 고정된 것", "대상자의 무게를 지탱할 수 있는 것", "높낮이가 수동으로 조절되는 것", "철재로 만들어진 것", "요양보호사가 옮기기에 부담스러운 것"]'::jsonb, 2, NULL, NULL, '{"1": "등받이가 고정된 것은 사용에 불편함을 초래할 수 있습니다.\n[정답]", "2": "대상자의 무게를 지탱할 수 있는 것은 필수적인 요구 사항입니다.", "3": "높낮이가 수동으로 조절되는 것은 사용의 편의성을 저하시킬 수 있습니다.", "4": "철재로 만들어진 것은 내구성에 영향을 미칠 수 있지만, 반드시 필요한 조건은 아닙니다.", "5": "요양보호사가 옮기기에 부담스러운 것은 적절한 선택이 아닙니다."}'::jsonb, '[{"term_ko": "목욕리프트", "term_vi": "Xe nâng tắm", "def_ko": "욕실에서 환자를 들어 올리는데 사용하는 기기", "def_vi": "Thiết bị dùng để nâng người bệnh trong nhà tắm"}, {"term_ko": "고정", "term_vi": "Cố định", "def_ko": "고정된 상태를 유지하는 것", "def_vi": "Giữ nguyên trạng thái"}, {"term_ko": "무게", "term_vi": "Trọng lượng", "def_ko": "질량 혹은 중량", "def_vi": "Khối lượng hoặc cân nặng"}, {"term_ko": "지탱하다", "term_vi": "Gánh vác", "def_ko": "지탱하는 것, 지지하는 것", "def_vi": "Điều gì đó, hỗ trợ"}, {"term_ko": "부담스럽다", "term_vi": "Gánh nặng", "def_ko": "힘들고 불편하다", "def_vi": "Khó khăn và không thoải mái"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (380, '10', '거동이 불편한 대상자의 생활공간에 안전손잡이를 설치해야 하는 이유는?', '["근력과 지구력 증진", "심장과 폐기능 향상", "유연성과 신장성 향상", "스트레칭과 유산소 운동 증진", "자립심 향상과 신체 균형 유지"]'::jsonb, 5, NULL, NULL, '{"1": "근력과 지구력 증진은 안전손잡이 설치와 직접적인 관계가 없습니다.\n[정답]", "5": "자립심 향상과 신체 균형 유지는 안전손잡이를 설치함으로써 이룰 수 있는 중요한 효과입니다.", "2": "심장과 폐기능 향상은 주로 유산소 운동과 연관이 있습니다.", "3": "유연성과 신장성 향상은 운동의 결과일 수 있습니다.", "4": "스트레칭과 유산소 운동 증진은 다른 목적의 활동입니다."}'::jsonb, '[{"term_ko": "거동", "term_vi": "Hành động", "def_ko": "움직임(한국어)", "def_vi": "Hành động di chuyển"}, {"term_ko": "불편", "term_vi": "Khó khăn", "def_ko": "불편함(한국어)", "def_vi": "Tình trạng khó khăn"}, {"term_ko": "대상자", "term_vi": "Đối tượng", "def_ko": "환자, 사용자(한국어)", "def_vi": "Người cần chăm sóc"}, {"term_ko": "생활공간", "term_vi": "Không gian sống", "def_ko": "생활 공간(한국어)", "def_vi": "Không gian sinh hoạt"}, {"term_ko": "안전손잡이", "term_vi": "Tay cầm an toàn", "def_ko": "안전하게 잡을 수 있는 기구(한국어)", "def_vi": "Dụng cụ cầm nắm an toàn"}, {"term_ko": "자립심", "term_vi": "Tự lập", "def_ko": "자립하는 마음(한국어)", "def_vi": "Tinh thần tự lập"}, {"term_ko": "신체", "term_vi": "Cơ thể", "def_ko": "몸(한국어)", "def_vi": "Cơ thể"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (379, '10', '성인용 보행기 선정 시 고려해야 할 사항으로 옳은 것은?', '["고무받침은 매번 사용할 때마다 교환한다.", "접이식 보행기라면 펼친 후에 잠금 버튼을 확인한다.", "잘 미끄러지는 신발을 신는다.", "바퀴가 있는 경우 잠금장치를 풀고 일어난다.", "팔꿈치가 약 15˚구부러지도록 대상자 둔부 높이로 한다."]'::jsonb, 2, NULL, NULL, '{"1": "고무받침은 매번 교환할 필요가 없습니다. 주기적으로 확인하고 교환해야 하지만 매번 사용할 때마다 교환할 필요는 없습니다.\n[정답]", "2": "접이식 보행기를 사용할 경우, 펼친 후에 잠금 버튼이 제대로 작동하는지 확인하는 것은 매우 중요합니다. 이는 안전사고를 예방하는 데 필수적입니다.", "3": "잘 미끄러지는 신발은 보행 안전에 도움이 되지 않습니다. 미끄러짐을 방지할 수 있는 적절한 신발이 필요합니다.", "4": "바퀴가 있는 경우, 잠금장치를 해제한 상태에서 일어나는 것은 위험합니다. 항상 잠금을 걸어야 합니다.", "5": "팔꿈치가 약 15˚ 구부러지도록 조정하는 것은 적절하지만, 대상자의 둔부 높이에 맞춰야 하며, 이를 주의 깊게 고려해야 합니다."}'::jsonb, '[{"term_ko": "성인용 보행기", "term_vi": "Xe đi bộ cho người lớn tuổi", "def_ko": "성인을 위한 보행 보조기구", "def_vi": "Thiết bị hỗ trợ đi lại cho người lớn tuổi"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (378, '10', '휠체어의 잠금장치 기능이 약할 때 점검해야 할 사항으로 옳은 것은?', '["팔걸이", "받침쇠", "바퀴 손잡이", "발 받침대", "타이어 공기압"]'::jsonb, 5, NULL, NULL, '{"1": "팔걸이는 잠금장치와 직접적인 관련이 없습니다.", "2": "받침쇠는 일반적으로 안정성을 높이는 역할을 하지만 잠금장치의 기능을 점검하는 데는 필요하지 않습니다.", "3": "바퀴 손잡이는 휠체어 조작에 중요한 요소이나 잠금장치와 관계는 적습니다.\n[정답]", "4": "발 받침대는 사용자의 안전을 위해 조정할 수 있으나 잠금장치의 점검과는 관계가 없습니다.", "5": "타이어 공기압은 휠체어의 안정성과 관련이 있으며, 잠금장치 기능이 약할 때 필수적으로 점검해야 할 사항입니다."}'::jsonb, '[{"term_ko": "휠체어", "term_vi": "Xe lăn", "def_ko": "휠체어(한국어)", "def_vi": "Xe lăn"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (377, '10', '복지용구 중에서 요실금 팬티를 사용하는 방법으로 옳은 것은?', '["요실금 팬티는 세탁하여 사용할 수 있다.", "실금량이 적을 때는 말려서 재사용한다.", "요실금 팬티 위에 일반 팬티를 덧입힌다.", "신체보다 한두 치수 큰 것으로 사용한다.", "외형이 보통 팬티와 달라 구분이 잘 된다."]'::jsonb, 1, NULL, NULL, '{"1": "요실금 팬티는 세탁하여 사용할 수 있다.\n[정답]", "2": "실금량이 적을 때는 말려서 재사용한다.", "3": "요실금 팬티 위에 일반 팬티를 덧입힌다.", "4": "신체보다 한두 치수 큰 것으로 사용한다.", "5": "외형이 보통 팬티와 달라 구분이 잘 된다."}'::jsonb, '[{"term_ko": "요실금", "term_vi": "Tiểu tiện không tự chủ", "def_ko": "의도하지 않은 소변의 유출", "def_vi": "Sự rò rỉ nước tiểu không có ý định"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (376, '10', '간이변기의 재질로 적합한 것은?', '["세척 후 변형이 없어야 한다.", "물 세척이나 소독약으로 소독할 수 있는 재질이어야 한다.", "열탕으로 소독할 수 있도록 충분한 내열성이 있어야 한다.", "녹이 슬지 않고 미끄러지지 않는 재질이 좋다.", "표면에 도장이 되어 있어야 한다."]'::jsonb, 3, NULL, NULL, '{"1": "간이변기는 세척 후 변형이 없어야 한다는 것은 중요하지만, 재질로 적합한지의 기준이 아니다.\n[정답]", "2": "물 세척이나 소독약으로 소독할 수 있는 재질이어야 한다는 것은 필요조건이지만, 내열성의 중요성을 간과할 수 없다.", "3": "열탕으로 소독할 수 있도록 충분한 내열성이 있어야 한다는 것이 가장 적합한 조건이다.", "4": "녹이 슬지 않고 미끄러지지 않는 재질이 좋지만, 이것이 재질의 직접적인 특성상 우선 순위는 아니다.", "5": "표면에 도장이 되어 있어야 한다는 조건은 필수 조건이 아니다."}'::jsonb, '[{"term_ko": "간이변기", "term_vi": "Bồn vệ sinh di động", "def_ko": "이동하는 화장실", "def_vi": "Nhà vệ sinh có thể di chuyển"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (375, '10', '노인장기요양보험 급여 복지용구 중 구입 가능한 품목으로 옳은 것은?', '["전동침대", "이동욕조", "수동휠체어", "배회감지기", "성인용 보행기"]'::jsonb, 5, NULL, NULL, '{"1": "전동침대는 노인장기요양보험 지원 품목이 아닙니다.", "2": "이동욕조는 노인장기요양보험 지원 품목이 아닙니다.", "3": "수동휠체어는 노인장기요양보험 지원 품목이 아닙니다.\n[정답]", "4": "배회감지기는 노인장기요양보험 지원 품목이 아닙니다.", "5": "성인용 보행기는 노인장기요양보험에서 구입 가능한 품목입니다."}'::jsonb, '[{"term_ko": "노인장기요양보험", "term_vi": "Bảo hiểm chăm sóc dài hạn cho người cao tuổi", "def_ko": "노인을 위한 장기적인 요양 서비스 제공을 위한 보험", "def_vi": "Bảo hiểm cung cấp dịch vụ chăm sóc dài hạn cho người cao tuổi"}, {"term_ko": "복지용구", "term_vi": "Thiết bị hỗ trợ", "def_ko": "노인이나 장애인을 위한 행복과 편리함을 제공하는 기구", "def_vi": "Dụng cụ cung cấp tiện nghi và hạnh phúc cho người cao tuổi hoặc người khuyết tật"}, {"term_ko": "구입", "term_vi": "Mua sắm", "def_ko": "구매하다", "def_vi": "Mua hàng"}, {"term_ko": "품목", "term_vi": "Hạng mục", "def_ko": "물품의 종류", "def_vi": "Loại hàng hóa"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (374, '10', '다리가 모두 약한 대상자가 보행보조차를 사용하여 이동하는 방법으로 옳은 것은?', '["보행보조차 → 오른발 → 왼발", "오른쪽 발과 보행보조차 → 왼발", "보행보조차 → 오른발·왼발", "고무받침은 정해진 날짜에만 확인한다.", "팔꿈치가 약 15˚구부러지도록 손잡이를 엉덩이 높이로 조절한다."]'::jsonb, 1, NULL, NULL, '{"1": "보행보조차를 먼저 놓고 그 다음에 오른발, 왼발의 순서로 이동하는 방법입니다. [정답]", "2": "오른발과 보행보조차를 함께 이동시키는 방법은 올바르지 않습니다.", "3": "보행보조차와 함께 양발을 동시에 움직이는 것은 올바른 보행 방법이 아닙니다.", "4": "고무받침은 늘 확인이 필요하며 정해진 날짜에만 확인하는 것은 틀린 내용입니다.", "5": "손잡이 높이는 개개인에 맞춰 조정해야 하며, 15˚ 구부리는 것은 적절하지 않을 수 있습니다."}'::jsonb, '[{"term_ko": "다리", "term_vi": "Chân", "def_ko": "다리(한국어)", "def_vi": "chân(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (373, '10', '왼쪽 다리가 마비된 대상자가 지팡이를 짚고 계단을 내려갈 때 순서로 옳은 것은?', '["지팡이 → 왼쪽 다리 → 오른쪽 다리", "지팡이 → 오른쪽 다리 → 왼쪽 다리", "오른쪽 다리 → 지팡이 → 왼쪽 다리", "오른쪽 다리 → 왼쪽 다리 → 지팡이", "왼쪽 다리 → 지팡이 → 오른쪽 다리"]'::jsonb, 1, NULL, NULL, '{"1": "지팡이를 먼저 짚고 마비된 왼쪽 다리를 내린 후, 건강한 오른쪽 다리를 내리는 순서가 옳습니다.\n[정답]", "2": "지팡이와 오른쪽 다리를 먼저 내리는 것은 잘못된 순서입니다.", "3": "오른쪽 다리를 먼저 내리는 것은 마비된 쪽에 부상을 줄 수 있으므로 옳지 않습니다.", "4": "오른쪽 다리를 내린 후 왼쪽 다리를 내리는 순서는 반대가 되어 잘못된 순서입니다.", "5": "마비된 왼쪽 다리를 먼저 내리면 넘어질 위험이 큽니다."}'::jsonb, '[{"term_ko": "다리", "term_vi": "Chân", "def_ko": "다리(한국어)", "def_vi": "Chân"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (372, '10', '왼쪽 편마비 대상자가 지팡이가 없을 때 계단을 내려가는 순서로 옳은 것은?', '["오른쪽 손으로 계단 손잡이 → 왼쪽 다리 → 오른쪽 다리", "오른쪽 손으로 계단 손잡이 → 오른쪽 다리 → 왼쪽 다리", "오른쪽 다리 → 오른쪽 손으로 계단 손잡이 → 왼쪽 다리", "오른쪽 다리 → 왼쪽 다리 → 오른쪽 손으로 계단 손잡이", "왼쪽 다리 → 오른쪽 손으로 계단 손잡이 → 오른쪽 다리"]'::jsonb, 1, NULL, NULL, '{"1": "오른쪽 손으로 계단 손잡이를 잡고, 왼쪽 다리를 먼저 내리고, 그 다음 오른쪽 다리를 내려야 합니다. 이는 편마비 환자가 균형을 유지하며 안전하게 내려갈 수 있는 방법입니다.\n[정답]", "2": "오른쪽 다리는 먼저 내리고, 왼발을 그 뒤에 일반적으로 내리는 수순은 올바르지 않습니다.", "3": "오른쪽 다리를 먼저 내리고 손잡이를 잡는 것은 불안정할 수 있으며 불편합니다.", "4": "오른쪽 다리부터 내리고 왼쪽 다리를 내려가는 것은 균형을 잃을 위험이 있습니다.", "5": "왼쪽 다리를 먼저 내리고 후에 손잡이를 잡는 것 역시 위험합니다."}'::jsonb, '[{"term_ko": "편마비", "term_vi": "Liệt nửa người", "def_ko": "왼쪽 또는 오른쪽 신체의 근육 기능이 약화된 상태", "def_vi": "trạng thái yếu cơ của một bên cơ thể"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (371, '10', '오른쪽 편마비 대상자가 지팡이를 이용하여 계단을 오를 때 순서로 옳은 것은?', '["지팡이 → 왼쪽 다리 → 오른쪽 다리", "지팡이 → 오른쪽 다리 → 왼쪽 다리", "오른쪽 다리 → 지팡이 → 왼쪽 다리", "오른쪽 다리 → 왼쪽 다리 → 지팡이", "왼쪽 다리 → 지팡이 → 오른쪽 다리"]'::jsonb, 1, NULL, NULL, '{"1": "지팡이를 사용하여 왼쪽 다리를 먼저 내디디고 오른쪽 다리를 뒤따라 오르는 올바른 순서이다.\n[정답]", "2": "오른쪽 다리로 이동하고 난 후 왼쪽 다리를 내디디는 방법은 부적절하다.", "3": "오른쪽 다리를 먼저 내디디는 것은 편마비 환자에게 위험하다.", "4": "오른쪽 다리는 뒤에 남기고 왼쪽 다리를 먼저 내디디는 순서는 잘못되었다.", "5": "왼쪽 다리를 먼저 내디디고 지팡이를 사용하는 것은 순서 상으로 올바르지 않다."}'::jsonb, '[{"term_ko": "편마비", "term_vi": "Liệt nửa người", "def_ko": "반쪽 몸이 마비된 상태", "def_vi": "Tình trạng bị liệt một nửa cơ thể"}, {"term_ko": "지팡이", "term_vi": "Gậy", "def_ko": "보행을 도와주는 도구", "def_vi": "Công cụ giúp đi lại"}, {"term_ko": "계단", "term_vi": "Cầu thang", "def_ko": "올라가는 구조물", "def_vi": "Cấu trúc để đi lên"}, {"term_ko": "대상자", "term_vi": "Người nhận trợ giúp", "def_ko": "도움을 받는 환자", "def_vi": "Bệnh nhân nhận giúp đỡ"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (370, '10', '오른쪽 편마비 대상자가 지팡이가 없을 때 계단을 오르는 순서로 옳은 것은?', '["왼쪽 손으로 계단 손잡이 → 왼쪽 다리 → 오른쪽 다리", "왼쪽 손으로 계단 손잡이 → 오른쪽 다리 → 왼쪽 달 ㅣ", "오른쪽 다리 → 왼쪽 손으로 계단 손잡이 → 왼쪽 다리", "오른쪽 다리 → 왼쪽 다리 → 왼손으로 계단 손잡이", "왼쪽 다리 → 왼쪽 손으로 계단 손잡이 → 오른쪽 다리"]'::jsonb, 1, NULL, NULL, '{"1": "왼쪽 손으로 계단 손잡이를 잡고, 왼쪽 다리로 먼저 올라가면 몸의 균형을 유지하며 이동할 수 있습니다.\n[정답]", "2": "오른쪽 다리로 올라가면 편마비 상태에서 균형을 잡기 어려워 위험할 수 있습니다.", "3": "오른쪽 다리로 먼저 오르면 이동의 안전성이 떨어집니다.", "4": "오른쪽 다리로 먼저 올라가면 중심이 불안정해질 수 있습니다.", "5": "왼쪽 다리가 아닌 오른쪽 다리를 먼저 올라가는 것은 안전하지 않습니다."}'::jsonb, '[{"term_ko": "편마비", "term_vi": "Liệt nửa người", "def_ko": "한쪽 신체의 마비 상태", "def_vi": "Tình trạng mất khả năng vận động một bên cơ thể"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (369, '10', '오른쪽 편마비 대상자를 부축하며 걷는 방법으로 옳은 것은?', '["대상자 옆에서 팔로 양 어깨를 껴안듯 잡는다.", "대상자의 오른쪽 어깨를 감싸고, 오른손을 잡고 걷는다.", "서로 같은 편 발을 앞으로 내딛어 발을 맞춰 걷는다.", "대상자의 왼쪽 팔로 요양보호사의 허리를 감싸게 하여 이동한다.", "대상자는 오른쪽 다리를 먼저 내딛도록 한다."]'::jsonb, 5, NULL, NULL, '{"1": "대상자의 팔로 양 어깨를 껴안듯 잡는 것은 안정적이지 않습니다.\n[정답]", "5": "대상자는 오른쪽 다리를 먼저 내딛도록 하여 균형을 유지하도록 하는 방법이 올바릅니다.", "2": "오른쪽 어깨를 감싸고 오른손을 잡는 것은 안정성이 떨어집니다.", "3": "같은 편 발을 내딛는 것은 균형을 해칠 수 있습니다.", "4": "대상자의 왼쪽 팔로 허리를 감싸는 것은 불안정할 수 있습니다."}'::jsonb, '[{"term_ko": "편마비", "term_vi": "Bệnh liệt một bên", "def_ko": "한쪽 신체가 마비된 상태(편 liệt)", "def_vi": "Tình trạng bị liệt một bên cơ thể"}, {"term_ko": "부축", "term_vi": "Hỗ trợ", "def_ko": "걸을 때 도움을 주다", "def_vi": "Giúp đỡ khi đi lại"}, {"term_ko": "올바른", "term_vi": "Đúng", "def_ko": "정확한, 맞는", "def_vi": "Chính xác"}, {"term_ko": "균형", "term_vi": "Cân bằng", "def_ko": "안정된 상태 또는 비율", "def_vi": "Tình trạng ổn định hoặc tỷ lệ"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (368, '10', '편마비 대상자를 자동차에서 휠체어로 옮기는 순서로 옳은 것은?
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (367, '10', '대상자를 휠체어에서 자동차로 이동시키는 순서로 옳은 것은?
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (366, '10', '대상자를 휠체어에서 이동변기로 이동하는 순서로 옳은 것은?
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (365, '10', '오른쪽 편마비 대상자를 휠체어에서 방바닥으로 옮기는 순서로 옳은 것은?
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (364, '10', '요양보호사 두 사람이 휠체어에 앉아있는 대상자로 침대로 이동할 때 각각 지지해야 하는 부위로 옳은 것은?', '["등과 허리 종아리와 발목", "등과 허리 대퇴(넙다리)와 발목", "겨드랑이와 팔 대퇴(넙다리)와 종아리", "겨드랑이와 가슴 종아리와 발목", "겨드랑이와 가슴 대퇴(넙다리)와 발목"]'::jsonb, 3, NULL, NULL, '{"1": "등과 허리 종아리와 발목: 지지 부위가 적절하지 않음.\n[정답]", "2": "등과 허리 대퇴(넙다리)와 발목: 지지 부위가 일정하게 분포되어 있지만, 대퇴(넙다리)와 발목의 조합은 비효율적임.", "3": "겨드랑이와 팔 대퇴(넙다리)와 종아리: 겨드랑이와 팔로 안정적으로 지지할 수 있어 올바른 선택.", "4": "겨드랑이와 가슴 종아리와 발목: 효과적인 지지가 부족함.", "5": "겨드랑이와 가슴 대퇴(넙다리)와 발목: 허리와 대퇴(넙다리) 간의 균형이 위태로울 수 있음."}'::jsonb, '[{"term_ko": "요양보호사", "term_vi": "Người chăm sóc", "def_ko": "요양보호를 담당하는 사람", "def_vi": "Người phụ trách chăm sóc"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (363, '10', '휠체어에 타고 있는 오른쪽 편마비 대상자를 침대로 옮기는 순서로 옳은 것은?
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (362, '10', '침대에 걸터앉아 있는 오른쪽 편마비 대상자를 휠체어로 이동시키는 순서로 옳은 것은?
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (361, '10', '바닥에 누워있는 대상자를 휠체어로 이동하는 순서로 옳은 것은?
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (360, '10', '바닥이 울퉁불퉁한 길을 휠체어로 이동할 때 방법으로 옳은 것은?', '["휠체어를 뒤쪽으로 기울이고 앞바퀴를 들어올린다.", "앞바퀴를 들어올린 상태로 뒷바퀴를 천천히 뒤로 빼면서 앞바퀴를 조심히 내려놓는다.", "앞바퀴를 들어올려 뒤로 젖힌 상태에서 이동한다.", "가급적 자세를 낮추고 다리에 힘을 주어 밀고 올라간다.", "휠체어를 뒤로 돌려 뒷걸음으로 내려간다."]'::jsonb, 3, NULL, NULL, '{"1": "휠체어를 뒤쪽으로 기울이면 불안정해지므로 위험할 수 있다.\n[정답]", "2": "앞바퀴를 들어올린 상태로 뒷바퀴를 천천히 빼는 것은 효과적이지만 올바른 방법은 아니므로 정답이 아니다.", "3": "앞바퀴를 들어올려 뒤로 젖힌 상태에서 이동하는 것은 안전한 방법으로 적절하다.", "4": "자세를 낮추고 힘을 주는 것은 하지만 휠체어의 안전한 이동과는 관련이 없다.", "5": "휠체어를 뒤로 돌려 뒷걸음으로 내려가는 것은 안전하지 않은 행동이다."}'::jsonb, '[{"term_ko": "바닥", "term_vi": "울퉁불퉁", "def_ko": "바닥(한국어) / mặt đất: mặt đất(베트남어)", "def_vi": "울퉁불퉁한(한국어) / gồ ghề: gồ ghề(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (359, '10', '대상자가 타고 있는 휠체어를 지그재그로 이동해야 하는 경우로 옳은 것은?', '["도로 턱을 넘을 때", "엘리베이터를 탈 때", "문턱을 내려갈 때", "울퉁불퉁한 길을 갈 때", "경사가 큰 경우 내리막길을 갈 때"]'::jsonb, 5, NULL, NULL, '{"1": "도로 턱을 넘을 때, 지그재그로 이동하는 것이 적절하지 않습니다.\n[정답]", "5": "경사가 큰 경우 내리막길을 갈 때, 지그재그로 이동하여 안정성을 확보해야 합니다.", "2": "엘리베이터를 탈 때, 지그재그로 이동할 필요가 없습니다.", "3": "문턱을 내려갈 때, 직진으로 내려가는 것이 더 효율적입니다.", "4": "울퉁불퉁한 길을 갈 때, 지그재그보다 직선 이동이 더 안전합니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người sử dụng", "def_ko": "환자", "def_vi": "Bệnh nhân"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (358, '10', '휠체어로 문턱을 내려갈 때 휠체어 조작 방법으로 옳은 것은?', '["앞바퀴를 들고 앞으로 내려간다.", "뒤로 돌려 뒷걸음으로 한 번에 내려간다.", "바퀴 한쪽씩 지그재그로 앞으로 내려간다.", "뒤로 돌려 바퀴 한쪽씩 지그재그로 내려간다.", "뒤로 돌려 뒷바퀴를 내린 후 앞바퀴를 조심히 내려놓는다."]'::jsonb, 5, NULL, NULL, '{"1": "앞바퀴를 들어내고 문턱을 내려가는 것은 안전하지 않습니다.\n[정답]", "5": "뒤로 돌려 뒷바퀴를 내린 후 앞바퀴를 조심히 내려놓는 것이 가장 안전한 방법입니다.", "2": "뒤로 돌려 뒷걸음으로 한 번에 내려가는 것은 위험할 수 있습니다.", "3": "바퀴 한쪽씩 지그재그로 앞으로 내려가는 방법은 불안정할 수 있습니다.", "4": "뒤로 돌려 바퀴 한쪽씩 지그재그로 내려가는 방법도 안전하지 않습니다."}'::jsonb, '[{"term_ko": "휠체어", "term_vi": "Xe lăn", "def_ko": "이동 보조 기구", "def_vi": "thiết bị hỗ trợ di chuyển"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (357, '10', '휠체어 기본 조작 시 접기 순서로 옳은 것은?
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (356, '10', '기본 체위에 따른 대상자의 적용 상황으로 옳은 것은?', '["앙와위 - 위관 영양을 할 때 자세", "반좌위 - 숨이 찰 때 자세", "복위 - 관장을 할 때 자세", "측위 - 휴식을할 때 자세", "바로 누워 무릎을 세운 자세 - 엉덩이에 욕창이 있을 때 자세"]'::jsonb, 2, NULL, NULL, '{"1": "위관 영양을 할 때는 일반적으로 반좌위 자세가 추천되므로 잘못된 설명입니다.\n[정답]", "2": "숨이 찰 때는 반좌위 자세가 적합하여 옳은 설명입니다.", "3": "관장을 할 때는 양무릎 위 자세나 앙와위가 일반적으로 사용되므로 잘못된 설명입니다.", "4": "휴식을 할 때는 측위도 가능하지만 더 적합한 자세가 많아 잘못된 설명입니다.", "5": "욕창이 있을 때는 가능한 한 엉덩이에 압력이 가해지지 않는 자세가 필요하므로 잘못된 설명입니다."}'::jsonb, '[{"term_ko": "체위", "term_vi": "Vị trí cơ bản", "def_ko": "자세(한국어)", "def_vi": "Tư thế cơ bản(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (355, '10', '침대에 걸터앉아 있는 대상자를 일으켜 세우는 순서로 옳은 것은?
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (354, '10', '대상자를 침대 끝으로 이동하여 걸터앉는 순서로 옳은 것은?
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (353, '10', '침상에 누워있는 편마비대상자를 일으켜 앉히는 순서로 옳은 것은?
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (352, '10', '침대에 누워있는 대상자를 옆으로 돌려 눕히는 순서로 옳은 것은?
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (351, '10', '오른쪽 편마비 대상자가 왼쪽으로 쏠려 누워있을 때 침대 중앙으로 이동시키는 순서로 옳은 것은?
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (350, '10', '협조할 수 없는 대상자가 침대 아래로 미끄러져 내려가 누워있을 때 두 명의 요양보호사가 올려 눕히는 순서로 옳은 것은?
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (349, '10', '대상자의 체위변경이나 이동을 도움 때 요양 보호사의 신체손상을 예방하는 방법으로 옳은 것은?', '["대상자와 멀리하여 지지면을 넓힌다.", "허리를 돌리지 않고 발을 움직여 방향을 바꾼다.", "양발을 모으고 다리에 체중을 싣는다.", "허리는 구부리고 무릎을 펴고 무게중심을 높인다.", "손을 이용한 작은 근육을 사용한다."]'::jsonb, 2, NULL, NULL, '{"1": "대상자를 멀리 두는 것은 올바른 지지면을 확보하지 못하므로 신체 손상을 초래할 수 있습니다.\n[정답]", "2": "허리를 돌리지 않고 발을 움직여 방향을 바꾸는 것은 허리의 부하를 줄여 신체 손상을 예방하는 올바른 방법입니다.", "3": "양발을 모으고 다리에 체중을 싣는 것은 무게중심을 불안정하게 하여 부상의 위험이 있습니다.", "4": "허리를 구부리고 무릎을 펴면 무게중심이 높아져서 신체 손상 위험이 증가합니다.", "5": "손을 이용한 작은 근육을 사용하는 것은 힘의 전달이 비효율적이므로 신체 손상 예방에 도움이 되지 않습니다."}'::jsonb, '[{"term_ko": "체위변경", "term_vi": "이동", "def_ko": "자세 thay đổi", "def_vi": "di chuyển"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (348, '10', '수액을 맞고 있는 왼쪽 편마비대상자의 단추가 달린 옷을 벗기는 순서로 옳은 것은?', '["오른쪽 팔 → 수액 → 왼쪽 팔", "오른쪽 팔 → 왼쪽 팔 → 수액", "수액 → 오른쪽 팔 → 왼쪽 팔", "왼쪽 팔 → 오른쪽 팔 → 수액", "왼쪽 팔 → 수액 →오른쪽 팔"]'::jsonb, 1, NULL, NULL, '{"1": "오른쪽 팔을 먼저 벗기고, 수액 주입을 한 후 왼쪽 팔을 벗기는 것이 안전하다.\n[정답]", "2": "왼쪽 팔을 먼저 벗기면 수액이 끊어질 위험이 있다.", "3": "수액을 먼저 제거하는 것은 위험하다.", "4": "왼쪽 팔이 마비되어 있어 오른쪽 팔이 먼저 벗겨져야 안전하다.", "5": "왼쪽 팔이 마비된 상태이므로 오른쪽 팔부터 벗겨야 한다."}'::jsonb, '[{"term_ko": "수액", "term_vi": "Dịch tĩnh mạch", "def_ko": "체액(한국어)", "def_vi": "Chất lỏng trong cơ thể"}, {"term_ko": "편마비", "term_vi": "Liệt nửa người", "def_ko": "한쪽 팔 및 다리에 마비가 있는 상태(한국어)", "def_vi": "Trạng thái bị liệt một bên cơ thể"}, {"term_ko": "안전", "term_vi": "An toàn", "def_ko": "위험이 없는 상태(한국어)", "def_vi": "Trạng thái không có nguy hiểm"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (347, '10', '누워있는 편마비 대상자의 하의를 갈아입힐 때 순서로 옳은 것은?
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (346, '10', '편마비 대상자에게 단추가 없는 상의를 입히는 순서로 옳은 것은?', '["마비된 팔 → 머리 → 건강한 팔", "마비된 팔 → 건강한 팔 → 머리", "머리 → 마비된 팔 → 건강한 팔", "건강한 팔 → 머리 → 마비된 팔", "건강한 팔 → 마비된 팔 → 머리"]'::jsonb, 1, NULL, NULL, '{"1": "마비된 팔 → 머리 → 건강한 팔: 편마비 환자에게 가장 적절한 옷 입히기 순서입니다. 옷을 입힐 때는 마비된 쪽의 팔부터 시작하여 머리를 지나 건강한 팔 순으로 입혀야 합니다.\n[정답]", "2": "마비된 팔 → 건강한 팔 → 머리: 이 순서는 옷을 입히는 과정에 적합하지 않습니다.", "3": "머리 → 마비된 팔 → 건강한 팔: 머리부터 시작하는 것은 잘못된 순서입니다.", "4": "건강한 팔 → 머리 → 마비된 팔: 건강한 팔 먼저 입히는 것은 바람직하지 않습니다.", "5": "건강한 팔 → 마비된 팔 → 머리: 후순위로 마비된 팔을 입히는 것은 잘못된 방법입니다."}'::jsonb, '[{"term_ko": "편마비", "term_vi": "Bệnh liệt nửa người", "def_ko": "반쪽이 마비된 상태", "def_vi": "Tình trạng bị liệt một nửa cơ thể"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (345, '10', '치매 대상자의 옷을 갈아입히는 방법으로 옳은 것은?', '["서있는 자세로 옷을 갈아입힌다.", "장식이 많은 옷으로 갈아입는다.", "스스로 옷을 갈아입도록 자리를 피해준다.", "갈아입기를 거부하면 목욕 시간을 이용한다.", "겉옷이 맨 위로 오게 하여 옷을 정리해둔다."]'::jsonb, 4, NULL, NULL, '{"1": "치매 대상자는 서 있는 자세보다 앉는 자세에서 더 안전하게 옷을 갈아입을 수 있습니다.", "2": "장식이 많은 옷은 혼란을 줄 수 있어 바람직하지 않습니다.\n[정답]", "3": "치매 환자가 스스로 옷을 갈아입을 수 있도록 자리를 피해주는 것이 적절합니다.", "4": "갈아입기를 거부할 경우, 목욕 시간을 이용해 자연스럽게 갈아입힐 수 있습니다.", "5": "겉옷이 위로 오게 정리하는 것은 실수할 가능성을 높여줍니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Sa sút trí tuệ", "def_ko": "기억력 및 사고력이 저하되는 질병", "def_vi": "Bệnh giảm trí nhớ và khả năng suy nghĩ"}, {"term_ko": "대상자", "term_vi": "Đối tượng", "def_ko": "서비스를 받는 사람", "def_vi": "Người nhận dịch vụ"}, {"term_ko": "옷", "term_vi": "Quần áo", "def_ko": "착용하는 의류", "def_vi": "Trang phục"}, {"term_ko": "갈아입다", "term_vi": "Thay", "def_ko": "옷을 교체하다", "def_vi": "Thay thế"}, {"term_ko": "거부하다", "term_vi": "Từ chối", "def_ko": "무엇인가를 하지 않겠다고 말하다", "def_vi": "Nói rằng không làm một việc gì đó"}, {"term_ko": "목욕", "term_vi": "Tắm", "def_ko": "몸을 씻는 행위", "def_vi": "Hành động rửa sạch cơ thể"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (344, '10', '침상목욕을 도울 때 신체부위(A)와 몸 닦기 방향(B)으로 옳은 것은?', '["팔 위팔에서 손목 쪽으로", "유방 목에서 배꼽 쪽으로", "복부 배꼽을 중심으로 시계 반대 방향으로", "다리 발끝에서 허벅지 쪽으로", "회음부 항문에서 요도 쪽으로"]'::jsonb, 4, NULL, NULL, '{"1": "팔 위팔에서 손목 쪽으로는 팔의 닦기 방향으로 적절하지 않습니다.\n[정답]", "2": "유방 목에서 배꼽 쪽으로는 위에서 아래로 내려가는 방향으로 적절하지 않습니다.", "3": "복부 배꼽을 중심으로 시계 반대 방향으로는 오히려 알맞지 않은 방향입니다.", "4": "다리 발끝에서 허벅지 쪽으로는 올바른 방향입니다.", "5": "회음부 항문에서 요도 쪽으로도 올바르지 않습니다."}'::jsonb, '[{"term_ko": "침상목욕", "term_vi": "Tắm trên giường", "def_ko": "침대에서 하는 목욕", "def_vi": "Tắm trên giường"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (343, '10', '편마비 대상자의 통목욕 돕기 방법으로 옳은 것은?', '["욕조의 턱보다 의자 높이를 낮춘다.", "마비된 쪽 다리부터 욕조에 들어가게 한다.", "말초에서 중심방향으로 닦아준다.", "욕조에 있는 시간을 20~30분 정도로 한다.", "욕조에서 머리를 감긴 후 밖으로 나오게 한다."]'::jsonb, 3, NULL, NULL, '{"1": "욕조의 턱보다 의자 높이를 낮추는 것은 욕조에 안전하게 들어가기 위한 방법이지만, 통목욕에서는 일반적으로 마비된 쪽의 안전이 더 중요합니다.\n[정답]", "3": "말초에서 중심방향으로 닦아주는 것은 편마비 환자의 피부를 자극하지 않으면서 깨끗하게 유지할 수 있는 방법입니다.", "2": "마비된 쪽 다리부터 욕조에 들어가게 하는 것은 환자의 안전을 위협할 수 있으므로 바람직하지 않습니다.", "4": "욕조에 있는 시간을 20~30분 정도로 하는 것은 일반적인 목욕 기준이긴 하지만, 편마비 환자에게는 개인의 상태에 따라 조절이 필요합니다.", "5": "욕조에서 머리를 감긴 후 밖으로 나오게 하는 것은 안전 문제를 야기할 수 있으므로 주의가 필요합니다."}'::jsonb, '[{"term_ko": "편마비", "term_vi": "Liệt nửa người", "def_ko": "한쪽 몸의 마비 상태", "def_vi": "Tình trạng tê liệt một bên cơ thể"}, {"term_ko": "통목욕", "term_vi": "Tắm ngâm", "def_ko": "전체 몸을 담그는 목욕", "def_vi": "Tắm trên toàn bộ cơ thể"}, {"term_ko": "말초", "term_vi": "Ngoại vi", "def_ko": "신체의 끝 부분", "def_vi": "Phần xa cơ thể"}, {"term_ko": "중심방향", "term_vi": "Hướng vào giữa", "def_ko": "몸의 중심으로 향하는 방향", "def_vi": "Hướng vào trung tâm cơ thể"}, {"term_ko": "욕조", "term_vi": "Bồn tắm", "def_ko": "목욕을 위한 큰 통", "def_vi": "Thùng tắm lớn"}, {"term_ko": "다리", "term_vi": "Chân", "def_ko": "신체의 아래쪽 부분", "def_vi": "Phần dưới của cơ thể"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (342, '10', '목욕을 하는 동안 대상자의 체온이 떨어지지 않도록 돕는 방법으로 옳은 것은?', '["욕실 문을 열어 습기를 제거한다.", "목욕 중 몸에 따뜻한 물을 자주 뿌려준다.", "목욕 후 몸의 물기는 자연 건조 되게 한다.", "목욕물의 온도는 50˚C 이상이 되도록 한다.", "시원한 우유를 마셔 수분을 보충해준다."]'::jsonb, 2, NULL, NULL, '{"1": "욕실 문을 열면 외부 공기가 들어오고, 습기가 저절로 제거되지만, 이는 체온 유지에 도움이 되지 않습니다.\n[정답]", "2": "목욕 중 따뜻한 물을 몸에 자주 뿌리는 것은 체온이 떨어지지 않도록 돕는 방법입니다.", "3": "목욕 후 몸의 물기가 자연 건조되면 체온이 떨어질 수 있습니다.", "4": "목욕물의 온도는 너무 높으면 화상을 입을 수 있으며 안전하지 않습니다.", "5": "시원한 우유는 체온 유지에 도움이 되지 않습니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người bệnh", "def_ko": "환자", "def_vi": "Bệnh nhân"}, {"term_ko": "체온", "term_vi": "Nhiệt độ cơ thể", "def_ko": "몸의 온도", "def_vi": "Nhiệt độ cơ thể"}, {"term_ko": "목욕", "term_vi": "Tắm", "def_ko": "몸을 깨끗하게 하는 행위", "def_vi": "Hành động gội rửa cơ thể"}, {"term_ko": "물기", "term_vi": "Độ ẩm", "def_ko": "물의 존재", "def_vi": "Sự tồn tại của nước"}, {"term_ko": "자연", "term_vi": "Tự nhiên", "def_ko": "자연스럽게", "def_vi": "Tự nhiên"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (341, '10', '침상에서 세수하는 대상자를 돕는 방법으로 옳은 것은?', '["침대를 수평으로 하여 똑바로 눕힌다.", "코, 뺨, 눈, 귀, 목 순으로 닦는다.", "귀지 제거는 의료기관에서 시행한다.", "입술과 그 주변을 알코올 솜으로 닦아낸다.", "수건에 비누를 묻혀 눈의 안쪽에서 바깥쪽으로 닦아준다."]'::jsonb, 3, NULL, NULL, '{"1": "침대를 수평으로 하여 똑바로 눕히는 것은 안전상 좋으나, 세수와 관련된 방법이 아닙니다.\n[정답]", "3": "귀지 제거는 의료기관에서 시행하는 것이 맞으며, 가정에서 하지 않는 것이 안전합니다.", "2": "코, 뺨, 눈, 귀, 목 순으로 닦는 것은 일반적이지 않으며, 세수 순서가 바람직하지 않습니다.", "4": "입술과 그 주변을 알코올 솜으로 닦는 것은 적절하지 않을 수 있으며, 자극을 줄 수 있습니다.", "5": "수건에 비누를 묻혀 눈의 안쪽에서 바깥쪽으로 닦는 것은 잘못된 방법으로, 눈에 자극을 줄 수 있습니다."}'::jsonb, '[{"term_ko": "침상", "term_vi": "Giường", "def_ko": "침대(한국어)", "def_vi": "giường ngủ"}, {"term_ko": "세수", "term_vi": "Rửa mặt", "def_ko": "얼굴을 씻다(한국어)", "def_vi": "rửa mặt"}, {"term_ko": "대상자", "term_vi": "Đối tượng", "def_ko": "환자(한국어)", "def_vi": "người bệnh"}, {"term_ko": "귀지", "term_vi": "Ráy tai", "def_ko": "귀에서 나오는 찌꺼기(한국어)", "def_vi": "chất nhờn trong tai"}, {"term_ko": "알코올", "term_vi": "Cồn", "def_ko": "알코올 (소독제)(한국어)", "def_vi": "chất khử trùng"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (340, '10', '남서 대상자의 회음부 청결 돕기 방법으로 옳은 것은?', '["요로감염 예방을 위해 멸균장갑을 착용한다.", "둔부 밑에 변기를 넣은 다음 그 아래에 방수포를 깐다.", "차가운 물을 음부에 끼얹은 다음 비누로 닦는다.", "음경을 수건으로 잡고 피부가 겹치는 부분과 음낭의 뒷면을 닦는다.", "세안 후에 사용한 수건으로 음경을 잡고 닦는다."]'::jsonb, 4, NULL, NULL, '{"1": "요로감염 예방을 위해 멸균장갑을 착용하는 것은 중요하지만, 회음부 청결을 돕기 위해서는 반드시 필요한 조치는 아닙니다.\n[정답]", "2": "둔부 밑에 변기를 넣은 다음 그 아래에 방수포를 깔고, 청결을 유지하는 것이 좋은 방법입니다.", "3": "차가운 물을 음부에 끼얹는 것은 피부를 자극할 수 있으므로 바람직하지 않습니다.", "4": "음경을 수건으로 잡고 피부가 겹치는 부분과 음낭의 뒷면을 닦는 것이 가장 적절한 방법입니다.", "5": "세안 후에 사용한 수건으로 음경을 잡고 닦는 것은 위생적인 방법이 아닙니다."}'::jsonb, '[{"term_ko": "회음부", "term_vi": "Vùng âm đạo", "def_ko": "생식기와 항문 사이의 부위", "def_vi": "Vùng giữa bộ phận sinh dục và hậu môn"}, {"term_ko": "요로감염", "term_vi": "Nhiễm trùng đường tiết niệu", "def_ko": "요로에서 발생하는 감염", "def_vi": "Nhiễm trùng xảy ra trong đường tiết niệu"}, {"term_ko": "멸균장갑", "term_vi": "Găng tay tiệt trùng", "def_ko": "감염을 예방하기 위한 장갑", "def_vi": "Găng tay dùng để ngăn ngừa nhiễm trùng"}, {"term_ko": "음경", "term_vi": "Dương vật", "def_ko": "남성의 성기", "def_vi": "Bộ phận sinh dục nam"}, {"term_ko": "음낭", "term_vi": "Bìu", "def_ko": "음경을 보호하는 피부 주머니", "def_vi": "Túi da bảo vệ dương vật"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (339, '10', '여성 대상자의 회음부를 청결하게 하는 방법으로 옳은 것은?', '["대상자를 눕혀 무릎을 펴고 다리를 벌리게 한다.", "목욕담요를 마름모꼴로 하여 몸통과 다리를 덮어준다.", "항문 - 요도 - 질 순서로 뒤쪽에서 앞으로 닦는다.", "대상자가 수치심을 느낀다면 닦지 않는다.", "회음부에 분비물이 있으면 소독해준다."]'::jsonb, 2, NULL, NULL, '{"1": "대상자를 눕히고 무릎을 펴고 다리를 벌리게 하는 것은 청결 관리를 위한 적절한 자세가 아닙니다. \n[정답]", "2": "목욕담요를 마름모꼴로 하여 몸통과 다리를 덮어주면 프라이버시를 보호하면서 청결하게 관리할 수 있습니다.", "3": "항문 - 요도 - 질 순서로 닦는 것은 청결도와 관련하여 잘못된 방법입니다.", "4": "대상자가 수치심을 느낀다면 청결 관리 방법이 적절하지 않기 때문에 권장하지 않습니다.", "5": "회음부에 분비물이 있을 경우 소독하기보다는 적절한 세척이 필요합니다."}'::jsonb, '[{"term_ko": "회음부", "term_vi": null, "def_ko": "외부 생식기와 항문 사이의 부위", "def_vi": null}, {"term_ko": "청결", "term_vi": null, "def_ko": "깨끗함", "def_vi": null}, {"term_ko": "대상자", "term_vi": null, "def_ko": "돌봄을 받는 사람", "def_vi": null}, {"term_ko": "수치심", "term_vi": null, "def_ko": "부끄러움을 느끼는 감정", "def_vi": null}, {"term_ko": "분비물", "term_vi": null, "def_ko": "체내에서 만들어져 나오는 액체", "def_vi": null}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (338, '10', '대상자가 부끄럽다며 회음부 씻는 것을 거부할 때 대처 방법으로 옳은 것은?', '["대상자가 요청할 때 까지 기다린다.", "보호자에게 연락하여 도움을 청한다.", "대상자의 거부의사를 존중하고 세척하지 않는다.", "전용 물수건을 제공하여 스스로 씻을 수 있게 한다.", "청결을 위해 본인 의사와 관계없이 씻긴다."]'::jsonb, 4, NULL, NULL, '{"1": "대상자가 요청할 때까지 기다리는 것은 세척을 미루는 것이므로 적절하지 않습니다.\n[정답]", "4": "전용 물수건을 제공하여 스스로 씻을 수 있게 하는 것은 대상자의 자율성을 존중하면서 청결을 유지할 수 있는 방법입니다.", "2": "보호자에게 연락하여 도움을 청하는 것은 주로 의료적 상황에서 필요하지만, 현재 상황에서는 적절하지 않습니다.", "3": "대상자의 거부 의사를 존중하는 것은 중요하지만, 세척이 필요한 경우에는 다른 방법이 필요합니다.", "5": "청결을 위해 본인의 의사와 관계없이 씻기는 것은 권리 침해가 될 수 있습니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người bệnh", "def_ko": "환자", "def_vi": "Bệnh nhân"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (337, '10', '대상자의 머리손질을 돕는 방법으로 옳은 것은?', '["손톱으로 두피를 마사지한다.", "빗질은 두피에서 모발 끝 쪽으로 한다.", "두피 손상이 있으면 연고를 발라준다.", "두피건강을 위해 잡아당기며 손질한다.", "엉킨 머리카락은 두발세정제를 발라 벗긴다."]'::jsonb, 2, NULL, NULL, '{"1": "손톱으로 두피를 마사지하는 것은 자극을 줄 수 있으므로 바람직하지 않습니다.\n[정답]", "2": "빗질은 두피에서 모발 끝 쪽으로 하는 것이 올바른 방법입니다.", "3": "두피 손상이 있는 경우에는 직접적으로 연고를 바르는 것이 아닌 의사의 처방이 필요합니다.", "4": "두피 건강을 위해서는 잡아당기지 않고 부드럽게 손질해야 합니다.", "5": "엉킨 머리카락은 두발세정제가 아닌 전용 헤어 제품 또는 전용 빗을 활용해야 합니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người chăm sóc", "def_ko": "환자나 돌봐야 할 사람", "def_vi": "Bệnh nhân hoặc người cần được chăm sóc"}, {"term_ko": "머리손질", "term_vi": "Chăm sóc tóc", "def_ko": "머리를 씻거나 빗는 등의 행동", "def_vi": "Hành động như gội đầu hoặc chải tóc"}, {"term_ko": "두피", "term_vi": "Da đầu", "def_ko": "머리의 피부", "def_vi": "Da của đầu"}, {"term_ko": "모발", "term_vi": "Tóc", "def_ko": "머리카락", "def_vi": "Tóc"}, {"term_ko": "연고", "term_vi": "Thuốc bôi", "def_ko": "피부에 바르는 약제", "def_vi": "Dược phẩm bôi trên da"}, {"term_ko": "잡아당기다", "term_vi": "Kéo", "def_ko": "힘으로 끌어당기다", "def_vi": "Kéo hoặc lôi"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (336, '10', '대상자의 손발 청결을 위한 관리 방법으로 옳은 것은?', '["보온을 위해 모직 양말을 신긴다.", "피부가 자극되도록 마사지한다.", "피부 건조 예방을 위해 오일을 발라준다.", "손톱은 일자, 발톱은 둥글게 잘라준다.", "안쪽으로 파고드는 발톱은 알코올로 소독해준다."]'::jsonb, 3, NULL, NULL, '{"1": "양말을 신기는 것은 보온 효과가 있지만 청결 관리와는 직접적인 관련이 없다.\n[정답]", "3": "피부 건조 예방을 위해 오일을 발라주는 것은 손발 청결 유지에 도움을 준다.", "2": "자극적인 마사지는 피부에 해로울 수 있다.", "4": "손톱을 일자, 발톱을 둥글게 자르는 것은 일반적인 팁이지만, 청결과는 다소 거리가 있다.", "5": "발톱 소독은 필요할 수 있으나 알코올은 자극을 줄 수 있어 주의해야 한다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người bệnh", "def_ko": "환자", "def_vi": "Bệnh nhân"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (335, '10', '드라이샴푸를 이용하여 머리를 감기는 방법으로 옳은 것은?', '["드라이샴푸를 모발에 발라 거품이 나도록 마사지한다.", "머리카락에 물을 적신 후 드라이샴푸를 충분히 바른다.", "드라이샴푸를 모발에 발라 두피에서 모발 끝으로 빗질을 한다.", "드라이샴푸를 모발에 바르고 샴푸로 헹구어낸다.", "드라이샴푸를 수건에 묻혀 모발을 닦아낸다."]'::jsonb, 1, NULL, NULL, '{"1": "드라이샴푸를 모발에 발라 거품이 나도록 마사지한다. [정답] 드라이샴푸는 일반적으로 모발에 직접 발라 마사지하여 기름기를 흡수하는 방식이므로 옳은 방법입니다.", "2": "머리카락에 물을 적신 후 드라이샴푸를 충분히 바른다. 물과 함께 사용하면 드라이샴푸의 효과가 감소할 수 있습니다.", "3": "드라이샴푸를 모발에 발라 두피에서 모발 끝으로 빗질을 한다. 빗질 후 남은 잔여물이 있을 수 있어 적절하지 않습니다.", "4": "드라이샴푸를 모발에 바르고 샴푸로 헹구어낸다. 드라이샴푸는 일반 샴푸처럼 헹구지 않고 사용해야 합니다.", "5": "드라이샴푸를 수건에 묻혀 모발을 닦아낸다. 이는 효과적인 사용법이 아닙니다."}'::jsonb, '[{"term_ko": "드라이샴푸", "term_vi": "Dầu gội khô", "def_ko": "샴푸 없이 사용 가능한 헤어 제품", "def_vi": "Sản phẩm chăm sóc tóc có thể sử dụng không cần gội"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (334, '10', '침상에 누워있는 대상자의 머리를 감기기 위한 준비로 옳은 것은?', '["샤워기 물은 요양보호사의 손등으로 확인한다.", "대상자의 눈과 귀에 수건을 올려 덮는다.", "대상자의 머리를 침대 모서리에 오게 한다.", "방수포를 머리 밑에서 목까지 깐다.", "수건으로 가슴부터 허리까지 감싼다."]'::jsonb, 3, NULL, NULL, '{"1": "샤워기 물은 손등을 사용하여 확인하는 것은 적절하지 않습니다. 온도 확인은 신중하게 해야 합니다.\n[정답]", "2": "대상자의 눈과 귀를 수건으로 덮는 것은 중요한 보호 조치입니다.", "3": "대상자의 머리를 침대 모서리에 위치시키는 것은 안전한 방법입니다.", "4": "방수포를 깔아야 하지만, 목까지가 아니라 머리 아래에만 깔아야 합니다.", "5": "수건으로 가슴을 감싸는 것은 권장하지 않으며, 방법이 안전하지 않을 수 있습니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Đối tượng", "def_ko": "환자, 고객", "def_vi": "bệnh nhân, khách hàng"}, {"term_ko": "머리", "term_vi": "Đầu", "def_ko": "머리", "def_vi": "đầu"}, {"term_ko": "수건", "term_vi": "Khăn", "def_ko": "수건", "def_vi": "khăn"}, {"term_ko": "방수포", "term_vi": "Nilon", "def_ko": "방수포", "def_vi": "nilon"}, {"term_ko": "올바른", "term_vi": "Đúng", "def_ko": "올바른, 맞는", "def_vi": "đúng"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (333, '10', '의치 세정제가 없을 때 대체할 수 있는 것으로 옳은 것은?', '["치약", "레몬즙", "주방세제", "표백제", "과탄화수소"]'::jsonb, 3, NULL, NULL, '{"1": "치약은 의치 세정용으로 적합하지 않음.\n[정답]", "2": "레몬즙은 산성으로 세척에 도움을 줄 수 있으나, 의치 세정제로 적합하지 않음.", "3": "주방세제는 기름기 제거에 효과적이며, 의치 세정제로도 사용 가능함.", "4": "표백제는 독성이 있어 사용하면 안됨.", "5": "과탄화수소는 산화제로 적합하지 않음."}'::jsonb, '[{"term_ko": "의치", "term_vi": "Răng giả", "def_ko": "틀니", "def_vi": "Hàm giả"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (332, '10', '대상자의 머리를 감기는 방법으로 옳은 것은?', '["두피를 손톱으로 마사지한다.", "공복과 식후를 피하여 감긴다.", "모발 끝에서 두피 쪽으로 빗질한다.", "머리카락을 비비며 물기를 말린다.", "두피에 상처가 있으면 연고를 발라준다."]'::jsonb, 2, NULL, NULL, '{"1": "두피를 손톱으로 마사지하는 것은 상처를 유발할 수 있으므로 옳지 않습니다.\n[정답]", "2": "공복과 식후를 피하여 감기는 것이 일반적인 요양 방법으로, 대상자의 편안함을 고려한 올바른 방법입니다.", "3": "모발 끝에서 두피 쪽으로 빗질하면 엉킴이 발생할 수 있습니다.", "4": "머리카락을 비비며 물기를 말리는 것은 모발 손상의 원인이 될 수 있습니다.", "5": "두피에 상처가 있으면 연고를 바르는 것은 예외적인 조치가 필요합니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Đối tượng", "def_ko": "환자(한국어)", "def_vi": "Bệnh nhân"}, {"term_ko": "머리", "term_vi": "Đầu", "def_ko": "머리(한국어)", "def_vi": "Đầu"}, {"term_ko": "두피", "term_vi": "Da đầu", "def_ko": "머리 피부(한국어)", "def_vi": "Da đầu"}, {"term_ko": "마사지", "term_vi": "Mát-xa", "def_ko": "마사지하다(한국어)", "def_vi": "Mát-xa"}, {"term_ko": "공복", "term_vi": "Đói", "def_ko": "공복 상태(한국어)", "def_vi": "Trạng thái đói"}, {"term_ko": "물기", "term_vi": "Nước", "def_ko": "물기가 있는 상태(한국어)", "def_vi": "Nước"}, {"term_ko": "상처", "term_vi": "Vết thương", "def_ko": "손상(한국어)", "def_vi": "Vết thương"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (331, '10', '대상자의 의치를 관리하는 방법으로 옳은 것은?', '["하루 12시간 이상 의치를 빼놓는다.", "의치를 표백제에 담가 세척한다.", "의치를 뺄 때 아래쪽부터 천천히 뺀다.", "냉수가 담긴 보관용기에 담아 보관한다.", "취침 전 의치를 세척 후 다시 끼워준다."]'::jsonb, 4, NULL, NULL, '{"1": "하루 12시간 이상 의치를 빼놓는 것은 치아 건강에 좋지 않으므로 부적절합니다.\n[정답]", "4": "냉수가 담긴 보관용기에 담아 보관하는 것은 의치를 안전하게 유지하는 방법입니다.", "2": "의치를 표백제에 담가 세척하면 의치 재료를 손상시킬 수 있습니다.", "3": "의치를 뺄 때 아래쪽부터 천천히 뺀다라는 방법은 잘못된 방법입니다.", "5": "취침 전 의치를 세척 후 다시 끼워주는 것은 비위생적일 수 있습니다."}'::jsonb, '[{"term_ko": "의치", "term_vi": "Dụng cụ răng giả", "def_ko": "틀니", "def_vi": "Hộp chứa dụng cụ này"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (330, '10', '칫솔질을 할 때 유의사항으로 옳은 것은?', '["치약을 칫솔위에 두툼하게 올린다.", "칫솔 각도는 90˚로 닦는다.", "치아에서 잇몸 쪽으로 닦는다.", "구토를 유발하므로 혀는 닦지 않는다.", "혈액응고 대상자는 치실을 사용하지 않는다."]'::jsonb, 5, NULL, NULL, '{"1": "치약을 너무 많이 올리면 불필요한 낭비가 발생하고 효과적인 칫솔질을 방해합니다.\n[정답]", "5": "혈액응고 대상자는 치실을 사용하지 않아야 하며, 출혈 위험이 있으므로 주의해야 합니다.", "2": "칫솔 각도는 45˚로 기울여서 닦는 것이 올바릅니다.", "3": "칫솔질은 잇몸에서 치아 방향으로 하는 것이 바람직하지만, 이 방향으로만 닦으면 어려움이 있습니다.", "4": "혀는 구강 위생을 위해 브러시로 닦는 것이 좋습니다."}'::jsonb, '[{"term_ko": "칫솔질", "term_vi": "Đánh răng", "def_ko": "이는 닦다(한국어)", "def_vi": "Làm sạch răng miệng(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (329, '10', '대상자의 구강청결을 돕는 방법으로 옳은 것은?', '["입안을 닦아 낼 때는 목젖까지 닦는다.", "일회용 스펀지에 치약을 묻혀 닦는다.", "대상자를 똑바로 눕힌 자세에서 닦는다.", "구강 점막에 염증이 있으면 구강청정제로 닦는다.", "위쪽 잇몸과 이를 닦은 후 아래쪽 잇몸과 이를 닦는다."]'::jsonb, 5, NULL, NULL, '{"1": "입안을 닦는 방법으로 목젖까지 닦는 것은 잘못된 방법이다. \n[정답]", "5": "위쪽 잇몸과 이를 닦은 후 아래쪽 잇몸과 이를 닦는 것이 올바른 순서이다.", "2": "일회용 스펀지의 사용은 필요에 따라 가능하지만 치약을 묻혀 닦는 것은 적절하지 않다.", "3": "구강청결은 환자가 편안한 자세에서 이루어져야 하므로 똑바로 눕힌 자세는 바람직하지 않다.", "4": "구강 점막에 염증이 있는 경우에는 구강청결제를 사용하지 않는 것이 좋다."}'::jsonb, '[{"term_ko": "구강청결", "term_vi": "Sát khuẩn miệng", "def_ko": "구강 위생 유지(한국어)", "def_vi": "Duy trì vệ sinh miệng(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (328, '10', '장루보유 대상자의 관리 방법으로 옳은 것은?', '["복벽을 통해 체외로 소변을 배설시키는 소변통로다.", "주머니에서 냄새가 나면 비운다.", "주 1회 정도 주기로 교환한다.", "장루주머니의 불편감은 무시한다.", "무른 변을 예방하기 위해 수분섭취를 줄인다."]'::jsonb, 3, NULL, NULL, '{"1": "복벽을 통해 체외로 소변을 배설시키는 소변통로는 장루와는 관련이 없습니다.\n[정답]", "3": "장루주머니는 일반적으로 주 1회 정도 주기로 교환하는 것이 바람직합니다.", "2": "주머니에서 냄새가 나면 즉시 비우는 것이 좋습니다.", "4": "장루주머니의 불편감은 무시하면 안 됩니다.", "5": "무른 변을 예방하기 위해서는 오히려 수분 섭취를 충분히 해야 합니다."}'::jsonb, '[{"term_ko": "장루", "term_vi": "Ống tiêu hóa", "def_ko": "장이 외부로 나오는 것(한국어)", "def_vi": "Đường tiêu hóa"}, {"term_ko": "주머니", "term_vi": "Túi", "def_ko": "수집하는 용기(한국어)", "def_vi": "Bình chứa"}, {"term_ko": "불편감", "term_vi": "Cảm giác khó chịu", "def_ko": "불편한 느낌(한국어)", "def_vi": "Cảm giác không thoải mái"}, {"term_ko": "변", "term_vi": "Phân", "def_ko": "배설물(한국어)", "def_vi": "Chất thải"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (327, '10', '요루보유 대상자의 관리 방법으로 옳은 것은?', '["요루 안으로 물이 들어가므로 통목욕을 금한다.", "통목욕 시에는 주머니의 소변을 비우고 주머니를 착용한다.", "주머니의 소변이 가득 차면 비운다.", "주머니의 소변이 새면 교환한다.", "샤워 시 물이 안으로 들어가므로 주머니를 떼지 않는다."]'::jsonb, 2, NULL, NULL, '{"1": "요루 안으로 물이 들어가므로 통목욕을 금한다. 이는 요루가 물에 닿으면 감염 위험이 있을 수 있기 때문에 일반적인 관리 방법입니다.\n[정답]", "2": "통목욕 시에는 주머니의 소변을 비우고 주머니를 착용한다. 이는 목욕 중 요루의 안전한 관리를 위해 권장되는 방법입니다.", "3": "주머니의 소변이 가득 차면 비운다. 일정 시간마다 비우는 것이 필요하지만, 통목욕 시 주머니를 비우는 것이 중요합니다.", "4": "주머니의 소변이 새면 교환한다. 이는 필요하지만 통목욕과 관련된 직접적인 지침은 아닙니다.", "5": "샤워 시 물이 안으로 들어가므로 주머니를 떼지 않는다. 확실히 주머니를 떼지 않는 것이 좋지만, 관리 방법에 대한 질문의 맥락에서 통목욕 시에는 주머니 비움이 우선입니다."}'::jsonb, '[{"term_ko": "요루", "term_vi": "Y tá", "def_ko": "인공적으로 만들어진 배뇨 경로", "def_vi": "Đường tiểu nhân tạo"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (326, '10', '유치도뇨관을 삽입하고 있는 대상자에게서 다음과 같은 상황이 관찰될 때 간호사에게 보고해야 하는 상황으로 옳은 것은?', '["연결관이 꼬여 있는 경우", "소변이 도뇨관 밖으로 새는 경우", "소변주머니가 가득 차있는 경우", "소변주머니를 들고 걸어 다니는 경우", "소변주머니의 배출구가 잠겨있는 경우"]'::jsonb, 2, NULL, NULL, '{"1": "연결관이 꼬여 있는 경우: 연결관이 꼬인 경우 관리를 필요로 하지만 즉각적인 보고가 필요하지 않습니다.\n[정답]", "2": "소변이 도뇨관 밖으로 새는 경우: 이는 즉각적인 문제로, 간호사에게 보고해야 합니다.", "3": "소변주머니가 가득 차있는 경우: 소변주머니의 내용물은 정기적으로 비워져야 하나, 즉각적인 보고 사안은 아닙니다.", "4": "소변주머니를 들고 걸어 다니는 경우: 이는 환자의 이동 방법으로, 문제가 아니라 주의가 필요합니다.", "5": "소변주머니의 배출구가 잠겨있는 경우: 이 또한 문제이나 즉각적인 보고가 필요하지 않습니다."}'::jsonb, '[{"term_ko": "유치도뇨관", "term_vi": "Ống thông tiểu", "def_ko": "체내에 놓인 소변관", "def_vi": "Ống dẫn nước tiểu vào cơ thể"}, {"term_ko": "소변", "term_vi": "Nước tiểu", "def_ko": "체내의 노폐물로 포함된 액체", "def_vi": "Chất lỏng chứa chất thải trong cơ thể"}, {"term_ko": "소변주머니", "term_vi": "Túi nước tiểu", "def_ko": "소변을 저장하는 용기", "def_vi": "Bình chứa nước tiểu"}, {"term_ko": "배출구", "term_vi": "Cổng xả", "def_ko": "내용물을 내보내는 부분", "def_vi": "Phần xả ra ngoài"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (325, '10', '유치도뇨관을 삽입하고 있는 대상자에게 요로감염이 발생할 수 있는 상황으로 옳은 것은?', '["매일 충분한 수분을 섭취하고 있다.", "소변주머니가 방광 위치보다 높게 두고 있다.", "소변의 양과 색깔을 2~3시간마다 확인한다.", "소변주머니가 침대 매트리스 아래쪽에 고정되어 있다.", "배출구가 잠그고 알코올 솜으로 소독 후 제자리에 꽂는다."]'::jsonb, 2, NULL, NULL, '{"1": "매일 충분한 수분을 섭취하면 오히려 요로감염 예방에 도움이 된다.\n[정답]", "2": "소변주머니가 방광 위치보다 높게 두고 있으면 소변이 역류하여 감염 위험이 증가할 수 있다.", "3": "소변의 양과 색깔을 2~3시간마다 확인하는 것은 감염 예방에 도움이 된다.", "4": "소변주머니가 침대 매트리스 아래쪽에 고정되어 있으면 역류 가능성이 있어 감염 위험이 높아질 수 있다.", "5": "배출구를 잠그고 알코올 솜으로 소독 후 제자리에 꽂으면 감염 예방 조치를 취한 것으로 적절하다."}'::jsonb, '[{"term_ko": "유치도뇨관", "term_vi": "Ống thông tiểu", "def_ko": "방광에 소변을 배출하기 위해 삽입하는 관", "def_vi": "Ống được đặt vào bàng quang để thải nước tiểu"}, {"term_ko": "요로감염", "term_vi": "Nhiễm trùng đường tiết niệu", "def_ko": "요로에 발생하는 감염", "def_vi": "Nhiễm trùng xảy ra trong đường tiết niệu"}, {"term_ko": "소변주머니", "term_vi": "Túi tiểu", "def_ko": "방광에서 나오는 소변을 저장하는 기기", "def_vi": "Thiết bị lưu trữ nước tiểu từ bàng quang"}, {"term_ko": "역류", "term_vi": "Chảy ngược", "def_ko": "소변이 뒤로 흐르는 현상", "def_vi": "Hiện tượng nước tiểu chảy ngược lại"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (324, '10', '유치도뇨관을 삽입하고 있는 대상자가 아랫배에 가스가 찬 것처럼 불편해요.라고 호소할 때 대처방법으로 옳은 것은?', '["소화제를 제공한다.", "소변주머니를 비워준다.", "도뇨관이 꺾여있는지 확인한다.", "따뜻한 물주머니를 복부에 대어준다.", "침대 머리를 올려 반좌위를 취하게 한다."]'::jsonb, 3, NULL, NULL, '{"1": "소화제를 제공한다: 소화제는 가스 불편감에 직접적인 도움이 되지 않습니다.\n[정답]", "2": "소변주머니를 비워준다: 소변주머니를 비우면 편안해질 수 있지만 문제의 상황과는 직접적인 연관이 없습니다.", "3": "도뇨관이 꺾여있는지 확인한다: 도뇨관의 상태를 확인하는 것이 가장 적절한 대처입니다.", "4": "따뜻한 물주머니를 복부에 대어준다: 따뜻한 물주머니는 불편감 완화에 도움을 줄 수 있지만 근본적인 문제 해결에는 미치지 못합니다.", "5": "침대 머리를 올려 반좌위를 취하게 한다: 조금 더 편안함을 제공할 수 있지만, 도뇨관이 꺾인 경우에는 별로 의미가 없습니다."}'::jsonb, '[{"term_ko": "유치도뇨관", "term_vi": "Ống thông niệu", "def_ko": "배뇨를 위한 관", "def_vi": "Ống sử dụng để tiểu tiện"}, {"term_ko": "소화제", "term_vi": "Thuốc tiêu hóa", "def_ko": "소화에 도움을 주는 약물", "def_vi": "Thuốc giúp tiêu hóa"}, {"term_ko": "소변주머니", "term_vi": "Túi nước tiểu", "def_ko": "소변을 받는 용기", "def_vi": "Bình chứa nước tiểu"}, {"term_ko": "도뇨관", "term_vi": "Ống thông", "def_ko": "소변을 배출하기 위해 삽입하는 관", "def_vi": "Ống được đặt để thải nước tiểu"}, {"term_ko": "꺾이다", "term_vi": "Gập lại", "def_ko": "접히다", "def_vi": "Bị gập"}, {"term_ko": "따뜻한", "term_vi": "Ấm", "def_ko": "따뜻한 상태", "def_vi": "Nóng"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (323, '10', '유치도뇨관을 삽입하고 있는 대상자의 보행을 돕는 방법으로 옳은 것은?', '["유치도뇨관을 잠근 후 보행하게 한다.", "수분 섭취를 제한하면서 보행하게 한다.", "유치도뇨관을 새것으로 교체한 후 보행하게 한다.", "소변주머니를 아랫배보다 아래로 오도록 들고 보행하게 한다.", "하루 2~3시간만 보행하게 한다."]'::jsonb, 4, NULL, NULL, '{"1": "유치도뇨관을 잠그면 소변이 배출되지 않아 문제를 일으킬 수 있다.\n[정답]", "4": "소변주머니를 아랫배보다 아래로 오도록 들고 보행하게 하면, 소변의 역류를 방지할 수 있어 안전하다.", "2": "수분 섭취를 제한하면 환자의 건강에 좋지 않다.", "3": "유치도뇨관을 새것으로 교체한 후에는 환자가 안정 상태여야 하며 즉시 보행하는 것은 바람직하지 않다.", "5": "보행 시간을 제한하는 것은 환자의 운동 능력의 향상에 방해가 될 수 있다."}'::jsonb, '[{"term_ko": "유치도뇨관", "term_vi": "Ống thông tiểu", "def_ko": "소변을 정기적으로 배출하기 위해 삽입하는 도관", "def_vi": "Ống được đặt để thải nước tiểu định kỳ"}, {"term_ko": "소변주머니", "term_vi": "Túi nước tiểu", "def_ko": "소변을 저장하는 가방", "def_vi": "Túi chứa nước tiểu"}, {"term_ko": "보행", "term_vi": "Đi bộ", "def_ko": "걷는 행동", "def_vi": "Hành động đi lại"}, {"term_ko": "건강", "term_vi": "Sức khỏe", "def_ko": "신체적, 정신적으로 좋은 상태", "def_vi": "Tình trạng tốt về thể chất và tâm lý"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (322, '10', '협조가 불가능한 대상자의 기저귀를 갈아 주는 방법으로 옳은 것은?', '["소변이 조금 묻은 기저귀는 말려서 재사용한다.", "피부의 발적을 발견했을 때 연고를 발라준다", "옆으로 돌려 눕혀 기저귀를 교환한다.", "냄새가 나지 않도록 기저귀를 단단히 조여 채운다.", "기저귀를 두 개씩 겹쳐서 채운다."]'::jsonb, 3, NULL, NULL, '{"1": "기저귀는 일회용이며 재사용하면 감염의 위험이 있습니다.\n[정답]", "3": "옆으로 돌려 눕히는 방법은 기저귀 교환 시 안전하고 효과적인 방법입니다.", "2": "피부 발적을 발견했을 때 연고를 바르는 것은 필요하지만 기저귀 교환 전에 확인해야 하는 점입니다.", "4": "어른의 욕실에서 냄새를 방지하기 위해 기저귀를 단단히 조여 채우는 것은 오히려 불편함을 줄 수 있습니다.", "5": "기저귀를 두 개씩 겹쳐 채우는 것은 적절하지 않으며, 기저귀의 본래 목적을 해치는 행동입니다."}'::jsonb, '[{"term_ko": "기저귀", "term_vi": "Tã", "def_ko": "기저귀(한국어)", "def_vi": "tã(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (321, '10', '한쪽으로만 누워있는 대상자가 기저귀 밖으로 소변이 샐 때 대처방법으로 옳은 것은?', '["기저귀 안에 속 기저귀를 한 개 더 채워준다.", "기저귀 밑에 방수포를 깔아둔다.", "정해진 시간에 기저귀를 갈아준다.", "몸 한쪽에 베개를 대는 방식으로 체위를 자주 바꾸어준다.", "소변이 새는 쪽 기저귀 안에 물티슈를 넣어준다."]'::jsonb, 4, NULL, NULL, '{"1": "기저귀 안에 속 기저귀를 한 개 더 채워주는 것은 과도한 흡수 능력을 요하므로 적절하지 않습니다.\n[정답]", "4": "몸 한쪽에 베개를 대는 방식으로 체위를 자주 바꾸어주는 것은 누워 있는 상태에서의 압력을 분산시키므로 효과적입니다.", "2": "기저귀 밑에 방수포를 깔아두는 것은 누수에 대한 방어책이지만 본질적인 해결책이 아닙니다.", "3": "정해진 시간에 기저귀를 갈아주는 것은 일반적으로 필요하지만, 소변이 새는 상황에서는 즉각적인 대처가 필요합니다.", "5": "소변이 새는 쪽 기저귀 안에 물티슈를 넣는 것은 실질적인 도움이 되지 않습니다."}'::jsonb, '[{"term_ko": "기저귀", "term_vi": "Bỉm", "def_ko": "기저귀(한국어)", "def_vi": "Bỉm(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (320, '10', '대상자의 기저귀를 교환하는 방법으로 옳은 것은?', '["창문을 닫고 탈취제나 방향제를 사용한다.", "기저귀를 정해진 시간에 교환한다.", "기저귀를 교환할 때마다 보호자에게 알린다.", "기저귀의 깨끗한 면이 보이도록 말아 넣는다.", "대상자가 허리를 들 수 없으면 엎드리게 하여 기저귀를 교환한다."]'::jsonb, 4, NULL, NULL, '{"1": "창문을 닫고 탈취제나 방향제를 사용하는 것은 적절한 방법이 아닙니다. 기저귀 교환 시에는 환기가 필요합니다.\n[정답]", "4": "기저귀의 깨끗한 면이 보이도록 말아 넣는 것은 올바른 방법입니다. 이는 청결을 유지하는 데 도움이 됩니다.", "2": "기저귀를 정해진 시간에 교환하는 것이 좋지만, 대상자의 상태에 따라 필요할 때 교환하는 것이 중요합니다.", "3": "기저귀를 교환할 때마다 보호자에게 알리는 것은 필수 사항이 아닙니다.", "5": "대상자가 허리를 들 수 없는 경우에는 엎드리게 하기보다는 적절한 자세로 지지하여 교환하는 것이 안전합니다."}'::jsonb, '[{"term_ko": "기저귀", "term_vi": "Tã", "def_ko": "기저귀(한국어)", "def_vi": "bỉm"}, {"term_ko": "교환", "term_vi": "Thay", "def_ko": "교환(한국어)", "def_vi": "thay thế"}, {"term_ko": "탈취제", "term_vi": "Chất khử mùi", "def_ko": "탈취제(한국어)", "def_vi": "chất khử mùi"}, {"term_ko": "방향제", "term_vi": "Thuốc xịt thơm", "def_ko": "방향제(한국어)", "def_vi": "thuốc xịt tạo hương"}, {"term_ko": "대상자", "term_vi": "Bệnh nhân", "def_ko": "대상자(한국어)", "def_vi": "bệnh nhân"}, {"term_ko": "보호자", "term_vi": "Người thân", "def_ko": "보호자(한국어)", "def_vi": "người thân"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (319, '10', '대상자의 기저귀 사용 돕기로 옳은 것은?', '["정해진 시간에 기저귀를 갈아준다.", "바지를 내린 후 면 덮개로 덮어준다.", "물수건으로 닦은 후 바로 기저귀를 채운다.", "피부상태 변화 및 상처를 살펴본다.", "회음부는 뒤에서 앞으로 닦는다."]'::jsonb, 4, NULL, NULL, '{"1": "정해진 시간에 기저귀를 갈아주는 것은 좋지만, 필요에 따라 수시로 갈아줘야 합니다.\n[정답]", "4": "피부상태 변화 및 상처를 살펴보는 것이 중요합니다.", "2": "바지를 내린 후 면 덮개로 덮어주는 것은 잘못된 방법입니다.", "3": "물수건으로 닦은 후 바로 기저귀를 채우는 것은 피부에 좋지 않습니다.", "5": "회음부를 닦는 방향은 앞에서 뒤로 닦는 것이 맞습니다."}'::jsonb, '[{"term_ko": "기저귀", "term_vi": "Tã", "def_ko": "기저귀(한국어)", "def_vi": "tã(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (318, '10', '대상자가 몇 번의 실금을 했어도 기저귀를 바로 사용하지 않는 이유로 옳은 것은?', '["낙상의 위험이 높아지기 때문에", "움직임이 제한되기 때문에", "기저귀 사용 비용이 부담되기 때문에", "비뇨기계 감염이 발생할 수 있기 때문에", "스스로 배설하는 습관이 사라질 수 있기 때문에"]'::jsonb, 5, NULL, NULL, '{"1": "낙상의 위험이 높아지기 때문에\n기저귀를 사용하면 화장실에 가는 빈도가 줄어 들어 낙상의 위험이 증가할 수 있다.\n[정답]", "5": "스스로 배설하는 습관이 사라질 수 있기 때문에\n기저귀 사용이 잦으면 자연스러운 배설 습관이 저하될 수 있다.", "3": "기저귀 사용 비용이 부담되기 때문에\n비용도 고려될 수 있으나, 주된 이유는 아니다.", "4": "비뇨기계 감염이 발생할 수 있기 때문에\n기저귀 사용으로 인해 감염 위험이 증가할 수 있으나, 주된 이유는 아니다.", "2": "움직임이 제한되기 때문에\n기저귀 사용 자체로 움직임이 크게 제한되지는 않는다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người nhận", "def_ko": "환자, 수급자", "def_vi": "Bệnh nhân, người thụ hưởng"}, {"term_ko": "실금", "term_vi": "Rò rỉ", "def_ko": "배뇨 또는 배변 조절을 못함", "def_vi": "Không thể kiểm soát việc tiểu tiện hoặc đại tiện"}, {"term_ko": "기저귀", "term_vi": "Tã", "def_ko": "아기나 성인이 사용하는 배변 용품", "def_vi": "Sản phẩm sử dụng cho trẻ em hoặc người lớn để đi vệ sinh"}, {"term_ko": "낙상", "term_vi": "Ngã", "def_ko": "높은 곳에서 떨어져 다치는 것", "def_vi": "Bị ngã từ một độ cao"}, {"term_ko": "비용", "term_vi": "Chi phí", "def_ko": "지출해야 하는 돈", "def_vi": "Tiền phải chi trả"}, {"term_ko": "감염", "term_vi": "Nhiễm trùng", "def_ko": "질병에 의해 발생하는 병리적 상태", "def_vi": "Tình trạng bệnh lý do bệnh gây ra"}, {"term_ko": "습관", "term_vi": "Thói quen", "def_ko": "반복적으로 행하는 행동", "def_vi": "Hành động thực hiện một cách lặp đi lặp lại"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (317, '10', '이동변기를 사용하여 배설하는 대상자를 돕는 방법으로 옳은 것은?', '["침대 양쪽 난간을 내리고 이동한다.", "변기 옆에 작은 매트를 깔아준다.", "움직이기 힘들어하면 안아서 변기에 앉힌다.", "두 발의 발가락 끝이 바닥에 닿게 변기에 앉힌다.", "배설 시 소리가 나지 않게 주변 환경을 조용하게 한다."]'::jsonb, 3, NULL, NULL, '{"1": "침대 양쪽 난간을 내리고 이동한다. 이런 방법은 불안정할 수 있으므로 적절하지 않습니다.\n[정답]", "2": "변기 옆에 작은 매트를 깔아준다. 매트를 깔아줘도 도움이 되지만, 가장 중요한 것은 환자를 안전하게 앉히는 것입니다.", "3": "움직이기 힘들어하면 안아서 변기에 앉힌다. 이 방법은 안전성을 위해 주의해야 하며, 체중을 지탱할 수 있는 방법이 필요합니다.", "4": "두 발의 발가락 끝이 바닥에 닿게 변기에 앉힌다. 이 방식은 바람직하지 않습니다, 환자의 안전을 특히 우선시할 여지가 있습니다.", "5": "배설 시 소리가 나지 않게 주변 환경을 조용하게 한다. 이를 지켜야 하지만 가장 중요한 것은 환자를 안전하게 도와주는 것입니다."}'::jsonb, '[{"term_ko": "이동변기", "term_vi": "Bồn cầu di động", "def_ko": "이동할 수 있는 변기", "def_vi": "Toilet có thể di chuyển"}, {"term_ko": "배설", "term_vi": "Tiểu tiện", "def_ko": "소변이나 대변을 보는 것", "def_vi": "Đi tiểu hoặc đi đại tiện"}, {"term_ko": "매트", "term_vi": "Thảm", "def_ko": "바닥에 깔아놓는 것", "def_vi": "Vật trải sàn"}, {"term_ko": "주변 환경", "term_vi": "Môi trường xung quanh", "def_ko": "주위의 상황", "def_vi": "Tình huống xung quanh"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (316, '10', '이동변기를 사용하여 배변중인 대상자가 배설을 어려워 할 때 돕는 방법으로 옳은 것은?', '["차가운 물을 마시게 한다.", "조용한 음악을 틀어준다.", "배변할 때까지 앉아 있게 한다.", "이동변기 대신 기저귀를 채워준다.", "항문 주위에 미지근한 물을 끼얹어준다."]'::jsonb, 5, NULL, NULL, '{"1": "차가운 물은 배변에 도움이 되지 않는다.\n[정답]", "5": "항문 주위에 미지근한 물을 끼얹는 것은 배변을 도와줄 수 있는 방법이다.", "2": "조용한 음악은 긴장을 완화시킬 수 있지만 직접적인 도움은 아니다.", "3": "배변할 때까지 앉아 있게 하는 것은 심리적 압박을 줄 수 있다.", "4": "기저귀를 채우는 것은 의도하지 않은 방법이다."}'::jsonb, '[{"term_ko": "이동변기", "term_vi": "Bệ vệ sinh di động", "def_ko": "이동형 변기", "def_vi": "Nhà vệ sinh di động"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (315, '10', '대상자가 밤에는 추워서 화장실 가기 싫다며 기저귀 사용을 원할 때 대처방법으로 옳은 것은?', '["원하는 대로 기저귀를 사용한다.", "간이변기를 대어준다.", "겉옷을 준비하여 준다.", "이동식 변기를 옆에 둔다.", "대상자를 설득하여 화장실을 사용한다."]'::jsonb, 4, NULL, NULL, '{"1": "기저귀 사용은 대상자의 요청에 따라 수용할 수 있지만, 건강한 욕구를 위한 대처 방법이 아닙니다.\n[정답]", "2": "간이변기는 매우 유용한 도구로, 야간에 화장실 이용을 쉽게 도와줍니다.", "3": "겉옷을 준비해주는 것은 도움이 될 수 있지만, 화장실 이용의 결정을 직접적으로 바꾸지는 않습니다.", "4": "이동식 변기는 환자가 빠르게 접근할 수 있는 방법으로, 적절한 대처입니다.", "5": "대상자를 설득하는 것은 긍정적이지만, 대상자의 기저귀 사용 요청을 무시할 수 있습니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người bệnh", "def_ko": "환자", "def_vi": "Bệnh nhân"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (314, '10', '왼쪽 편마비 대상자의 이동변기 사용을 돕는 방법으로 옳은 것은?', '["이동변기를 침대 높이보다 낮게 한다.", "이동변기를 하루에 한 번 세척한다.", "이동변기를 대상자의 왼쪽에 놓는다.", "이동변기 앞에 미끄럼방지 매트를 깔아준다.", "소독약으로 세척할 수 있는 이동변기를 사용한다."]'::jsonb, 5, NULL, NULL, '{"1": "이동변기를 침대 높이보다 낮게 하면 오히려 불편할 수 있다.\n[정답]", "5": "소독약으로 세척할 수 있는 이동변기를 사용하면 위생적이다.", "3": "이동변기를 대상자의 왼쪽에 놓는 것은 편마비 환자에게 어려움을 줄 수 있다.", "4": "이동변기 앞에 미끄럼방지 매트를 깔아주면 좋지만, 반드시 필요한 것은 아니다.", "2": "이동변기를 하루에 한 번 세척하는 것은 위생 관리에 부족하다."}'::jsonb, '[{"term_ko": "편마비", "term_vi": "Liệt nửa người", "def_ko": "반쪽이 마비된 상태", "def_vi": "Tình trạng bị liệt một bên cơ thể"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (313, '10', '간이변기를 사용하여 침상에서 배설하는 대상자를 돕는 방법으로 옳은 것은?', '["대상자의 두분 아래에 방수포를 깐다.", "조용한 환경에서 배설할 수 있게 한다.", "변기를 침대 난간과 30~45˚가 되게 붙인다.", "바지를 내린 후에 허리 아래 부분을 가려준다.", "대상자가 협조할 수 있으면 옆으로 돌려 눕혀 변기를 대어준다."]'::jsonb, 1, NULL, NULL, '{"1": "대상자의 두분 아래에 방수포를 깐다: 침대에 방수포를 깔아두는 것은 배설 시 청결과 편안함을 제공하기 때문에 적절한 방법입니다.\n[정답]", "2": "조용한 환경에서 배설할 수 있게 한다: 배설하는 동안 편안한 환경을 제공하는 것은 중요하지만, 본 질문에서 더 적절한 방법은 방수포를 깔는 것입니다.", "3": "변기를 침대 난간과 30~45˚가 되게 붙인다: 변기의 각도 조정은 필요할 수 있지만, 방수포 준비와 더 밀접한 관련이 없습니다.", "4": "바지를 내린 후에 허리 아래 부분을 가려준다: 사생활 보호는 중요하지만, 본 문제에서 제시된 정답에는 해당되지 않습니다.", "5": "대상자가 협조할 수 있으면 옆으로 돌려 눕혀 변기를 대어준다: 대상자가 협조할 경우 이러한 방법도 가능하지만, 방수포를 깔아야 할 필요성이 더 우선시 됩니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người bệnh", "def_ko": "환자 또는 고객", "def_vi": "Người bệnh hoặc khách hàng"}, {"term_ko": "방수포", "term_vi": "Tấm trải chống thấm", "def_ko": "물이 스며들지 않는 포", "def_vi": "Tấm trải không thấm nước"}, {"term_ko": "조용한", "term_vi": "Yên tĩnh", "def_ko": "소음이 없거나 평온한", "def_vi": "Không có tiếng ồn hoặc thanh bình"}, {"term_ko": "허리", "term_vi": "Eo", "def_ko": "허리 부분", "def_vi": "Vùng eo"}, {"term_ko": "협조", "term_vi": "Hợp tác", "def_ko": "서로 도와주다", "def_vi": "Giúp đỡ lẫn nhau"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (312, '10', '거동이 불편한 대상자가 침상에서 자주 배변 실수를 할 때 돕는 방법으로 옳은 것은?', '["음식섭취량을 줄여준다.", "낮 동안에 기저귀를 채워준다.", "간이변기를 침대에 두고 사용하게 한다.", "대상자가 변의를 호소할 때 즉시 배설할 수 있도록 한다.", "기저귀를 깔고 하의를 벗긴 후 이불을 덮어준다."]'::jsonb, 4, NULL, NULL, '{"1": "음식섭취량을 줄이면 배변 횟수를 감소시킬 수 있지만, 건강에 문제가 될 수 있다.\n[정답]", "2": "낮 동안에 기저귀를 채우는 것은 유용할 수 있지만, 대상자가 배변 욕구에 즉시 반응할 수 있도록 돕는 것이 중요하다.", "3": "간이변기를 침대에 두도록 하는 것은 좋은 방법이나, 사용 방법을 제대로 배워야 한다.", "4": "대상자가 변의를 호소할 때 즉시 배설할 수 있도록 하는 것이 가장 바람직한 도움이다.", "5": "기저귀를 깔고 하의를 벗기는 것은 현실적이지만, 필요한 상황에서 즉시 도움을 주는 것이 더 효과적이다."}'::jsonb, '[{"term_ko": "거동", "term_vi": "불편", "def_ko": "행동, di chuyển", "def_vi": "không thoải mái"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (311, '10', '침대에 누워 지내는 대상자의 침상 배설을 돕는 방법으로 옳은 것은?', '["복부를 시계 방향으로 마사지한다.", "배변 후 물티슈로 닦고 바로 옷을 입힌다.", "앙와위로 눕혀 배변하기 쉬운 자세가 되게 한다.", "찬 수건으로 항문 주위를 닦아주어 변의를 자극한다.", "변의를 호소하면 한두 번 참게 한 후 변기를 대어준다."]'::jsonb, 1, NULL, NULL, '{"1": "복부를 시계 방향으로 마사지하는 것은 장의 운동을 돕고 배변을 유도하는 효과가 있습니다.\n[정답]", "2": "배변 후에 물티슈로 닦고 즉시 옷을 입히는 것은 청결을 고려하지 않은 방법입니다.", "3": "앙와위로 눕혀 배변하기 쉬운 자세를 제공하는 것은 배변을 돕지 않는 자세입니다.", "4": "찬 수건으로 항문 주위를 닦는 것은 불편하고 자극이 부족합니다.", "5": "변의를 호소한 대상자를 한두 번 참게 하는 것은 건강에 좋지 않습니다."}'::jsonb, '[{"term_ko": "침상", "term_vi": "Giường", "def_ko": "침대(한국어)", "def_vi": "cái giường"}, {"term_ko": "배설", "term_vi": "Đi tiêu", "def_ko": "대변을 처리하다(한국어)", "def_vi": "đi vệ sinh"}, {"term_ko": "복부", "term_vi": "Bụng", "def_ko": "배(한국어)", "def_vi": "cái bụng"}, {"term_ko": "마사지", "term_vi": "Mát-xa", "def_ko": "마사지하다(한국어)", "def_vi": "xoa bóp"}, {"term_ko": "물티슈", "term_vi": "Khăn ướt", "def_ko": "물로 적신 티슈(한국어)", "def_vi": "khăn lau ướt"}, {"term_ko": "앙와위", "term_vi": "Nằm ngửa", "def_ko": "눕는 자세(한국어)", "def_vi": "nằm ở tư thế ngửa"}, {"term_ko": "변의", "term_vi": "Cảm giác muốn đi vệ sinh", "def_ko": "대변을 보고 싶다는 느낌(한국어)", "def_vi": "cảm giác muốn đi tiêu"}, {"term_ko": "항문", "term_vi": "Hậu môn", "def_ko": "항문(한국어)", "def_vi": "hậu môn"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (310, '10', '요실금 대상자의 배뇨를 돕는 방법으로 옳은 것은?', '["배뇨후 치골상부를 눌러 방광을 완전히 비운다.", "주기적으로 도뇨관을 사용한다.", "식이섬유가 적은 음식을 제공한다.", "더운물주머니를 복부에 대주어 방광을 자극한다.", "활동을 제한하여 배뇨 횟수를 줄인다."]'::jsonb, 1, NULL, NULL, '{"1": "배뇨후 치골상부를 눌러 방광을 완전히 비운다. - 이는 방광을 비우는 올바른 방법으로, 요실금 대상자에게 적합합니다.\n[정답]", "2": "주기적으로 도뇨관을 사용한다. - 도뇨관 사용은 특정 상황에서 필요하지만 일반적인 방법은 아닙니다.", "3": "식이섬유가 적은 음식을 제공한다. - 식이섬유가 부족한 음식은 오히려 변비를 유발할 수 있습니다.", "4": "더운물주머니를 복부에 대주어 방광을 자극한다. - 방광 자극은 필요할 수 있지만, 이것이 적절한 배뇨 방법이라고 할 수 없습니다.", "5": "활동을 제한하여 배뇨 횟수를 줄인다. - 활동 제한은 건강에 좋지 않을 수 있습니다."}'::jsonb, '[{"term_ko": "요실금", "term_vi": "Tiểu không tự chủ", "def_ko": "소변을 조절하지 못하는 상태", "def_vi": "Trạng thái không kiểm soát được nước tiểu"}, {"term_ko": "배뇨", "term_vi": "Tiểu tiện", "def_ko": "소변을 보는 행동", "def_vi": "Hành động đi tiểu"}, {"term_ko": "방광", "term_vi": "Bàng quang", "def_ko": "소변이 저장되는 기관", "def_vi": "Cơ quan chứa nước tiểu"}, {"term_ko": "치골", "term_vi": "Xương mu", "def_ko": "골반의 앞부분", "def_vi": "Phần phía trước của xương chậu"}, {"term_ko": "도뇨관", "term_vi": "Ống dẫn nước", "def_ko": "소변을 배출하기 위해 사용하는 튜브", "def_vi": "Ống sử dụng để dẫn nước tiểu"}, {"term_ko": "식이섬유", "term_vi": "Chất xơ", "def_ko": "장 건강에 도움이 되는 섬유소", "def_vi": "Chất giúp cải thiện sức khỏe đường ruột"}, {"term_ko": "제한하다", "term_vi": "Hạn chế", "def_ko": "활동이나 섭취량을 줄이다", "def_vi": "Giảm hoạt động hoặc lượng tiêu thụ"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (309, '10', '휠체어를 사용하는 왼쪽 편마비 대상자의 화장실 이용을 돕는 방법으로 옳은 것은?', '["화장실 밖에 응급벨을 설치한다.", "대상자의 두 발이 바닥에 닿지 않게 앉힌다.", "배뇨 후 도움이 필요한 부분을 도와준다.", "화장실 앞에 화분을 놓아 화장실 위치를 표시한다.", "침대에서 휠체어로 옮길 때 대상자의 왼쪽에 휠체어를 놓는다."]'::jsonb, 3, NULL, NULL, '{"1": "화장실 밖에 응급벨을 설치하는 것은 안전을 위한 조치이나, 화장실 이용 방법과는 직접적인 관련이 없습니다.\n[정답]", "2": "대상자의 두 발이 바닥에 닿지 않게 앉힌 것은 안전하게 화장실을 이용하기 위한 방법이 아닙니다.", "3": "배뇨 후 도움이 필요한 부분을 도와주는 것은 가장 적절한 방법입니다.", "4": "화장실 앞에 화분을 놓아 화장실 위치를 표시하는 것은 파악을 돕는 방법이지만, 대상자에게 직접적인 도움을 주지 않습니다.", "5": "침대에서 휠체어로 옮길 때 대상자의 왼쪽에 휠체어를 놓는 것은 편마비 환자를 도와주는 방법으로 적절하지 않습니다."}'::jsonb, '[{"term_ko": "휠체어", "term_vi": "Xe lăn", "def_ko": "휠체어(장애인을 위한 의자형 수송기구)", "def_vi": "Ghế ngồi di chuyển cho người khuyết tật"}, {"term_ko": "편마비", "term_vi": "Liệt nửa người", "def_ko": "신체의 한쪽이 마비된 상태", "def_vi": "Tình trạng bị liệt bên một nửa cơ thể"}, {"term_ko": "배뇨", "term_vi": "Đi tiểu", "def_ko": "소변을 보는 과정", "def_vi": "Quá trình đi vệ sinh"}, {"term_ko": "두 발", "term_vi": "Hai chân", "def_ko": "사람의 다리", "def_vi": "Chân của con người"}, {"term_ko": "응급벨", "term_vi": "Chuông khẩn cấp", "def_ko": "긴급 상황에서 호출하는 벨", "def_vi": "Chuông dùng để gọi trong trường hợp khẩn cấp"}, {"term_ko": "화분", "term_vi": "Chậu cây", "def_ko": "식물이나 꽃을 기르는 그릇", "def_vi": "Để trồng cây hoặc hoa"}, {"term_ko": "화장실", "term_vi": "Nhà vệ sinh", "def_ko": "소변이나 대변을 보는 방", "def_vi": "Phòng để đi vệ sinh"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (308, '10', '휠체어로 이동하여 화장실을 사용하는 오른쪽 편마비 대상자를 돕는 방법은?', '["대상자의 오른쪽에 휠체어를 놓고 옮긴다.", "이동할 때는 휠체어 의자 끝에 걸터앉게 한다.", "휠체어 잠금장치를 풀고 발 받침대를 접은 후 변기에 옮긴다.", "대상자의 겨드랑이를 감싸 일으킨 후 몸을 회전시켜 변기에 앉힌다.", "배설이 끝날 때까지 화장실 문을 열어둔다."]'::jsonb, 4, NULL, NULL, '{"1": "대상자의 오른쪽에 휠체어를 놓고 옮긴다. - 오른쪽 편마비인 경우 왼쪽에서 도움을 주는 것이 더 안전하다.\n[정답]", "2": "이동할 때는 휠체어 의자 끝에 걸터앉게 한다. - 휠체어 끝에 걸터앉는 것은 안전하지 않다.", "3": "휠체어 잠금장치를 풀고 발 받침대를 접은 후 변기에 옮긴다. - 잠금장치는 반드시 해제해야 하지만 이 순서로 진행하는 것은 비효율적이다.", "4": "대상자의 겨드랑이를 감싸 일으킨 후 몸을 회전시켜 변기에 앉힌다. - 올바른 방법으로, 편마비 대상자를 안전하게 화장실에 옮기는 방법이다.", "5": "배설이 끝날 때까지 화장실 문을 열어둔다. - 개인정보 보호와 안전을 위해 문을 닫아야 한다."}'::jsonb, '[{"term_ko": "편마비", "term_vi": "Bán liệt", "def_ko": "한쪽 신체의 운동 기능이 소실된 상태", "def_vi": "Tình trạng mất chức năng vận động của một bên cơ thể"}, {"term_ko": "겨드랑이", "term_vi": "Nách", "def_ko": "팔과 몸통 사이의 부위", "def_vi": "Khu vực giữa tay và thân"}, {"term_ko": "화장실", "term_vi": "Nhà vệ sinh", "def_ko": "배설을 위한 공간", "def_vi": "Không gian để đi vệ sinh"}, {"term_ko": "휠체어", "term_vi": "Xe lăn", "def_ko": "이동을 위해 사용하는 의자", "def_vi": "Ghế ngồi di chuyển"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (307, '10', '침대에 누워 있던 대상자가 화장실에 간다며 일어나 앉더니 어지럽다고 할 때 대처 방법으로 옳은 것은?', '["따뜻한 차를 마시게 한다.", "똑바로 누워 다리를 높여준다.", "이동변기를 사용하게 한다.", "서둘러 화장실에 데려간다.", "잠시 침대에 앉아있게 하고 지켜본다."]'::jsonb, 5, NULL, NULL, '{"1": "따뜻한 차를 마시는 것은 도움이 될 수 있지만, 즉각적인 대처 방법으로는 적합하지 않습니다.\n[정답]", "5": "잠시 침대에 앉아있게 하고 지켜보는 것이 가장 안전한 방법입니다.", "3": "이동변기를 사용하게 하는 것은 대상자가 어지럼증을 느끼는 상황에서는 적절치 않습니다.", "4": "서둘러 화장실에 데려가는 것은 더 위험할 수 있습니다.", "2": "똑바로 눕히고 다리를 높이는 것도 하지만, 바로 앉아있는 수가 더 안전합니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "어지럽다", "def_ko": "환자, Người bệnh", "def_vi": "어지럽다, Chóng mặt"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (306, '10', '대상자가 안전하게 화장실을 이용할 수 있도록 돕는 방법으로 옳은 것은?', '["화장실을 대상자의 방과 가까운 곳으로 정한다.", "화장실 표시는 입구 아래쪽에 한다.", "화장실 전등은 밤에는 소등을 한다.", "화장실 복도에 조형물을 두어 미관을 좋게 한다.", "화장실에 갈 때 신고 벗기 쉽게 슬리퍼를 이용한다."]'::jsonb, 1, NULL, NULL, '{"1": "화장실을 대상자의 방과 가까운 곳으로 정하는 것은 대상자가 쉽게 접근할 수 있게 하여 안전하게 이용할 수 있도록 돕는 방법입니다.\n[정답]", "2": "화장실 표시는 입구 아래쪽에 하는 것이 아니라 쉽게 볼 수 있는 곳에 해야 합니다.", "3": "화장실 전등은 밤에 소등하는 것이 아니라 불을 켜두어야 안전합니다.", "4": "화장실 복도에 조형물이 있을 경우 오히려 방해가 될 수 있습니다.", "5": "신고 벗기 쉽게 슬리퍼는 편리함을 줄 수 있으나, 안전을 고려하면 통제된 신발을 권장합니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người tham gia", "def_ko": "환자, 수혜자", "def_vi": "Bệnh nhân, người được hưởng lợi"}, {"term_ko": "화장실", "term_vi": "Nhà vệ sinh", "def_ko": "배변 및 세면을 하는 곳", "def_vi": "Nơi đi vệ sinh và rửa mặt"}, {"term_ko": "안전", "term_vi": "An toàn", "def_ko": "위험이 없는 상태", "def_vi": "Trạng thái không có nguy hiểm"}, {"term_ko": "근접", "term_vi": "Gần", "def_ko": "가까이 있음", "def_vi": "Ở gần"}, {"term_ko": "조형물", "term_vi": "Tượng", "def_ko": "미관을 위한 설계된 객체", "def_vi": "Đối tượng được thiết kế cho mục đích mỹ quan"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (305, '10', '대상자의 배설물을 관찰한 결과 시설장에게 보고해야 하는 경우로 옳은 것은?', '["소변이 투명하다.", "소변에 거품이 없다.", "소변이 엷은 노란색이다.", "대변에 점액질이 섞여 나온다.", "대변이 부드럽고 형태가 있다."]'::jsonb, 4, NULL, NULL, '{"1": "소변이 투명하다. - 정상적인 소변의 특징으로, 보고할 필요는 없다.", "2": "소변에 거품이 없다. - 정상적인 소변의 특징으로, 보고할 필요는 없다.", "3": "소변이 엷은 노란색이다. - 정상적인 소변의 색상으로, 보고할 필요는 없다.\n[정답]", "4": "대변에 점액질이 섞여 나온다. - 점액질이 섞인 대변은 이상징후로, 반드시 보고해야 한다.", "5": "대변이 부드럽고 형태가 있다. - 정상적인 대변의 상태로, 보고할 필요는 없다."}'::jsonb, '[{"term_ko": "배설물", "term_vi": "Chất thải", "def_ko": "분비물(소변, 대변)", "def_vi": "Chất dịch được bài tiết (nước tiểu, phân)"}, {"term_ko": "소변", "term_vi": "Nước tiểu", "def_ko": "체내에서 배설되는 액체", "def_vi": "Chất lỏng được bài tiết ra từ cơ thể"}, {"term_ko": "대변", "term_vi": "Phân", "def_ko": "장의 내용물이 체외로 배출된 형태", "def_vi": "Hình thức mà nội dung của ruột được thải ra ngoài cơ thể"}, {"term_ko": "점액질", "term_vi": "Chất nhầy", "def_ko": "점성이 있는 액체", "def_vi": "Chất lỏng có độ nhớt"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (303, '10', '경관영양 시 비위관이 새고 있을 때 돕기 방법으로 옳은 것은?', '["역류가 되지 않는다면 그대로 둔다.", "왼쪽으로 눕혀 구토를 예방한다.", "요양보호사가 비위관을 제거한다.", "비위관을 잠그고 간호사에게 연락한다.", "청색증이 나타나는지 관찰한다."]'::jsonb, 4, NULL, NULL, '{"1": "역류가 되지 않는다면 그대로 두는 것은 안전하지 않다.", "2": "왼쪽으로 눕히는 것만으로는 충분한 예방조치가 아니다.\n[정답]", "3": "요양보호사가 비위관을 제거하는 것은 적절하지 않으며, 전문적인 조치가 필요하다.", "4": "비위관을 잠그고 간호사에게 연락하는 것이 가장 적절한 대처 방법이다.", "5": "청색증 관찰은 중요하지만, 문제 해결의 직접적인 방법이 아니다."}'::jsonb, '[{"term_ko": "경관영양", "term_vi": "Dinh dưỡng qua ống", "def_ko": "영양을 공급하기 위한 의학적 방법", "def_vi": "Phương pháp cung cấp dinh dưỡng"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (302, '10', '의식이 없는 대상자의 경관영양을 돕는 방법으로 옳은 것은?', '["영양액은 체온보다 낮은 온도로 준비한다.", "영양액 주머니를 침대 높이에 맞추어 건다.", "비위관이 빠지면 최대한 빨리 밀어 넣는다.", "영양액은 1분에 50mL 이상 주입되지 않도록 주의한다.", "구토 증상을 보이면 소화제와 함께 주입한다."]'::jsonb, 4, NULL, NULL, '{"1": "영양액은 체온보다 낮은 온도로 준비하는 것은 올바르지 않습니다. 영양액은 체온과 유사한 온도로 준비해야 합니다.\n[정답]", "2": "영양액 주머니를 침대 높이에 맞추어 건다는 것은 일반적인 지침이나, 높이를 맞추는 것이 꼭 반드시 필요한 것은 아닙니다.", "3": "비위관이 빠지면 최대한 빨리 밀어 넣는 것은 위험할 수 있으므로 올바르지 않은 방법입니다.", "4": "영양액은 1분에 50mL 이상 주입되지 않도록 주의한다는 것이 올바른 방법입니다. 이는 부작용을 예방하기 위해 중요합니다.", "5": "구토 증상을 보이면 소화제와 함께 주입하는 것은 잘못된 방법입니다. 구토가 발생하면 즉시 주입을 중단하고 의사와 상담해야 합니다."}'::jsonb, '[{"term_ko": "의식", "term_vi": "경관영양", "def_ko": "의식을 가진 상태, 의식이 없다: không có ý thức", "def_vi": "위로 음식이 아닌 약품을 주입하는 방법, dinh dưỡng qua ống"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (301, '10', '침상에 누워있는 오른쪽 편마비 대상자의 식사 돕기로 옳은 것은?', '["오른쪽 밑으로 하여 옆으로 눕힌다.", "왼쪽 허리를 베개로 받쳐 지지해준다.", "똑바로 누운 채 고개를 요양보호사 쪽으로 돌린다.", "숟가락 끝을 왼쪽 입술에 대고 음식물을 넣어준다.", "왼쪽 입안에 음식찌꺼기가 있는지 확인한다."]'::jsonb, 4, NULL, NULL, '{"1": "오른쪽 밑으로 하여 옆으로 눕히는 것은 편마비 환자에게 위험할 수 있습니다.\n[정답]", "4": "숟가락 끝을 왼쪽 입술에 대고 음식물을 넣어주는 방법이 가장 적절합니다.", "2": "왼쪽 허리를 베개로 받쳐 지지하는 것은 필요할 수 있지만, 직접적으로 식사 보조와 관련이 없습니다.", "3": "똑바로 누워 있는 상태는 편마비 환자의 안전과 관련하여 부적절할 수 있습니다.", "5": "왼쪽 입안에 음식찌꺼기가 있는지 확인하는 것은 중요하지만, 즉각적인 식사 보조와 직접적인 연결이 없습니다."}'::jsonb, '[{"term_ko": "편마비", "term_vi": "Liệt nửa người", "def_ko": "반쪽 몸의 기능이 저하된 상태", "def_vi": "Tình trạng giảm chức năng của một nửa cơ thể"}, {"term_ko": "베개", "term_vi": "Gối", "def_ko": "목이나 허리를 받쳐주는 도구", "def_vi": "Dụng cụ hỗ trợ cổ hoặc lưng"}, {"term_ko": "입술", "term_vi": "Môi", "def_ko": "음식물이 들어가는 구강의 일부", "def_vi": "Một phần của cơ thể dùng để ăn uống"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (300, '10', '편마비 대상자의 식사 돕기 방법으로 옳은 것은?', '["건강한 쪽을 밑으로 하여 옆으로 눕힌다.", "숟가락에 밥과 반찬을 가득 올려 먹인다.", "숟가락 끝부분을 입술 중앙에 대고 음식을 넣어준다.", "음식을 완전히 삼키기 전에 음식을 넣어준다.", "식사가 끝난 직후 똑바로 누워 쉬게 한다."]'::jsonb, 1, NULL, NULL, '{"1": "건강한 쪽을 밑으로 하여 옆으로 눕힌다. - 편마비 환자가 안전하게 식사를 할 수 있도록 도와주는 방법입니다.\n[정답]", "2": "숟가락에 밥과 반찬을 가득 올려 먹인다. - 과도한 양은 삼키기 어려워 위험할 수 있습니다.", "3": "숟가락 끝부분을 입술 중앙에 대고 음식을 넣어준다. - 정확한 위치에서 음식을 넣는 것이 필요합니다.", "4": "음식을 완전히 삼키기 전에 음식을 넣어준다. - 이는 질식을 유발할 수 있어 위험합니다.", "5": "식사가 끝난 직후 똑바로 누워 쉬게 한다. - 식사 후 자세에 대한 안전 고려가 필요합니다."}'::jsonb, '[{"term_ko": "편마비", "term_vi": "Bán liệt", "def_ko": "절반이 마비된 상태", "def_vi": "Tình trạng bị liệt một nửa"}, {"term_ko": "식사", "term_vi": "Bữa ăn", "def_ko": "음식을 섭취하는 행동", "def_vi": "Hành động tiêu thụ đồ ăn"}, {"term_ko": "술관", "term_vi": "Thìa", "def_ko": "음식을 먹기 위해 사용하는 도구", "def_vi": "Dụng cụ sử dụng để ăn uống"}, {"term_ko": "삼키다", "term_vi": "Nuốt", "def_ko": "음식을 목구멍으로 넘기는 행동", "def_vi": "Hành động đưa đồ ăn vào họng"}, {"term_ko": "안전", "term_vi": "An toàn", "def_ko": "위험 요소로부터 보호되는 상태", "def_vi": "Trạng thái được bảo vệ khỏi nguy hiểm"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (299, '10', '사레예방 방법으로 옳은 것은?', '["식사 전 물이나 국물로 식도를 적신다.", "의자에 앉을 수 없는 대상자는 누운 자세를 취한다.", "천천히 드시게 하기 위해 음식 섭취 도중에 말을 건넨다.", "점도가 높은 떡 종류를 준비한다.", "목을 축일 수 있는 신맛이 강한 과일을 준비한다."]'::jsonb, 1, NULL, NULL, '{"1": "식사 전 물이나 국물로 식도를 적신다: 이는 식사 중 기도가 막히는 것을 예방하는 좋은 방법입니다.\n[정답]", "2": "의자에 앉을 수 없는 대상자는 누운 자세를 취한다: 누운 자세는 오히려 기도를 막을 수 있으므로 잘못된 방법입니다.", "3": "천천히 드시게 하기 위해 음식 섭취 도중에 말을 건넨다: 음식 섭취 도중에 말을 하는 것은 위험할 수 있습니다.", "4": "점도가 높은 떡 종류를 준비한다: 점도가 높은 음식은 삼키기 어려울 수 있어 위험할 수 있습니다.", "5": "목을 축일 수 있는 신맛이 강한 과일을 준비한다: 신맛이 강한 과일은 오히려 삼키기 어렵게 만들 수 있습니다."}'::jsonb, '[{"term_ko": "사례", "term_vi": "예방", "def_ko": "사례(사례)", "def_vi": "예방(ngăn ngừa)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (298, '10', '입맛이 없는 대상자의 식욕을 증진할 수 있는 방법으로 옳은 것은?', '["혼자서 조용히 식사하게 한다.", "음식의 형태를 알 수 없도록 갈아서 제공한다.", "감칠맛 나는 단 음식 위주로 준비한다.", "다양한 색깔의 반찬을 골고루 제공한다.", "신맛이 강한 음식을 주어 미각을 돋운다."]'::jsonb, 4, NULL, NULL, '{"1": "혼자서 조용히 식사하게 하면 식욕이 더욱 감소할 수 있다.\n[정답]", "4": "다양한 색깔의 반찬을 제공하면 시각적으로 식욕을 자극할 수 있다.", "2": "음식의 형태를 알 수 없도록 갈아서 제공하면 식욕 저하를 초래할 수 있다.", "3": "감칠맛 나는 단 음식 위주로 준비하는 것은 영양 편중의 위험이 있다.", "5": "신맛이 강한 음식을 주면 일부 환자에게는 식욕을 돋울 수 있지만, 대부분에게는 불쾌감을 줄 수 있다."}'::jsonb, '[{"term_ko": "입맛", "term_vi": "Khẩu vị", "def_ko": "식욕(한국어)", "def_vi": "Sự thèm ăn(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (297, '10', '의자에 앉아 식탁에서 식사하는 대상자를 돕는 방법으로 옳은 것은?', '["등받이가 없는 의자에 앉게 한다.", "대상자를 의자에 걸터앉게 한다.", "식탁의 상판이 대상자의 배꼽 높이에 오게 한다.", "대상자의 발가락 끝이 바닥에 닿게 한다.", "의자를 식탁과 30˚~45˚각도가 되도록 하여 비스듬히 앉게 한다."]'::jsonb, 3, NULL, NULL, '{"1": "등받이가 없는 의자에 앉게 할 경우 안정성이 떨어진다.", "2": "대상자를 의자에 걸터앉게 하는 것은 올바르지 않은 방법이다.\n[정답]", "3": "식탁의 상판이 대상자의 배꼽 높이에 오게 하는 것이 가장 적절한 방법이다.", "4": "대상자의 발가락 끝이 바닥에 닿게 하는 것은 필요하지만 전제가 아니다.", "5": "의자를 식탁과 비스듬히 앉게 하는 것은 바람직하지 않다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người được chăm sóc", "def_ko": "환자 또는 도움이 필요한 사람", "def_vi": "Bệnh nhân hoặc người cần sự giúp đỡ"}, {"term_ko": "식탁", "term_vi": "Bàn ăn", "def_ko": "식사를 하는 테이블", "def_vi": "Bàn dùng để ăn"}, {"term_ko": "배꼽", "term_vi": "Rốn", "def_ko": "몸의 중앙에 있는 부위", "def_vi": "Vùng trung tâm của cơ thể"}, {"term_ko": "발가락", "term_vi": "Ngón chân", "def_ko": "발의 끝 부분", "def_vi": "Phần đầu của chân"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (296, '10', '음식물을 삼키는 데 어려움이 있는 대상자의 식사를 돕는 방법으로 옳은 것은?', '["식전 입맛을 돋게 하기 위해 레몬차를 제공한다.", "식사 중에 물을 자주 마시게 한다.", "수시로 말을 걸어 음식을 천천히 삼키게 한다.", "머리와 목을 약간 뒤로 젖혀 음식을 삼키게 한다.", "액체는 증점제를 첨가하여 점도를 높인다."]'::jsonb, 5, NULL, NULL, '{"1": "식전 입맛을 돋게 하기 위해 레몬차를 제공하는 것은 삼키기 어려운 대상자에게 도움이 되지 않습니다.\n[정답]", "5": "액체는 증점제를 첨가하여 점도를 높이면 삼키기 쉽도록 도와줍니다.", "2": "식사 중에 물을 자주 마시게 하는 것은 삼키는 데 방해가 될 수 있습니다.", "3": "수시로 말을 걸면 대상자가 음식을 빨리 삼키게 되어 위험할 수 있습니다.", "4": "머리와 목을 뒤로 젖히면 기도가 막힐 수 있어 위험합니다."}'::jsonb, '[{"term_ko": "음식물", "term_vi": "Thức ăn", "def_ko": "음식", "def_vi": "Thức ăn"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (295, '9', '월례회의의 주된 내용으로 옳은 것은?', '["대상자의 성향과 제공되는 서비스를 점검한다.", "대상자에 대한 건강, 사고 등에 대해 정보를 전달한다.", "대상자와 관계된 직종들의 역할 분담을 명확히 한다.", "대상자 가족의 복리후생, 애로사항을 듣는다.", "대상자에 대한 서비스 제공계획을 검토한다."]'::jsonb, 2, NULL, NULL, '{"1": "대상자의 성향과 제공되는 서비스를 점검하는 것은 회의의 일환일 수 있지만 주된 내용은 아닙니다.\n[정답]", "2": "대상자에 대한 건강, 사고 등에 대해 정보를 전달하는 것이 월례회의의 주된 내용입니다.", "3": "직종들의 역할 분담은 필요하지만 주된 내용으로 보기 어렵습니다.", "4": "대상자 가족의 애로사항을 듣는 것은 중요하지만 주된 내용은 아닙니다.", "5": "서비스 제공계획의 검토도 중요하지만 주된 내용으로 명시되지 않습니다."}'::jsonb, '[{"term_ko": "월례회의", "term_vi": "Cuộc họp hàng tháng", "def_ko": "매월 열리는 회의", "def_vi": "Cuộc họp diễn ra mỗi tháng"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (294, '9', '다음 내용에 해당하는 회의로 옳은 것은?', '["운영회의", "월례회의", "사례회의", "연구회의", "운영회의"]'::jsonb, 2, NULL, NULL, '{"1": "운영회의: 운영 관련 사항을 다루는 회의지만, 이 내용과는 맞지 않습니다.\n[정답]", "2": "월례회의: 요양보호사의 업무와 관련된 준수사항 및 정보를 전달하는 회의입니다.", "3": "사례회의: 특정 사례에 대한 논의가 중심이 되며, 이 내용과는 부합하지 않습니다.", "4": "연구회의: 연구 목적의 회의로, 해당되지 않습니다.", "5": "운영회의: 중복된 보기이며, 정답이 아닙니다."}'::jsonb, '[{"term_ko": "업무", "term_vi": "Công việc", "def_ko": "일(한국어)", "def_vi": "Công việc"}, {"term_ko": "준수사항", "term_vi": "Điều cần tuân thủ", "def_ko": "지켜야 할 사항(한국어)", "def_vi": "Những điều cần tuân thủ"}, {"term_ko": "정보", "term_vi": "Thông tin", "def_ko": "알림(한국어)", "def_vi": "Thông báo"}, {"term_ko": "의견", "term_vi": "Ý kiến", "def_ko": "의견(한국어)", "def_vi": "Ý kiến"}, {"term_ko": "애로사항", "term_vi": "Khó khăn", "def_ko": "어려운 점(한국어)", "def_vi": "Những vấn đề khó khăn"}, {"term_ko": "조치", "term_vi": "Biện pháp", "def_ko": "조치를 취하다(한국어)", "def_vi": "Thực hiện biện pháp"}, {"term_ko": "보고하다", "term_vi": "Báo cáo", "def_ko": "알리다(한국어)", "def_vi": "Báo cáo"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (293, '9', '장기요양기관 사례관리에서 요양보호사의 역할로 옳은 것은?', '["요양보호의 주된 서비스 제공자는 보호자이다.", "사례관리에서 요양보호사는 제외된다.", "사회복지사가 수급자의 가정방문 시 요양보호사의 서비스는 중단된다.", "수급자가 병원에 입원하더라도 사후 관리업무에 협조한다.", "급여제공계획은 요양보호사가 단독으로 계획한다."]'::jsonb, 4, NULL, NULL, '{"1": "요양보호의 주된 서비스 제공자는 보호자가 아니라 요양보호사입니다.", "2": "사례관리에서 요양보호사는 제외되지 않고 중요한 역할을 맡습니다.", "3": "사회복지사가 방문하는 경우에도 요양보호사의 서비스가 중단되지 않습니다.\n[정답]", "4": "수급자가 병원에 입원하더라도 요양보호사는 사후 관리업무에 협조해야 합니다.", "5": "급여제공계획은 요양보호사 혼자서 계획할 수 없으며 협력해야 합니다."}'::jsonb, '[{"term_ko": "장기요양기관", "term_vi": "Cơ sở chăm sóc dài hạn", "def_ko": "장기 요양 서비스를 제공하는 기관", "def_vi": "Cơ sở cung cấp dịch vụ chăm sóc dài hạn"}, {"term_ko": "사례관리", "term_vi": "Quản lý trường hợp", "def_ko": "개별 환자를 평가하고 관리하는 과정", "def_vi": "Quá trình đánh giá và quản lý bệnh nhân cá nhân"}, {"term_ko": "요양보호사", "term_vi": "Điều dưỡng viên chăm sóc", "def_ko": "환자를 돌보는 전문 인력", "def_vi": "Nhân viên chuyên trách chăm sóc bệnh nhân"}, {"term_ko": "수급자", "term_vi": "Người thụ hưởng", "def_ko": "서비스를 받는 사람", "def_vi": "Người nhận dịch vụ"}, {"term_ko": "사회복지사", "term_vi": "Nhân viên xã hội", "def_ko": "사회복지 서비스를 제공하는 전문가", "def_vi": "Chuyên gia cung cấp dịch vụ phúc lợi xã hội"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (292, '9', '장기요양기관에서 실시하는 사례회의 목적으로 옳은 것은?', '["기관의 신규사업 홍보", "요양보호사의 직무평가", "노인 학대에 대한 정기교육", "서비스계획의 타당성 검토와 조정", "요양보호사 복리후생에 대한 의견 수렴"]'::jsonb, 4, NULL, NULL, '{"1": "기관의 신규사업 홍보는 사례회의의 주요 목적이 아닙니다.\n[정답]", "2": "서비스계획의 타당성 검토와 조정은 사례회의의 중요한 목적입니다.", "3": "노인 학대에 대한 정기교육은 별도의 교육 프로그램에 해당합니다.", "4": "요양보호사 복리후생에 대한 의견 수렴은 사례회의의 목적과 관련이 없습니다."}'::jsonb, '[{"term_ko": "장기요양기관", "term_vi": "Cơ sở chăm sóc dài hạn", "def_ko": "장기적인 요양 서비스를 제공하는 기관", "def_vi": "Cơ sở cung cấp dịch vụ chăm sóc dài hạn"}, {"term_ko": "사례회의", "term_vi": "Cuộc họp trường hợp", "def_ko": "특정 환자의 치료나 서비스 계획에 대해 논의하는 회의", "def_vi": "Cuộc họp thảo luận về kế hoạch điều trị hoặc dịch vụ cho bệnh nhân cụ thể"}, {"term_ko": "서비스계획", "term_vi": "Kế hoạch dịch vụ", "def_ko": "환자를 위한 서비스의 구체적인 계획", "def_vi": "Kế hoạch cụ thể cho dịch vụ cho bệnh nhân"}, {"term_ko": "타당성", "term_vi": "Tính khả thi", "def_ko": "실현 가능성", "def_vi": "Khả năng thực hiện"}, {"term_ko": "요양보호사", "term_vi": "Người chăm sóc", "def_ko": "환자의 요양을 담당하는 사람", "def_vi": "Người chịu trách nhiệm chăm sóc bệnh nhân"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (291, '9', '보고 내용이 복잡하거나 자료 보존이 필요할 때 사용하는 업무보고 형식으로 옳은 것은?', '["원격보고", "수시보고", "서면보고", "대면보고", "구두보고"]'::jsonb, 3, NULL, NULL, '{"1": "원격보고: 원거리에서 이루어지는 보고 방식으로 자료 보존과는 거리가 있음.\n[정답]", "3": "서면보고: 복잡한 내용을 명확하게 전달하고 자료로 보존하기에 적합한 형태입니다.", "2": "수시보고: 필요할 때 즉시 이루어지지만 자료가 남지 않음.", "4": "대면보고: 직접 만나서 하는 보고 방식으로는 자료 보존이 어려움.", "5": "구두보고:口頭報告, 기록이 남지 않아 보존에 적합하지 않음."}'::jsonb, '[{"term_ko": "보고", "term_vi": "Báo cáo", "def_ko": "보고(한국어)", "def_vi": "báo cáo(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (290, '9', '상황이 급하거나 사안이 가벼울 때 활용할 수 있는 업무보고 형식으로 옳은 것은?', '["구두보고", "서면보고", "주간보고", "월례회의 보고", "정기업무보고"]'::jsonb, 1, NULL, NULL, '{"1": "구두보고는 빠른 의사소통에 유리하며, 급한 상황에서 유용합니다.\n[정답]", "2": "서면보고는 종종 시간이 걸리고, 가벼운 사안에는 적합하지 않을 수 있습니다.", "3": "주간보고는 정기적인 업무 업데이트에 적합하지만, 급한 상황에 적합하지 않습니다.", "4": "월례회의 보고는 정기적인 회의에서 사용하는 형식으로, 긴급 상황에 부합하지 않습니다.", "5": "정기업무보고는 공식적인 문서로, 비상시에 사용하기에는 부적합합니다."}'::jsonb, '[{"term_ko": "구두보고", "term_vi": "Báo cáo bằng miệng", "def_ko": "말로 전달하는 보고", "def_vi": "Báo cáo được truyền đạt bằng lời"}, {"term_ko": "서면보고", "term_vi": "Báo cáo bằng văn bản", "def_ko": "문서로 작성된 보고", "def_vi": "Báo cáo được viết thành tài liệu"}, {"term_ko": "주간보고", "term_vi": "Báo cáo hàng tuần", "def_ko": "매주 정기적으로 제출하는 보고서", "def_vi": "Báo cáo được gửi định kỳ mỗi tuần"}, {"term_ko": "월례회의 보고", "term_vi": "Báo cáo cuộc họp hàng tháng", "def_ko": "매월 회의에서 보고하는 형식", "def_vi": "Hình thức báo cáo trong cuộc họp hàng tháng"}, {"term_ko": "정기업무보고", "term_vi": "Báo cáo công việc chính thức", "def_ko": "공식적인 보고서", "def_vi": "Tài liệu báo cáo chính thức"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (289, '9', '재가방문 후 요양보호사가 시설장에게 신속하게 보고를 해야 하는 경우로 옳은 것은?', '["이불 빨래가 세탁실에 있다.", "유통기한이 임박한 유제품이 냉장고에 있다.", "화장실 등이 깜박거린다.", "대상자의 방문에 자물쇠가 설치되어 있다.", "대상자의 자녀가 오랜만에 방문하였다."]'::jsonb, 4, NULL, NULL, '{"1": "이불 빨래가 세탁실에 있다는 사실은 큰 문제가 되지 않으므로 신속하게 보고할 필요가 없습니다.", "2": "유통기한이 임박한 유제품은 관리해야 할 사항이지만, 긴급한 상황이 아닙니다.", "3": "화장실 등이 깜박거리는 것은 점검이 필요할 수 있지만, 즉각적인 보고가 필요한 상황은 아닙니다.\n[정답]", "4": "대상자의 방문에 자물쇠가 설치되어 있다면, 이는 긴급히 조치를 취해야 하는 상황이므로 즉시 보고해야 합니다.", "5": "대상자의 자녀 방문은 일반적인 사항이기 때문에 긴급 보고가 아닙니다."}'::jsonb, '[{"term_ko": "재가방문", "term_vi": "Thăm nhà", "def_ko": "집에서의 요양 서비스 제공", "def_vi": "Cung cấp dịch vụ chăm sóc tại nhà"}, {"term_ko": "시설장", "term_vi": "Người quản lý", "def_ko": "시설의 관리자", "def_vi": "Người quản lý cơ sở"}, {"term_ko": "신속하게", "term_vi": "Nhanh chóng", "def_ko": "빠르게", "def_vi": "Nhanh chóng"}, {"term_ko": "보고", "term_vi": "Báo cáo", "def_ko": "보고하다", "def_vi": "Báo cáo"}, {"term_ko": "대상자", "term_vi": "Đối tượng", "def_ko": "서비스 받는 사람", "def_vi": "Người nhận dịch vụ"}, {"term_ko": "자물쇠", "term_vi": "Khóa", "def_ko": "khóa", "def_vi": "Khóa"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (288, '9', '요양보호 업무보고가 중요한 이유는?', '["서비스 비용의 결정", "대상자의 사적 정보 공유", "기관 중심의 서비스 제공", "요양보호서비스의 질 향상", "다른 장기요양기관과의 경쟁"]'::jsonb, 4, NULL, NULL, '{"1": "서비스 비용은 요양보호 업무보고로 직접 결정되기 어렵다.\n[정답]", "4": "요양보호 업무보고는 서비스의 질을 높이는 데 중요한 역할을 한다.", "3": "기관 중심의 서비스 제공은 하나의 측면일 뿐이다.", "5": "경쟁도 존재하지만, 업무보고의 주된 목적은 아니다."}'::jsonb, '[{"term_ko": "요양보호", "term_vi": "Chăm sóc y tế", "def_ko": "돌보는 서비스(한국어)", "def_vi": "Dịch vụ chăm sóc"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (287, '9', '요양보호사가 기록한 내용으로 바르게 기록한 것은?', '["오늘 자장면을 많이 드셨다고 한다.", "소변을 시원하게 보았다고 한다.", "기분이 나쁜 것처럼 말하였다.", "1시부터 4시까지 낮잠을 주무심", "엉덩이에 욕창이 발생하였다."]'::jsonb, 4, NULL, NULL, '{"1": "''많이 드셨다고 한다''는 주관적인 표현으로, 구체적인 수치를 제시하지 않아 부적절합니다.\n[정답]", "2": "''시원하게 보았다''는 비유적 표현이 포함되어 있어 애매한 보고입니다.", "3": "''나쁜 기분처럼 말하였다''는 감정의 주관적 해석으로 부적합합니다.", "4": "''낮잠을 주무심''은 구체적인 시간과 행동을 명확하게 기록하여 적절합니다.", "5": "''욕창이 발생하였다''는 의학적 용어는 적절하나 발생 시점이나 상태 설명이 부족합니다."}'::jsonb, '[{"term_ko": "요양보호사", "term_vi": "Người chăm sóc", "def_ko": "환자 돌봄을 담당하는 사람", "def_vi": "Người phụ trách chăm sóc bệnh nhân"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (286, '9', '요양보호 기록에 관한 설명으로 옳은 것은?', '["일주일 단위로 핵심 내용을 보고한다.", "공식화된 용어를 사용하여 기록한다.", "기록지는 열람하기 쉬운 곳에 비치한다.", "요양보호사가 느낀 점을 중심으로 기록한다.", "서비스는 내용을 우회적으로 표현하여 기록한다."]'::jsonb, 2, NULL, NULL, '{"1": "일주일 단위로 핵심 내용을 보고하는 것은 일반적으로 필요하지 않습니다.\n[정답]", "2": "공식화된 용어를 사용하여 기록하는 것이 중요합니다.", "3": "기록지는 접근이 용이해야 하지만, ''열람하기 쉬운 곳''은 비밀 유지 측면에서 적절하지 않을 수 있습니다.", "4": "요양보호사가 느낀 점을 중심으로 기록하는 것은 주관적일 수 있습니다.", "5": "서비스 내용을 우회적으로 표현하여 기록하는 것은 명확성을 해칠 수 있습니다."}'::jsonb, '[{"term_ko": "요양보호 기록", "term_vi": "Ghi chép chăm sóc người cao tuổi", "def_ko": "환자를 돌보면서 기록하는 문서", "def_vi": "Tài liệu ghi lại quá trình chăm sóc bệnh nhân"}, {"term_ko": "공식화된 용어", "term_vi": "Thuật ngữ chính thức", "def_ko": "규칙적으로 사용하는 단어 등", "def_vi": "Từ ngữ sử dụng theo quy định"}, {"term_ko": "열람", "term_vi": "Xem xét", "def_ko": "열어보는 것", "def_vi": "Hành động xem, kiểm tra"}, {"term_ko": "주관적", "term_vi": "Chủ quan", "def_ko": "개인의 감정에 따른 것", "def_vi": "Điều gì đó dựa trên cảm xúc cá nhân"}, {"term_ko": "우회적", "term_vi": "Gián tiếp", "def_ko": "직접적이지 않은 방법", "def_vi": "Phương pháp không trực tiếp"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (285, '9', '재가급여전자관리시스템 업무 절차 중 ☐ 안에 들어갈 순서로 옳은 것은?', '["사용자 등록 급여내용 전송", "사용자 등록 재가시설 등록", "서비스 내용 급여내용 전송", "서비스 내용 사용자 등록", "급여내용 전송 사용자 등록"]'::jsonb, 1, NULL, NULL, '{"1": "사용자 등록 급여내용 전송\n[정답]", "2": "사용자 등록 재가시설 등록", "3": "서비스 내용 급여내용 전송", "4": "서비스 내용 사용자 등록", "5": "급여내용 전송 사용자 등록"}'::jsonb, '[{"term_ko": "재가급여", "term_vi": "Chăm sóc tại nhà", "def_ko": "가정에서 제공되는 요양 서비스", "def_vi": "Dịch vụ điều dưỡng được cung cấp tại nhà"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (284, '9', '요양보호사가 기록하는 급여제공기록지에 주요 내용으로 옳은 것은?', '["상담내용 및 결과", "서비스의 목표, 내용, 횟수", "서비스의 제공 내용 및 시간", "사례회의 검토 내용", "대상자의 욕구 사정"]'::jsonb, 3, NULL, NULL, '{"1": "상담내용 및 결과: 상담 결과는 중요한 정보이지만, 급여제공기록지의 주요 내용은 아니다.\n[정답]", "2": "서비스의 목표, 내용, 횟수: 이 항목은 서비스 제공에 필요한 중요한 정보를 포함한다.", "3": "서비스의 제공 내용 및 시간: 급여제공기록지에서 가장 중요하게 기록되는 내용이다.", "4": "사례회의 검토 내용: 사례회의는 중요하지만, 직접적인 급여제공기록지의 일부분은 아니다.", "5": "대상자의 욕구 사정: 욕구 사정은 필요하지만, 급여제공기록지의 주요 내용에는 포함되지 않는다."}'::jsonb, '[{"term_ko": "급여", "term_vi": "Dịch vụ", "def_ko": "보상받는 서비스", "def_vi": "Dịch vụ nhận được"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (283, '9', '요양보호사의 재가급여제공 내용을 국민건강보험 공단에 실시간으로 전송하고 이를 급여비용 청구와 자동으로 연계하는 관리체계로 옳은 것은?', '["장기요양급여제공 기록관리 시스템", "스마트장기요양 시스템", "24시간 방문요양 시스템", "재가급여전자관리 시스템(RFID)", "급여제공계획 관리 시스템"]'::jsonb, 4, NULL, NULL, '{"1": "장기요양급여제공 기록관리 시스템: 요양급여 제공 기록을 관리하는 시스템으로, 실시간 전송 기능이 없다.\n[정답]", "2": "스마트장기요양 시스템: 최신 기술을 이용한 요양 시스템이나, 질문의 관리체계와는 다름.", "3": "24시간 방문요양 시스템: 방문요양 서비스 제공에 관한 시스템이지만, 실시간 전송과 연계 기능이 부족하다.", "4": "재가급여전자관리 시스템(RFID): 재가급여를 실시간으로 전송하고 청구와 연계되는 관리체계를 갖춘 시스템이다.", "5": "급여제공계획 관리 시스템: 급여 제공 계획을 관리하는 시스템으로, 실시간 전송과는 관련이 없다."}'::jsonb, '[{"term_ko": "재가급여", "term_vi": "Trợ cấp tại nhà", "def_ko": "가정에서 제공되는 요양 서비스", "def_vi": "Dịch vụ chăm sóc sức khỏe được cung cấp tại nhà"}, {"term_ko": "국민건강보험 공단", "term_vi": "Cơ quan bảo hiểm y tế quốc gia", "def_ko": "국민의 건강보험을 관리하는 기관", "def_vi": "Cơ quan quản lý bảo hiểm y tế cho công dân"}, {"term_ko": "실시간", "term_vi": "Thời gian thực", "def_ko": "즉시, 동시에", "def_vi": "Ngay lập tức, đồng thời"}, {"term_ko": "청구", "term_vi": "Yêu cầu thanh toán", "def_ko": "비용을 요구하는 행위", "def_vi": "Hành động yêu cầu chi phí"}, {"term_ko": "관리체계", "term_vi": "Hệ thống quản lý", "def_ko": "체계적으로 관리하는 시스템", "def_vi": "Hệ thống quản lý một cách có tổ chức"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (282, '9', '요양보호사의 업무내용을 기록하는 이유로 옳은 것은?', '["대상자의 개인정보를 공유할 수 있다.", "대상자의 책임성을 높일 수 있다.", "타 전문직과의 원활한 업무협조를 할 수 있다.", "요양보호사의 자질을 평가할 수 있다.", "대상자의 태도를 평가할 수 있다."]'::jsonb, 3, NULL, NULL, '{"1": "개인정보를 공유할 수는 있지만, 이는 윤리적으로 문제가 될 수 있습니다.\n[정답]", "3": "기록을 통해 타 전문직과의 원활한 업무협조가 가능해집니다.", "2": "대상자의 책임성을 높이는 것은 기록과는 직접적인 연관이 없습니다.", "4": "기록은 요양보호사의 자질을 직접적으로 평가하기보다는 업무 수행을 평가하는 데 사용됩니다.", "5": "대상자의 태도는 기록으로 평가하기 어려운 주관적인 부분입니다."}'::jsonb, '[{"term_ko": "업무", "term_vi": "Nhiệm vụ", "def_ko": "일(한국어)", "def_vi": "Công việc(chăm sóc sức khỏe)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (281, '9', '요양보호사가 업무 내용을 기록하는 이유로 옳은 것은?', '["예산을 효율적으로 분배한다.", "대상자의 사생활을 파악한다.", "가족과의 의사송통을 제한한다.", "관련 전문가에게 정보를 제공한다.", "문제 발생 시 법적 책임을 회피할 수 있다."]'::jsonb, 4, NULL, NULL, '{"1": "예산을 효율적으로 분배한다는 것은 직접적인 관계가 없습니다.\n[정답]", "4": "관련 전문가에게 정보를 제공하는 것은 중요한 이유 중 하나입니다.", "3": "가족과의 의사소통을 제한하는 것은 바람직하지 않습니다.", "5": "문제 발생 시 법적 책임을 회피할 수 있다는 것은 기록의 주된 목적이 아닙니다.", "2": "대상자의 사생활을 파악하는 것은 업무 기록과는 관련이 없습니다."}'::jsonb, '[{"term_ko": "업무", "term_vi": "Công việc", "def_ko": "일이나 과제", "def_vi": "Công việc hoặc nhiệm vụ"}, {"term_ko": "기록", "term_vi": "Ghi chép", "def_ko": "적어두다, 문서화하다", "def_vi": "Để ghi lại, tài liệu hóa"}, {"term_ko": "사생활", "term_vi": "Quyền riêng tư", "def_ko": "개인의 비공식적인 생활", "def_vi": "Cuộc sống không chính thức của cá nhân"}, {"term_ko": "전문가", "term_vi": "Chuyên gia", "def_ko": "특정 분야에서 지식과 경험이 있는 사람", "def_vi": "Người có kiến thức và kinh nghiệm trong một lĩnh vực cụ thể"}, {"term_ko": "법적 책임", "term_vi": "Trách nhiệm pháp lý", "def_ko": "법적으로 책임을 져야 하는 상태", "def_vi": "Tình trạng phải chịu trách nhiệm về mặt pháp lý"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (280, '1', '국가는 ''어버이날''을 지정하여 매년 기념하면서 모범 어르신을 선정하여 보상하는 유형으로 옳은 것은?', '["지적 보상", "경제적 보상", "정치적 보상", "자유적 보상", "문화유산의 전수"]'::jsonb, 3, NULL, NULL, '{"1": "지적 보상은 주로 지식이나 기술에 관련된 보상을 뜻하므로 틀립니다.\n[정답]", "2": "경제적 보상은 금전적인 보상을 의미하며, 어버이날 기념과 관련이 없습니다.", "3": "정치적 보상은 정치적 활동에 대한 대가를 의미하므로 부적합합니다.", "4": "자유적 보상은 자유를 기준으로 한 보상이기 때문에 맞지 않습니다.", "5": "문화유산의 전수는 전통이나 문화를 배우고 전하는 것으로, 질문의 맥락과는 관련이 없습니다."}'::jsonb, '[{"term_ko": "국가", "term_vi": "Quốc gia", "def_ko": "나라의 정치적 조직", "def_vi": "Tổ chức chính trị của một đất nước"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (279, '1', '노화의 긍정적 측면으로 옳은 것은?', '["노화로 인해 일상적인 균형을 유지하기 힘들다.", "수준 높은 동기부여 직무를 수행하기 힘들다.", "즉각적인 의사소통을 하는 데 어려움이 없다.", "젊은 세대에 비해 중요한 정보를 추출하기 힘들다.", "젊은 세대에 비해 신중하고 조심스러워 실수가 적다."]'::jsonb, 5, NULL, NULL, '{"1": "노화로 인해 일상적인 균형을 유지하기 힘들다는 부정적 측면입니다.", "2": "수준 높은 동기부여 직무를 수행하기 힘들다고 하는 것은 노화의 부정적인 면을 나타냅니다.", "3": "즉각적인 의사소통을 하는 데 어려움이 없다는 것은 긍정적 측면이 아닙니다.\n[정답]", "4": "젊은 세대에 비해 중요한 정보를 추출하기 힘들다는 것은 노화의 부정적인 면을 강조하는 것입니다.", "5": "젊은 세대에 비해 신중하고 조심스러워 실수가 적다는 것은 노화의 긍정적 측면을 나타냅니다."}'::jsonb, '[{"term_ko": "노화", "term_vi": "Lão hóa", "def_ko": "노화(성장과 발달 동안 발생하는 신체적, 정신적 변화의 자연적인 과정)", "def_vi": "Quá trình tự nhiên của sự thay đổi thể chất và tinh thần xảy ra trong suốt sự phát triển và trưởng thành"}, {"term_ko": "균형", "term_vi": "Cân bằng", "def_ko": "안정 상태", "def_vi": "Trạng thái ổn định"}, {"term_ko": "신중", "term_vi": "Thận trọng", "def_ko": "조심스러운 태도", "def_vi": "Thái độ cẩn thận"}, {"term_ko": "실수", "term_vi": "Lỗi", "def_ko": "잘못된 행동", "def_vi": "Hành động sai lầm"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (278, '1', '노년기를 건강하게 보내기 위한 방법으로 옳은 것은?', '["사회 활동 참여를 제한한다.", "부부간 애정 표현을 삼간다.", "혼자 보내는 시간을 늘린다.", "뇌를 자극하는 독서 활동을 늘린다.", "영양보조식품 중심으로 식단을 구성한다."]'::jsonb, 4, NULL, NULL, '{"1": "사회 활동 참여를 제한한다. 이는 건강한 노년기를 보내는 데 부정적 영향을 미칩니다.", "2": "부부간 애정 표현을 삼간다. 이것도 정서적 지원을 줄이는 행동입니다.", "3": "혼자 보내는 시간을 늘린다. 고립감을 증가시켜 건강에 좋지 않습니다.\n[정답]", "4": "뇌를 자극하는 독서 활동을 늘린다. 이는 뇌 건강에 긍정적인 영향을 줍니다.", "5": "영양보조식품 중심으로 식단을 구성한다. 이는 균형 잡힌 식사를 대체할 수 없습니다."}'::jsonb, '[{"term_ko": "노년기", "term_vi": "Thời kỳ cao niên", "def_ko": "노인의 시기", "def_vi": "Thời kỳ của người già"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (277, '1', '노년기의 신체적 특성으로 옳은 것은?', '["기초대사율이 증가한다.", "신체회복력이 향상된다.", "일상생활 수행능력이 향상된다.", "노화가 비가역적으로 진행된다.", "신체기관의 잔존능력이 향상된다."]'::jsonb, 4, NULL, NULL, '{"1": "기초대사율은 노화에 따라 일반적으로 감소합니다.", "2": "신체회복력은 노화에 따라 감소합니다.", "3": "일상생활 수행능력은 노화로 인해 저하될 수 있습니다.\n[정답]", "4": "노화는 비가역적으로 진행되며, 이는 불가역적인 신체적 변화를 의미합니다.", "5": "신체기관의 잔존능력은 보통 저하되는 경향이 있습니다."}'::jsonb, '[{"term_ko": "노년기", "term_vi": null, "def_ko": "유년이 지난 후의 나이, 신체적 특성: 몸의 특성, 기초대사율: 기본적인 에너지 소비량, 신체회복력: 몸의 회복 능력, 비가역적: 되돌릴 수 없는, 잔존능력: 남아있는 능력", "def_vi": null}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (276, '1', '다음의 노인의 심리적 특성으로 옳은 것은?• 식욕부진, 체중 감소 등 신체적인 증상을 호소한다.• 주변 사람들에게 적대적으로 대하거나 비난하는 행동을 보인다.', '["우울증 경향의 증가", "내향성의 증가", "조심성의 증가", "경직성의 증가", "생에 대한 회고의 경향 증가"]'::jsonb, 1, NULL, NULL, '{"1": "우울증 경향의 증가: 노인이 식욕부진, 체중 감소 등의 신체적 증상을 보이는 경우 우울증의 징후일 수 있다.\n[정답]", "2": "내향성의 증가: 내향성이 증가하는 것은 항상 우울과 관련이 있는 것은 아니다.", "3": "조심성의 증가: 조심성 증가와 관련된 심리적 증상은 다른 경우에 해당한다.", "4": "경직성의 증가: 경직성의 증가는 특정한 인격 특성이며 우울증의 직접적인 징후가 아니다.", "5": "생에 대한 회고의 경향 증가: 생에 대한 회고는 노인의 일반적인 특성일 수 있지만 우울증과는 명확한 연관성이 없다."}'::jsonb, '[{"term_ko": "심리적", "term_vi": "Tâm lý", "def_ko": "정신적인", "def_vi": "liên quan đến tinh thần"}, {"term_ko": "신체적", "term_vi": "Thể chất", "def_ko": "신체와 관련된", "def_vi": "liên quan đến cơ thể"}, {"term_ko": "우울증", "term_vi": "Trầm cảm", "def_ko": "깊은 슬픔의 상태", "def_vi": "trạng thái buồn sâu sắc"}, {"term_ko": "식욕부진", "term_vi": "Giảm sự thèm ăn", "def_ko": "식욕이 감소함", "def_vi": "giảm sự đói"}, {"term_ko": "체중", "term_vi": "Cân nặng", "def_ko": "몸의 무게", "def_vi": "trọng lượng cơ thể"}, {"term_ko": "경향", "term_vi": "Xu hướng", "def_ko": "특정 방향으로의 성향", "def_vi": "sự thiên về một hướng"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (275, '1', '결단이나 행동이 느려지고 매사에 신중해지는 노인의 심리적 배경으로 옳은 것은?', '["비가역성", "의존성", "조심성", "경직성", "내향성"]'::jsonb, 3, NULL, NULL, '{"1": "비가역성: 노화로 인해 일어나는 어떤 변화는 되돌릴 수 없다는 의미입니다.", "2": "의존성: 노인이 신체적, 정서적으로 타인에게 의존하게 되는 경향을 나타냅니다.\n[정답]", "3": "조심성: 노화로 인해 신중해지고 결단력이 느려지는 경향을 설명합니다.", "4": "경직성: 사고나 행동이 융통성 없이 고정된 상태를 의미합니다.", "5": "내향성: 외부와의 상호작용보다 자신의 내면을 중시하는 성향을 뜻합니다."}'::jsonb, '[{"term_ko": "결단", "term_vi": "Quyết định", "def_ko": "결정하고 실행하는 것", "def_vi": "Quyết định và thực hiện"}, {"term_ko": "행동", "term_vi": "Hành động", "def_ko": "어떤 행동이나 작업을 수행하는 것", "def_vi": "Thực hiện một hành động hoặc công việc"}, {"term_ko": "노인", "term_vi": "Người cao tuổi", "def_ko": "나이가 많은 사람", "def_vi": "Người có tuổi"}, {"term_ko": "심리적", "term_vi": "Tâm lý", "def_ko": "마음과 정신과 관련된", "def_vi": "Liên quan đến tâm trí và tinh thần"}, {"term_ko": "신중", "term_vi": "Thận trọng", "def_ko": "조심스럽고 고려하는 태도", "def_vi": "Thái độ cẩn thận và xem xét"}, {"term_ko": "의존성", "term_vi": "Tính phụ thuộc", "def_ko": "다른 사람에게 의지하는 상태", "def_vi": "Trạng thái phụ thuộc vào người khác"}, {"term_ko": "조심성", "term_vi": "Thận trọng", "def_ko": "신중함", "def_vi": "Tính cẩn trọng"}, {"term_ko": "경직성", "term_vi": "Tính cứng nhắc", "def_ko": "생각과 행동이 경직된 상태", "def_vi": "Trạng thái tư duy và hành động không linh hoạt"}, {"term_ko": "내향성", "term_vi": "Tính hướng nội", "def_ko": "외향적이지 않음", "def_vi": "Không hướng ngoại"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (274, '1', '다음의 노인의 심리적 특성으로 옳은 것은?• 노인은 자신에게 익숙한 습관적인 태도나 방법을 고수한다.• 매사에 융통성이 없어지고, 새로운 변화를 싫어하며, 도전적인 일을 꺼리는 경향을 보인다.• 새로운 기구를 사용하거나 새로운 방식으로 일을 처리하는 데에 저항한다.', '["우울증 경향의 증가", "내향성의 증가", "조심성의 증가", "경직성의 증가", "의존성의 증가"]'::jsonb, 4, NULL, NULL, '{"1": "우울증 경향의 증가: 노인이 느끼는 심리적 특성이 반드시 우울증으로 연결되지는 않는다.", "2": "내향성의 증가: 노인이 내향적으로 변할 수 있지만, 이것이 주된 특징은 아니다.", "3": "조심성의 증가: 조심성은 중요하지만, 경직성이 더 나타나기 쉽다.\n[정답]", "4": "경직성의 증가: 노인이 새로운 변화를 싫어하고 고수하는 모습은 경직성을 나타낸다.", "5": "의존성의 증가: 의존성도 나타날 수 있지만, 경직성이 더 두드러진다."}'::jsonb, '[{"term_ko": "노인", "term_vi": "Người cao tuổi", "def_ko": "노인(한국어)", "def_vi": "Người già"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (273, '1', '노년기의 일반적인 특성으로 옳은 것은?', '["사고의 융통성이 증대된다.", "사회적 유대관계가 확대된다.", "삶에 대한 회고적 경향이 나타난다.", "역할 상실로 자기정체성이 강화된다.", "내향성의 감소로 매사에 신중해진다."]'::jsonb, 3, NULL, NULL, '{"1": "사고의 융통성이 감소한다.\n[정답]", "3": "노년기는 회고적 경향이 나타나 삶을 돌아보게 된다.", "2": "사회적 유대관계는 축소되는 경향이 있다.", "4": "역할 상실이 일어나면 자기정체성이 흔들리는 경우가 많다.", "5": "내향성의 감소는 일반적으로 나타나지 않는다."}'::jsonb, '[{"term_ko": "노년기", "term_vi": "Người già", "def_ko": "나이가 많은 시기(한국어)", "def_vi": "Thời kỳ có tuổi cao"}, {"term_ko": "특성", "term_vi": "Đặc điểm", "def_ko": "특징(한국어)", "def_vi": "Tính chất, đặc điểm"}, {"term_ko": "사고", "term_vi": "Suy nghĩ", "def_ko": "사고(한국어)", "def_vi": "Suy nghĩ"}, {"term_ko": "융통성", "term_vi": "Linh hoạt", "def_ko": "유연함(한국어)", "def_vi": "Tính linh hoạt"}, {"term_ko": "사회적", "term_vi": "Xã hội", "def_ko": "사회와 관련된(한국어)", "def_vi": "Liên quan đến xã hội"}, {"term_ko": "유대관계", "term_vi": "Quan hệ", "def_ko": "연결관계(한국어)", "def_vi": "Mối quan hệ"}, {"term_ko": "회고적", "term_vi": "Hồi tưởng", "def_ko": "회고하는 것(한국어)", "def_vi": "Nhớ lại"}, {"term_ko": "경향", "term_vi": "Xu hướng", "def_ko": "경향(한국어)", "def_vi": "Xu hướng"}, {"term_ko": "자기정체성", "term_vi": "Bản sắc cá nhân", "def_ko": "자기 정체성(한국어)", "def_vi": "Danh tính cá nhân"}, {"term_ko": "내향성", "term_vi": "Hướng nội", "def_ko": "내향적인 성향(한국어)", "def_vi": "Tính hướng nội"}, {"term_ko": "신중", "term_vi": "Thận trọng", "def_ko": "신중함(한국어)", "def_vi": "Sự thận trọng"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (272, '1', '노화에 따른 노년기 특성으로 옳은 것은?', '["유대감이 줄어든다.", "조심성이 감소한다.", "우울증 경향이 감소한다.", "정서적 의존성이 감소한다.", "친근한 사물에 대한 애착이 감소한다."]'::jsonb, 1, NULL, NULL, '{"1": "노화가 진행됨에 따라 유대감이 줄어드는 경향이 있습니다.\n[정답]", "2": "일반적으로 조심성이 오히려 증가하는 경향이 있습니다.", "3": "우울증 경향이 증가하는 경우가 많습니다.", "4": "정서적 의존성은 증가할 수 있습니다.", "5": "친근한 사물에 대한 애착은 오히려 증가할 수 있습니다."}'::jsonb, '[{"term_ko": "노화", "term_vi": "Lão hóa", "def_ko": "늙는 것(한국어)", "def_vi": "Sự già đi(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (271, '1', '에릭슨이 주장한 생애주기에서 노년기에 해당하는 특성으로 옳은 것은?', '["신뢰감 - 불신감", "자율성 - 의심", "정체감 - 고립감", "생산성 - 자아 침체", "자아통합 - 절망감"]'::jsonb, 5, NULL, NULL, '{"1": "신뢰감 - 불신감: 에릭슨의 초기 단계에서의 개념입니다.", "2": "자율성 - 의심: 유아기의 단계에서 해당하는 개념입니다.", "3": "정체감 - 고립감: 청소년기의 발달 단계에 해당합니다.", "4": "생산성 - 자아 침체: 중년기의 특징입니다.\n[정답]", "5": "자아통합 - 절망감: 노년기의 특징으로, 개인이 자신의 삶을 수용하고 일생을 통합적으로 이해하는 과정에서 느끼는 감정입니다."}'::jsonb, '[{"term_ko": "생애주기", "term_vi": "Giai đoạn cuộc đời", "def_ko": "인생의 다양한 단계", "def_vi": "Các giai đoạn khác nhau trong cuộc sống"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (270, '1', '다음에서 설명하는 가족형태로 옳은 것은?• 노인 부모가 같은 아파트에 따로 거주하고 있고, 성인 자녀로부터 필요할 때 돌봄을 받고 있다.', '["핵가족", "조손가족", "다문화가족", "한부모가족", "수정확대가족"]'::jsonb, 5, NULL, NULL, '{"1": "핵가족: 부모와 자녀로 구성된 기본적인 가족 형태입니다.", "2": "조손가족: 손주가 조부모와 함께 사는 형태입니다.", "3": "다문화가족: 서로 다른 문화적 배경을 가진 가족입니다.", "4": "한부모가족: 한 부모가 자녀를 양육하는 형태입니다.\n[정답]", "5": "수정확대가족: 부모, 자녀, 조부모 등이 함께 거주하거나 밀접하게 연결된 가족 형태입니다."}'::jsonb, '[{"term_ko": "가족형태", "term_vi": "Hình thức gia đình", "def_ko": "가족의 구성 구조", "def_vi": "Cấu trúc của gia đình"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (269, '1', '노년기 가족관계의 변화로 옳은 것은?', '["확대가족이 증가한다.", "고부 갈등이 해소된다.", "은퇴로 인해 부부관계가 수직적으로 변한다.", "조부모는 손자녀의 긍정적 자아 형성에 기여한다.", "배우자의 상실로 빈 둥지 증후군을 경험한다."]'::jsonb, 4, NULL, NULL, '{"1": "확대가족의 증가가 아니라 주로 핵가족이 증가하는 경향이 있습니다.\n[정답]", "4": "조부모는 손자녀의 긍정적 자아 형성에 기여하는 중요한 역할을 합니다.", "2": "고부 갈등은 종종 해소되지 않고 계속될 수 있습니다.", "3": "은퇴로 인해 부부관계는 흔히 수평적으로 변하는 경향이 있습니다.", "5": "배우자의 상실로 인해 빈 둥지 증후군을 경험할 수 있지만, 이 선택지는 전체적인 변화에 대한 직접적인 설명이 아닙니다."}'::jsonb, '[{"term_ko": "노년기", "term_vi": "Giai đoạn người già", "def_ko": "노인(성인) 시기(한국어)", "def_vi": "Giai đoạn của người già"}, {"term_ko": "가족관계", "term_vi": "Mối quan hệ gia đình", "def_ko": "가족 구성원 간의 관계(한국어)", "def_vi": "Mối quan hệ giữa các thành viên trong gia đình"}, {"term_ko": "확대가족", "term_vi": "Gia đình mở rộng", "def_ko": "조부모, 부모, 자녀가 함께 사는 가족(한국어)", "def_vi": "Gia đình có ông bà, cha mẹ và con cái sống cùng nhau"}, {"term_ko": "고부 갈등", "term_vi": "Xung đột mẹ chồng và nàng dâu", "def_ko": "시어머니와 며느리 간의 갈등(한국어)", "def_vi": "Sự xung đột giữa mẹ chồng và con dâu"}, {"term_ko": "빈 둥지 증후군", "term_vi": "Hội chứng tổ chim trống", "def_ko": "자녀가 성장하여 집을 떠난 후 부모가 느끼는 외로움(한국어)", "def_vi": "Cảm giác cô đơn của cha mẹ khi con cái lớn lên và rời bỏ tổ ấm"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (268, '1', '노인부향 문제의 개선 방안으로 옳은 것은?', '["자녀에게 부양 부담을 부과한다.", "노인부양을 가족의 문제로 한정한다.", "소득 재분배를 위한 기초 연금을 축소한다.", "사회보험제도를 통해 세대통합을 증진한다.", "돌봄서비스에 대한 국각의 책임을 축소한다."]'::jsonb, 4, NULL, NULL, '{"1": "자녀에게 부양 부담을 부과하는 것은 가족의 부담을 가중시킬 뿐입니다.\n[정답]", "4": "사회보험제도를 통해 세대통합을 증진하는 것은 노인부양 문제의 해결에 긍정적인 역할을 할 수 있습니다.", "2": "노인부양을 가족의 문제로 한정하는 것은 사회적인 책임을 경시하는 결과를 초래할 수 있습니다.", "3": "소득 재분배를 위한 기초 연금을 축소하는 것은 노인들의 생활을 더욱 어렵게 만들 것입니다.", "5": "돌봄서비스에 대한 국가의 책임을 축소하는 것은 오히려 문제를 악화시킬 수 있습니다."}'::jsonb, '[{"term_ko": "부양", "term_vi": "Chăm sóc", "def_ko": "돌봄이나 지원", "def_vi": "Sự trợ cấp hoặc hỗ trợ"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (267, '1', '대상자 중심의 요양보호'' 의 원칙을 준수한 사례로 옳은 것은?', '["\"화장실에 가시면 어르신이나 저도 고생이니까 간이변기를 사용하시는 게 좋겠어요.\"", "\"걸으려면 힘들고 넘어지니까 그냥 휠체어 타세요. 제가 밀어 드릴게요.\"", "\"잠에서 깰 수 있으니 주무시는 동안에는 기저귀를 확인하지 않을게요.\"", "\"지금 목욕 안하면 다음 주까지 기다려야 해요. 그러니까 지금 얼른 하세요.\"", "\"안 묶으면 콧줄을 잡아 뽑으시니 억제대로 묶어 놓을 수밖에 없어요.\""]'::jsonb, 3, NULL, NULL, '{"1": "\"어르신이나 저도 고생이니까 간이변기를 사용하시는 게 좋겠어요.\" - 어르신의 편안함을 고려하지 않은 발언이다.", "2": "\"걸으려면 힘들고 넘어지니까 그냥 휠체어 타세요. 제가 밀어 드릴게요.\" - 대상자의 자율성을 무시한 결정이다.\n[정답]", "3": "\"잠에서 깰 수 있으니 주무시는 동안에는 기저귀를 확인하지 않을게요.\" - 대상자의 수면을 존중한 행동이다.", "4": "\"지금 목욕 안하면 다음 주까지 기다려야 해요. 그러니까 지금 얼른 하세요.\" - 대상자의 선택을 강요하는 발언이다.", "5": "\"안 묶으면 콧줄을 잡아 뽑으시니 억제대로 묶어 놓을 수밖에 없어요.\" - 대상자의 인권을 침해하는 행동이다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Đối tượng", "def_ko": "환자 또는 수혜자", "def_vi": "Bệnh nhân hoặc người thụ hưởng"}, {"term_ko": "요양보호", "term_vi": "Chăm sóc", "def_ko": "노인을 돌보는 일", "def_vi": "Công việc chăm sóc người cao tuổi"}, {"term_ko": "원칙", "term_vi": "Nguyên tắc", "def_ko": "기본 규칙, 가이드라인", "def_vi": "Quy tắc cơ bản, hướng dẫn"}, {"term_ko": "자율성", "term_vi": "Tự chủ", "def_ko": "스스로 결정할 수 있는 능력", "def_vi": "Khả năng tự quyết định"}, {"term_ko": "선택", "term_vi": "Lựa chọn", "def_ko": "고르거나 결정하는 것", "def_vi": "Việc chọn hoặc quyết định"}, {"term_ko": "인권", "term_vi": "Quyền lợi", "def_ko": "인간의 기본 권리", "def_vi": "Quyền cơ bản của con người"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (266, '1', '대상자와 의사소통할 때 편안하게 대면하는 방법으로 옳은 것은?', '["대상자와 눈을 맞추고 나서 말을 건넨다.", "손가락으로 대상자의 손목을 잡음녀서 말한다.", "잠에서 덜 깬 대상자에게는 옆으로 조용히 다가간다.", "대상자가 벽 쪽으로 돌아누워 있으면 등 뒤에서 말한다.", "반응이 없는 대상자는 말을 건네지 않고 하던 일을 계속한다."]'::jsonb, 1, NULL, NULL, '{"1": "대상자와 눈을 맞추고 나서 말을 건넨다. 이는 상대방에게 존중을 표시하고 편안한 대화를 유도하는 방법입니다.\n[정답]", "2": "손가락으로 대상자의 손목을 잡으면서 말한다. 이는 불편함을 초래할 수 있는 행동입니다.", "3": "잠에서 덜 깬 대상자에게는 옆으로 조용히 다가간다. 이는 적절하나 직접적인 대면이 부족할 수 있습니다.", "4": "대상자가 벽 쪽으로 돌아누워 있으면 등 뒤에서 말한다. 이는 상대방이 불안감을 느낄 수 있습니다.", "5": "반응이 없는 대상자는 말을 건네지 않고 하던 일을 계속한다. 이는 대상자와의 의사소통을 소홀히 하는 행동입니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người bệnh", "def_ko": "환자", "def_vi": "Bệnh nhân"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (265, '2', '생활이 어려운 사람에게 필요한 급여를 제공하여 최저생활을 보장하고 자활을 돕는 것을 목적으로 하는 공적부조제도로 옳은 것은?', '["국민연금제도", "고용보험제도", "국민건강보험제도", "국민기초생활보장제도", "산업재해보상보험제도"]'::jsonb, 4, NULL, NULL, '{"1": "국민연금제도는 노후 소득 보장을 위한 제도입니다.\n[정답]", "4": "국민기초생활보장제도는 생활이 어려운 사람에게 급여를 제공하여 최저생활을 보장하고 자활을 돕는 제도입니다.", "2": "고용보험제도는 실직 시 소득을 보장하는 제도입니다.", "3": "국민건강보험제도는 건강 관리를 위한 보험입니다.", "5": "산업재해보상보험제도는 산업재해로 인한 피해를 보상하는 제도입니다."}'::jsonb, '[{"term_ko": "공적부조제도", "term_vi": "Chế độ hỗ trợ công cộng", "def_ko": "공적 재정으로 지원을 받는 제도", "def_vi": "Chế độ nhận hỗ trợ từ ngân sách công"}, {"term_ko": "급여", "term_vi": "Trợ cấp", "def_ko": "급여(보조금)", "def_vi": "Trợ cấp(tiền hỗ trợ)"}, {"term_ko": "자활", "term_vi": "Tự lập", "def_ko": "스스로 생활을 할 수 있는 상태", "def_vi": "Trạng thái có thể tự sống"}, {"term_ko": "최저생활", "term_vi": "Cuộc sống tối thiểu", "def_ko": "최하층에서의 생활", "def_vi": "Cuộc sống ở mức thấp nhất"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (264, '2', '국민의 질병 및 건강 증진에 대하여 보험급여를 제공함으로써 국민 보건 향상과 사회보장 증진에 기여하는 제도로 옳은 것은?', '["국민연금보험제도", "긴급복지지원제도", "국민건강보험제도", "산업재해보상보험제도", "국민기초생활보장제도"]'::jsonb, 3, NULL, NULL, '{"1": "국민연금보험제도는 노후 생활 안정과 관련된 제도입니다.\n[정답]", "3": "국민건강보험제도는 국민의 질병 및 건강 증진을 위한 보험 제도입니다.", "2": "긴급복지지원제도는 긴급한 생계 지원을 위한 제도입니다.", "4": "산업재해보상보험제도는 산업재해로 인한 피해 보상을 위한 제도입니다.", "5": "국민기초생활보장제도는 기초생활 유지 지원을 위한 제도입니다."}'::jsonb, '[{"term_ko": "국민", "term_vi": "Công dân", "def_ko": "국민(한국어)", "def_vi": "Công dân"}, {"term_ko": "질병", "term_vi": "Bệnh tật", "def_ko": "질병(한국어)", "def_vi": "Bệnh tật"}, {"term_ko": "건강", "term_vi": "Sức khỏe", "def_ko": "건강(한국어)", "def_vi": "Sức khỏe"}, {"term_ko": "증진", "term_vi": "Nâng cao", "def_ko": "증진(한국어)", "def_vi": "Nâng cao"}, {"term_ko": "보험", "term_vi": "Bảo hiểm", "def_ko": "보험(한국어)", "def_vi": "Bảo hiểm"}, {"term_ko": "제도", "term_vi": "Chế độ", "def_ko": "제도(한국어)", "def_vi": "Chế độ"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (263, '2', '요양보호사가 실직했을 때 생활에 필요한 급여를 제공하는 사회보험으로 옳은 것은?', '["고용보험", "국민건강보험", "국민연금보험", "산업재해보상보험", "노인장기요양보험"]'::jsonb, 1, NULL, NULL, '{"1": "고용보험은 실직한 근로자에게 생활비를 지원하는 제도입니다.\n[정답]", "2": "국민건강보험은 건강을 유지하기 위한 보험으로, 실직과 관련이 없습니다.", "3": "국민연금보험은 노후를 대비한 제도입니다.", "4": "산업재해보상보험은 업무상 재해에 대한 보상을 제공합니다.", "5": "노인장기요양보험은 노인을 위한 장기 요양 서비스에 대한 보험입니다."}'::jsonb, '[{"term_ko": "요양보호사", "term_vi": "Nhân viên chăm sóc", "def_ko": "돌봄 및 지원을 제공하는 전문인력", "def_vi": "Người cung cấp sự hỗ trợ và chăm sóc"}, {"term_ko": "실직", "term_vi": "Thất nghiệp", "def_ko": "일자리를 잃다", "def_vi": "Mất việc"}, {"term_ko": "급여", "term_vi": "Trợ cấp", "def_ko": "보상금, 재정지원", "def_vi": "Tiền hỗ trợ"}, {"term_ko": "사회보험", "term_vi": "Bảo hiểm xã hội", "def_ko": "건강, 노후 등을 위해 정부가 제공하는 보험", "def_vi": "Bảo hiểm do chính phủ cung cấp cho sức khỏe và hưu trí"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (262, '2', '노인을 위한 유엔의 5원칙 중 ''독립의 원칙''의 원칙으로 옳은 것은?', '["가능한 오랫동안 가정에서 살 수 있어야 한다.", "노인들을 위한 사회운동을 하고 단체를 조직할 수 있어야 한다.", "자율과 보호를 높이는 사회적, 법률적인 서비스를 이용할 수 있어야 한다.", "노인의 잠재력을 계발할 수 있는 기회가 있어야 한다.", "존업과 안전 속에서 살 수 있어야 한다."]'::jsonb, 1, NULL, NULL, '{"1": "가능한 오랫동안 가정에서 살 수 있어야 한다.\n[정답]", "2": "노인들을 위한 사회운동을 하고 단체를 조직할 수 있어야 한다.", "3": "자율과 보호를 높이는 사회적, 법률적인 서비스를 이용할 수 있어야 한다.", "4": "노인의 잠재력을 계발할 수 있는 기회가 있어야 한다.", "5": "존엄과 안전 속에서 살 수 있어야 한다."}'::jsonb, '[{"term_ko": "원칙", "term_vi": "Nguyên tắc", "def_ko": "원칙(한국어)", "def_vi": "nguyên tắc(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (261, '2', '다음 사례에서 노인이 실천한 노인복지 원칙으로 옳은 것은?• 교사로 은퇴한 노인이 지역아동센터 아동을 대상으로 한 교육봉사 단체를 조직하여 활동하고 있다.', '["독립의 원칙", "참여의 원칙", "보호의 원칙", "자아실현의 원칙", "존엄의 원칙"]'::jsonb, 2, NULL, NULL, '{"1": "독립의 원칙: 노인이 자립하여 생활할 수 있도록 지원하는 원칙입니다.\n[정답]", "2": "참여의 원칙: 노인이 사회와 지역사회에 적극적으로 참여하고 활동할 수 있도록 장려하는 원칙입니다.", "3": "보호의 원칙: 노인의 안전과 권리를 보호하는 원칙입니다.", "4": "자아실현의 원칙: 노인이 자신의 잠재력과 능력을 발휘하여 자아를 실현할 수 있도록 지원하는 원칙입니다.", "5": "존엄의 원칙: 노인이 존중받고 권리를 인정받으며 존엄성을 유지하는 원칙입니다."}'::jsonb, '[{"term_ko": "노인", "term_vi": "Người cao tuổi", "def_ko": "노인(한국어)", "def_vi": "Người lớn tuổi"}, {"term_ko": "복지", "term_vi": "Phúc lợi", "def_ko": "복지(한국어)", "def_vi": "Phúc lợi"}, {"term_ko": "원칙", "term_vi": "Nguyên tắc", "def_ko": "원칙(한국어)", "def_vi": "Nguyên tắc"}, {"term_ko": "참여", "term_vi": "Tham gia", "def_ko": "참여(한국어)", "def_vi": "Tham gia"}, {"term_ko": "자립", "term_vi": "Tự lập", "def_ko": "자립(한국어)", "def_vi": "Tự lập"}, {"term_ko": "자아실현", "term_vi": "Tự thể hiện", "def_ko": "자아실현(한국어)", "def_vi": "Tự thực hiện"}, {"term_ko": "존엄", "term_vi": "Nhân phẩm", "def_ko": "존엄(한국어)", "def_vi": "Nhân phẩm"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (260, '2', '다음에서 설명하는 노인복지 원칙으로 옳은 것은?• 노인의 자율과 보호를 높이는 사회적, 법률적인 서비스를 이용할 수 있어야 한다.', '["독립의 원칙", "평등의 원칙", "보호의 원칙", "참여의 원칙", "존엄의 원칙"]'::jsonb, 3, NULL, NULL, '{"1": "독립의 원칙: 노인은 독립적으로 생활할 수 있어야 하며, 이를 위해 지원을 받아야 합니다.\n[정답]", "3": "보호의 원칙: 노인의 자율과 보호를 동시에 고려하는 원칙으로, 안전과 권리를 보호받아야 합니다.", "2": "평등의 원칙: 모든 노인이 평등하게 대우받아야 한다는 원칙입니다.", "4": "참여의 원칙: 노인이 사회생활에 참여할 수 있도록 보장해야 하는 원칙입니다.", "5": "존엄의 원칙: 노인의 존엄성을 존중해야 한다는 원칙입니다."}'::jsonb, '[{"term_ko": "노인", "term_vi": "Người cao tuổi", "def_ko": "고령자(한국어)", "def_vi": "Người già(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (259, '2', '다음에서 설명하는 노인복지 원칙으로 옳은 것은?• 노인의 잠재력을 계발할 수 있는 기회가 있어야 한다.• 사회의 교육적, 문화적, 정신적 자원과 여가서비스를 이용할 수 있어야 한다.', '["독립의 원칙", "평등의 원칙", "보호의 원칙", "존엄의 원칙", "자아실현의 원칙"]'::jsonb, 5, NULL, NULL, '{"1": "독립의 원칙: 노인이 스스로 결정하고 행동할 수 있는 것을 중요시하는 원칙입니다.", "2": "평등의 원칙: 모든 노인이 동등한 기회를 가져야 한다는 원칙입니다.", "3": "보호의 원칙: 노인을 외부로부터 보호해야 한다는 관점입니다.", "4": "존엄의 원칙: 노인의 존엄성을 존중하는 것을 강조합니다.\n[정답]", "5": "자아실현의 원칙: 노인이 자신의 잠재력을 개발하고 자아를 실현할 수 있는 기회를 제공해야 한다는 원칙입니다."}'::jsonb, '[{"term_ko": "노인", "term_vi": "Người cao tuổi", "def_ko": "노년기에 있는 사람", "def_vi": "Người trong độ tuổi cao niên"}, {"term_ko": "복지", "term_vi": "Phúc lợi", "def_ko": "사회적 서비스 제공", "def_vi": "Cung cấp dịch vụ xã hội"}, {"term_ko": "원칙", "term_vi": "Nguyên tắc", "def_ko": "기본적인 이념", "def_vi": "Truyền thống cơ bản"}, {"term_ko": "잠재력", "term_vi": "Tiềm năng", "def_ko": "겉으로 드러나지 않은 능력", "def_vi": "Năng lực chưa được thể hiện"}, {"term_ko": "자아실현", "term_vi": "Tự thực hiện", "def_ko": "자신의 가능성을 최대한 발휘함", "def_vi": "Phát huy tối đa khả năng của bản thân"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (258, '2', '치매 환자 및 가족들이 안심하고 살아가도록 전담 코디네이터를 1:1로 매칭하여 서비스를 연계하고 관리를 수행하는 기관으로 옳은 것은?', '["노인돌봄종합서비스", "노인보호 전문기관", "노인건강진단", "노인복지관", "치매안심센터"]'::jsonb, 5, NULL, NULL, '{"1": "노인돌봄종합서비스는 다양한 서비스를 제공하지만 1:1 매칭 서비스를 직접적으로 제공하지 않음.\n[정답]", "5": "치매안심센터는 치매 환자와 가족들을 위한 1:1 매칭 서비스를 제공하는 전문 기관임.", "3": "노인건강진단은 건강 검진을 목적으로 하는 것이므로 관련성이 없음.", "4": "노인복지관은 다양한 복지 서비스를 제공하지만 치매 전담 코디네이터와의 1:1 매칭과는 거리가 있음.", "2": "노인보호 전문기관은 노인 보호를 위한 기관으로, 치매 환자에 특화된 서비스는 아님."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억과 사고 능력의 감퇴를 유발하는 질환", "def_vi": "Bệnh gây giảm khả năng ghi nhớ và tư duy"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (257, '2', '노인의 인권보호 사업, 학대예방사업, 노인인식 개선, 노인자살 예방 교육 및 시설 내 노인권리보호, 피해노인에 대한 상담 및 보호를 담당하는 기관으로 옳은 것은?', '["보건소", "학대피해노인 전용쉼터", "노인보호 전문기관", "노인종합복지센터", "정신건강복지센터"]'::jsonb, 3, NULL, NULL, '{"1": "보건소는 일반 건강 관리를 담당하는 기관으로, 노인 전용 인권 보호와는 거리가 있습니다.\n[정답]", "3": "노인보호 전문기관은 노인의 인권 보호, 학대 예방, 상담 및 보호를 전문으로 하는 기관입니다.", "2": "학대피해노인 전용쉼터는 피해 노인의 일시적인 안전을 위한 공간일 뿐, 종합적인 권리 보호를 책임지는 기관은 아닙니다.", "4": "노인종합복지센터는 다양한 복지 서비스를 제공하지만, 법적 권리 보호에 전문적이지 않습니다.", "5": "정신건강복지센터는 정신 건강 문제를 다루는 기관으로, 노인의 권리 보호 전담 기관은 아닙니다."}'::jsonb, '[{"term_ko": "인권", "term_vi": "Quyền con người", "def_ko": "권리를 보호받는 것(한국어)", "def_vi": "nhận được sự bảo vệ quyền lợi"}, {"term_ko": "학대", "term_vi": "Lạm dụng", "def_ko": "부당한 대우(한국어)", "def_vi": "đối xử không công bằng"}, {"term_ko": "상담", "term_vi": "Tư vấn", "def_ko": "조언과 도움을 주는 것(한국어)", "def_vi": "cung cấp lời khuyên và sự giúp đỡ"}, {"term_ko": "전문기관", "term_vi": "Cơ quan chuyên môn", "def_ko": "특정 분야에 특화된 기관(한국어)", "def_vi": "cơ quan chuyên về một lĩnh vực cụ thể"}, {"term_ko": "예방", "term_vi": "Ngăn ngừa", "def_ko": "미리 막는 것(한국어)", "def_vi": "ngăn chặn trước"}, {"term_ko": "노인", "term_vi": "Người cao tuổi", "def_ko": "나이가 많은 사람(한국어)", "def_vi": "người lớn tuổi"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (256, '2', '학대피해노인 보호와 숙식 제공 등의 쉼터 생활지원, 의료비 등을 지원해주는 사업으로 옳은 것은?', '["학대피해노인 전용쉼터", "정신요양시설", "정신건강 복지센터", "주간보호센터", "노인학대 신고센터"]'::jsonb, 1, NULL, NULL, '{"1": "학대 피해 노인을 보호하고 숙식 및 의료비를 제공하는 전용 쉼터입니다.\n[정답]", "2": "정신질환자를 위한 시설로, 노인학대와는 관련이 없습니다.", "3": "정신건강 관련 시설로, 학대피해 노인 지원과는 거리가 있습니다.", "4": "주간에 노인을 보호하고 돌보는 시설로, 학대 피해 노인을 위한 전용 쉼터는 아닙니다.", "5": "노인학대를 신고하는 곳으로 직접적인 보호 서비스는 제공하지 않습니다."}'::jsonb, '[{"term_ko": "학대", "term_vi": "Lạm dụng", "def_ko": "폭력이나 고통을 주는 행위", "def_vi": "Hành động gây thương tích hoặc đau đớn"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (255, '2', '노인장기요양보험제도의 목적으로 옳은 것은?', '["직업능력개발을 통한 고용 촉진", "최저생활 보장을 통한 자활의욕 고취", "안정적 노후를 위한 소득보장체계 마련", "업무상 재해 보상을 통한 사회복귀 지원", "일상생활을 혼자 수행하기 어려운 노인의 신체활동 또는 가사활동 지원"]'::jsonb, 5, NULL, NULL, '{"1": "직업능력개발을 통한 고용 촉진은 해당 제도의 목적에 포함되지 않습니다.", "2": "최저생활 보장을 통한 자활의욕 고취는 주로 사회복지 정책의 목표입니다.\n[정답]", "3": "안정적 노후를 위한 소득보장체계 마련은 노인장기요양보험의 주요 목적은 아니지만 연결될 수 있습니다.", "4": "업무상 재해 보상을 통한 사회복귀 지원은 근로자의 안전과 관련된 제도입니다.", "5": "일상생활을 혼자 수행하기 어려운 노인의 신체활동 또는 가사활동 지원은 노인장기요양보험의 핵심 목적입니다."}'::jsonb, '[{"term_ko": "노인장기요양보험제도", "term_vi": "Hệ thống bảo hiểm chăm sóc dài hạn cho người cao tuổi", "def_ko": "뜻(한국어)", "def_vi": "뜻(베트남어)"}, {"term_ko": "신체활동", "term_vi": "Hoạt động thể chất", "def_ko": "뜻(한국어)", "def_vi": "뜻(베트남어)"}, {"term_ko": "가사활동", "term_vi": "Hoạt động sinh hoạt", "def_ko": "뜻(한국어)", "def_vi": "뜻(베트남어)"}, {"term_ko": "자활의욕", "term_vi": "Mong muốn tự lập", "def_ko": "뜻(한국어)", "def_vi": "뜻(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (254, '2', '노인장기요양보험제도에 관한 설명으로 옳은 것은?', '["고용노동부장관이 관장한다.", "보험자는 국민건강보험공단이다.", "단기보호는 시설급여에 해당한다.", "장기요양등급은 1등급에서 10등급까지이다.", "대상자 가족의 일상생활 지원을 목적으로 한다."]'::jsonb, 2, NULL, NULL, '{"1": "고용노동부가 아니라 보건복지부가 관장합니다.\n[정답]", "2": "보험자는 국민건강보험공단으로 맞습니다.", "3": "단기보호는 시설급여가 아닌 재가급여입니다.", "4": "장기요양등급은 1등급에서 5등급까지 있습니다.", "5": "대상자 가족의 지원은 목적 중 하나지만 주된 목적은 대상자의 일상생활 지원입니다."}'::jsonb, '[{"term_ko": "노인장기요양보험제도", "term_vi": "Chế độ bảo hiểm chăm sóc dài hạn cho người cao tuổi", "def_ko": "노인들을 위한 장기 요양 보험 제도", "def_vi": "Chế độ bảo hiểm cho người cao tuổi"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (253, '2', '노인장기요양서비스 전달체계에서 국민건강보험공단의 역할로 옳은 것은?', '["요양서비스 제공", "장기요양 등급판정", "서비스신청 및 계약", "서비스비용 청구", "장기요양기관의 설립인가"]'::jsonb, 2, NULL, NULL, NULL, '[{"term_ko": "노인장기요양서비스", "term_vi": "Dịch vụ chăm sóc dài hạn cho người cao tuổi", "def_ko": "노인을 위한 장기적인 요양 서비스", "def_vi": "Dịch vụ chăm sóc lâu dài cho người cao tuổi"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (252, '2', '다음 중 노인장기요양급여의 대상자로 옳은 것은?', '["뇌경색으로 병원에 입원한 65세 남성", "결핵으로 일상생활이 어려운 50세 여성", "혈관성 치매로 일상생활이 어려운 70세 남성", "고혈압이 있고 일상생활이 가능한 65세 여성", "뇌졸증에서 회복되어 일상생활이 가능한 70세 남성"]'::jsonb, 3, NULL, NULL, '{"1": "뇌경색으로 입원했으나, 노인장기요양급여 대상자가 되기 어렵습니다.\n[정답]", "3": "혈관성 치매로 인해 일상생활이 어려워져 노인장기요양급여의 대상자가 됩니다.", "2": "결핵으로 일상생활이 어려운 경우는 노인장기요양급여의 대상이 아닙니다.", "4": "고혈압 상태지만 일상생활이 가능한 경우는 대상자가 아닙니다.", "5": "뇌졸증에서 회복하여 일상생활을 할 수 있는 경우에는 요양 급여의 대상자가 아닙니다."}'::jsonb, '[{"term_ko": "노인장기요양급여", "term_vi": "Chăm sóc sức khỏe dài hạn cho người cao tuổi", "def_ko": "노인을 위한 장기요양 서비스", "def_vi": "Dịch vụ chăm sóc dài hạn cho người già"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (251, '2', '노인장기요양인정 절차에 관한 설명으로 옳은 것은?', '["지방자치단체에 장기요양인정을 신청한다.", "신청자가 동의하면 사회복지전담공무원이 대신 신청할 수 있다.", "장기요양인정 방문조사는 등급판정위원회에서 실시한다.", "국민건강보험공단의 방문조사원이 장기요양등급을 2차로 판정한다.", "보건복지부는 1차 장기요양등급 판정 결과를 심의하여 최종 판정한다."]'::jsonb, 2, NULL, NULL, '{"1": "지방자치단체에 장기요양인정을 신청하는 것이 맞지만, 이 보기는 지방자치단체를 직접 신청하는 과정이 아닌 ''대신'' 신청하는 부분에 초점을 맞추고 있다.\n[정답]", "2": "신청자가 동의하면 사회복지전담공무원이 대신 신청할 수 있다. 이는 관련 절차에서 정확한 설명이다.", "3": "장기요양인정 방문조사는 국민건강보험공단의 방문조사원이 진행한다.", "4": "2차 판단도 국민건강보험공단에서 실시하는 것으로, 등급판정위원회와는 다르다.", "5": "보건복지부는 장기요양등급 판정 결과를 심의하지만, 최종 판정은 국민건강보험공단에서 이루어진다."}'::jsonb, '[{"term_ko": "노인장기요양인정", "term_vi": "Công nhận chăm sóc dài hạn cho người cao tuổi", "def_ko": "고령자를 위한 장기적인 요양 서비스 인정", "def_vi": "Nhận dạng dịch vụ chăm sóc dài hạn cho người cao tuổi"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (250, '2', '노인장기 요양보험 등급 인정에 관한 설명으로 옳은 것은?', '["장기요양인정은 지방자치단체에 신청한다.", "장기요양인정 점수에 따라 9등급으로 나뉜다.", "보건복지부는 1차 장기요양등급판정을 심의하여 최종 판정한다.", "노인성 질병 대상자는 의사소견서 없이 장기요양 등급을 판정받는다.", "국민건강보험공단은 장기요양인정표에 따라 작성된 조사결과서를 등급판정위원회에 제출한다."]'::jsonb, 5, NULL, NULL, '{"1": "장기요양인정은 지방자치단체에 신청한다. (내용이 일부 정확하나, 실제로는 국민건강보험공단을 통한 신청이 바람직함)\n[정답]", "5": "국민건강보험공단은 장기요양인정표에 따라 작성된 조사결과서를 등급판정위원회에 제출한다. (정확한 설명)", "2": "장기요양인정 점수에 따라 9등급으로 나뉜다. (정확한 내용이지만, 현재는 5개 등급으로 나눠짐)", "3": "보건복지부는 1차 장기요양등급판정을 심의하여 최종 판정한다. (정확하지 않음. 최종 판정은 중앙장기요양위원회가 담당)", "4": "노인성 질병 대상자는 의사소견서 없이 장기요양 등급을 판정받는다. (정확하지 않음. 의사소견서 필요)"}'::jsonb, '[{"term_ko": "노인장기 요양보험", "term_vi": "Bảo hiểm chăm sóc dài hạn cho người cao tuổi", "def_ko": "노인의 요양 서비스를 제공하기 위한 보험 제도", "def_vi": "Hệ thống bảo hiểm cung cấp dịch vụ chăm sóc cho người cao tuổi"}, {"term_ko": "등급", "term_vi": "Cấp độ", "def_ko": "수준", "def_vi": "Mức độ"}, {"term_ko": "장기요양인정", "term_vi": "Công nhận chăm sóc dài hạn", "def_ko": "장기요양 서비스의 필요성을 공식적으로 인정받는 절차", "def_vi": "Quy trình công nhận sự cần thiết của dịch vụ chăm sóc dài hạn"}, {"term_ko": "조사결과서", "term_vi": "Bảng kết quả khảo sát", "def_ko": "조사 후 작성되는 결과 문서", "def_vi": "Tài liệu kết quả được biên soạn sau khi khảo sát"}, {"term_ko": "의사소견서", "term_vi": "Giấy xác nhận của bác sĩ", "def_ko": "의사가 작성한 환자의 건강 상태에 대한 의견서", "def_vi": "Tài liệu ý kiến về tình trạng sức khỏe của bệnh nhân do bác sĩ viết"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (249, '2', '장기요양인정 신청 및 판정 절차에 관한 설명으로 옳은 것은?', '["장기요양인정 신청서는 국민건강보험공단에 제출한다.", "대리인이 신청할 경우 시설장의 동의가 필요하다.", "교육을 이수한 장기요양기관의 직원이 방문조사를 한다.", "지방자치단체장이 장기요양인정 등급을 최종 판정한다.", "요양보호사가 대상자에게 장기요양인정서를 제공한다."]'::jsonb, 1, NULL, NULL, '{"1": "장기요양인정 신청서는 국민건강보험공단에 제출해야 한다. 이는 정확한 정보이다.\n[정답]", "2": "대리인이 신청할 경우, 시설장의 동의가 필요한 것은 아니다. 대리 신청이 가능하지만 동의는 필요하지 않다.", "3": "교육을 이수한 장기요양기관의 직원이 방문조사를 할 수 있으나, 반드시 그러해야하는 것은 아니다.", "4": "지방자치단체장이 장기요양인정 등급을 판정하는 것이 아니라, 국민건강보험공단이 최종 판정한다.", "5": "요양보호사는 장기요양인정서를 제공하지 않으며, 이는 주로 해당 기관이 담당한다."}'::jsonb, '[{"term_ko": "장기요양인정", "term_vi": "Công nhận chăm sóc dài hạn", "def_ko": "장기 요양이 필요한 사람들에 대한 공식적인 인정", "def_vi": "Công nhận chính thức cho những người cần chăm sóc dài hạn"}, {"term_ko": "국민건강보험공단", "term_vi": "Quỹ Bảo hiểm Y tế Quốc dân", "def_ko": "국민의 건강보험을 관리하는 기관", "def_vi": "Cơ quan quản lý bảo hiểm y tế của công dân"}, {"term_ko": "대리인", "term_vi": "Người đại diện", "def_ko": "대신하여 행동하는 사람", "def_vi": "Người hành động thay cho người khác"}, {"term_ko": "지방자치단체장", "term_vi": "Người đứng đầu chính quyền địa phương", "def_ko": "지역 정부의 책임자", "def_vi": "Người đứng đầu chính quyền tại địa phương"}, {"term_ko": "요양보호사", "term_vi": "Người chăm sóc", "def_ko": "요양을 돌보는 전문가", "def_vi": "Chuyên gia chăm sóc"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (248, '2', '다음에서 설명하는 장기요양급여로 옳은 것은?• 하루 중 일정 시간 동안 대상자를 보호하면서 신체활동을 지원하고 심신기능 향상을 위한 교육 · 훈련을 제공함', '["방문요양", "방문목욕", "방문간호", "주 · 야간 보호", "노인요양시설"]'::jsonb, 4, NULL, NULL, '{"1": "방문요양: 개인의 가정에서 필요한 신체적 도움을 제공하는 서비스이다.", "2": "방문목욕: 가정에서의 목욕 지원 서비스를 뜻한다.", "3": "방문간호: 간호사가 가정에서 환자에게 필요한 간호를 제공하는 서비스이다.\n[정답]", "4": "주 · 야간 보호: 장기요양급여 중 하루 중 일정 시간 동안 대상자를 보호하며, 신체 활동 지원과 교육 훈련을 포함함.", "5": "노인요양시설: 노인을 위한 시설로 24시간 돌봄 서비스를 제공하는 곳이다."}'::jsonb, '[{"term_ko": "장기요양급여", "term_vi": "Trợ cấp chăm sóc dài hạn", "def_ko": "장기간 동안 제공되는 요양 서비스(한국어)", "def_vi": "Dịch vụ chăm sóc được cung cấp trong thời gian dài(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (247, '2', '수급자를 일정한 기간 동안 장기요양기관에 보호하여 신체활동지원 등을 제공하는 장기요양급여로 옳은 것은?', '["단기보호 서비스", "주 · 야간보호 서비스", "방문목욕 서비스", "방문간호 서비스", "방문요양 서비스"]'::jsonb, 1, NULL, NULL, '{"1": "단기보호 서비스는 정기적으로 일정 기간 동안 제공되는 요양 서비스입니다.\n[정답]", "2": "주 · 야간보호 서비스는 낮과 밤에 각각 보호를 제공하는 서비스로, 장기 요양 기관에서 제공될 수 있습니다.", "3": "방문목욕 서비스는 가정에서 목욕을 지원하는 서비스입니다.", "4": "방문간호 서비스는 정기적인 간호 지원을 제공하는 서비스입니다.", "5": "방문요양 서비스는 가정에서 요양 보호 서비스를 제공하는 형태입니다."}'::jsonb, '[{"term_ko": "수급자", "term_vi": "Người thụ hưởng", "def_ko": "수혜자(한국어)", "def_vi": "Người nhận dịch vụ chăm sóc"}, {"term_ko": "장기요양기관", "term_vi": "Cơ sở chăm sóc dài hạn", "def_ko": "장기요양 서비스 제공소(한국어)", "def_vi": "Nơi cung cấp dịch vụ chăm sóc dài hạn"}, {"term_ko": "신체활동", "term_vi": "Hoạt động thể chất", "def_ko": "신체의 동작 및 행동(한국어)", "def_vi": "Hành động và cử động của cơ thể"}, {"term_ko": "서비스", "term_vi": "Dịch vụ", "def_ko": "서비스(한국어)", "def_vi": "Dịch vụ"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (246, '2', '재가대상자의 일상생활에 필요한 복지용구를 제공하는 급여로 옳은 것은?', '["기타재가급여", "주간보호급여", "방문요양급여", "방문목욕급여", "단기보호급여"]'::jsonb, 1, NULL, NULL, '{"1": "기타재가급여는 일상생활에 필요한 복지용구를 포함하여 다양한 급여를 지원하는 항목입니다.\n[정답]", "2": "주간보호급여는 낮 시간 동안의 보호와 서비스를 제공하는 급여입니다.", "3": "방문요양급여는 요양보호사가 가정에 방문하여 필요한 요양 서비스를 제공하는 급여입니다.", "4": "방문목욕급여는 요양보호사가 가정에서 목욕 서비스를 제공하는 급여입니다.", "5": "단기보호급여는 일시적으로 시설에서 보호를 받는 급여입니다."}'::jsonb, '[{"term_ko": "재가대상자", "term_vi": "Người được chăm sóc tại nhà", "def_ko": "가정에서 요양이 필요한 대상자", "def_vi": "Người cần được chăm sóc tại nhà"}, {"term_ko": "복지용구", "term_vi": "Thiết bị hỗ trợ", "def_ko": "일상생활에 필요한 보조 도구", "def_vi": "Công cụ hỗ trợ cần thiết cho cuộc sống hàng ngày"}, {"term_ko": "급여", "term_vi": "Trợ cấp", "def_ko": "지원되는 서비스", "def_vi": "Dịch vụ được hỗ trợ"}, {"term_ko": "주간보호", "term_vi": "Dịch vụ bảo trợ vào ban ngày", "def_ko": "낮 시간 동안 보호하는 서비스", "def_vi": "Dịch vụ bảo vệ trong thời gian ban ngày"}, {"term_ko": "방문요양", "term_vi": "Chăm sóc tại nhà", "def_ko": "가정에서의 요양 서비스", "def_vi": "Dịch vụ chăm sóc tại nhà"}, {"term_ko": "방문목욕", "term_vi": "Tắm tại nhà", "def_ko": "가정에서의 목욕 서비스", "def_vi": "Dịch vụ tắm tại nhà"}, {"term_ko": "단기보호", "term_vi": "Bảo vệ ngắn hạn", "def_ko": "일시적인 보호 서비스", "def_vi": "Dịch vụ bảo vệ tạm thời"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (245, '2', '장기요양급여 중 재가급여의 장점으로 옳은 것은?', '["가족이 선호하는 서비스가 제공된다.", "응급상황에서 신속하게 대응할 수 있다.", "평소 친숙한 환경에서 서비스가 제공된다.", "종합적인 재활치료 서비스가 제공될 수 있다.", "건강검진을 통해 질병을 조기에 발견할 수 있다."]'::jsonb, 3, NULL, NULL, '{"1": "가족이 선호하는 서비스가 제공되지만, 특정 가족의 선호는 상황에 따라 다를 수 있습니다.\n[정답]", "3": "평소 친숙한 환경에서 서비스가 제공되어 환자가 안정감을 느낄 수 있습니다.", "2": "응급상황에서 신속한 대응은 재가급여의 장점이 아닙니다.", "4": "종합적인 재활치료 서비스는 주로 요양시설에서 제공되며, 재가급여는 한정적입니다.", "5": "건강검진은 별도의 프로그램에 의해 이루어지며 재가급여와는 직결되지 않습니다."}'::jsonb, '[{"term_ko": "장기요양급여", "term_vi": "Chăm sóc dài hạn", "def_ko": "장기 요양이 필요한 환자를 위해 제공되는 급여", "def_vi": "Các phúc lợi được cung cấp cho bệnh nhân cần chăm sóc dài hạn."}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (244, '2', '장기요양급여 중 시설급여에 해당하는 것으로 옳은 것은?', '["단기보호", "복지용구", "가족요양비", "주 · 야간 보호", "노인요양공동생활가정"]'::jsonb, 5, NULL, NULL, '{"1": "단기보호는 시설급여에 포함되지 않는다.\n[정답]", "5": "노인요양공동생활가정은 시설급여에 해당한다.", "2": "복지용구는 장비를 제공하는 서비스로 시설급여가 아니다.", "3": "가족요양비는 가족이 요양을 제공하는 경우에 대한 지원으로 시설급여가 아니다.", "4": "주 · 야간 보호는 시설급여보다는 서비스의 일종이다."}'::jsonb, '[{"term_ko": "장기요양급여", "term_vi": "Trợ cấp chăm sóc dài hạn", "def_ko": "장기적인 요양을 제공하는 지원금", "def_vi": "Tiền hỗ trợ chăm sóc lâu dài"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (243, '2', '장기요양급여 시설급여의 장점으로 옳은 것은?', '["사생활이 보장된다.", "친숙한 환경에서 지낼 수 있다.", "개인 중심의 생활을 보장받을 수 있다.", "종합적인 서비스를 받을 수 있다.", "본인일부부담금이 재가 급여 보다 저렴하다."]'::jsonb, 4, NULL, NULL, '{"1": "사생활이 보장되지 않을 수 있습니다. 의료인력과 다른 입소자들과의 관계에서 개인의 사생활이 제한될 수 있습니다.", "2": "친숙한 환경에서 지내기 어려울 수 있으며, 병원처럼 낯선 환경일 수 있습니다.\n[정답]", "3": "개인 중심의 생활을 보장할 수 있으나, 실제로는 제약이 있을 수 있습니다.", "4": "종합적인 서비스를 받을 수 있어 다양한 필요에 맞춘 통합적인 관리가 가능합니다.", "5": "본인일부부담금은 경우에 따라 다를 수 있으며, 재가 급여보다 저렴한 경우가 많지만 항상 그렇지 않습니다."}'::jsonb, '[{"term_ko": "장기요양급여", "term_vi": "Dịch vụ chăm sóc dài hạn", "def_ko": "장기간 동안 제공되는 의료 및 요양 서비스", "def_vi": "Dịch vụ y tế và chăm sóc được cung cấp trong thời gian dài"}, {"term_ko": "주거시설", "term_vi": "Cơ sở lưu trú", "def_ko": "주거용 건물 또는 시설", "def_vi": "Tòa nhà hoặc cơ sở sinh hoạt"}, {"term_ko": "사생활", "term_vi": "Quyền riêng tư", "def_ko": "개인의 개인적인 일상이나 공간", "def_vi": "Cuộc sống cá nhân hoặc không gian cá nhân"}, {"term_ko": "복지", "term_vi": "Phúc lợi", "def_ko": "사회가 국민에게 제공하는 지원 또는 서비스", "def_vi": "Các hỗ trợ hoặc dịch vụ mà xã hội cung cấp cho công dân"}, {"term_ko": "비용", "term_vi": "Chi phí", "def_ko": "재화나 서비스에 대한 금전적 지불", "def_vi": "Sự trả tiền cho hàng hóa hoặc dịch vụ"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (242, '2', '가족요양비가 포함된 장기요양급여의 종류로 옳은 것은?', '["시설급여", "재가급여", "간병급여", "장애급여", "특별현금급여"]'::jsonb, 5, NULL, NULL, '{"1": "시설급여는 주로 시설에서 제공되는 요양 서비스를 말합니다.", "2": "재가급여는 가정에서 제공되는 요양 서비스를 포함합니다.", "3": "간병급여는 환자가 일상생활을 영위할 수 있도록 돕는 서비스입니다.", "4": "장애급여는 장애인을 위한 지원을 포함하고 있습니다.\n[정답]", "5": "특별현금급여는 가족요양비가 포함된 장기요양급여의 일종입니다."}'::jsonb, '[{"term_ko": "가족요양비", "term_vi": "Phí chăm sóc gia đình", "def_ko": "가족이 제공하는 요양에 대한 비용", "def_vi": "Chi phí cho việc chăm sóc của gia đình"}, {"term_ko": "장기요양급여", "term_vi": "Trợ cấp chăm sóc dài hạn", "def_ko": "장기간에 걸쳐 제공되는 요양 서비스", "def_vi": "Dịch vụ chăm sóc kéo dài"}, {"term_ko": "시설급여", "term_vi": "Trợ cấp cơ sở", "def_ko": "시설에서 제공되는 요양 서비스", "def_vi": "Dịch vụ chăm sóc tại cơ sở"}, {"term_ko": "재가급여", "term_vi": "Trợ cấp tại nhà", "def_ko": "가정에서 제공되는 요양 서비스", "def_vi": "Dịch vụ chăm sóc tại nhà"}, {"term_ko": "간병급여", "term_vi": "Trợ cấp chăm sóc", "def_ko": "환자의 일상생활 지원 서비스", "def_vi": "Dịch vụ hỗ trợ sinh hoạt hàng ngày của bệnh nhân"}, {"term_ko": "장애급여", "term_vi": "Trợ cấp cho người khuyết tật", "def_ko": "장애인을 위한 지원", "def_vi": "Hỗ trợ cho người khuyết tật"}, {"term_ko": "특별현금급여", "term_vi": "Trợ cấp tiền mặt đặc biệt", "def_ko": "가족요양비 포함 장기요양급여의 일종", "def_vi": "Một loại trợ cấp dài hạn bao gồm phí chăm sóc gia đình"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (241, '2', '장기요양기관의 비용 청구 및 재원에 관한 설명으로 옳은 것은?', '["국가는 보험료 예상 수입액의 20%를 부담한다.", "장기요양기관은 본인부담금을 보건복지부에 청구한다.", "장기요양보험료와 건강보험료는 통합회계로 관리한다.", "장기요양기관은 의료급여수습권자의 급여비용을 전액 부담한다.", "국민건강보험공단은 급여비용을 연 1회 장기요양기관에 지급한다."]'::jsonb, 1, NULL, NULL, '{"1": "국가는 보험료 예상 수입액의 20%를 부담한다.\n[정답]", "2": "장기요양기관은 본인부담금을 보건복지부에 청구한다.", "3": "장기요양보험료와 건강보험료는 통합회계로 관리한다.", "4": "장기요양기관은 의료급여수습권자의 급여비용을 전액 부담한다.", "5": "국민건강보험공단은 급여비용을 연 1회 장기요양기관에 지급한다."}'::jsonb, '[{"term_ko": "장기요양기관", "term_vi": "Cơ sở điều dưỡng dài hạn", "def_ko": "장기적으로 요양 서비스를 제공하는 기관", "def_vi": "Cơ sở cung cấp dịch vụ chăm sóc lâu dài"}, {"term_ko": "비용", "term_vi": "Chi phí", "def_ko": "금액을 지불해야 하는 금액", "def_vi": "Số tiền phải trả"}, {"term_ko": "청구", "term_vi": "Yêu cầu", "def_ko": "청구서 또는 요구하는 것", "def_vi": "Đòi hỏi hoặc yêu cầu"}, {"term_ko": "본인부담금", "term_vi": "Khoản tự chi trả", "def_ko": "개인이 부담해야 할 금액", "def_vi": "Số tiền tự chi trả bởi cá nhân"}, {"term_ko": "급여비용", "term_vi": "Chi phí trợ cấp", "def_ko": "급여를 위한 비용", "def_vi": "Chi phí cho các khoản trợ cấp"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (240, '2', '노인장기요양보호험 급여 중 본인 부담금에 관한 설명으로 옳은 것은?', '["비급여 항목은 본인이 60% 부담한다.", "복지용구 비용은 본인이 8% 부담한다.", "재가급여 비용은 본인이 20% 부담한다.", "국민기초생활수습권자는 본인 부담금이 없다.", "의사소견서 발급 비용은 본인이 15% 부담한다."]'::jsonb, 4, NULL, NULL, '{"1": "비급여 항목은 본인이 60% 부담하는 것이 아니라 본인이 전액 부담합니다.\n[정답]", "4": "국민기초생활수급자는 본인 부담금이 없으며, 이 점에서 올바른 설명입니다.", "2": "복지용구 비용은 본인이 8% 부담하는 것이 아니라 대부분 무료 지원을 받습니다.", "3": "재가급여 비용은 본인이 20% 부담하는 것이 맞지만, 번호 4가 정답입니다.", "5": "의사소견서 발급 비용은 본인이 15% 부담하는 것이 아니라 본인이 부담하지 않습니다."}'::jsonb, '[{"term_ko": "노인장기요양보험", "term_vi": "Bảo hiểm chăm sóc dài hạn cho người cao tuổi", "def_ko": "노인을 위한 장기요양 보호 서비스 보험", "def_vi": "Dịch vụ bảo hiểm cho người cao tuổi"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (239, '2', '장기요양서비스 이용절차 중 ☐ 안에 들어갈 내용으로 옳은 것은?『서비스 신청 접수 및 방문 상담』 → 『서비스 제공 계획 수립』 → 『서비스 이용 계약 체결』 → 『 ☐ 』 → 『모니터링 실시 / 서비스 종료 혹은 계속』', '["서비스 방법 개발", "서비스 기관 안내", "서비스 제공", "서비스 개입 계획 설정", "공식, 비공식 자원 발급"]'::jsonb, 3, NULL, NULL, '{"1": "서비스 방법 개발: 이는 초기 계획 단계이므로 올바르지 않은 선택이다.", "2": "서비스 기관 안내: 서비스 제공 이전 과정에서 필요한 정보지만, 정확한 단계에 해당하지 않다.\n[정답]", "3": "서비스 제공: 서비스 계약 체결 후 실제로 서비스를 제공하는 단계로, 맞는 선택이다.", "4": "서비스 개입 계획 설정: 서비스 개입과 관련된 단계이나, 계약 후 단계에는 해당되지 않는다.", "5": "공식, 비공식 자원 발급: 자원 할당과 관련 있지만, 해당 절차에서의 올바른 단계가 아니다."}'::jsonb, '[{"term_ko": "장기요양서비스", "term_vi": "Dịch vụ chăm sóc dài hạn", "def_ko": "길게 지속되는 요양 서비스", "def_vi": "Dịch vụ chăm sóc kéo dài"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (238, '2', '등급판정 이후 장기요양 서비스를 받고자 할 때 기관에 제출해야 하는 서류로 옳은 것은?', '["의사소견서", "급여제공계획서", "장기요양급여제공기록지", "장기요양인정서", "상태기록지"]'::jsonb, 4, NULL, NULL, '{"1": "의사소견서는 장기요양 서비스 이용 시 필요하지만, 제출해야 하는 서류는 아닙니다.\n[정답]", "4": "장기요양인정서는 장기요양 서비스를 받기 위해 반드시 제출해야 하는 서류입니다.", "2": "급여제공계획서는 서비스 제공에 필요한 문서이나, 단계적 제출이기 때문에 보통 후에 제출합니다.", "3": "장기요양급여제공기록지는 서비스 이용 후 기록하는 문서로, 초기 제출 서류가 아닙니다.", "5": "상태기록지는 환자의 상태를 기록하는 문서로, 서비스 신청 시 제출해야 하는 서류는 아닙니다."}'::jsonb, '[{"term_ko": "장기요양", "term_vi": "Dịch vụ chăm sóc dài hạn", "def_ko": "장기간에 걸쳐 제공되는 요양 서비스", "def_vi": "Dịch vụ chăm sóc kéo dài trong thời gian dài"}, {"term_ko": "서류", "term_vi": "Tài liệu", "def_ko": "문서", "def_vi": "Giấy tờ"}, {"term_ko": "제출", "term_vi": "Nộp", "def_ko": "제출하다", "def_vi": "Nộp"}, {"term_ko": "인정서", "term_vi": "Giấy chứng nhận", "def_ko": "증명이 되는 서류", "def_vi": "Tài liệu chứng nhận"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (237, '2', '등급판정을 받은 대상자에게 발급하는 장기요양 인정서에 기재되는 항목으로 옳은 것은?', '["월 한도액", "이용할 수 있는 급여의 종류와 내용", "본인부담 금액", "수급자희망급여", "서비스 목표"]'::jsonb, 2, NULL, NULL, '{"1": "월 한도액: 장기요양급여의 월 한도액은 기재되지 않음.\n[정답]", "2": "이용할 수 있는 급여의 종류와 내용: 장기요양 인정서에 명시되는 항목이며, 수급자가 받을 수 있는 급여의 종류와 내용을 구체적으로 설명함.", "3": "본인부담 금액: 장기요양 인정서에 포함되지 않음.", "4": "수급자희망급여: 수급자가 희망하는 급여는 별도로 기재되므로 포함되지 않음.", "5": "서비스 목표: 장기요양 인정서에는 명시되지 않음."}'::jsonb, '[{"term_ko": "장기요양", "term_vi": "Chăm sóc dài hạn", "def_ko": "장기적인 요양 및 돌봄 서비스", "def_vi": "Dịch vụ chăm sóc và hỗ trợ kéo dài"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (236, '2', '장기요양서비스를 이용하고자 할 때 다음의 내용의 서식 유형으로 옳은 것은?• 대상자의 등급에 따른 이용 한도액과 본인 부담률, 급여의 종류와 횟수, 비용, 인정유효기간', '["장기요양 인정서", "개인별 장기요양 이용계획서", "상태기록지", "장기요양급여제공 기록지", "급여제공 계획서"]'::jsonb, 2, NULL, NULL, '{"1": "장기요양 인정서는 서비스를 이용하기 위한 기준을 정하는 서식입니다.\n[정답]", "2": "개인별 장기요양 이용계획서는 대상자의 맞춤형 이용 계획을 기록하는 서식으로, 등급에 따른 한도액 및 본인 부담률과 급여의 종류, 횟수, 비용, 인정유효기간 등을 포함합니다.", "3": "상태기록지는 환자의 상태를 기록하는 서식입니다.", "4": "장기요양급여제공 기록지는 서비스 제공 내역을 기록하는 서식입니다.", "5": "급여제공 계획서는 서비스 제공의 전반적인 계획을 서술한 문서입니다."}'::jsonb, '[{"term_ko": "장기요양서비스", "term_vi": "Dịch vụ chăm sóc dài hạn", "def_ko": "장기적으로 필요한 요양 서비스를 제공하는 시스템", "def_vi": "Hệ thống cung cấp dịch vụ chăm sóc cần thiết trong thời gian dài"}, {"term_ko": "서식", "term_vi": "Mẫu", "def_ko": "공식적인 문서 형태", "def_vi": "Dạng tài liệu chính thức"}, {"term_ko": "이용 계획서", "term_vi": "Kế hoạch sử dụng", "def_ko": "특정 목적을 위한 계획 문서", "def_vi": "Tài liệu kế hoạch cho mục đích cụ thể"}, {"term_ko": "대상자", "term_vi": "Đối tượng", "def_ko": "서비스나 혜택을 받는 사람", "def_vi": "Người nhận dịch vụ hoặc lợi ích"}, {"term_ko": "인정유효기간", "term_vi": "Thời gian hiệu lực công nhận", "def_ko": "서비스가 승인된 유효 기간", "def_vi": "Thời gian mà dịch vụ đã được phê duyệt"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (235, '2', '요양보호 업무의 목적으로 옳은 것은?', '["평생교육프로그램 개발 및 참여", "대상자의 신체기능 증진", "가족 중심의 서비스 제공", "대상자의 시설입소 홍보", "일자리 재창출을 위한 정보제공"]'::jsonb, 2, NULL, NULL, '{"1": "평생교육프로그램 개발 및 참여는 요양보호의 직접적인 목적이 아니다.\n[정답]", "2": "대상자의 신체기능 증진은 요양보호의 핵심 목적이다.", "3": "가족 중심의 서비스 제공도 중요한 요소지만 주된 목적은 아니다.", "4": "대상자의 시설입소 홍보는 부가적인 역할일 뿐이다.", "5": "일자리 재창출을 위한 정보제공도 업무의 직접적인 목적이 아니다."}'::jsonb, '[{"term_ko": "요양보호", "term_vi": "업무", "def_ko": "돌봄, chăm sóc", "def_vi": "일, công việc"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (234, '2', '다음에 해당하는 노인장기요양보험 표준서비스 유형으로 옳은 것은?• 간식을 포함한 식사 돕기• 참대에서 휠체어로 옮겨 태우기', '["정서지원서비스", "신체활동지원서비스", "일상생활지원서비스", "개인활동지원서비스", "기능회복훈련서비스"]'::jsonb, 2, NULL, NULL, '{"1": "정서지원서비스: 정서적인 지지와 상담을 제공하는 서비스입니다.\n[정답]", "2": "신체활동지원서비스: 노인이 필요한 신체적인 활동을 도와주는 서비스로, 식사 돕기와 같은 신체적 지원이 포함됩니다.", "3": "일상생활지원서비스: 일상생활에서 필요한 기본적인 지원을 제공하는 서비스입니다.", "4": "개인활동지원서비스: 개인의 특성에 맞춰 지원하는 활동입니다.", "5": "기능회복훈련서비스: 기능 회복을 위한 훈련 프로그램을 제공하는 서비스입니다."}'::jsonb, '[{"term_ko": "노인", "term_vi": "Người cao tuổi", "def_ko": "노인(한국어)", "def_vi": "Người già"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (233, '2', '노인장기요양보험 표준서비스 중 가사 및 일상생활지원서비스에 해당되는 것으로 옳은 것은?', '["식사도움", "물품관리", "청소 및 정리정돈", "생활상담", "신체기능 유지"]'::jsonb, 3, NULL, NULL, '{"1": "식사도움: 환자의 식사를 도와주는 서비스입니다.\n[정답]", "3": "청소 및 정리정돈: 가사 및 일상생활 지원에 해당되는 서비스입니다.", "2": "물품관리: 필요한 물품을 관리하는 서비스입니다.", "4": "생활상담: 생활에 대한 상담을 제공하는 서비스입니다.", "5": "신체기능 유지: 신체 기능을 유지하는 데 도움을 주는 서비스입니다."}'::jsonb, '[{"term_ko": "노인장기요양보험", "term_vi": "Bảo hiểm chăm sóc dài hạn cho người cao tuổi", "def_ko": "노인들을 위한 장기 요양 보험", "def_vi": "Bảo hiểm chi trả cho việc chăm sóc lâu dài"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (232, '2', '가사 및 일상생활지원 표준서비스 중 개인활동 지원 내용으로 옳은 것은?', '["화장실 이용 돕기", "외출 시 동행", "옷 갈아입히기", "식사 준비 및 정리", "청소 및 주변정돈"]'::jsonb, 2, NULL, NULL, '{"1": "화장실 이용 돕기는 개인활동 지원의 일환이지만, 표준서비스 범위에는 포함되지 않는다.\n[정답]", "2": "외출 시 동행은 개인활동 지원에 해당하며, 표준서비스에 포함된다.", "3": "옷 갈아입히기는 개인활동 지원에 해당하지만, 이번 문제의 관점에서 벗어난다.", "4": "식사 준비 및 정리는 가사 지원 서비스에 해당한다.", "5": "청소 및 주변정돈은 일상생활 지원 서비스 중 가사 지원의 일부이다."}'::jsonb, '[{"term_ko": "가사", "term_vi": "Hỗ trợ sinh hoạt", "def_ko": "집안일(한국어)", "def_vi": "hỗ trợ sinh hoạt(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (231, '2', '정서지원 및 의사소통 도움 서비스 내용으로 옳은 것은?', '["입욕준비 및 목용을 도왔다.", "은행 외출 시 동행을 하였다.", "생활의 문제 상담을 하였다.", "욕창 예방을 위한 체위변경을 도왔다.", "장보기 및 식사준비를 도왔다."]'::jsonb, 3, NULL, NULL, '{"1": "입욕준비 및 목용을 도왔다. 이는 신체적 지원에 해당한다.\n[정답]", "3": "생활의 문제 상담을 하였다. 이는 정서적 지원 및 의사소통 도움에 해당한다.", "2": "은행 외출 시 동행을 하였다. 이는 이동 지원에 해당한다.", "4": "욕창 예방을 위한 체위변경을 도왔다. 이는 신체적 지원에 해당한다.", "5": "장보기 및 식사준비를 도왔다. 이는 생활 지원에 해당한다."}'::jsonb, '[{"term_ko": "정서지원", "term_vi": "Hỗ trợ cảm xúc", "def_ko": "감정적 지원( 한국어 )", "def_vi": "Hỗ trợ liên quan đến cảm xúc( 베트남어 )"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (230, '2', '치매 대상자가 같은 옷만 입으려고 할 때 대처 방법으로 옳은 것은?', '["거울을 보여 주며 더러워진 옷이라고 한다.", "옷을 갈아입어야 한다는 것을 설명한다.", "가족과 상의하여 동일한 유형의 옷을 추가로 구입한다.", "물을 엎질러 다른 옷을 입게 한다.", "좋아하는 음식을 주며 다른 옷을 입게 한다."]'::jsonb, 3, NULL, NULL, '{"1": "거울을 보여 주며 더러워진 옷이라고 한다는 것은 대처 방법으로 적절하지 않습니다. 대상자가 혼란스러워할 수 있습니다.\n[정답]", "2": "옷을 갈아입어야 한다는 것을 설명하는 것은 인지 기능이 저하된 대상을 혼란스럽게 할 수 있으므로 효과적이지 않습니다.", "3": "가족과 상의하여 동일한 유형의 옷을 추가로 구입하는 것은 대상자의 정서적 안정에 도움이 되므로 적절한 대처 방법입니다.", "4": "물을 엎질러 다른 옷을 입게 하는 것은 의도적인 행동으로, 대상자에게 부정적인 경험을 줄 수 있습니다.", "5": "좋아하는 음식을 주며 다른 옷을 입게 하는 것은 이 방법이 아닌 다른 대처 방법일 수 있으므로 잘못된 접근입니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억력이나 판단력이 저하된 상태", "def_vi": "Trạng thái suy giảm trí nhớ hoặc phán đoán"}, {"term_ko": "대상자", "term_vi": "Người đối tượng", "def_ko": "돌봄이나 요양이 필요한 사람", "def_vi": "Người cần chăm sóc hoặc điều dưỡng"}, {"term_ko": "대처 방법", "term_vi": "Cách xử lý", "def_ko": "어떤 상황에서 대응하는 방법", "def_vi": "Phương pháp đối phó với tình huống"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (229, '2', '대상자가 기저귀 안으로 자꾸 손을 넣을 때 요양보호사의 대처 방법으로 옳은 것은?', '["단호하게 하지 말라고 말한다.", "손을 억제대로 묶어 놓는다.", "음부에 습진이 있는지 확인한다.", "손톱을 짧게 깎아준다.", "음부를 청결히 한다."]'::jsonb, 3, NULL, NULL, '{"1": "단호하게 하지 말라고 말하는 것은 문제가 지속될 수 있는 상황을 방치하는 것이다.\n[정답]", "3": "음부에 습진이 있는지 확인하는 것은 대상자의 피부 상태를 점검하기 위한 중요한 조치이다.", "2": "손을 억제대로 묶어 놓는 것은 대상자의 인권을 침해할 수 있는 부적절한 방법이다.", "4": "손톱을 짧게 깎아주는 것은 예방적인 조치지만, 현재 문제 해결과는 직접적인 관련이 없다.", "5": "음부를 청결히 하는 것은 중요하지만, 현재 손을 넣는 행동의 원인을 분석하는 것이 우선이다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người nhận chăm sóc", "def_ko": "환자, 돌봄을 받는 사람", "def_vi": "Bệnh nhân, người được chăm sóc"}, {"term_ko": "기저귀", "term_vi": "Tã", "def_ko": "아기나 성인 환자의 배변을 위한 용품", "def_vi": "Đồ dùng cho trẻ em hoặc bệnh nhân người lớn để đi vệ sinh"}, {"term_ko": "손을 넣다", "term_vi": "Đưa tay vào", "def_ko": "손을 특정한 장소에 넣는 행동", "def_vi": "Hành động đưa tay vào một vị trí cụ thể"}, {"term_ko": "습진", "term_vi": "Bệnh chàm", "def_ko": "피부 발진, 염증", "def_vi": "Nổi mẩn, viêm da"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (228, '2', '요양보호서비스 제공의 기본 원칙으로 옳은 것은?', '["요양보호사가 추가 서비스를 결정한다.", "대상자와의 심각한 갈등을 직접 해결한다.", "서비스 계획 시 대상자의 습관을 반영한다.", "대상자의 상태에 따라 처방약의 용량을 조절한다.", "대상자의 인지능력이 악화된 경우에는 서비스를 중단한다."]'::jsonb, 3, NULL, NULL, '{"1": "요양보호사는 추가 서비스를 결정할 권한이 없다. 서비스 제공은 대상자의 요구에 기반하여 이루어져야 한다.\n[정답]", "3": "서비스 계획 시에는 항상 대상자의 습관과 선호를 반영해야 하며, 이는 개인 맞춤형 서비스를 제공하기 위해 중요하다.", "2": "대상자와의 심각한 갈등은 전문 상담을 통해 해결하는 것이 바람직하다.", "4": "처방약의 용량 조절은 의사의 권한이며, 요양보호사가 임의로 조절할 수 없다.", "5": "대상자의 인지능력이 악화되었다고 해서 즉시 서비스를 중단하는 것은 적절하지 않다. 상황에 따라 적절한 대처가 필요하다."}'::jsonb, '[{"term_ko": "요양보호서비스", "term_vi": "Dịch vụ chăm sóc", "def_ko": "돌봄 서비스를 제공하는 지원", "def_vi": "Dịch vụ hỗ trợ chăm sóc"}, {"term_ko": "대상자", "term_vi": "Người nhận dịch vụ", "def_ko": "서비스를 받는 사람", "def_vi": "Người nhận sự chăm sóc"}, {"term_ko": "갈등", "term_vi": "Xung đột", "def_ko": "의견이나 감정의 차이", "def_vi": "Sự khác biệt về quan điểm hoặc cảm xúc"}, {"term_ko": "습관", "term_vi": "Thói quen", "def_ko": "반복적으로 하는 행동", "def_vi": "Hành vi lặp lại"}, {"term_ko": "처방약", "term_vi": "Thuốc theo toa", "def_ko": "의사가 특정 환자에게 제공하는 약", "def_vi": "Thuốc được bác sĩ kê cho bệnh nhân"}, {"term_ko": "인지능력", "term_vi": "Năng lực nhận thức", "def_ko": "정보를 이해하고 처리하는 능력", "def_vi": "Khả năng hiểu và xử lý thông tin"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (227, '2', '요양보호서비스 제공 원칙으로 옳은 겻은?', '["대상자가 인지능력이 없는 경우 보호자의 동의를 받는다.", "서비스의 추가 및 변경 사항은 보호자와 의논한다.", "대상자가 관장을 원하면 시설장과 의논하여 제공한다.", "응급상황 발생 시 가족에게 우선 알린다.", "치매 대상자의 돌발상황 시 가족과 의논한다."]'::jsonb, 1, NULL, NULL, '{"1": "대상자가 인지능력이 없는 경우 보호자의 동의를 받는다.\n[정답]", "2": "서비스의 추가 및 변경 사항은 보호자와 의논한다.", "3": "대상자가 관장을 원하면 시설장과 의논하여 제공한다.", "4": "응급상황 발생 시 가족에게 우선 알린다.", "5": "치매 대상자의 돌발상황 시 가족과 의논한다."}'::jsonb, '[{"term_ko": "요양보호서비스", "term_vi": "원칙", "def_ko": "돌봄 서비스(서비스 chăm sóc)", "def_vi": "기본 법칙(nguyên tắc)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (226, '2', '방문요양 서비스 제공 시 요양보호사의 준수사항으로 옳은 것은?', '["서비스 제공 중 알게 된 비밀은 시설장에게 보고한다.", "제공되는 서비스에 대해 보호자에게 충분히 설명한다.", "대상자의 상태와 관계없이 서비스를 제공한다.", "체온, 맥박, 호흡, 혈압측정은 하지 않는다.", "대상자 부축 시 넘어져 부상을 입은 경우 시설장에게 즉시 보고한다."]'::jsonb, 5, NULL, NULL, '{"1": "서비스 제공 중 알게 된 비밀은 보호자에게 보고해야 하며, 시설장에게 직접 보고하는 것은 아닙니다.\n[정답]", "5": "대상자 부축 시 넘어져 부상을 입은 경우는 즉시 시설장에게 보고해야 합니다.", "3": "대상자의 상태에 따라 서비스 제공 여부가 달라져야 하므로, 관계없이 서비스를 제공하는 것은 틀립니다.", "4": "체온, 맥박, 호흡, 혈압 측정은 필수적인 건강 관리의 일환으로 수행해야 합니다.", "2": "제공되는 서비스에 대해 보호자에게 충분히 설명하는 것이 중요합니다."}'::jsonb, '[{"term_ko": "방문요양 서비스", "term_vi": "요양보호사", "def_ko": "방문 chăm sóc", "def_vi": "Người chăm sóc"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (225, '2', '요양보호서비스 제공원칙을 준수한 경우로 옳은 겻은?', '["대상자의 가래를 흡인한다.", "상황에 따라 서비스 비용을 청구한다.", "대상자의 선호보다 시설의 규칙을 우선시한다.", "응급 상황에서는 응급처치 우선순위에 따라 처치한다.", "대상자의 인지능력이 악화되면 서비스를 중단한다."]'::jsonb, 4, NULL, NULL, '{"1": "가래 흡인은 특별한 상황에서만 필요한 조치이며, 일반적인 원칙에 어긋날 수 있습니다.\n[정답]", "2": "서비스 비용 청구는 상황에 따라 접근해야 하지만, 원칙적으로 대상자의 동의를 받아야 합니다.", "3": "시설의 규칙보다 대상자의 선호가 우선되어야 합니다.", "4": "응급 상황에서는 응급처치가 우선이므로, 옳은 선택입니다.", "5": "인지능력 저하 시 서비스 중단은 적절하지 않습니다."}'::jsonb, '[{"term_ko": "요양보호서비스", "term_vi": "Dịch vụ chăm sóc", "def_ko": "돌봄 서비스를 제공하는 것", "def_vi": "Cung cấp dịch vụ chăm sóc"}, {"term_ko": "제공원칙", "term_vi": "Nguyên tắc cung cấp", "def_ko": "서비스를 제공할 때 따르는 규칙", "def_vi": "Quy tắc khi cung cấp dịch vụ"}, {"term_ko": "대상자", "term_vi": "Đối tượng", "def_ko": "돌봄을 받는 사람", "def_vi": "Người nhận sự chăm sóc"}, {"term_ko": "가래", "term_vi": "Đờm", "def_ko": "폐에서 나오는 점액", "def_vi": "Chất nhầy từ phổi"}, {"term_ko": "응급 상황", "term_vi": "Tình huống khẩn cấp", "def_ko": "긴급 상황", "def_vi": "Tình huống cần giải quyết ngay"}, {"term_ko": "인지능력", "term_vi": "Khả năng nhận thức", "def_ko": "사고하거나 이해하는 능력", "def_vi": "Khả năng suy nghĩ hoặc hiểu"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (224, '2', '다음의 사례 내용 중 요양보호사 금지 행위에 해당하는 것으로 옳은 것은?• 요양보호사에게 수급자의 본인부담금을 전가시키는 경우• 수급자에게 비급여 대상의 비용을 면제 · 할인하는 경우', '["노인학대 등의 금지 행위", "수급자 유인 알선 행위 금지", "본인부담금 면제 감경 금지", "부당수급 관련 행위 금지", "급여제공자료 거짓 작성 금지"]'::jsonb, 3, NULL, NULL, '{"1": "노인학대는 명백한 범죄행위로 요양보호사의 금지 행위에 해당합니다.", "2": "수급자 유인 알선 행위도 금지된 행위입니다.\n[정답]", "3": "본인부담금 면제 감경은 요양보호사가 하지 말아야 할 행위로 정확히 금지됩니다.", "4": "부당수급 관련 행위는 요양보호사의 활동과 관련하여 금지됩니다.", "5": "급여제공자료 거짓 작성도 요양보호사의 금지 행위입니다."}'::jsonb, '[{"term_ko": "금지", "term_vi": "Cấm", "def_ko": "금지하다(한국어)", "def_vi": "cấm(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (223, '2', '요양보호서비스에 대한 지식과 기술로 대상자의 불편함을 경감하는 요양보호사의 역할로 옳은 것은?', '["옹호자", "촉진자", "숙련된 수발자", "정보전달자", "동기유발자"]'::jsonb, 3, NULL, NULL, '{"1": "옹호자는 환자의 권리를 지키고 보장하는 역할을 합니다.\n[정답]", "3": "숙련된 수발자는 대상자의 요구를 이해하고 적절한 도움을 제공하는 역할입니다.", "2": "촉진자는 사회적 상호작용을 촉진하는 역할을 합니다.", "4": "정보전달자는 필요한 정보를 전달하는 역할을 수행합니다.", "5": "동기유발자는 대상자를 격려하고 동기를 부여하는 역할입니다."}'::jsonb, '[{"term_ko": "요양보호사", "term_vi": "Người chăm sóc", "def_ko": "돌보는 사람", "def_vi": "Người chăm sóc"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (222, '2', '배우자의 사별로 우울증상을 겪는 대상자의 신체 · 심리적 정보를 가족과 의료진에게 알리는 요양보호사의 역할로 옳은 것은?', '["숙련된 수발자", "정보전달자", "관찰자", "말벗과 상담자", "동기유발자"]'::jsonb, 2, NULL, NULL, '{"1": "숙련된 수발자: 요양보호사는 숙련된 기술을 가지고 있지만, 정보 전달의 역할과는 직접적인 관련이 없습니다.\n[정답]", "2": "정보전달자: 요양보호사는 대상자의 상태를 가족과 의료진에게 효과적으로 전달해야 하는 역할을 가지고 있습니다.", "3": "관찰자: 관찰자는 상태 파악에 기여하지만, 정보 전달의 주된 역할은 아닙니다.", "4": "말벗과 상담자: 정서적 지원을 제공하는 역할이나 정보 전달과는 구분됩니다.", "5": "동기유발자: 동기를 유발하는 역할은 중요하지만, 정보 전달과는 직접적인 관련이 없습니다."}'::jsonb, '[{"term_ko": "사별", "term_vi": "Mất người thân", "def_ko": "사랑하는 사람을 잃는 것", "def_vi": "Mất đi người yêu thương"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (221, '2', '요양보호서비스를 제공할 때 대상자의 상태 변화와 투약 여부를 파악하는 요양보호사의 역할로 옳은 것은?', '["옹호자", "관찰자", "중개자", "정보전달자", "동기유발자"]'::jsonb, 2, NULL, NULL, '{"1": "옹호자는 환자의 권리를 보호하고 지지하는 역할을 한다.\n[정답]", "2": "관찰자는 대상자의 상태 변화를 주의 깊게 살펴보는 역할을 하며, 투약 여부를 파악하는 것이 중요한 임무이다.", "3": "중개자는 정보나 서비스를 이전하는 역할을 한다.", "4": "정보전달자는 다른 사람에게 정보를 전파하는 역할을 한다.", "5": "동기유발자는 환자의 동기를 유발하고 유도하는 역할을 한다."}'::jsonb, '[{"term_ko": "요양보호서비스", "term_vi": "Dịch vụ chăm sóc", "def_ko": "돌봄 서비스(한국어)", "def_vi": "Dịch vụ chăm sóc"}, {"term_ko": "대상자", "term_vi": "Đối tượng", "def_ko": "환자를 의미(한국어)", "def_vi": "Có nghĩa là bệnh nhân"}, {"term_ko": "상태", "term_vi": "Trạng thái", "def_ko": "상태(한국어)", "def_vi": "Trạng thái"}, {"term_ko": "변화", "term_vi": "Biến đổi", "def_ko": "변화(한국어)", "def_vi": "Sự thay đổi"}, {"term_ko": "투약", "term_vi": "Dùng thuốc", "def_ko": "약물의 투여(한국어)", "def_vi": "Sự dùng thuốc"}, {"term_ko": "역할", "term_vi": "Vai trò", "def_ko": "역할(한국어)", "def_vi": "Vai trò"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (220, '2', '요양보호사가 동기 유발자로서 역할을 수행한 경우로 옳은 것은?', '["대상자의 투약여부를 면밀히 관찰한다.", "대상자의 심리적 문제를 가족에게 알린다.", "숙련된 기술로 질 높은 서비스를 제공한다.", "대상자 스스로 신체 활동을 하도록 격려한다.", "대상자의 말을 경청하며 신뢰관계를 형성한다."]'::jsonb, 4, NULL, NULL, '{"1": "대상자의 투약여부를 면밀히 관찰하는 것은 동기 유발자 역할이 아니다.\n[정답]", "4": "대상자 스스로 신체 활동을 하도록 격려하는 것은 동기 유발자로서의 역할이다.", "3": "숙련된 기술로 질 높은 서비스를 제공하는 것은 중요하지만 동기 유발자 역할과는 관련이 없다.", "2": "대상자의 심리적 문제를 가족에게 알리는 것은 필요한 조치지만 동기 유발자 역할이라고 보기 어렵다.", "5": "대상자의 말을 경청하며 신뢰관계를 형성하는 것은 중요하지만 동기 유발과는 거리가 있다."}'::jsonb, '[{"term_ko": "요양보호사", "term_vi": "Người chăm sóc", "def_ko": "환자를 돌보고 그들의 필요를 지원하는 전문가", "def_vi": "Chuyên gia chăm sóc và hỗ trợ nhu cầu của bệnh nhân"}, {"term_ko": "동기 유발자", "term_vi": "Người kích thích động lực", "def_ko": "대상자가 스스로 행동하도록 동기를 부여하는 역할", "def_vi": "Vai trò khuyến khích bệnh nhân tự thực hiện hành động"}, {"term_ko": "신체 활동", "term_vi": "Hoạt động thể chất", "def_ko": "움직임, 운동", "def_vi": "Sự di chuyển, tập thể dục"}, {"term_ko": "격려", "term_vi": "Khuyến khích", "def_ko": "자극, 응원", "def_vi": "Khích lệ, động viên"}, {"term_ko": "신뢰관계", "term_vi": "Mối quan hệ tin cậy", "def_ko": "서로 믿을 수 있는 관계", "def_vi": "Quan hệ giữa những người có thể tin tưởng lẫn nhau"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (219, '2', '다음과 같은 상황에서 요양보호사가 수행하는 역할로 옳은 것은?• 대상자가 성희롱을 당했을 때 기관장에게 보고함 • 학대 의심 사례가 발생했을 때 경찰서에 신고함', '["촉진자", "옹호자", "교육자", "동기유발자", "숙련된 수발자"]'::jsonb, 2, NULL, NULL, '{"1": "촉진자는 단순히 어떤 행동을 유도하는 역할로, 요양보호사와는 관련이 적습니다.\n[정답]", "2": "옹호자는 대상자를 대변하고 보호하는 역할로, 문제 상황에서 적절한 조치를 취하는 요양보호사의 역할을 잘 나타냅니다.", "3": "교육자는 지식이나 기술을 가르치는 역할로, 본 문제와는 관련이 없습니다.", "4": "동기유발자는 개인의 행동을 자극하는 역할로, 이 문제의 상황과는 맞지 않습니다.", "5": "숙련된 수발자는 기초적인 돌봄 기술을 수행하는 역할이지만, 문제의 핵심인 보고 및 신고와는 다릅니다."}'::jsonb, '[{"term_ko": "요양보호사", "term_vi": "Nhân viên chăm sóc", "def_ko": "노인이나 장애인을 돌보는 사람", "def_vi": "Người chăm sóc người già hoặc người khuyết tật"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (218, '2', '요양보호사의 역할(A)과 관련된 내용(B)이 바르게 연결된 것으로 옳은 것은?', '["관찰자 필요한 서비스 연계 활동", "옹호자 차별받는 대상자 지지", "정보전달자 직접적인 서비스 제공", "동기 유발자 질병의 증상 확인", "숙련된 수발자 서비스 제공 게획 및 수립"]'::jsonb, 2, NULL, NULL, '{"1": "관찰자: 필요한 서비스 연계 활동은 요양보호사의 역할 중 하나이나 정확한 연결이 아님.\n[정답]", "2": "옹호자: 차별받는 대상자 지지는 요양보호사가 수행하는 핵심 역할 중 하나입니다.", "3": "정보전달자: 직접적인 서비스 제공은 다른 전문가의 역할에 가까움.", "4": "동기 유발자: 질병의 증상 확인은 요양보호사의 핵심 역할이 아님.", "5": "숙련된 수발자: 서비스 제공 계획 및 수립은 관리자의 역할에 가까움."}'::jsonb, '[{"term_ko": "요양보호사", "term_vi": "Nhân viên chăm sóc", "def_ko": "환자를 요양하고 돌보는 전문인력", "def_vi": "Nhân lực chuyên chăm sóc và nuôi dưỡng bệnh nhân"}, {"term_ko": "역할", "term_vi": "Vai trò", "def_ko": "근무에서의 역할", "def_vi": "Vai trò trong công việc"}, {"term_ko": "관찰자", "term_vi": "Người quan sát", "def_ko": "상황이나 행동을 주의 깊게 살펴보는 사람", "def_vi": "Người chú ý đến tình huống hoặc hành vi"}, {"term_ko": "옹호자", "term_vi": "Người bảo vệ", "def_ko": "지원 및 변호를 하는 사람", "def_vi": "Người hỗ trợ và đại diện"}, {"term_ko": "정보전달자", "term_vi": "Người truyền đạt thông tin", "def_ko": "정보를 전달하는 사람", "def_vi": "Người truyền tải thông tin"}, {"term_ko": "동기 유발자", "term_vi": "Người khơi gợi động lực", "def_ko": "동기를 주는 사람", "def_vi": "Người tạo động lực"}, {"term_ko": "숙련된 수발자", "term_vi": "Người chăm sóc có kỹ năng", "def_ko": "전문가적인 돌봄을 하는 사람", "def_vi": "Người chăm sóc có chuyên môn"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (217, '2', '다음 중 수급자가 요양보호사에게 요구해서는 안 되는 행위로 옳은 것은?', '["대상자를 위한 관공서 등 업무지원", "대상자 생일을 위한 미역국 끓이기", "대상자 아들 가게의 음식을 준비함.", "보호자가 어머님이 베란다에서 배변하는 것을 발견하여 문의함", "대상자가 은행의 고액 업무를 부탁함"]'::jsonb, 3, NULL, NULL, '{"1": "대상자를 위한 관공서 등 업무지원은 가능하므로 요구할 수 있습니다.\n[정답]", "3": "대상자 아들 가게의 음식을 준비하는 것은 개인적인 부탁으로 요구해서는 안 됩니다.", "2": "대상자 생일을 위한 미역국 끓이기는 요양 서비스를 포함할 수 있습니다.", "4": "보호자가 어머님이 베란다에서 배변하는 것을 발견하여 문의하는 것은 적절한 행위입니다.", "5": "대상자가 은행의 고액 업무를 부탁하는 것은 부적절한 요구입니다."}'::jsonb, '[{"term_ko": "수급자", "term_vi": "Người hưởng", "def_ko": "서비스를 받는 사람", "def_vi": "Người nhận dịch vụ"}, {"term_ko": "요양보호사", "term_vi": "Người chăm sóc", "def_ko": "보호와 돌봄을 제공하는 사람", "def_vi": "Người cung cấp sự chăm sóc và bảo vệ"}, {"term_ko": "행위", "term_vi": "Hành vi", "def_ko": "행동", "def_vi": "Hành động"}, {"term_ko": "업무지원", "term_vi": "Hỗ trợ công việc", "def_ko": "업무에 대한 지원", "def_vi": "Hỗ trợ công việc"}, {"term_ko": "요구", "term_vi": "Yêu cầu", "def_ko": "요청", "def_vi": "Yêu cầu"}, {"term_ko": "부탁", "term_vi": "Nhờ", "def_ko": "부탁하다", "def_vi": "Nhờ cậy"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (216, '2', '다음과 같은 요양보호사의 고충이 있을 경우 장기요양기관장의 적절한 조치로 옳은 것은?• 치매 대상자의 배우자는 요양보호사가 대상자를 제대로 돌보지 않아 치매 증상이 심해졌다며 심한 폭언을 하였다.', '["요양보호사의 고충 요청을 무시한다.", "조리업무로 업무를 전환한다.", "상담심리 지원 프로그램을 제공한다.", "대상자의 일부 부담금을 할인해준다.", "요양보호사에게 적성이 맞는지 상담을 한다."]'::jsonb, 3, NULL, NULL, '{"1": "요양보호사의 고충 요청을 무시한다는 것은 잘못된 대처 방법이다.\n[정답]", "3": "상담심리 지원 프로그램을 제공하는 것은 요양보호사의 정서적 지지를 위한 올바른 조치이다.", "2": "조리업무로 업무를 전환하는 것은 문제 해결에 도움이 되지 않는다.", "4": "대상자의 일부 부담금을 할인해주는 것은 요양보호사의 고충과는 무관한 조치이다.", "5": "요양보호사에게 적성이 맞는지 상담하는 것은 필요한 조치일 수 있지만, 현재 상황에 대한 즉각적인 지원이 아니다."}'::jsonb, '[{"term_ko": "요양보호사", "term_vi": "Nhân viên chăm sóc", "def_ko": "환자를 돌보는 사람", "def_vi": "Người chăm sóc bệnh nhân"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (215, '3', '김씨 할머니는 거울을 보며 에휴, 매번 머리 모양을 남자처럼 짧게 깎아놔...라며 투덜거리는 상황에서 대상자가 요구할 수 있는 권리로 옳은 것은?', '["개별화된 서비스를 제공받고 선택할 수 있는 권리", "안락하고 안전한 생활환경을 제공받을 권리", "존엄한 존재로 대우받을 권리", "건강한 생활을 위한 질 높은 생활서비스 및 보건의료서비스를 받을 권리", "시설운영과 서비스에 대한 개인적 견해를 표현학 해결을 요구할 권리"]'::jsonb, 1, NULL, NULL, '{"1": "개별화된 서비스를 제공받고 선택할 수 있는 권리: 개인의 필요와 선호에 따라 서비스를 선택할 수 있는 권리로, 대상자의 고유한 요구를 반영합니다.\n[정답]", "2": "안락하고 안전한 생활환경을 제공받을 권리: 기본적인 안전과 안락함을 보장받을 권리지만, 문제의 상황과는 직접적 관련이 적습니다.", "3": "존엄한 존재로 대우받을 권리: 존엄성은 중요하지만, 이 상황에서는 개인의 선택권이 더 부각됩니다.", "4": "건강한 생활을 위한 질 높은 생활서비스 및 보건의료서비스를 받을 권리: 건강과 관련된 권리로 의미가 있으나, 이 문제에서는 개인의 선택권이 주제입니다.", "5": "시설운영과 서비스에 대한 개인적 견해를 표현하고 해결을 요구할 권리: 개인의 의견과 요구를 표현할 수 있는 권리이나, 상황의 맥락을 봤을 때 더 적합한 선택은 아닙니다."}'::jsonb, '[{"term_ko": "권리", "term_vi": "Quyền", "def_ko": "권리(한국어)", "def_vi": "Quyền"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (214, '3', '다음과 같은 상황에서 대상자가 침해받은 권리로 옳은 것은?• 시설장 : (입소자가 가져온 짐을 보면서) 어르신, 전화로도 말씀드렸듯이 이 시설에서는 개인의 물품을 설치하거나 이용하는 것을 허용하지 않습니다. • 대상자 : ......', '["신체구속을 받지 않을 권리", "시설 운영 전반에 관한 충분한 정보를 제공 받을 권리", "차별 및 노인학대를 받지 않을 권리", "사생활과 비밀보장에 대한 권리", "개별화된 서비스를 제공받고 선택할 수 있는 권리"]'::jsonb, 5, NULL, NULL, '{"1": "신체구속을 받지 않을 권리는 특정 상황에서 적용되는 것이므로, 이번 상황에 직접적인 관련이 없습니다.", "2": "시설 운영 전반에 관한 충분한 정보를 제공 받을 권리는 중요하지만, 문제 상황에서는 개인 물품 설치에 대한 제한을 다루고 있습니다.", "3": "차별 및 노인학대를 받지 않을 권리는 일반적인 권리이지만, 여기에서는 특정한 조치와 관련된 권리를 묻고 있습니다.\n[정답]", "4": "사생활과 비밀보장에 대한 권리는 시설에서 개인 물품을 설치할 수 없다는 조치와 관련이 있으며, 사생활 보호와 맞물려 있습니다.", "5": "개별화된 서비스를 제공받고 선택할 수 있는 권리는 개인의 자유와 관계가 깊어서, 물품 설치 자유와 관련이 있습니다."}'::jsonb, '[{"term_ko": "권리", "term_vi": "Quyền", "def_ko": "권리(한국어)", "def_vi": "Quyền lợi"}, {"term_ko": "사생활", "term_vi": "Cuộc sống riêng tư", "def_ko": "개인의 프라이버시(한국어)", "def_vi": "Cuộc sống riêng tư"}, {"term_ko": "시설", "term_vi": "Cơ sở", "def_ko": "시설(한국어)", "def_vi": "Cơ sở"}, {"term_ko": "개별화", "term_vi": "Cá nhân hóa", "def_ko": "맞춤형(한국어)", "def_vi": "Cá nhân hóa"}, {"term_ko": "선택", "term_vi": "Lựa chọn", "def_ko": "선택(한국어)", "def_vi": "Lựa chọn"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (213, '3', '다음과 같은 사례에서 보장되어야 하는 대상자의 권리로 옳은 것은?• 대상자는 평소에 온돌에서 생활해 왔는데, 시설에 입소 후 침대생활을 해야 해서 쉽게 잠이 들지 않고 떨어질까 봐 불안하여 잠을 깊게 잘 수가 없다고 한다.', '["사생활과 비밀보장에 대한 권리", "신체구속을 받지 않을 권리", "시설 운영 전반에 관한 충분한 정보를 제공 받을 권리", "차별 및 노인 학대를 받지 않을 권리", "안락하고 안전한 생활환경을 제공받을 권리"]'::jsonb, 5, NULL, NULL, '{"1": "사생활과 비밀보장에 대한 권리는 중요하지만, 현재 사례와 직접적인 관련은 적습니다.\n[정답]", "5": "안락하고 안전한 생활환경을 제공받을 권리 가 가장 적절한 선택입니다. 대상자가 편안한 수면을 취할 수 있는 환경이 필요하기 때문입니다.", "3": "정보 제공 권리도 중요하지만, 현재 사례의 핵심은 생활환경에 대한 것입니다.", "4": "차별과 노인 학대의 방지 또한 중요한 권리지만, 현재 사례와는 맞지 않습니다.", "2": "신체구속을 받지 않을 권리도 중요하지만, 이 사례에서는 다루지 않은 내용입니다."}'::jsonb, '[{"term_ko": "권리", "term_vi": "Quyền", "def_ko": "권리(한국어)", "def_vi": "Quyền lợi của người dùng(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (212, '3', '다음과 같은 사례에 해당되는 시설 대상자의 권리로 옳은 것은?• 편마비 대상자가 시설장에게 화장실에 비상벨이 없어 불편하다고 하였다.', '["신체구속을 받지 않을 권리", "시설 운영 전반에 관한 충분한 정보를 제공 받을 권리", "사생활과 비밀보장에 대한 권리", "노인 스스로 입소를 결정하며, 공정한 입소 계약을 맺을 권리", "안락하고 안전한 생활환경을 제공받을 권리"]'::jsonb, 5, NULL, NULL, '{"1": "신체구속을 받지 않을 권리는 중요하지만, 이 사례와는 관련이 없습니다.\n[정답]", "5": "안락하고 안전한 생활환경을 제공받을 권리는 편마비 대상자의 불편함과 직접적으로 관련이 있습니다.", "2": "시설 운영 전반에 관한 충분한 정보를 제공받을 권리는 일반적인 권리이나, 해당 사례와는 관계가 적습니다.", "3": "사생활과 비밀보장에 대한 권리는 중요하지만, 이번 사례와는 연결되지 않습니다.", "4": "노인 스스로 입소를 결정하며, 공정한 입소 계약을 맺을 권리는 대상자의 상황에 비추어 볼 때 이러한 권리는 이미 충족된 것으로 보입니다."}'::jsonb, '[{"term_ko": "편마비", "term_vi": "Liệt nửa người", "def_ko": "한쪽 몸의 감각이나 운동 기능이 상실된 상태(한국어)", "def_vi": "Tình trạng mất cảm giác hoặc chức năng vận động ở một bên cơ thể"}, {"term_ko": "비상벨", "term_vi": "Chuông báo động", "def_ko": "긴급 상황에서 사용되는 경고 장치(한국어)", "def_vi": "Thiết bị cảnh báo được sử dụng trong trường hợp khẩn cấp"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (211, '3', '다음 사례에 해당하는 시설노인을 위한 윤리강령의 원칙 중 침해받은 권리로 옳은 것은?• 어르신께서는 시설 실습을 나온 실습생들이 기념이라며 자기들 맘대로 사진을 찍거나 방에 불쑥불쑥 들어와 구경하고 나가는 것을 보면 매우 불쾌하다고 하신다.', '["안락하고 안전한 생활환경을 제공받을 권리", "사생활과 비밀보장에 대한 권리", "존엄한 존재로 대우받을 권리", "건강한 생활을 위한 질 높은 생활서비스 및 보건의료서비스를 받을 권리", "시설운영과 서비스에 대한 개인적 견해를 표현하고 해결을 요구할 권리"]'::jsonb, 2, NULL, NULL, '{"1": "안락하고 안전한 생활환경은 중요하지만, 사진 촬영과 관련된 권리는 아닙니다.\n[정답]", "2": "사생활과 비밀보장에 대한 권리는 사진촬영과 사적인 공간 침해와 관련이 있습니다.", "3": "존엄한 존재로 대우받는 것도 중요하지만, 주어진 사례에서는 사생활의 침해가 더욱 명확합니다.", "4": "건강과 관련된 권리는 중요하나, 이번 문제의 사례와는 직접적인 연관이 없습니다.", "5": "개인적 견해 표현은 권리지만, 사례에서 중심이 되는 문제는 사생활의 침해입니다."}'::jsonb, '[{"term_ko": "시설노인", "term_vi": "Người lớn tuổi trong viện dưỡng lão", "def_ko": "시설에서 생활하는 노인", "def_vi": "Người sống trong cơ sở chăm sóc dài hạn"}, {"term_ko": "윤리강령", "term_vi": "Nguyên tắc đạo đức", "def_ko": "윤리 원칙을 규정한 문서", "def_vi": "Tài liệu quy định các nguyên tắc đạo đức"}, {"term_ko": "사생활", "term_vi": "Cá nhân", "def_ko": "개인의 사적 공간과 정보", "def_vi": "Không gian và thông tin cá nhân"}, {"term_ko": "권리", "term_vi": "Quyền", "def_ko": "개인의 기본적인 요구 또는 요청", "def_vi": "Nhu cầu hoặc yêu cầu cơ bản của cá nhân"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (210, '3', '치매 대상자가 같은 방을 쓰는 동료 노인에게 소리치고, 발로 차고 동료 노인의 따귀를 때릴 때 대처 방법으로 옳은 것은?', '["치매 노인에게 왜 때리는지 이유를 물어본다.", "침해 당한 노인의 방을 옮겨 마주치지 않게 한다.", "치매 대상에게 퇴소시킬 수 있다고 경고한다.", "치매 대상자의 습성이라고 이해한다.", "치매 대상자의 가족에게 인권교육을 시킨다."]'::jsonb, 2, NULL, NULL, '{"1": "치매 노인은 상황을 인지하기 어려워 이유를 물어봐도 의미가 없을 수 있습니다.\n[정답]", "2": "침해 당한 노인의 방을 옮겨 마주치지 않게 하는 것이 가장 효과적인 대처 방법입니다.", "3": "퇴소 위협은 치매 환자에게는 오히려 부정적인 영향을 미칠 수 있습니다.", "4": "습성을 이해하는 것이 중요하지만, 이를 방치하면 문제를 해결할 수 없습니다.", "5": "가족에게 인권교육은 필요하지만, 상황 해결과는 직접적인 연관이 없습니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "대상자", "def_ko": "기억력이나 사고 기능의 저하가 있는 뇌질환(병 lão hóa trí nhớ, bệnh Alzheimer)", "def_vi": "치료나 도움이 필요한 사람(người được điều trị)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (209, '3', '다음과 같은 상황에서 시설대상자가 침해받는 권리로 옳은 것은?• 다른 대상자에게 따귀를 맞은 사실에 대해 요양보호사가 아무런 개입을 하지 않았다. • 요양보호사가 치매 대상자에게 폭언을 하였다.', '["신체구속을 받지 않을 권리", "개별화된 서비스를 제공받고 선택할 수 있는 권리", "시설 운영 전반에 관한 충분한 정보를 제공 받을 권리", "존엄한 존재로 대우받을 권리", "사생활과 비밀보장에 대한 권리"]'::jsonb, 4, NULL, NULL, '{"1": "신체구속을 받지 않을 권리: 질문에 언급된 상황은 신체구속과 관련이 없다.\n[정답]", "2": "개별화된 서비스를 제공받고 선택할 수 있는 권리: 요양보호사의 폭언으로 인해 대우받지 못하였다.", "3": "시설 운영 전반에 관한 충분한 정보를 제공 받을 권리: 질문의 맥락과는 관련이 없다.", "4": "존엄한 존재로 대우받을 권리: 대상자가 폭언과 타인에게 따귀를 맞는 상황에서 이 권리가 침해된 것이므로 정답이다.", "5": "사생활과 비밀보장에 대한 권리: 질문과 관련이 없는 권리이다."}'::jsonb, '[{"term_ko": "권리", "term_vi": "Quyền lợi", "def_ko": "권리(한국어)", "def_vi": "Quyền"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (208, '3', '다음의 시설대상자가 보장받아야 할 기본 권리로 옳은 것은?"우리 가족들이 잘 안 와서 그런지 똑같이 음식을 흘려도 나한테만 유난히 더 화를 내. 나를 괄시하는 거지."', '["신체구속을 받지 않을 권리", "시설 운영 전반에 관한 충분한 정보를 제공 받을 권리", "개인 소유의 재산과 소유물을 스스로 관리할 권리", "사생활과 비밀보장에 대한 권리", "차별 및 노인학대를 받지 않을 권리"]'::jsonb, 5, NULL, NULL, '{"1": "신체구속을 받지 않을 권리에 대한 설명은 맞지만, 이 사례에서는 강조되지 않는다.\n[정답]", "5": "차별 및 노인학대를 받지 않을 권리는 상황에 비추어 가장 적합하다.", "3": "개인 소유의 재산과 소유물을 스스로 관리할 권리는 중요하지만 이 문장에서 직접적으로 다루지 않는다.", "2": "시설 운영 전반에 관한 충분한 정보를 제공 받을 권리는 필수적이지만, 사례와는 관계가 없다.", "4": "사생활과 비밀보장에 대한 권리는 중요하지만, 문맥에서는 차별 문제에 더 집중하고 있다."}'::jsonb, '[{"term_ko": "시설", "term_vi": "Cơ sở", "def_ko": "시설(한국어)", "def_vi": "Cơ sở"}, {"term_ko": "보장", "term_vi": "Bảo đảm", "def_ko": "보장(한국어)", "def_vi": "Bảo đảm"}, {"term_ko": "권리", "term_vi": "Quyền", "def_ko": "권리(한국어)", "def_vi": "Quyền"}, {"term_ko": "차별", "term_vi": "Phân biệt", "def_ko": "차별(한국어)", "def_vi": "Phân biệt"}, {"term_ko": "노인", "term_vi": "Người cao tuổi", "def_ko": "노인(한국어)", "def_vi": "Người cao tuổi"}, {"term_ko": "학대", "term_vi": "Bạo lực", "def_ko": "학대(한국어)", "def_vi": "Bạo lực"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (207, '3', '다음 사례에 해당하는 시설생활노인의 보장받을 권리로 옳은 것은?• 거동이 불편한 김씨 할아버지는 산책 중에 넘어져 손목을 골절당한 경험이 있다. 이후부터 요양보호사는 자리를 비울 때마다 손과 발을 묶어 놓고 나가기 때문에 하루에도 몇 번씩 억제를 당하고 있다.', '["존엄한 존재로 대우받을 권리", "사생활과 비밀보장에 대한 권리", "신체구속을 받지 않을 권리", "안락하고 안전한 생활환경을 제공받을 권리", "건강한 생활을 위한 질 높은 생활서비스 및 보건의료서비스를 받을 권리"]'::jsonb, 3, NULL, NULL, '{"1": "존엄한 존재로 대우받을 권리는 기본적인 권리지만, 사례와 직접적인 연관이 없습니다.\n[정답]", "3": "신체구속을 받지 않을 권리는 노인의 권리 중 하나로 사례에서 명백히 위반되고 있습니다.", "2": "사생활과 비밀보장에 대한 권리는 중요하지만, 이 사례에서 논의하는 부분과는 관계가 없습니다.", "4": "안락하고 안전한 생활환경을 제공받을 권리는 기본적이지만, 문제의 핵심은 신체구속입니다.", "5": "건강한 생활을 위한 질 높은 생활서비스 및 보건의료서비스를 받을 권리는 관련있지만 이 사례의 본질과는 거리가 있습니다."}'::jsonb, '[{"term_ko": "권리", "term_vi": "Quyền", "def_ko": "권리(한국어)", "def_vi": "Quyền"}, {"term_ko": "시설생활노인", "term_vi": "Người cao tuổi sống trong cơ sở", "def_ko": "시설에서 생활하는 노인(한국어)", "def_vi": "Người cao tuổi sống trong cơ sở"}, {"term_ko": "신체구속", "term_vi": "Hạn chế thể xác", "def_ko": "신체의 일부가 제한되는 것(한국어)", "def_vi": "Bị giới hạn một phần thân thể"}, {"term_ko": "안락", "term_vi": "An nhàn", "def_ko": "편안함(한국어)", "def_vi": "Sự thoải mái"}, {"term_ko": "환경", "term_vi": "Môi trường", "def_ko": "주위의 상황(한국어)", "def_vi": "Tình huống xung quanh"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (206, '3', '다음의 내용과 같은 시설대상자의 기본 권리로 옳은 것은?• 개인의 선호와 건강 상태에 따른 개별화된 식단을 제공한다. • 잔존능력을 유지시키기 위해 재활프로그램을 제공한다. • 시설은 종사자에게 직무훈련과 교육기회를 충분히 부여한다.', '["존엄한 존재로 대우받을 권리", "사생활과 비밀보장에 대한 권리", "신체구속을 받지 않을 권리", "안락하고 안전한 생활환경을 제공받을 권리", "건강한 생활을 위한 질 높은 생활서비스 및 보건의료서비스를 받을 권리"]'::jsonb, 5, NULL, NULL, '{"1": "존엄한 존재로 대우받을 권리는 기본적인 인권을 포함하지만, 직접적인 내용과는 관련이 없습니다.", "2": "사생활과 비밀보장에 대한 권리는 중요한 권리이나, 제시된 예시와 연관이 없습니다.", "3": "신체구속을 받지 않을 권리는 특정한 권리 중 하나로 관련성이 적습니다.\n[정답]", "4": "안락하고 안전한 생활환경을 제공받을 권리는 예시와 맞물려 있으며,", "5": "건강한 생활을 위한 질 높은 생활서비스 및 보건의료서비스를 받을 권리, 제시된 모든 내용과 일치합니다."}'::jsonb, '[{"term_ko": "권리", "term_vi": "Quyền", "def_ko": "권리(한국어)", "def_vi": "Quyền(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (205, '3', '시설 내 · 외부 활동 및 사회적 관계에 참여할 권리에 침해 받은 것은?', '["노인의 정치적 이념을 존중한다.", "특정 인물에 투표하도록 영향력을 행사한다.", "노인의 종교적 신념을 인정한다.", "종교적 신념의 변화를 목적으로 영향력을 행사하지 않는다.", "노인의 문화적 다양성을 인정한다."]'::jsonb, 2, NULL, NULL, '{"1": "노인의 정치적 이념을 존중하는 것은 권리를 보호하는 행동이다.\n[정답]", "2": "특정 인물에 투표하도록 영향력을 행사하는 것은 노인의 권리를 침해하는 행위이다.", "3": "노인의 종교적 신념을 인정하는 것은 권리를 보호하는 행동이다.", "4": "종교적 신념의 변화를 목적으로 영향력을 행사하지 않는 것은 권리를 지키는 일이다.", "5": "노인의 문화적 다양성을 인정하는 것은 권리를 존중하는 행동이다."}'::jsonb, '[{"term_ko": "노인", "term_vi": "Người cao tuổi", "def_ko": "고령자(한국어)", "def_vi": "Người già"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (204, '3', '다음에 해당하는 시설생활노인의 보장받을 권리로 옳은 것은?• 노인의 이성교제를 금기시하거나 흥밋거리로 다루지 않아야 한다. • 노인의 성적 욕구를 인간의 기본욕구로서 선입견 없이 받아들여야 한다. • 흡연, 음주 등 특정 기호품 사용에 대해 시설환경 내에서 해결할 수 있는 방안을 마련한다.', '["신체구속을 받지 않을 권리", "시설 운영 전반에 관한 충분한 정보를 제공 받을 권리", "사생활과 비밀보장에 대한 권리", "이성교제, 성생활, 기호품 사용에 관한 가지 결정의 권리", "시설운영과 서비스에 대한 개인적 견해를 표현하고 해결을 요구할 권리"]'::jsonb, 4, NULL, NULL, '{"1": "신체구속을 받지 않을 권리는 노인의 신체적 자유를 보장하는 내용입니다.\n[정답]", "4": "이성교제, 성생활, 기호품 사용에 관한 결정 권리는 노인의 기본적인 인권을 존중하는 내용을 포함합니다.", "2": "시설 운영 전반에 관한 충분한 정보를 제공 받을 권리는 노인의 정보 접근성을 의미합니다.", "3": "사생활과 비밀보장에 대한 권리는 노인의 개인적 사생활을 보호하는 내용을 담고 있습니다.", "5": "시설 운영과 서비스에 대한 개인적 견해를 표현하고 해결을 요구할 권리는 노인의 의견을 반영하는 내용을 포함합니다."}'::jsonb, '[{"term_ko": "시설생활노인", "term_vi": "Người già sống trong cơ sở", "def_ko": "시설에서 생활하는 노인", "def_vi": "Người già sống trong môi trường điều trị"}, {"term_ko": "신체구속", "term_vi": "Ràng buộc thể xác", "def_ko": "신체적으로 자유를 제한받는 것", "def_vi": "Bị hạn chế về mặt thể xác"}, {"term_ko": "이성교제", "term_vi": "Quan hệ tình cảm", "def_ko": "이성과의 관계 형성", "def_vi": "Hình thành mối quan hệ với người khác giới"}, {"term_ko": "성적 욕구", "term_vi": "Nhu cầu tình dục", "def_ko": "성에 관한 욕구", "def_vi": "Nhu cầu liên quan đến tình dục"}, {"term_ko": "기호품", "term_vi": "Sản phẩm sở thích", "def_ko": "개인이 선호하는 물품", "def_vi": "Các sản phẩm mà cá nhân ưa thích"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (203, '3', '시설에 대상자의 의견 수렴 건의함을 설치하지 않았을 때 대상자가 침해받을 수 있는 권리로 옳은 것은?', '["신체구속을 받지 않을 권리", "시설 운영 전반에 관한 충분한 정보를 제공 받을 권리", "사생활과 비밀보장에 대한 권리", "노인 스스로 입소를 결정하며, 공정한 입소 계약을 맺을 권리", "시설운영과 서비스에 대한 개인적 견해를 표현하고 해결을 요구할 권리"]'::jsonb, 5, NULL, NULL, '{"1": "신체구속을 받지 않을 권리는 기본적인 인권으로, 시설에 의견 수렴 건의함의 설치 여부와는 직접적인 관계가 없습니다.\n[정답]", "5": "시설운영과 서비스에 대한 개인적 견해를 표현하고 해결을 요구할 권리는 의견 수렴을 통해 보장되는 권리입니다.", "2": "시설 운영 전반에 관한 충분한 정보를 제공 받을 권리는 정보 제공의 의무에 해당하지만, 의견 수렴 건의함의 부재와는 직접적인 연관이 없습니다.", "3": "사생활과 비밀보장에 대한 권리는 개인의 프라이버시를 보호하는 것을 의미하며, 이 경우와 연관이 없습니다.", "4": "노인이 스스로 입소를 결정하며, 공정한 입소 계약을 맺을 권리는 입소 계약 관련 권리로, 의견 수렴 건의함과는 상관이 없습니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người sử dụng dịch vụ", "def_ko": "환자, 서비스 이용자", "def_vi": "Người nhận chăm sóc, bệnh nhân"}, {"term_ko": "권리", "term_vi": "Quyền", "def_ko": "권한, 법적인 권리", "def_vi": "Quyền hợp pháp, quyền hạn"}, {"term_ko": "입소", "term_vi": "Nhập viện", "def_ko": "시설에 들어가는 것", "def_vi": "Vào cơ sở"}, {"term_ko": "의견", "term_vi": "Ý kiến", "def_ko": "생각, 의견", "def_vi": "Suy nghĩ, đề xuất"}, {"term_ko": "건의", "term_vi": "Đề xuất", "def_ko": "제안하는 것", "def_vi": "Đề nghị"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (202, '3', '노인학대의 발생요인에 해당하는 것으로 옳은 것은?', '["학력 수준의 증가", "가족관계 갈등 해소", "노인의 의존성 증가", "노인부양 의식 강화", "노인의 사회적 관계망 확대"]'::jsonb, 3, NULL, NULL, '{"1": "노인학대의 발생과는 상관이 없는 요인입니다.", "2": "가족관계 갈등 해소는 오히려 학대의 감소로 이어질 수 있습니다.\n[정답]", "3": "노인의 의존성이 증가하면 학대의 위험이 커질 수 있습니다.", "4": "노인부양 의식의 강화는 긍정적인 요인이지 학대를 유발하는 요인이 아닙니다.", "5": "노인의 사회적 관계망이 확대되면 오히려 보호받는 경우가 많습니다."}'::jsonb, '[{"term_ko": "노인학대", "term_vi": "Lạm dụng người cao tuổi", "def_ko": "노인에게 가해지는 신체적, 정신적, 정서적 폭력", "def_vi": "Bạo lực về thể chất, tâm lý, và tinh thần đối với người cao tuổi"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (201, '3', '자식 내외가 노인부모의 기본 생존 유지에 필요한 장치, 식사, 약물 등으로부터 단절하였을 때 학대의 종류로 옳은 것은?', '["신체적 학대", "정서적 학대", "성적 학대", "경제적 학대", "방임"]'::jsonb, 1, NULL, NULL, '{"1": "신체적 학대: 신체에 위한 상해나 고통을 가하는 행동입니다.\n[정답]", "2": "정서적 학대: 정신적 고통을 주는 행동이지만, 여기서는 생존 유지 단절에 해당하지 않습니다.", "3": "성적 학대: 환자의 의사에 반하는 성적 행위를 강요하는 것입니다.", "4": "경제적 학대: 재정적 자원의 이용에 대한 부적절한 처리가 해당하나, 생존 유지와는 거리가 있습니다.", "5": "방임: 필요한 돌봄을 제공하지 않는 상태로, 이 경우에 가장 적합한 유형입니다."}'::jsonb, '[{"term_ko": "노인", "term_vi": "Người cao tuổi", "def_ko": "나이가 많은 사람", "def_vi": "Người lớn tuổi"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (200, '3', '다음에 해당하는 노인학대 유형으로 옳은 것은?• 집 밖으로 나가지 못하게 통제한다. • 강제로 수감하거나 위협하여 일을 강요한다.', '["방임", "유기", "신체적 학대", "정서적 학대", "경제적 학대"]'::jsonb, 3, NULL, NULL, '{"1": "방임: 노인을 돌보지 않거나 필요한 도움을 제공하지 않는 경우를 말합니다.", "2": "유기: 노인을 단독으로 방치하여 위험에 처하게 하는 것을 의미합니다.\n[정답]", "3": "신체적 학대: 신체적 폭력이나 강압으로 신체에 피해를 주는 행위로, 질문에서 언급한 통제와 강압이 해당됩니다.", "4": "정서적 학대: 심리적 고통이나 두려움을 주는 행동을 포함합니다.", "5": "경제적 학대: 재정적 자원을 착취하거나 통제하는 것을 의미합니다."}'::jsonb, '[{"term_ko": "노인학대", "term_vi": "Lạm dụng người cao tuổi", "def_ko": "고의적으로 노인을 해치거나 방치하는 행위", "def_vi": "Hành động cố ý gây hại hoặc bỏ mặc người cao tuổi"}, {"term_ko": "강압", "term_vi": "Ép buộc", "def_ko": "무언가를 하도록 강제로 만드는 것", "def_vi": "Bắt ai đó làm điều gì đó"}, {"term_ko": "통제", "term_vi": "Kiểm soát", "def_ko": "자유롭게 행동하지 못하도록 제한하는 것", "def_vi": "Hạn chế hành động tự do"}, {"term_ko": "신체적", "term_vi": "Thân thể", "def_ko": "몸과 관련된", "def_vi": "Liên quan đến cơ thể"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (199, '3', '노인의 이성 교제를 방해, 말과 행동을 무시하고 따로 식사하게 할 때 노인학대의 유형으로 옳은 것은?', '["신체적 학대", "정서적 학대", "성적 학대", "경제적 학대", "방임"]'::jsonb, 2, NULL, NULL, '{"1": "신체적 학대: 신체에 직접적인 피해를 주는 학대 형태입니다.\n[정답]", "2": "정서적 학대: 감정적으로 상처를 주거나 무시하는 행위로 노인에게 정서적 고통을 줌.", "3": "성적 학대: 성적인 행위에 대한 학대로, 노인의 동의 없이 이루어져서는 안 됩니다.", "4": "경제적 학대: 노인의 재산이나 수입을 부당하게 관리하는 행위입니다.", "5": "방임: 필요한 보호나 돌봄을 제공하지 않는 경우를 의미합니다."}'::jsonb, '[{"term_ko": "노인", "term_vi": "이성", "def_ko": "老人", "def_vi": "性别"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (198, '3', '다음 사례에 해당하는 학대 유형으로 옳은 것은?• 요양시설 방문객들이 자주 오는 주말임에도 요양보호사는 목욕탕 문을 열어 놓고 어르신을 알몸으로 목욕을 시키고 있었다.', '["신체적 학대", "정서적 학대", "성적 학대", "경제적 학대", "자기방임"]'::jsonb, 3, NULL, NULL, '{"1": "신체적 학대는 신체에 대한 물리적 피해를 주는 행위로 이 경우와는 다르다.\n[정답]", "3": "성적 학대는 개인의 신체를 성적 목적에 이용하거나 노출시키는 행위로 여기서 어르신이 알몸으로 목욕하는 상황이 이에 해당한다.", "2": "정서적 학대는 감정적으로 상처를 주는 행위로, 이 사례에서는 해당되지 않는다.", "4": "경제적 학대는 재정적인 자산을 부당하게 이용하는 것이며 이 사례와 관계가 없다.", "5": "자기방임은 스스로 돌봄을 하지 않는 상태를 뜻하는데, 이 역시 해당되지 않는다."}'::jsonb, '[{"term_ko": "학대", "term_vi": "Lạm dụng", "def_ko": "괴롭히거나 해치는 것(한국어)", "def_vi": "Hành động gây tổn hại hoặc làm phiền"}, {"term_ko": "요양시설", "term_vi": "Cơ sở chăm sóc", "def_ko": "노인을 돌보는 시설(한국어)", "def_vi": "Cơ sở chăm sóc người cao tuổi"}, {"term_ko": "알몸", "term_vi": "Khỏa thân", "def_ko": "옷을 입지 않은 상태(한국어)", "def_vi": "Trạng thái không mặc quần áo"}, {"term_ko": "목욕", "term_vi": "Tắm", "def_ko": "물로 몸을 씻는 것(한국어)", "def_vi": "Hành động rửa cơ thể bằng nước"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (197, '3', '다음 사례에 해당하는 학대 유형으로 옳은 것은?• 대상자의 손자가 대상자가 받고 있는 국민기초생활보장 급여를 몰래 인출해가는 것을 요양보호사가 목격하였다.', '["유기", "자기방임", "경제적 학대", "정서적 학대", "신체적 학대"]'::jsonb, 3, NULL, NULL, '{"1": "유기는 대상자를 방치하거나 돌보지 않는 행위를 의미한다.", "2": "자기방임은 대상자가 스스로 자신의 건강이나 안전을 돌보지 않는 경우이다.\n[정답]", "3": "경제적 학대는 대상자의 재산이나 소득을 불법적으로 착취하는 행위로, 여기서는 손자가 대상자의 급여를 몰래 인출한 사례를 설명한다.", "4": "정서적 학대는 정신적, 정서적 고통을 주는 행위로, 이 사례와는 관련이 없다.", "5": "신체적 학대는 대상을 신체적으로 해치는 경우로, 이 사례와 관계가 없다."}'::jsonb, '[{"term_ko": "학대", "term_vi": "Lạm dụng", "def_ko": "학대(보호자 또는 가족이 피해자에게 가하는 해로운 행위)", "def_vi": "Hành vi có hại của người chăm sóc hoặc gia đình đối với nạn nhân"}, {"term_ko": "경제적", "term_vi": "Kinh tế", "def_ko": "경제적 (물질적 가치와 관련된)", "def_vi": "Liên quan đến giá trị vật chất"}, {"term_ko": "손자", "term_vi": "Cháu trai", "def_ko": "손자의 의미", "def_vi": "Con của con"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (196, '3', '다음이 내용에 해당하는 노인학대 유형으로 옳은 것은?• 치매 대상자가 고열 증세로 몸져누워 있지만 아들 내외는 치료비가 없다며 대상자를 병원에 데려가지 않고 며칠 동안 집을 비웠다.', '["신체적 학대", "정서적 학대", "경제적 학대", "방임", "유기"]'::jsonb, 4, NULL, NULL, '{"1": "신체적 학대: 신체에 직접적인 해를 가하는 행위로, 예시에는 해당하지 않습니다.", "2": "정서적 학대: 감정적으로 상처를 주는 행위나 언어적 폭력을 포함하나, 여기서는 해당하지 않습니다.", "3": "경제적 학대: 경제적 자원을 부당하게 유용하는 것이지만, 이 사례에서는 병원 치료를 거부하여 방임의 경우에 해당합니다.\n[정답]", "4": "방임: 치료가 필요한 상황에서 대상자를 방치하고 집을 비운 경우로 명백한 방임으로 판단됩니다.", "5": "유기: 의도적으로 부모나 노인을 버리는 행위로, 이 경우와는 다릅니다."}'::jsonb, '[{"term_ko": "노인학대", "term_vi": "Lạm dụng người già", "def_ko": "노인을 괴롭히는 행위", "def_vi": "Hành vi làm tổn hại đến người cao tuổi"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (195, '3', '노인학대의 유형으로 옳은 것은?• 대상자의 건강이 악화됨에도 계속 술을 마신다. • 요양보호사가 집 안을 청소하려 해도 대상자가 거부한다.', '["신체적 학대", "정서적 학대", "자기방임", "방임", "유기"]'::jsonb, 3, NULL, NULL, '{"1": "신체적 학대: 신체에 대한 직접적인 폭력을 의미합니다.", "2": "정서적 학대: 정신적 고통이나 괴롭힘을 포함합니다.\n[정답]", "3": "자기방임: 자신의 기본적인 필요를 스스로 충족시키지 못하는 상태를 의미합니다.", "4": "방임: 필요한 보호나 돌봄을 제공받지 못하는 상황입니다.", "5": "유기: 누군가를 책임지는 사람이 그을 방치하는 상태입니다."}'::jsonb, '[{"term_ko": "노인학대", "term_vi": "Lạm dụng người cao tuổi", "def_ko": "노인을 학대하거나 방치하는 행위", "def_vi": "Hành vi lạm dụng hoặc bỏ bê người già"}, {"term_ko": "자기방임", "term_vi": "Tự bỏ bê", "def_ko": "자신의 기본적인 필요를 스스로 충족하지 못함", "def_vi": "Không thể tự đáp ứng nhu cầu cơ bản"}, {"term_ko": "신체적", "term_vi": "Thể chất", "def_ko": "신체와 관련된", "def_vi": "Liên quan đến cơ thể"}, {"term_ko": "정서적", "term_vi": "Tình cảm", "def_ko": "정신적인 측면", "def_vi": "Khía cạnh tâm lý"}, {"term_ko": "방임", "term_vi": "Bỏ mặc", "def_ko": "보호가 부족한 상태", "def_vi": "Tình trạng thiếu bảo vệ"}, {"term_ko": "유기", "term_vi": "Bỏ rơi", "def_ko": "책임자에 의한 방치", "def_vi": "Bị bỏ mặc bởi người có trách nhiệm"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (194, '3', '치매 대상자를 고의적으로 가출하게 하는 학대 유형으로 옳은 것은?', '["유기", "자기방임", "정서적 학대", "신체적 학대", "경제적 학대"]'::jsonb, 1, NULL, NULL, '{"1": "유기: 보호자가 의도적으로 돌보지 않고 방치하는 행위이다.\n[정답]", "2": "자기방임: 대상자가 자신을 돌보지 않는 것을 의미한다.", "3": "정서적 학대: 언어적 폭력이나 정신적 고통을 주는 방식이다.", "4": "신체적 학대: 폭력을 행사하는 것을 포함한다.", "5": "경제적 학대: 금전적 이득을 취하기 위해 대상자를 착취하는 것이다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí", "def_ko": "기억과 사고 능력이 감소하는 병", "def_vi": "Bệnh mà làm giảm khả năng ghi nhớ và suy nghĩ"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (193, '3', '학대의 유형 (A)과 행위 (B)가 바르게 연결된 것으로 옳은 것은?', '["자기방임 가출해도 찾지 않는다.", "정서적 학대 치료를 받지 못하게 한다.", "신체적 학대 낯선 장소에 버린다.", "경제적 학대 유언장의 서명을 변조한다.", "유기 식사를 제공하지 않는다."]'::jsonb, 4, NULL, NULL, '{"1": "자기방임: 자기관리를 하지 못하는 경우로, 가출만으로는 학대와 연결되지 않음.\n[정답]", "2": "정서적 학대: 정신적인 고통을 주는 행위를 나타내며, 치료를 받지 못하게 하는 것은 정서적 학대의 예시입니다.", "3": "신체적 학대: 신체적 피해를 주는 행위를 말하며, 낯선 장소에 버리는 것은 다른 학대 유형에 더 적합합니다.", "4": "경제적 학대: 재정적인 피해를 주는 행위로, 유언장의 서명을 변조하는 것은 경제적 학대의 예시입니다.", "5": "유기: 돌보아야 할 사람을 방치하는 행위로, 식사를 제공하지 않는 것은 유기의 일종이지만, 정확한 연결은 아닙니다."}'::jsonb, '[{"term_ko": "학대", "term_vi": "Lạm dụng", "def_ko": "폭력, 신체적, 정서적, 경제적 해를 가하는 행위", "def_vi": "Hành vi gây tổn hại về thể chất, tinh thần hoặc tài chính"}, {"term_ko": "유기", "term_vi": "Bỏ rơi", "def_ko": "방치, 돌보지 않음", "def_vi": "Không chăm sóc, bỏ mặc"}, {"term_ko": "정서적", "term_vi": "Tâm lý", "def_ko": "정신적인, 감정의", "def_vi": "Tâm thần, cảm xúc"}, {"term_ko": "신체적", "term_vi": "Thể chất", "def_ko": "신체와 관련된, 육체적인", "def_vi": "Liên quan đến thể xác, cơ thể"}, {"term_ko": "경제적", "term_vi": "Kinh tế", "def_ko": "재정적, 자산의", "def_vi": "Liên quan đến tài chính, tài sản"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (192, '3', '방문요양 시 대상자 머리에 멍든 자국과 상처를 발견하였을 때 요양보호사의 대처 방법으로 옳은 것은?', '["방문간호사에게 보고한다.", "가족에게 말한다.", "시설장에게 보고한다.", "노인보호전문기관에 신고한다.", "동료 요양보호사와 의논한다."]'::jsonb, 4, NULL, NULL, '{"1": "방문간호사에게 보고한다는 방법은 중요하지만, 노인학대나 안전 문제를 신고하는 우선 조치는 아닙니다.", "2": "가족에게 말하는 것은 필요할 수 있지만, 적절한 신고 절차를 선행해야 합니다.", "3": "시설장에게 보고하는 것은 후속 조치로 필요한 경우가 있지만, 직접적인 신고는 아닙니다.\n[정답]", "4": "노인보호전문기관에 신고하는 것은 법적으로 요구되는 조치로, 신속하게 문제를 해결하기 위한 첫 번째 단계입니다.", "5": "동료 요양보호사와 의논하는 것은 유용할 수 있지만, 즉각적인 신고가 우선해야 합니다."}'::jsonb, '[{"term_ko": "방문요양", "term_vi": "Chăm sóc tại nhà", "def_ko": "집이나 시설에 가서 직접 돌보는 서비스", "def_vi": "Dịch vụ chăm sóc trực tiếp tại nhà hoặc cơ sở"}, {"term_ko": "멍든 자국", "term_vi": "Dấu hiệu bầm tím", "def_ko": "피부에 생긴 푸른자국", "def_vi": "Vết thương tim xanh hoặc bầm trên da"}, {"term_ko": "상처", "term_vi": "Vết thương", "def_ko": "피부가 다친 상태", "def_vi": "Tình trạng tổn thương da"}, {"term_ko": "신고", "term_vi": "Báo cáo", "def_ko": "공식적으로 알리는 것", "def_vi": "Việc thông báo chính thức"}, {"term_ko": "노인보호전문기관", "term_vi": "Trung tâm chuyên môn bảo vệ người cao tuổi", "def_ko": "노인 학대 및 안전 문제를 다루는 기관", "def_vi": "Cơ quan xử lý vấn đề bạo hành và an toàn cho người cao tuổi"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (191, '3', '노인 학대 문제를 해결하기 위한 유관기관 (A)과 역할 (B)을 바르게 연결한 것은?', '["의료기관 이용자 대상을 위한 학대 예방 교육", "경찰관서 학대판정을 위한 의학적 진단 및 치료", "노인보호 전문기관 학대사례 신고 접수", "법률기관 현장조사 시 동행", "노인 및 사회복지 시설 학대피해노인 후견인 지정"]'::jsonb, 3, NULL, NULL, '{"1": "의료기관 이용자 대상을 위한 학대 예방 교육: 의료기관은 주로 치료와 예방을 담당하지만, 구체적인 예방 교육을 주로 수행하지는 않음.\n[정답]", "3": "노인보호 전문기관 학대사례 신고 접수: 노인보호 전문기관은 신고 및 상담을 위한 전문 기관으로, 학대 사례를 접수하는 역할을 수행함.", "2": "경찰관서 학대판정을 위한 의학적 진단 및 치료: 경찰관서는 범죄 처벌을 위한 역할을 수행하지만, 의학적 진단 및 치료는 의료기관의 역할임.", "4": "법률기관 현장조사 시 동행: 법률기관이 현장조사를 하는 업무가 있지만, 동행하는 것은 구체적인 역할이 아님.", "5": "노인 및 사회복지 시설 학대피해노인 후견인 지정: 후견인 지정은 사회복지 전반에서 중요한 역할이지만, 특정 기관의 역할로만 명확하게 정의되지는 않음."}'::jsonb, '[{"term_ko": "노인", "term_vi": "Người cao tuổi", "def_ko": "할머니/할아버지(한국어)", "def_vi": "Ông bà"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (190, '4', '요양보호사 채용과정에서 기관장이 다음과 같이 말했을 때 요양보호사가 침해받은 권리에 해당하는 것은?"이력서를 보니 나이가 많으시네요. 아무래도 어르신을 돌보는 업무가 힘들것 같네요."', '["자유권", "참정권", "평등권", "신체적 안정 보장 권리", "휴식 및 여가 보장 권리"]'::jsonb, 3, NULL, NULL, '{"1": "자유권은 개인의 기본적인 자유를 의미하며, 이 상황과는 관계가 없습니다.\n[정답]", "3": "평등권은 모든 사람들이 동등하게 대우받아야 함을 의미하며, 이 경우 나이에 따른 차별이 해당됩니다.", "2": "참정권은 투표와 관련된 권리이며, 여기서는 관련이 없습니다.", "4": "신체적 안정 보장 권리는 신체적 안전과 관련된 권리로, 이번 상황과는 다소 차이가 있습니다.", "5": "휴식 및 여가 보장 권리는 근로자의 권리로, 현재의 상황에서는 적합하지 않습니다."}'::jsonb, '[{"term_ko": "요양보호사", "term_vi": "Người chăm sóc bệnh nhân", "def_ko": "돌봄 서비스를 제공하는 사람", "def_vi": "Người cung cấp dịch vụ chăm sóc"}, {"term_ko": "채용", "term_vi": "Tuyển dụng", "def_ko": "새로운 직원을 뽑는 과정", "def_vi": "Quy trình chọn nhân viên mới"}, {"term_ko": "기관장", "term_vi": "Giám đốc cơ sở", "def_ko": "기관의 최고 책임자", "def_vi": "Người chịu trách nhiệm cao nhất của cơ sở"}, {"term_ko": "침해", "term_vi": "Xâm phạm", "def_ko": "권리나 자유를 방해하는 것", "def_vi": "Việc cản trở quyền hoặc tự do"}, {"term_ko": "평등권", "term_vi": "Quyền bình đẳng", "def_ko": "모든 사람에게 동등하게 권리를 보장하는 것", "def_vi": "Đảm bảo quyền lợi cho mọi người một cách công bằng"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (189, '4', '다음 상황에서 요양보호사가 침해받은 권리로 옳은 것은?• 인지장애 어르신을 돌보느라 점심시간도 없이 일을 하고, 퇴근 시간 이후에도 초과수당 없이 근무를 하였다.', '["평등 관련 권리", "자유 관련 권리", "노동 관련 권리", "문화 관련 권리", "교육 관련 권리"]'::jsonb, 3, NULL, NULL, '{"1": "평등 관련 권리는 개별적 차별을 금하는 기본적인 원칙이지만, 여기서는 적용되지 않는다.", "2": "자유 관련 권리는 선택의 자유를 포함하나, 주어진 상황에서는 업무 강제가 문제가 된다.\n[정답]", "3": "노동 관련 권리는 근로자의 근무 조건과 관련되며, 초과 근무와 초과수당의 문제에 해당하여 이 상황에 적절하다.", "4": "문화 관련 권리는 개인의 문화적 표현과 생활 방식을 보호하지만, 이 사례와는 관계가 없다.", "5": "교육 관련 권리는 학습 권리를 말하며, 여기서는 관련성이 없다."}'::jsonb, '[{"term_ko": "요양보호사", "term_vi": "Người chăm sóc", "def_ko": "환자를 돌보는 직업", "def_vi": "Người chăm sóc bệnh nhân"}, {"term_ko": "침해", "term_vi": "Xâm phạm", "def_ko": "권리가 침해당하는 것", "def_vi": "Bị xâm phạm quyền"}, {"term_ko": "퇴근", "term_vi": "Về nhà", "def_ko": "근무를 마치고 집으로 돌아감", "def_vi": "Về nhà sau khi làm việc"}, {"term_ko": "초과근무", "term_vi": "Làm thêm giờ", "def_ko": "정해진 근무 시간을 초과하여 일하는 것", "def_vi": "Làm việc quá giờ quy định"}, {"term_ko": "초과수당", "term_vi": "Trả thêm", "def_ko": "초과근무에 대해 추가로 지급되는 급여", "def_vi": "Tiền lương trả thêm cho giờ làm thêm"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (188, '4', '다음 상황에서 요양보호사가 침해받은 권리로 옳은 것은?• 노인주거 시설에서 시설 내 종교활동이 있을 때마다 요양보호사들에게 종교 행사 활동 및 종교를 강요한다.', '["평등권", "자유권", "노동 관련 권리", "문화 관련 권리", "교육 관련 권리"]'::jsonb, 2, NULL, NULL, '{"1": "평등권은 모든 사람이 차별 없이 대우받아야 한다는 권리이다.\n[정답]", "2": "자유권은 개인이 자유롭게 행동할 수 있는 권리로, 종교 활동 등에 강요받지 않아야 한다.", "3": "노동 관련 권리는 근로자가 직장에서 부당한 대우를 받지 않아야 한다는 권리이다.", "4": "문화 관련 권리는 개인의 문화적 권리를 보호하는 것이지만, 이 상황에서는 직접적인 관련이 없다.", "5": "교육 관련 권리는 교육을 받을 권리로, 이 상황과는 무관하다."}'::jsonb, '[{"term_ko": "요양보호사", "term_vi": "종교", "def_ko": "돌보기 간호사", "def_vi": "tôn giáo"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (187, '4', '요양보호사의 상담 및 대체인력 지원을 위한 사업을 하는 기관으로 옳은 것은?', '["근로복지공단", "산업안전 보건공단", "장기요양요원지원센터", "요양보호협회", "노인장기요양보험 공단"]'::jsonb, 3, NULL, NULL, '{"1": "근로복지공단: 근로자의 권리 보호와 복지 향상을 위한 기관입니다. 요양보호사와는 직접적으로 연관이 없습니다.", "2": "산업안전 보건공단: 산업안전 및 보건관련 사업을 하는 기관입니다. 요양보호사와 관련된 지원은 아닙니다.\n[정답]", "3": "장기요양요원지원센터: 요양보호사 및 대체인력 지원을 위한 사업을 하는 기관입니다.", "4": "요양보호협회: 요양보호사들을 위한 협회이나, 지원 기관은 아닙니다.", "5": "노인장기요양보험 공단: 노인 장기요양에 관한 보험을 운영하는 기관으로, 직접적인 상담 지원과는 거리가 있습니다."}'::jsonb, '[{"term_ko": "요양보호사", "term_vi": "Người chăm sóc", "def_ko": "환자를 돌보는 사람", "def_vi": "Người chăm sóc bệnh nhân"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (186, '4', '요양보호사의 근로계약서에 명시해야 할 내용으로 옳은 것은?', '["기관의 회계기준", "표준서비스의 분류", "임금의 구성 항목", "직원 채용의 과정", "장기요양 인정번호"]'::jsonb, 3, NULL, NULL, '{"1": "기관의 회계기준은 근로계약서의 필수 항목이 아닙니다.", "2": "표준서비스의 분류도 계약서에 명시되지 않습니다.\n[정답]", "3": "임금의 구성 항목은 근로계약서에 반드시 포함되어야 하는 내용입니다.", "4": "직원 채용의 과정은 계약서와 관련이 없습니다.", "5": "장기요양 인정번호 또한 계약서의 필수 사항이 아닙니다."}'::jsonb, '[{"term_ko": "근로계약서", "term_vi": "Hợp đồng lao động", "def_ko": "고용 계약 문서", "def_vi": "Tài liệu hợp đồng lao động"}, {"term_ko": "명시", "term_vi": "Chỉ định", "def_ko": "구체적으로 표시하다", "def_vi": "chỉ rõ"}, {"term_ko": "임금", "term_vi": "Tiền lương", "def_ko": "급여", "def_vi": "tiền công"}, {"term_ko": "구성 항목", "term_vi": "Mục cấu thành", "def_ko": "구성 요소", "def_vi": "thành phần"}, {"term_ko": "장기요양", "term_vi": "Chăm sóc dài hạn", "def_ko": "장기 요양", "def_vi": "chăm sóc lâu dài"}, {"term_ko": "인정번호", "term_vi": "Số hiệu công nhận", "def_ko": "인증번호", "def_vi": "mã số chứng nhận"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (185, '4', '다음에 해당하는 요양보호사의 권리를 보장하는 법으로 옳은 것은?• 서비스 제공 중 요양보호사가 보호자에게 폭언 및 신체폭력의 위협을 받아 안전상의 이유로 업무를 중단하였을 때, 기관장은 요양보호사에게 해고를 하거나 그밖에 불리한 처우를 하여서는 안 된다.', '["노인복지법", "근로기준법", "산업안전보건법", "노인장기요양보험법", "산업재해보상보험법"]'::jsonb, 3, NULL, NULL, '{"1": "노인복지법: 노인에 대한 기본적인 복지 서비스를 규정하는 법입니다.\n[정답]", "2": "근로기준법: 근로자의 기본적인 권리와 조건을 규정하는 법이나, 이 경우 특정 상황과 관련성 낮음입니다.", "3": "산업안전보건법: 근로자가 안전하게 근무할 수 있는 환경을 보장하기 위한 법입니다.", "4": "노인장기요양보험법: 노인 요양 서비스를 제공하는 제도에 대한 법령입니다.", "5": "산업재해보상보험법: 산업재해에 대한 보상을 규정하는 법입니다."}'::jsonb, '[{"term_ko": "권리", "term_vi": "요양보호사", "def_ko": "권리(한국어)  권 lợi: quyền lợi(베트남어)", "def_vi": "요양보호사(한국어)  Nhân viên chăm sóc: nhân viên chăm sóc(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (184, '4', '『산업재해보상보험법』에 따른 근로자 보호의 내용으로 옳은 것은?', '["보험급여는 채권자가 압류할 수 있다.", "보험급여를 받을 권리는 2년간 유효하다.", "산업재해를 당했다는 이유로 해고할 수 없다.", "보험급여는 조세로 적용되어 세금을 부과한다.", "사업장이 폐업된 경우는 장애급여를 받지 못한다."]'::jsonb, 3, NULL, NULL, '{"1": "보험급여는 채권자가 압류할 수 없습니다.\n[정답]", "3": "산업재해를 당했다는 이유로 해고할 수 없습니다.", "2": "보험급여를 받을 권리는 2년간 유효하지 않고, 특정 조건에 따라 연장될 수 있습니다.", "4": "보험급여는 조세가 아닌 사회보험으로 적용되어 세금이 부과되지 않습니다.", "5": "사업장이 폐업된 경우에도 일정 조건 하에 장애급여를 받을 수 있습니다."}'::jsonb, '[{"term_ko": "산업재해", "term_vi": "Tai nạn nghề nghiệp", "def_ko": "사고 nghề nghiệp(한국어)", "def_vi": "Tai nạn xảy ra trong quá trình làm việc"}, {"term_ko": "보험급여", "term_vi": "Tiền bảo hiểm", "def_ko": "보험으로부터 지급받는 금전적 도움(한국어)", "def_vi": "Sự trợ giúp tài chính từ bảo hiểm"}, {"term_ko": "해고", "term_vi": "Sa thải", "def_ko": "근로칸에서 쫓겨나다(한국어)", "def_vi": "Bị đuổi việc"}, {"term_ko": "조세", "term_vi": "Thuế", "def_ko": "정부에 의해 부과되는 세금(한국어)", "def_vi": "Thuế áp dụng bởi chính phủ"}, {"term_ko": "장애급여", "term_vi": "Trợ cấp khuyết tật", "def_ko": "장애로 인해 지급되는 금융 지원(한국어)", "def_vi": "Hỗ trợ tài chính do khuyết tật"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (183, '4', '다음 내용과 같은 성희롱 유형으로 옳은 것은?• 음탕하고 상스러운 이야기 • 옆에 앉아서 술을 따르라고 말함', '["언어적 성희롱", "시각적 성희롱", "사회적 성희롱", "육체적 성희롱", "물리적 성희롱"]'::jsonb, 1, NULL, NULL, '{"1": "언어적 성희롱은 음탕하고 상스러운 이야기 등 언어를 통해 이루어지는 성희롱을 의미한다.\n[정답]", "2": "시각적 성희롱은 음란한 시각적 표현을 포함하는 성희롱이다.", "3": "사회적 성희롱은 사회적 관계를 이용한 성희롱을 의미한다.", "4": "육체적 성희롱은 신체적 접촉을 포함한다.", "5": "물리적 성희롱은 물리적인 힘이나 압력을 이용한 성희롱이다."}'::jsonb, '[{"term_ko": "성희롱", "term_vi": "Quấy rối tình dục", "def_ko": "성적으로 불쾌감을 주는 행동", "def_vi": "Hành động gây khó chịu về mặt tình dục"}, {"term_ko": "음탕", "term_vi": "Dâm đãng", "def_ko": "음란하고 추잡한", "def_vi": "Khiêu dâm và thô tục"}, {"term_ko": "상스러운", "term_vi": "Thô tục", "def_ko": "상징적이고 추잡한", "def_vi": "Mang tính biểu thị và khiếm nhã"}, {"term_ko": "언어적", "term_vi": "Bằng lời nói", "def_ko": "말을 통한", "def_vi": "Qua lời nói"}, {"term_ko": "시각적", "term_vi": "Bằng hình ảnh", "def_ko": "시각을 통한", "def_vi": "Qua hình ảnh"}, {"term_ko": "사회적", "term_vi": "Xã hội", "def_ko": "사회적 관계와 관련된", "def_vi": "Liên quan đến mối quan hệ xã hội"}, {"term_ko": "육체적", "term_vi": "Thân thể", "def_ko": "신체와 관련된", "def_vi": "Liên quan đến cơ thể"}, {"term_ko": "물리적", "term_vi": "Vật lý", "def_ko": "물리적인 힘과 관련된", "def_vi": "Liên quan đến sức mạnh vật lý"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (182, '4', '다음에 해당하는 성희롱 유형으로 옳은 것은?• 신체 일부를 밀착하거나 잡아당김 • 뒤에서 껴안기', '["시각적 성희롱", "언어적 성희롱", "육체적 성희롱", "사회적 성희롱", "위계적 성희롱"]'::jsonb, 3, NULL, NULL, '{"1": "시각적 성희롱: 성적으로 부적절한 시각적 자극에 해당합니다.", "2": "언어적 성희롱: 성적 언어 표현이나 농담 등으로 상대방을 불쾌하게 하는 경우입니다.\n[정답]", "3": "육체적 성희롱: 타인의 신체를 밀착하거나 잡아당기는 등의 행동을 포함합니다.", "4": "사회적 성희롱: 직장 내 사회적 위치를 이용하여 성적 압박을 가하는 경우입니다.", "5": "위계적 성희롱: 권력 관계를 이용한 성희롱을 뜻합니다."}'::jsonb, '[{"term_ko": "성희롱", "term_vi": "Quấy rối tình dục", "def_ko": "성적인 행동이나 말로 불쾌감을 주는 것", "def_vi": "Hành động hoặc lời nói gây khó chịu về mặt tình dục"}, {"term_ko": "육체적", "term_vi": "Vật lý", "def_ko": "신체와 관련된", "def_vi": "Liên quan đến cơ thể"}, {"term_ko": "언어적", "term_vi": "Ngôn ngữ", "def_ko": "언어와 관련된", "def_vi": "Liên quan đến ngôn ngữ"}, {"term_ko": "위계", "term_vi": "Cấp bậc", "def_ko": "권력을 기반으로 한", "def_vi": "Dựa trên quyền lực"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (181, '4', '대상자의 행위 중 시각적 성희롱에 해당하는 것으로 옳은 것은?', '["성적인 정보를 의도적으로 유포하기", "뒤에서 껴안기", "외모에 대한 성적인 평가", "음란한 내용의 편지 보내기", "옆에 앉으며 허리 잡아당기기"]'::jsonb, 4, NULL, NULL, '{"1": "성적인 정보를 의도적으로 유포하기는 전반적으로 성희롱에 해당하나, 시각적 성희롱에는 포함되지 않습니다.\n[정답]", "4": "음란한 내용의 편지 보내기는 명백한 시각적 성희롱으로 이해됩니다.", "2": "뒤에서 껴안기는 신체적 성희롱입니다.", "3": "외모에 대한 성적인 평가는 심리적 성희롱에 해당하지만, 시각적이지 않습니다.", "5": "옆에 앉으며 허리 잡아당기기는 신체적 성희롱입니다."}'::jsonb, '[{"term_ko": "행위", "term_vi": "Hành vi", "def_ko": "행동(한국어)", "def_vi": "hành động(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (180, '4', '성희롱 유형 (A)과 행위 (B)가 올바르게 연결된 것은?', '["언어적 성희롱 신체 일부를 잡아당김", "육체적 성희롱 성과 관련된 농담을 함", "육체적 성희롱 음란한 사진을 보여 줌", "시각적 성희롱 외모에 관한 성적인 비유를 함", "시각적 성희롱 성과 관련한 신체부위를 고의적으로 노출함"]'::jsonb, 5, NULL, NULL, '{"1": "언어적 성희롱은 주로 말이나 언어를 통해 이루어지는 것으로, 신체 일부를 잡아당기는 행위는 신체적 성희롱에 해당합니다.\n[정답]", "5": "시각적 성희롱은 성적으로 노출된 신체부위를 의도적으로 드러내는 행위로, 성과 관련한 신체부위를 고의적으로 노출하는 것은 올바른 연결입니다.", "3": "육체적 성희롱에서는 음란한 사진을 보여주는 경우가 해당하지만, 이는 시각적 성희롱의 예로 볼 수 있습니다.", "4": "외모에 관한 성적인 비유는 언어적 성희롱으로 분류됩니다.", "2": "성과 관련된 농담은 언어적 성희롱의 일종입니다."}'::jsonb, '[{"term_ko": "성희롱", "term_vi": "Quấy rối tình dục", "def_ko": "성적 수치를 느끼게 하는 행위", "def_vi": "Hành vi gây cảm giác xúc phạm tình dục"}, {"term_ko": "행위", "term_vi": "Hành động", "def_ko": "행동", "def_vi": "Hành vi"}, {"term_ko": "언어적", "term_vi": "Bằng lời", "def_ko": "말로", "def_vi": "Bằng ngôn ngữ"}, {"term_ko": "육체적", "term_vi": "Thân thể", "def_ko": "신체적", "def_vi": "Cơ thể"}, {"term_ko": "시각적", "term_vi": "Thị giác", "def_ko": "시각적", "def_vi": "Thị giác"}, {"term_ko": "외모", "term_vi": "Ngoại hình", "def_ko": "외관", "def_vi": "Hình thức"}, {"term_ko": "비유", "term_vi": "So sánh", "def_ko": "비유", "def_vi": "So sánh"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (179, '4', '대상자로부터 요양보호사가 성희롱을 당했을 때 장기요양기관장의 대처 방법으로 옳은 것은?', '["대상자를 다른 요양기관으로 전원시킨다.", "대상자 가족에게 시정해줄 것을 요구한다.", "기관장이 판단하에 요양보호사를 조리 업무에 배치시킨다.", "대상자가 원하면 성희롱 예방교육을 제공한다.", "요양보호사에게 심리치료가 필요하다고 판단되면 기관장이 직접 치료한다."]'::jsonb, 2, NULL, NULL, '{"1": "대상자를 다른 요양기관으로 전원시키는 것은 문제의 본질을 해결하지 못합니다.\n[정답]", "2": "대상자 가족에게 시정해줄 것을 요구하는 것은 올바른 대처 방법입니다.", "3": "기관장이 판단하에 요양보호사를 조리 업무에 배치하는 것은 적절하지 않습니다.", "4": "대상자가 원하면 성희롱 예방교육을 제공하는 것은 필요하지만, 이러한 상황에서는 즉각적인 조치가 우선입니다.", "5": "요양보호사에게 심리치료가 필요하다고 판단되면 기관장이 직접 치료하는 것은 부적절합니다."}'::jsonb, '[{"term_ko": "성희롱", "term_vi": "Quấy rối tình dục", "def_ko": "성적 언행으로 상대방을 괴롭히는 행위", "def_vi": "Hành vi làm phiền người khác bằng cách nói hoặc hành động liên quan đến tình dục"}, {"term_ko": "장기요양기관", "term_vi": "Cơ sở chăm sóc dài hạn", "def_ko": "요양 서비스를 제공하는 곳", "def_vi": "Nơi cung cấp dịch vụ chăm sóc"}, {"term_ko": "대상자", "term_vi": "Người nhận dịch vụ", "def_ko": "요양 서비스를 받는 사람", "def_vi": "Người nhận dịch vụ chăm sóc"}, {"term_ko": "기관장", "term_vi": "Giám đốc", "def_ko": "기관의 책임자", "def_vi": "Người đứng đầu cơ sở"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (178, '4', '요양보호사가 상습적으로 성희롱을 당했을 때 대처 방법으로 옳은 것은?', '["대상자에게 1년에 한 번씩 성폭력 예방교육을 한다.", "몰래 녹취하거나 일자를 작성한다.", "요양보호사는 외부 전문기관에 문의 및 상담을 한다.", "보호자에게 연락하고 서비스를 중단한다.", "요양보호사의 업무를 주방보조로 변경한다."]'::jsonb, 3, NULL, NULL, '{"1": "성폭력 예방교육은 중요하지만, 1년에 한 번씩 교육하는 것만으로는 대처할 수 없다.\n[정답]", "2": "몰래 녹취하거나 일자를 작성하는 것은 일부 상황에서 도움이 될 수 있지만, 전문기관에 상담하는 것이 가장 중요하다.", "3": "외부 전문기관에 문의 및 상담하는 것은 올바른 대처 방법이다.", "4": "보호자에게 연락하고 서비스를 중단하는 것은 상황에 따라 다르지만, 직접적인 해결에는 도움이 되지 않는다.", "5": "업무를 주방보조로 변경하는 것은 문제를 해결하는 방법이 아니다."}'::jsonb, '[{"term_ko": "요양보호사", "term_vi": "Nhân viên chăm sóc", "def_ko": "노인을 돌보는 전문 직종", "def_vi": "Nghề chuyên chăm sóc người già"}, {"term_ko": "성희롱", "term_vi": "Quấy rối tình dục", "def_ko": "성적인 괴롭힘", "def_vi": "Hành vi gây khó chịu về mặt tình dục"}, {"term_ko": "상습적", "term_vi": "Thường xuyên", "def_ko": "반복적인", "def_vi": "Lặp lại"}, {"term_ko": "대처", "term_vi": "Xử lý", "def_ko": "대응하다", "def_vi": "Đối phó"}, {"term_ko": "전문기관", "term_vi": "Cơ quan chuyên môn", "def_ko": "전문적인 기관", "def_vi": "Tổ chức chuyên nghiệp"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (177, '4', '시설에서 대상자가 다른 대상자를 성희롱하는 것을 발견하였을 때 대처 방법으로 옳은 것은?', '["큰 소리로 단호하게 꾸짖는다.", "대상자의 행동을 못 본 척한다.", "가족에게 알리고 퇴소시킨다.", "동료 요양보호사와 대처 방법을 의논한다.", "행이를 중단시키고 시설장에게 즉시 알린다."]'::jsonb, 5, NULL, NULL, '{"1": "큰 소리로 단호하게 꾸짖는 것은 상황을 악화시킬 수 있으므로 부적절합니다.\n[정답]", "5": "행위를 중단시키고 시설장에게 즉시 알리는 것이 가장 적절한 대처 방법입니다.", "2": "대상자의 행동을 못 본 척하는 것은 문제를 방치하는 것이므로 바람직하지 않습니다.", "3": "가족에게 알리고 퇴소시키는 것은 상황을 바로잡는 것이 아닌, 피해자를 더 위험에 처할 수 있는 방법입니다.", "4": "동료 요양보호사와 대처 방법을 의논하는 것은 좋지만, 즉각적인 행동이 필요한 상황에서 지체되는 것은 문제입니다."}'::jsonb, '[{"term_ko": "성희롱", "term_vi": "Quấy rối tình dục", "def_ko": "부적절한 성적 언행(한국어)", "def_vi": "Những hành vi lời nói không thích hợp về tình dục(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (176, '4', '요양보호사의 윤리적 태도로 옳은 것은?', '["수급자 부재 시 들어가지 말고, 다음 방문일을 메모해둔다.", "보호자가 원하는 대로 서비스를 해준다.", "요양보호사와 같은 종교를 가진 대상자에게 더 잘해준다.", "업무상 알게 된 대상자의 비밀을 시설장과 공유한다.", "대상자의 동의 없이 오래된 물건은 버린다."]'::jsonb, 1, NULL, NULL, '{"1": "수급자가 부재할 때 다음 방문일을 메모하는 것은 윤리적으로 올바른 행동입니다.\n[정답]", "2": "보호자의 요청이 무조건적으로 수용되는 것은 윤리적이지 않습니다.", "3": "특정 종교를 가진 대상자에게만 특별히 대하는 것은 공정하지 않으며 윤리적이지 않습니다.", "4": "업무상 알게 된 비밀은 대상자와의 신뢰를 저해하므로 비공유가 바람직합니다.", "5": "대상자의 동의 없이 물건을 버리는 것은 권리를 침해할 수 있습니다."}'::jsonb, '[{"term_ko": "요양보호사", "term_vi": "Người chăm sóc", "def_ko": "돌보는 사람", "def_vi": "Người chăm sóc cho người khác"}, {"term_ko": "윤리적", "term_vi": "Đạo đức", "def_ko": "도덕적인", "def_vi": "Liên quan đến đúng sai"}, {"term_ko": "수급자", "term_vi": "Người nhận dịch vụ", "def_ko": "서비스 받는 사람", "def_vi": "Người được chăm sóc"}, {"term_ko": "비밀", "term_vi": "Bí mật", "def_ko": "은밀한 정보", "def_vi": "Thông tin riêng tư"}, {"term_ko": "동의", "term_vi": "Đồng ý", "def_ko": "허락", "def_vi": "Sự cho phép"}, {"term_ko": "물건", "term_vi": "Đồ vật", "def_ko": "사물", "def_vi": "Vật phẩm"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (175, '4', '다음 상황에서 직업윤리를 준수한 요양보호사의 태도로 옳은 것은?• 서비스 제공 중 대상자의 전화통화 내용을 듣게 된 요양보호사는 배우자의 외도 사실을 알게 되었다.', '["대상자를 공감하며 위로한다.", "다른 대상자에게 이야기한다.", "동료 요양보호사에게 전달한다.", "대상자에게 외도 사유를 묻는다.", "비밀을 유지하고 내색하지 않는다."]'::jsonb, 5, NULL, NULL, '{"1": "대상자를 공감하며 위로하는 것은 긍정적이나, 개인적인 비밀을 알게 된 상황에서 적절하지 않다.\n[정답]", "5": "비밀을 유지하고 내색하지 않는 것이 올바른 직업윤리의 태도이다.", "2": "다른 대상자에게 이야기하는 것은 직업윤리에 반하는 행위이다.", "3": "동료 요양보호사에게 전달하는 것도 비밀을 누설하는 행위이므로 옳지 않다.", "4": "대상자에게 외도 사유를 묻는 것은 사생활 침해가 된다."}'::jsonb, '[{"term_ko": "직업윤리", "term_vi": "Đạo đức nghề nghiệp", "def_ko": "직업에서의 도덕적 원칙", "def_vi": "Nguyên tắc đạo đức trong công việc"}, {"term_ko": "비밀", "term_vi": "Bí mật", "def_ko": "타인에게 알려지지 않도록 숨기는 것", "def_vi": "Điều không được tiết lộ cho người khác"}, {"term_ko": "공감", "term_vi": "Đồng cảm", "def_ko": "감정을 이해하고 함께 느끼는 것", "def_vi": "Hiểu và cảm nhận cảm xúc của người khác"}, {"term_ko": "사생활", "term_vi": "Cuộc sống riêng tư", "def_ko": "개인의 사적인 생활", "def_vi": "Cuộc sống cá nhân của mỗi người"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (174, '4', '다음 사례에서 요양보호사가 준수한 직업윤리로 옳은 것은?• 방문요양 시 대상자가 손주의 간식을 만들어 달라고 부탁하였을 때, 급여내용에 없어 서비스를 제공할 수 없다고 정중히 거절함', '["협력하려는 태도", "자기계발을 하려는 태도", "인권을 옹호하려는 태도", "전문상담가로서의 태도", "규정에 따라 업무를 수행하려는 태도"]'::jsonb, 5, NULL, NULL, '{"1": "협력하려는 태도: 요양보호사가 협력을 하는 것으로 오해할 수 있지만, 서비스 제공의 원칙을 따르는 것이 중요합니다.\n[정답]", "5": "규정에 따라 업무를 수행하려는 태도: 요양보호사가 제공할 수 있는 서비스의 범위를 이해하고 이를 준수해서 탈선을 막는 행동입니다.", "2": "자기계발을 하려는 태도: 요양보호사의 개인적인 성장과 개발은 중요하지만, 이 사례와는 관련이 없습니다.", "3": "인권을 옹호하려는 태도: 인권 존중은 중요한 가치이나, 이 사례의 주된 내용은 아닙니다.", "4": "전문상담가로서의 태도: 전문 상담가는 다른 역할을 수행하기 때문에 이 사례와 부합하지 않습니다."}'::jsonb, '[{"term_ko": "직업윤리", "term_vi": "Đạo đức nghề nghiệp", "def_ko": "직업 생활에서 지켜야 할 기본적인 도리와 규범", "def_vi": "Những quy tắc và quy định cơ bản cần tuân theo trong công việc"}, {"term_ko": "규정", "term_vi": "Quy định", "def_ko": "특정한 기준이나 규칙", "def_vi": "Tiêu chuẩn hoặc quy tắc cụ thể"}, {"term_ko": "서비스", "term_vi": "Dịch vụ", "def_ko": "제공되는 지원이나 도움", "def_vi": "Hỗ trợ hoặc giúp đỡ được cung cấp"}, {"term_ko": "협력", "term_vi": "Hợp tác", "def_ko": "함께 일하는 것", "def_vi": "Làm việc cùng nhau"}, {"term_ko": "자기계발", "term_vi": "Phát triển bản thân", "def_ko": "자신의 능력을 개발하는 것", "def_vi": "Phát triển khả năng của bản thân"}, {"term_ko": "인권", "term_vi": "Nhân quyền", "def_ko": "사람으로서의 권리", "def_vi": "Quyền của con người"}, {"term_ko": "전문상담가", "term_vi": "Cố vấn chuyên nghiệp", "def_ko": "전문가로서 상담하는 사람", "def_vi": "Người tư vấn ở tư cách chuyên gia"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (173, '4', '대상자가 연말을 앞두고 요양보호사에게 감사의 의미로 상품권을 주고자 할 때 요양보호사의 대처 방법으로 옳은 것은?', '["\"정말 왜 이러세요!\"라고 정색하며 거절한다.", "\"고맙습니다.\"라고 하며 받은 후 다음 날 돌려준다.", "\"이런 것 받으면 안 됩니다. 마음만 받겠습니다.\"라고 정중히 거절한다.", "\"다음에 좋아하는 케이크를 사다 드릴게요.\"라며 받는다.", "\"마침 센터에서 기부행사가 있는데 잘됐네요.\"라며 받는다."]'::jsonb, 3, NULL, NULL, '{"1": "정색하며 거절하는 것은 부적절한 태도이다.\n[정답]", "2": "상품권을 받은 후 다음 날 돌려주는 것은 마음을 상하게 할 수 있다.", "3": "''이런 것 받으면 안 됩니다. 마음만 받겠습니다.''라고 정중히 거절하는 것이 바람직하다.", "4": "''다음에 좋아하는 케이크를 사다 드릴게요.''라고 하면 부담스럽게 느낄 수 있다.", "5": "기부행사와 관련된 언급은 상황에 따라 부적절할 수 있다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người nhận", "def_ko": "환자나 고객", "def_vi": "bệnh nhân hoặc khách hàng"}, {"term_ko": "상품권", "term_vi": "Thẻ quà tặng", "def_ko": "상점에서 사용할 수 있는 카드 형식의 쿠폰", "def_vi": "thẻ coupon sử dụng tại cửa hàng"}, {"term_ko": "대처", "term_vi": "Đối phó", "def_ko": "대응 방법", "def_vi": "phương pháp ứng xử"}, {"term_ko": "정중히", "term_vi": "Lịch sự", "def_ko": "예의 바르게", "def_vi": "một cách tôn trọng"}, {"term_ko": "부담스럽다", "term_vi": "Cảm thấy áp lực", "def_ko": "부담을 주다", "def_vi": "gây áp lực"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (172, '4', '시설에서 요양보호사가 지켜야 할 직업윤리로 옳은 것은?', '["타 직종과의 협력보다 업무의 신속성을 중시한다.", "서비스 제공 시 시설장의 의사결정을 우선한다.", "대상자가 실수를 하면 질책하여 재발을 방지한다.", "자신의 종료를 권유하기 위해 친절을 베푼다.", "보수교육을 통해 전문적 지식과 기술을 익힌다."]'::jsonb, 5, NULL, NULL, '{"1": "타 직종과의 협력보다 업무의 신속성을 중시한다. 이 선택지는 직업윤리와 할당된 책임을 소홀히 할 수 있기 때문에 옳지 않습니다.\n[정답]", "5": "보수교육을 통해 전문적 지식과 기술을 익힌다. 이는 요양보호사가 직업적 윤리를 지키기 위해 필요한 중요한 요소입니다.", "2": "서비스 제공 시 시설장의 의사결정을 우선한다. 이는 협업보다 개인의 의사결정이 중요하여 바람직하지 않습니다.", "3": "대상자가 실수를 하면 질책하여 재발을 방지한다. 이는 긍정적인 피드백 대신 부정적인 접근으로 해결하려는 것이기 때문에 적절하지 않습니다.", "4": "자신의 종료를 권유하기 위해 친절을 베푼다. 이는 업무의 본질이 아닌 개인의 이익을 위해 친절을 베푸는 것이기 때문에 올바르지 않습니다."}'::jsonb, '[{"term_ko": "직업윤리", "term_vi": "Đạo đức nghề nghiệp", "def_ko": "직업에서 지켜야 할 도리와 규범", "def_vi": "Nghĩa vụ và quy tắc cần tuân theo trong nghề nghiệp"}, {"term_ko": "보수교육", "term_vi": "Đào tạo bổ sung", "def_ko": "지속적인 교육을 통해 기술과 지식을 보완하는 것", "def_vi": "Bổ sung kỹ năng và kiến thức thông qua việc học liên tục"}, {"term_ko": "서비스 제공", "term_vi": "Cung cấp dịch vụ", "def_ko": "특정 고객에게 서비스를 제공하는 것", "def_vi": "Cung cấp dịch vụ cho khách hàng cụ thể"}, {"term_ko": "시설장", "term_vi": "Giám đốc cơ sở", "def_ko": "특정 시설의 관리자", "def_vi": "Người quản lý một cơ sở cụ thể"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (171, '4', '요양보호사가 지켜야 할 직업윤리로 옳은 것은?', '["대상자와 상호 대등한 관계임을 인식한다.", "계획된 것보다 시간을 줄여 서비스를 제공한다.", "대상자의 성별에 따라 서비스 내용을 달리한다.", "대상자 부재 시에 서비스를 제공하고 메모를 남긴다.", "타 직종과의 협력보다 업무의 신속성을 중요시한다."]'::jsonb, 1, NULL, NULL, '{"1": "대상자와 상호 대등한 관계임을 인식하는 것은 요양보호사의 기본적 윤리이다.\n[정답]", "2": "계획된 것보다 시간을 줄여 서비스를 제공하는 것은 윤리에 어긋난다.", "3": "대상자의 성별에 따라 서비스 내용을 달리하는 것은 차별이 될 수 있다.", "4": "대상자 부재 시에 서비스를 제공하고 메모를 남기는 것은 신뢰성을 떨어뜨릴 수 있다.", "5": "타 직종과의 협력보다 업무의 신속성을 중요시하는 것은 협업의 중요성을 간과하는 것이다."}'::jsonb, '[{"term_ko": "직업윤리", "term_vi": "대상자", "def_ko": "직업에서 지켜야 할 도덕적 원칙(직 nghiệp đạo đức)", "def_vi": "서비스를 받는 사람(người nhận dịch vụ)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (170, '4', '요양보호사의 직업윤리 원칙으로 옳은 것은?', '["기관의 결정을 우선시한다.", "보호자의 판단대로 서비스를 제공한다.", "대상자와 수직적 관계를 유지한다.", "복지용구가 필요하다고 하면 대여해준다.", "제공된 서비스 내용은 정확히 기록한다."]'::jsonb, 5, NULL, NULL, '{"1": "기관의 결정을 우선시하는 것은 직업윤리가 아닙니다.", "2": "보호자의 판단대로 서비스를 제공하는 것은 윤리적으로 문제가 될 수 있습니다.", "3": "대상자와 수직적 관계를 유지하는 것은 바람직하지 않습니다.\n[정답]", "4": "복지용구가 필요하다고 하면 대여해주는 것은 윤리적입니다.", "5": "제공된 서비스 내용은 정확히 기록해야 합니다."}'::jsonb, '[{"term_ko": "직업윤리", "term_vi": "Nguyên tắc đạo đức nghề nghiệp", "def_ko": "직업 활동에서 지켜야 할 도덕적 원칙", "def_vi": "Nguyên tắc đạo đức cần tuân thủ trong hoạt động nghề nghiệp"}, {"term_ko": "보호자", "term_vi": "Người bảo vệ", "def_ko": "환자의 보호자", "def_vi": "Người chăm sóc bệnh nhân"}, {"term_ko": "복지용구", "term_vi": "Thiết bị phúc lợi", "def_ko": "복지 목적으로 사용하는 기구", "def_vi": "Công cụ sử dụng cho mục đích phúc lợi"}, {"term_ko": "수직적 관계", "term_vi": "Mối quan hệ theo chiều dọc", "def_ko": "위아래 관계", "def_vi": "Quan hệ lên xuống"}, {"term_ko": "정확히", "term_vi": "Chính xác", "def_ko": "틀림없이, 잘못되지 않게", "def_vi": "Không sai, không nhầm lẫn"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (169, '4', '다음의 상황에서 요양보호사의 대처방법으로 옳은 것은?• 동료 요양보호사가 개인적인 일이 있을 때마다 서비스를 대신 제공해줄 것을 요청한다.', '["고민해 보겠다고 하며 대답을 피한다.", "직업윤리에 위배된다며 거절한다.", "다른 동료 요양보호사를 연결해준다.", "동료 요양보호사에게 별도의 수고비를 요구한다.", "개인 용무가 있을 때마다 서로의 부탁을 들어주고자 한다."]'::jsonb, 2, NULL, NULL, '{"1": "고민해 보겠다고 하며 대답을 피한다는 것은 회피하는 태도로, 적절하지 않습니다.\n[정답]", "2": "직업윤리에 위배된다며 거절하는 것이 올바른 대처입니다.", "3": "다른 동료 요양보호사를 연결해주는 것은 책임을 회피하는 것으로 판단됩니다.", "4": "동료 요양보호사에게 별도의 수고비를 요구하는 것은 비윤리적입니다.", "5": "개인 용무가 있을 때마다 서로의 부탁을 들어주겠다는 것은 비정상적인 상호 의존 관계를 초래할 수 있습니다."}'::jsonb, '[{"term_ko": "대처방법", "term_vi": "Cách ứng phó", "def_ko": "대처 방식(한국어)", "def_vi": "Cách xử lý tình huống"}, {"term_ko": "직업윤리", "term_vi": "Đạo đức nghề nghiệp", "def_ko": "직업의 도리와 가치(한국어)", "def_vi": "Đạo đức trong công việc"}, {"term_ko": "동료", "term_vi": "Đồng nghiệp", "def_ko": "같은 직장에서 일하는 사람(한국어)", "def_vi": "Người làm cùng nghề"}, {"term_ko": "수고비", "term_vi": "Phí công sức", "def_ko": "추가 비용(한국어)", "def_vi": "Chi phí thêm"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (168, '4', '재가서비스 중 치매 대상자의 증상이 악화되어 서서 대변을 보는 행동을 보일 때 대처방법으로 옳은 것은?', '["식사량을 줄이겠다고 한다.", "서비스를 중단하겠다고 말한다.", "방으로 데려가 기저귀를 채운다.", "변화된 증상을 관할하여 기록한다.", "재가서비스 제공이 어렵다며 시설 입소를 유도한다."]'::jsonb, 4, NULL, NULL, '{"1": "식사량을 줄이는 것은 증상 악화를 초래할 수 있다.\n[정답]", "4": "변화된 증상을 관찰하여 기록하는 것은 중요하며, 적절한 대처 방법이다.", "2": "서비스를 중단하는 것은 문제 해결에 도움이 되지 않는다.", "3": "기저귀를 채우는 것은 일시적인 대처일 뿐, 문제의 본질을 해결하지 않는다.", "5": "시설 입소를 유도하는 것은 섣부른 판단일 수 있다."}'::jsonb, '[{"term_ko": "재가서비스", "term_vi": "치매", "def_ko": "가정에서 제공되는 서비스(dịch vụ tại nhà)", "def_vi": "기억력, 사고, 행동의 기능이 저하되는 질병(người bị mất trí nhớ)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (167, '4', '대상자가 본인부담금 할인을 요구할 때 요양보호사의 대처방법으로 옳은 것은?', '["\"네, 시설장님과 의논해보고 말씀드릴게요.\"", "\"그럴 리가요? 다시 알아보시고 말씀해주세요.\"", "\"다른 대상자를 소개해 주시면 싸게 해 드릴게요.\"", "\"고민해보고 내일 말씀드릴게요.\"", "\"불법이라서 저희 센터에서는 할 수 없습니다.\""]'::jsonb, 5, NULL, NULL, '{"1": "''시설장님과 의논해보겠다''는 답변은 책임 회피처럼 보일 수 있습니다.\n[정답]", "5": "''불법이라서 저희 센터에서는 할 수 없습니다.'' 이는 합법적인 차원에서 잘 대처한 경우입니다.", "2": "''그럴 리가요? 다시 알아보시고 말씀해주세요.''는 오히려 대화를 단절할 수 있습니다.", "3": "''다른 대상자를 소개해 주시면 싸게 해 드릴게요.''는 윤리적으로 문제가 될 수 있습니다.", "4": "''고민해보고 내일 말씀드릴게요.''는 결정을 미루는 것으로 부적절합니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người nhận chăm sóc", "def_ko": "환자, 수혜자", "def_vi": "Bệnh nhân, đối tượng được chăm sóc"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (166, '4', '다음 상황에서 요양보호사의 대처방법으로 옳은 것은?• 대상자가 고장난 휠체어를 바꾸고 싶은데 형편이 어렵다고 호소한다.', '["직접 구매하여 가져다준다.", "휠체어를 대여해 주고 사례금을 받는다.", "이용할 수 있는 서비스를 안내해준다.", "다른 대상자가 사용 중인 휠체어를 가져다준다.", "평소 알고 있는 업체에서 구매하도록 권유한다."]'::jsonb, 3, NULL, NULL, '{"1": "직접 구매하여 가져다주는 것은 경제적 부담을 초래할 수 있다.\n[정답]", "3": "이용할 수 있는 서비스를 안내해주는 것은 대상자의 권리를 존중하며, 필요에 따라 적절한 지원을 제공하는 방법이다.", "2": "휠체어를 대여해 주고 사례금을 받는 것은 비윤리적이다.", "4": "다른 대상자가 사용 중인 휠체어를 가져다주는 것은 적법하지 않으며 대상자에게 피해를 줄 수 있다.", "5": "평소 알고 있는 업체에서 구매하도록 권유하는 것은 대상자에게 강요하는 것으로 여겨질 수 있다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": null, "def_ko": "환자, người bệnh", "def_vi": null}, {"term_ko": "호소", "term_vi": null, "def_ko": "불만을 표현하다, kêu ca", "def_vi": null}, {"term_ko": "형편", "term_vi": null, "def_ko": "경제적 상황, tình hình tài chính", "def_vi": null}, {"term_ko": "대여", "term_vi": null, "def_ko": "잠시 사용하는 것, cho mượn", "def_vi": null}, {"term_ko": "서비스", "term_vi": null, "def_ko": "제공되는 도움, dịch vụ", "def_vi": null}, {"term_ko": "업체", "term_vi": null, "def_ko": "회사, cơ sở", "def_vi": null}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (165, '4', '재가센터에서 함께 일하고 있는 요양보호사가 서로의 부모님에게 교차서비스를 제공하는 것으로 처리하여 급여를 더 받자고 제안할 때 대처 방법으로 옳은 것은?', '["마찰을 파하기 위해 대응하지 않는다.", "윤리원칙에 어긋난다고 말하며 거부한다.", "제안을 수용할 만한 다른 요양보호사를 소개한다.", "어머니에게 교차서비스를 미리 설명한다.", "교차 서비스에 대해 주변에 비밀로 해 줄 것을 부탁한다."]'::jsonb, 2, NULL, NULL, '{"1": "마찰을 파하기 위해 대응하지 않는다. - 대응하지 않는 것은 비윤리적 제안을 묵인하는 것이므로 바람직하지 않습니다.\n[정답]", "2": "윤리원칙에 어긋난다고 말하며 거부한다. - 윤리적 원칙을 지키는 것이 중요하며, 이를 통해 올바른 판단을 할 수 있습니다.", "3": "제안을 수용할 만한 다른 요양보호사를 소개한다. - 이는 윤리적 문제를 해결하기보다는 회피하는 방법일 뿐입니다.", "4": "어머니에게 교차서비스를 미리 설명한다. - 제안 자체가 비윤리적이므로 설명하는 것은 상황을 악화시킬 수 있습니다.", "5": "교차 서비스에 대해 주변에 비밀로 해 줄 것을 부탁한다. - 비밀을 부탁하는 것은 윤리적으로 잘못된 행동입니다."}'::jsonb, '[{"term_ko": "재가센터", "term_vi": "Trung tâm chăm sóc tại nhà", "def_ko": "가정에서 서비스를 제공하는 센터", "def_vi": "Trung tâm cung cấp dịch vụ tại nhà"}, {"term_ko": "교차서비스", "term_vi": "Dịch vụ chéo", "def_ko": "서로 다른 고객에 대한 서비스 제공", "def_vi": "Cung cấp dịch vụ cho khách hàng khác nhau"}, {"term_ko": "윤리", "term_vi": "Đạo đức", "def_ko": "도덕적 원칙", "def_vi": "Nguyên tắc đạo đức"}, {"term_ko": "급여", "term_vi": "Tiền lương", "def_ko": "보수, 급여", "def_vi": "Thù lao, lương"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (164, '4', '보호자가 기저귀 재사용을 강요할 때 대처 방법으로 옳은 것은?', '["가족이 방문하는 날만 재사용을 한다.", "재사용할 수 없는 이유를 설명한다.", "오염 정도가 적으면 말려서 사용한다.", "대상자에게 알리고 서비스를 중단한다.", "보호자의 요구사항을 기록한 후 재사용한다."]'::jsonb, 2, NULL, NULL, '{"1": "가족이 방문하는 날만 재사용을 한다. 이는 상황을 피하는 방안으로, 바람직하지 않습니다.\n[정답]", "2": "재사용할 수 없는 이유를 설명한다. 이는 보호자에게 이해를 돕고 바른 결정을 유도하는 올바른 방법입니다.", "3": "오염 정도가 적으면 말려서 사용한다. 이는 위생적이지 않으므로 바람직하지 않습니다.", "4": "대상자에게 알리고 서비스를 중단한다. 이는 가장 극단적인 조치로, 다른 대안이 있을 때는 피해야 합니다.", "5": "보호자의 요구사항을 기록한 후 재사용한다. 이는 환자의 건강과 안전을 해칠 수 있습니다."}'::jsonb, '[{"term_ko": "보호자", "term_vi": "Người chăm sóc", "def_ko": "환자를 돌보는 사람", "def_vi": "Người chăm sóc bệnh nhân"}, {"term_ko": "기저귀", "term_vi": "Tã", "def_ko": "환자가 착용하는 위생 용품", "def_vi": "Dụng cụ vệ sinh mà bệnh nhân mặc"}, {"term_ko": "재사용", "term_vi": "Tái sử dụng", "def_ko": "한번 사용한 것을 다시 사용하는 것", "def_vi": "Sử dụng lại cái gì đó đã được sử dụng một lần"}, {"term_ko": "오염", "term_vi": "Ô nhiễm", "def_ko": "더러워진 상태", "def_vi": "Tình trạng bị bẩn"}, {"term_ko": "설명하다", "term_vi": "Giải thích", "def_ko": "이유를 말하는 것", "def_vi": "Nói lý do"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (163, '4', '요양보호사의 근골격계 질환 발생 가능성을 줄이는 작업 환경 조성 방법으로 옳은 것은?', '["무거운 물건을 들고 이동한다.", "문턱을 설치하여 공간을 구분한다.", "거실 중앙에 얇은 매트를 깐다.", "바닥에 물을 뿌려 습도를 유지한다.", "야간 근무 시 통로에 조명을 켜둔다."]'::jsonb, 5, NULL, NULL, '{"1": "무거운 물건을 들고 이동하는 것은 근골격계 질환을 유발할 수 있습니다.", "2": "문턱을 설치하면 이동 시 걸림돌이 되어 오히려 위험합니다.", "3": "거실 중앙에 얇은 매트를 깔면 걸려 넘어질 위험이 있습니다.", "4": "바닥에 물을 뿌리면 미끄러짐 사고의 원인이 될 수 있습니다.\n[정답]", "5": "야간 근무 시 통로에 조명을 켜두면 안전성을 높여 근골격계 질환을 예방합니다."}'::jsonb, '[{"term_ko": "근골격계", "term_vi": "Hệ cơ xương", "def_ko": "근육과 뼈로 구성된 신체의 구조", "def_vi": "Cấu trúc cơ thể bao gồm cơ và xương"}, {"term_ko": "작업", "term_vi": "Công việc", "def_ko": "일이나 행동을 수행하는 것", "def_vi": "Thực hiện công việc hoặc hành động"}, {"term_ko": "환경", "term_vi": "Môi trường", "def_ko": "주변의 상태나 상황", "def_vi": "Tình trạng hoặc tình huống xung quanh"}, {"term_ko": "예방", "term_vi": "Phòng ngừa", "def_ko": "미리 조치를 취하여 사고를 막는 것", "def_vi": "Thực hiện các biện pháp để ngăn chặn tai nạn"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (162, '4', '요양보호사에게 나타날 수 있는 수근관 증후군에 관한 설명으로 옳은 것은?', '["밤중에 통증이 감소된다.", "손목을 굴곡시키면 통증이 감소된다.", "손목에서 팔꿈치까지 강직이 나타난다.", "손을 털면 저림과 통증이 완화될 수 있다.", "새끼손가락과 연결된 손바닥 감각이 둔해진다."]'::jsonb, 4, NULL, NULL, '{"1": "밤중에 통증이 감소되는 것은 잘못된 설명입니다. 수근관 증후군은 주로 밤에 증상이 심해지는 경향이 있습니다.\n[정답]", "4": "손을 털면 저림과 통증이 완화될 수 있다는 것은 수근관 증후군의 전형적인 증상입니다.", "2": "손목을 굴곡시키면 통증이 감소되는 것은 일반적으로 정확하지 않습니다. 오히려 통증이 증가할 수 있습니다.", "3": "손목에서 팔꿈치까지 강직이 나타난다는 것은 다른 문제로, 수근관 증후군과는 관련이 없습니다.", "5": "새끼손가락과 연결된 손바닥 감각이 둔해지는 것은 주로 외측신경과 관련 있으며, 수근관 증후군과는 다릅니다."}'::jsonb, '[{"term_ko": "수근관 증후군", "term_vi": "Hội chứng ống cổ tay", "def_ko": "손목에서 발생하는 압박으로 인한 신경 증상", "def_vi": "Vấn đề về thần kinh do áp lực ở cổ tay"}, {"term_ko": "감각", "term_vi": "Cảm giác", "def_ko": "느끼는 것", "def_vi": "Cảm nhận"}, {"term_ko": "주로", "term_vi": "Chủ yếu", "def_ko": "주된 형태로", "def_vi": "Dựa chủ yếu"}, {"term_ko": "통증", "term_vi": "Đau", "def_ko": "아픔", "def_vi": "Đau đớn"}, {"term_ko": "저림", "term_vi": "Tê", "def_ko": "감각이 둔해지는 상태", "def_vi": "Trạng thái cảm giác bị tê"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (161, '4', '요통을 예방하면서 물건을 들어 올리는 방법으로 옳은 것은?', '["물건을 몸에서 멀리 둔다.", "두 발을 모아 지지면을 좁힌다.", "몸의 무게중심을 높인다.", "무릎을 굽혀 자세를 낮춘다.", "방향을 바꿀 때는 허리를 돌린다."]'::jsonb, 4, NULL, NULL, '{"1": "물건을 몸에서 멀리 두는 것은 요통을 유발할 수 있습니다.\n[정답]", "4": "무릎을 굽혀 자세를 낮추면 하체의 힘을 이용하여 안전하게 물건을 들어올릴 수 있습니다.", "2": "두 발을 모아 지지면을 좁히면 균형이 불안정해질 수 있습니다.", "3": "몸의 무게중심을 높이는 것은 무게 중심의 불균형을 초래할 수 있습니다.", "5": "방향을 바꿀 때는 허리를 돌리는 것이 아니라 몸 전체를 회전해야 합니다."}'::jsonb, '[{"term_ko": "요통", "term_vi": "Đau lưng", "def_ko": "허리 통증(한국어)", "def_vi": "Cơn đau ở thắt lưng(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (160, '4', '대상자의 체위를 변경하다가 손목을 삐어 통증이 있을 때 초기 관리 방법으로 옳은 것은?', '["손목을 가볍게 움직여 준다.", "통증부위를 심장보다 낮게 한다.", "손목부위에 압박붕대를 적용한다.", "손상 직후 손목부위에 온찜질을 한다.", "손목을 털면서 굽혔다 폈다 하는 운동을 한다."]'::jsonb, 3, NULL, NULL, '{"1": "손목을 가볍게 움직이는 것은 통증이 있을 때 오히려 상태를 악화시킬 수 있습니다.\n[정답]", "3": "손목부위에 압박붕대를 적용하는 것은 부상을 관리하는 올바른 방법입니다.", "2": "통증부위를 심장보다 낮게 두는 것은 혈액 순환에 도움이 될 수 있지만 즉각적으로 적용해야 할 방법은 아닙니다.", "4": "손상 직후 손목부위에 온찜질을 하는 것은 부상 초기에는 적절하지 않습니다.", "5": "손목을 털면서 운동을 하는 것은 추가적인 부상을 초래할 수 있습니다."}'::jsonb, '[{"term_ko": "체위", "term_vi": "Vị trí", "def_ko": "상태(한국어)", "def_vi": "Trạng thái"}, {"term_ko": "손목", "term_vi": "Cổ tay", "def_ko": "팔목(한국어)", "def_vi": "Cổ tay"}, {"term_ko": "압박붕대", "term_vi": "Băng bó áp lực", "def_ko": "압박다친 것(한국어)", "def_vi": "Băng bó làm giảm trọng lượng"}, {"term_ko": "온찜질", "term_vi": "Chườm ấm", "def_ko": "따뜻한 찜질(한국어)", "def_vi": "Chườm ấm"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (159, '4', '요양보호사의 근골격계 예방을 위한 스트레칭 시 주의사항으로 옳은 것은?', '["빠르게 움직인다.", "통증을 느낄 때까지 한다.", "동작과 동작 사이에 쉬지 않는다.", "상하좌우 균형 있게 교대로 스트레칭 한다.", "동작 시 호흡은 멈춘다."]'::jsonb, 4, NULL, NULL, '{"1": "빠르게 움직인다: 부상의 위험이 있으므로 옳지 않음.", "2": "통증을 느낄 때까지 한다: 통증은 스트레칭의 지표가 아니므로 옳지 않음.", "3": "동작과 동작 사이에 쉬지 않는다: 휴식이 필요하므로 옳지 않음.\n[정답]", "4": "상하좌우 균형 있게 교대로 스트레칭 한다: 균형 있는 스트레칭은 근골격계 예방에 효과적임.", "5": "동작 시 호흡은 멈춘다: 호흡은 계속해야 하므로 옳지 않음."}'::jsonb, '[{"term_ko": "요양보호사", "term_vi": "Người chăm sóc", "def_ko": "노인이나 장애인을 돌보는 전문가", "def_vi": "chuyên gia chăm sóc người già hoặc người khuyết tật"}, {"term_ko": "근골격계", "term_vi": "Hệ cơ xương khớp", "def_ko": "뼈와 근육으로 이뤄진 몸의 계통", "def_vi": "hệ thống cơ và xương trong cơ thể"}, {"term_ko": "스트레칭", "term_vi": "Stretching", "def_ko": "근육을 늘리는 운동", "def_vi": "bài tập kéo giãn cơ"}, {"term_ko": "균형", "term_vi": "Cân bằng", "def_ko": "대칭을 이루는 상태", "def_vi": "trạng thái đối xứng"}, {"term_ko": "통증", "term_vi": "Đau", "def_ko": "신체에 느끼는 아픔", "def_vi": "cảm giác khó chịu trong cơ thể"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (158, '4', '서비스 제공 중 요양보호사가 고열과 인후통이 있어 독감이 의심될 때 대처방법으로 옳은 것은?', '["요양보호 서비스를 중단한다.", "독갑예방 접종을 한다.", "주민자치센터에 신고한다.", "가글액으로 입안을 헹군다.", "사용하던 물품을 소독한다."]'::jsonb, 1, NULL, NULL, '{"1": "요양보호 서비스를 중단하는 것이 옳습니다. 증상이 있는 상태에서 서비스를 지속할 경우 다른 환자에게 감염을 전파할 위험이 있습니다.\n[정답]", "2": "독감 예방 접종은 일반적으로 질병이 발병하기 전에 실시해야 하며, 현재 상태에서는 접근 방법이 아닙니다.", "3": "주민자치센터에 신고하는 것은 필요하지 않습니다.", "4": "가글액으로 입안을 헹구는 것은 증상을 완화할 수 있지만, 전염병 상황에서 기본적으로 필요한 조치가 아닙니다.", "5": "사용하던 물품을 소독하는 것은 필요할 수 있지만, 가장 중요한 것은 본인의 상태를 먼저 점검하고 서비스를 중단하는 것입니다."}'::jsonb, '[{"term_ko": "서비스", "term_vi": "Dịch vụ", "def_ko": "서비스(한국어)", "def_vi": "dịch vụ(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (157, '4', '폐결핵에 관한 설명으로 옳은 것은?', '["바이러스성 감염질환이다.", "스테로이드 약물 복용으로 예방할 수 있다.", "약물 복용 중 주기적인 간 기능 검사가 필요하다.", "치료 기간 중 증상이 사라지면 약물 복용을 중단한다.", "오전에 고열이 나고 오후에 열이 내리는 증상이 반복된다."]'::jsonb, 3, NULL, NULL, '{"1": "폐결핵은 세균에 의한 감염질환으로, 바이러스성이 아닙니다.\n[정답]", "3": "폐결핵 치료 중 약물 복용 환자는 간 기능 검사를 주기적으로 해야 합니다.", "2": "스테로이드 약물은 폐결핵의 예방에 효과적이지 않습니다.", "4": "치료 중 증상이 사라진 경우에도 약물 복용을 중단해서는 안 됩니다.", "5": "폐결핵의 고열 증상은 주로 오후에 열이 나고 저녁에 해열되는 경향이 있습니다."}'::jsonb, '[{"term_ko": "폐결핵", "term_vi": "Bệnh lao phổi", "def_ko": "폐에 발생하는 결핵 감염", "def_vi": "Nhiễm trùng lao xảy ra trong phổi"}, {"term_ko": "약물", "term_vi": "Thuốc", "def_ko": "치료를 위한 화학물질", "def_vi": "Chất hóa học dùng để điều trị"}, {"term_ko": "주기적", "term_vi": "Định kỳ", "def_ko": "정기적으로 반복되는", "def_vi": "Lặp lại một cách đều đặn"}, {"term_ko": "간 기능 검사", "term_vi": "Xét nghiệm chức năng gan", "def_ko": "간의 건강을 평가하는 검사", "def_vi": "Kiểm tra tình trạng sức khỏe của gan"}, {"term_ko": "예방", "term_vi": "Phòng ngừa", "def_ko": "증상을 미리 막는 것", "def_vi": "Ngăn chặn triệu chứng xảy ra trước đó"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (156, '4', '결핵 대상자와 접촉한 후 요양보호사의 대처방법으로 옳은 것은?', '["폐렴구균을 추가 접종한다.", "예방적 항생제를 복용한다.", "멸균소독가운과 멸균장갑을 착용한다.", "기침을 할 때는 손으로 가리고 한다.", "감염 여부를 확인하기 위해 검사를 한다."]'::jsonb, 5, NULL, NULL, '{"1": "폐렴구균과 결핵은 다른 감염병이므로 추가 접종은 해당하지 않습니다.\n[정답]", "5": "감염 여부를 확인하기 위해 검사를 하는 것이 적절한 대처 방법입니다.", "2": "예방적 항생제를 복용하는 것은 특정 상황에서만 필요하며 일반적인 대처 방법은 아닙니다.", "3": "멸균소독가운과 멸균장갑을 착용하는 것만으로는 충분하지 않습니다.", "4": "기침을 할 때 손으로 가리는 것은 비위생적이며 적절한 대처가 아닙니다."}'::jsonb, '[{"term_ko": "결핵", "term_vi": "Bệnh lao", "def_ko": "폐에 영향을 미치는 감염 질환", "def_vi": "Bệnh truyền nhiễm ảnh hưởng đến phổi"}, {"term_ko": "대처", "term_vi": "Xử lý", "def_ko": "상황에 맞게 대응하는 것", "def_vi": "Phản ứng theo tình huống"}, {"term_ko": "예방", "term_vi": "Phòng ngừa", "def_ko": "병이 생기는 것을 미리 막는 것", "def_vi": "Ngăn chặn bệnh tật xảy ra"}, {"term_ko": "검사", "term_vi": "Kiểm tra", "def_ko": "질병을 확인하기 위한 과정", "def_vi": "Quá trình xác nhận bệnh tật"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (155, '4', '다음에서 설명하는 감염성 질환으로 옳은 것은?• 질환에 걸린 대상자의 구토물에 의한 감염 • 구토, 메스꺼움, 오한, 복통, 설사 증상이 있음', '["결핵", "독감", "노로바이러스 감염", "옴", "머릿니"]'::jsonb, 3, NULL, NULL, '{"1": "결핵은 주로 호흡기로 전파되는 질환으로, 여기서 설명하는 증상과는 차이가 있습니다.", "2": "독감은 호흡기 감염으로 구토, 메스꺼움, 설사가 흔하지 않습니다.\n[정답]", "3": "노로바이러스 감염은 구토 및 설사를 유발하며, 구토물에 의한 감염이 가능합니다.", "4": "옴은 피부 기생충으로 감염 증상이 다릅니다.", "5": "머릿니는 머리카락에 기생하는 기생충으로, 구토나 설사 증상이 없습니다."}'::jsonb, '[{"term_ko": "감염성 질환", "term_vi": "Bệnh truyền nhiễm", "def_ko": "감염으로 인해 발생하는 질병", "def_vi": "Bệnh xảy ra do nhiễm trùng"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (154, '4', '옴에 감염된 대상자를 돕는 방법으로 옳은 것은?', '["공용 혈압계를 사용한다.", "맨손으로 도포용 약제를 발라준다.", "증상이 있는 부위만 약을 바른다.", "대상자가 사용한 침구류를 다른 대상자의 물품과 함께 세탁한다.", "대상자와 접촉한 사람은 증상 유무와 상관없이 함께 동시에 치료한다."]'::jsonb, 5, NULL, NULL, '{"1": "공용 혈압계를 사용하면 감염이 전파될 수 있다. 따라서 잘못된 방법이다.\n[정답]", "5": "대상자와 접촉한 사람은 증상 유무와 상관없이 함께 동시에 치료해야 감염을 예방할 수 있다.", "2": "맨손으로 도포용 약제를 바르면 감염이 전파될 수 있으므로 잘못된 방법이다.", "3": "증상이 있는 부위만 약을 바르는 것은 효과적이지 않으며, 전체적으로 치료해야 한다.", "4": "대상자가 사용한 침구류는 따로 세탁하여야 다른 대상자에게 전파되지 않는다."}'::jsonb, '[{"term_ko": "옴", "term_vi": "Ghẻ", "def_ko": "피부염의 일종", "def_vi": "Một loại viêm da"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (153, '4', '감염성 질환인 머릿니 관리법으로 옳은 것은?', '["요양보호사는 귀가 후 손을 씻어 감염을 예방한다.", "세탁물을 55도 이상에서 5분 이상 노출시켜 사멸시킨다.", "수건, 옷솔 등은 공동으로 사용한다.", "치료하기 전에 2일 동안 착용한 침구류는 햇빛에 말린다.", "대상자가 앉거나 누운 바닥은 빗자루를 이용하여 청소한다."]'::jsonb, 2, NULL, NULL, '{"1": "요양보호사는 감염 예방을 위해 손을 씻는 것이 필수적이다. 그러나 이는 직접적인 관리법이 아니라 예방 조치이다.\n[정답]", "2": "세탁물을 55도 이상에서 5분 이상 노출시켜 사멸시키는 것은 머릿니를 관리하는 올바른 방법이다.", "3": "수건, 옷솔 등은 개인 위생을 위해 공동으로 사용해서는 안 된다.", "4": "치료 전에 2일 동안 착용한 침구류는 세탁 후 햇빛에 말리기보다 바로 세탁하는 것이 더 효과적이다.", "5": "대상자가 앉거나 누운 바닥은 청소가 필요하나, 빗자루로 청소하는 것은 물리적 방법으로 완전히 제거하기 어렵다."}'::jsonb, '[{"term_ko": "감염성 질환", "term_vi": "Bệnh truyền nhiễm", "def_ko": "전염병(한국어)", "def_vi": "Bệnh có thể lây lan"}, {"term_ko": "머릿니", "term_vi": "Chấy", "def_ko": "이(한국어)", "def_vi": "Rận tóc"}, {"term_ko": "관리법", "term_vi": "Phương pháp quản lý", "def_ko": "관리 방법(한국어)", "def_vi": "Cách quản lý"}, {"term_ko": "사멸", "term_vi": "Tiêu diệt", "def_ko": "죽이다(한국어)", "def_vi": "Diệt trừ"}, {"term_ko": "침구류", "term_vi": "Đồ bedding", "def_ko": "침대 시트 및 베개 커버 (한국어)", "def_vi": "Ga trải giường và gối"}, {"term_ko": "햇빛", "term_vi": "Ánh sáng mặt trời", "def_ko": "태양광선(한국어)", "def_vi": "Ánh sáng mặt trời"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (152, '4', '감염예방을 위한 요양보호사의 대처방법으로 옳은 것은?', '["대상자가 감염된 경우 보호 장구를 착용하지 않는다.", "임신한 요양보호사는 수두바이러스 질환 대상자와 접촉하지 않는다.", "독감에 걸린 요양보호사는 보호 장구 착용 후 서비스를 제공한다.", "옴에 걸린 대상자의 가족은 증상이 있을 때 치료 받는다.", "노로바이러스에 감염된 요양보호사는 2 ~ 3일간 음식조리 업무만 한다."]'::jsonb, 2, NULL, NULL, '{"1": "대상자가 감염된 경우 보호 장구를 착용하지 않는 것은 잘못된 대처입니다.\n[정답]", "2": "임신한 요양보호사는 수두바이러스 질환 대상자와 접촉하지 않아야 합니다.", "3": "독감에 걸린 요양보호사는 보호 장구를 착용한 후에도 서비스 제공을 자제해야 합니다.", "4": "옴에 걸린 대상자의 가족은 증상이 있을 때 치료를 받는 것이 아닌 조기에 치료를 받아야 합니다.", "5": "노로바이러스에 감염된 요양보호사는 음식 조리 업무를 하지 말아야 하며, 격리 조치가 필요합니다."}'::jsonb, '[{"term_ko": "감염", "term_vi": "Nhiễm trùng", "def_ko": "감염(한국어)", "def_vi": "Nhiễm bệnh"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (151, '5', '노화에 따른 변화와 노인성 질환의 특성으로 옳은 것은?', '["질병의 경과가 짧다.", "질병의 초기진단이 쉽다.", "질병 발생의 원인이 명확하다.", "가벼운 질환에도 의식장애가 발생하기 쉽다.", "약성분이 체외로 빨리 배출되어 치료가 쉽다."]'::jsonb, 4, NULL, NULL, '{"1": "질병의 경과가 짧지 않습니다.", "2": "질병의 초기 진단이 쉽지 않습니다.", "3": "질병 발생의 원인이 항상 명확하지 않습니다.\n[정답]", "4": "가벼운 질환에도 의식장애가 발생하기 쉽습니다.", "5": "약성분이 체외로 빨리 배출되지 않습니다."}'::jsonb, '[{"term_ko": "노화", "term_vi": "Lão hóa", "def_ko": "나이가 들어감(한국어)", "def_vi": "Trở nên già"}, {"term_ko": "변화", "term_vi": "Thay đổi", "def_ko": "변화(한국어)", "def_vi": "Sự thay đổi"}, {"term_ko": "노인성", "term_vi": "Người cao tuổi", "def_ko": "노인에게 발생하는(한국어)", "def_vi": "Liên quan đến người già"}, {"term_ko": "질환", "term_vi": "Bệnh tật", "def_ko": "질병(한국어)", "def_vi": "Bệnh"}, {"term_ko": "의식", "term_vi": "Ý thức", "def_ko": "의식(한국어)", "def_vi": "Ý thức"}, {"term_ko": "장애", "term_vi": "Khuyết tật", "def_ko": "방해, 문제(한국어)", "def_vi": "Sự cản trở"}, {"term_ko": "약성분", "term_vi": "Thành phần thuốc", "def_ko": "약의 성분(한국어)", "def_vi": "Thành phần của thuốc"}, {"term_ko": "체외", "term_vi": "Ngoài cơ thể", "def_ko": "체외로, 신체 밖으로(한국어)", "def_vi": "Ra ngoài cơ thể"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (150, '5', '노인에게 약물중독의 위험이 증가하는 이유로 옳은 것은?', '["대상자의 운동성 증가", "심장 근육의 수축력 증가", "신경전달물질의 분비 증가", "신장의 배설능력 감소", "폐 조직의 탄력성 감소"]'::jsonb, 4, NULL, NULL, '{"1": "대상자의 운동성이 증가하면 약물의 이용도 증가할 수 있으나 중독 위험과는 관련이 없음.", "2": "심장 근육의 수축력이 증가하면 혈액순환이 개선될 수 있지만 약물중독과는 무관함.", "3": "신경전달물질의 분비가 증가하면 오히려 약물의 효과가 줄어들 수 있어 중독 위험과는 관련이 없음.\n[정답]", "4": "신장의 배설능력이 감소하면 노인이 약물의 대사가 제대로 이루어지지 않아 약물중독의 위험이 증가함.", "5": "폐 조직의 탄력성이 감소하면 호흡기능이 저하되지만 이는 약물중독과는 직접적인 관련이 없음."}'::jsonb, '[{"term_ko": "약물중독", "term_vi": "Ngộ độc thuốc", "def_ko": "독성 약물이 체내에 과하게 축적되어 나타나는 증상", "def_vi": "Triệu chứng xuất hiện khi thuốc độc tích tụ quá mức trong cơ thể"}, {"term_ko": "운동성", "term_vi": "Vận động", "def_ko": "신체의 움직임 속도나 능력", "def_vi": "Tốc độ hoặc khả năng di chuyển của cơ thể"}, {"term_ko": "신장", "term_vi": "Thận", "def_ko": "체내 노폐물 및 수분을 여과하고 배설하는 장기", "def_vi": "Cơ quan lọc và bài tiết chất thải và nước trong cơ thể"}, {"term_ko": "배설능력", "term_vi": "Khả năng bài tiết", "def_ko": "체내 노폐물이나 약물을 배출하는 능력", "def_vi": "Khả năng thải trừ chất thải hoặc thuốc ra khỏi cơ thể"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (149, '5', '노화현상으로 인한 소화기계 증상으로 옳은 것은?', '["후각기능의 증가", "쓴맛 감각의 증가", "당내성의 증가", "지방흡수력의 증가", "약물의 대사와 제거 능력의 증가"]'::jsonb, 2, NULL, NULL, '{"1": "후각기능의 증가: 노화로 인해 후각기능이 일반적으로 감소합니다.\n[정답]", "2": "쓴맛 감각의 증가: 노화에 따라 쓴맛 감각이 더 예민해지는 경우가 많습니다.", "3": "당내성의 증가: 노화와 관련하여 당내성은 감소하는 경향이 있습니다.", "4": "지방흡수력의 증가: 지방흡수력이 감소하는 것이 일반적입니다.", "5": "약물의 대사와 제거 능력의 증가: 노화로 인해 대사 및 제거 능력은 감소합니다."}'::jsonb, '[{"term_ko": "노화", "term_vi": "Lão hóa", "def_ko": "나이가 많아지는 것", "def_vi": "Trở nên già hơn"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (148, '5', '노화로 간 기능이 변화되어 나타날 수 있는 결과로 옳은 것은?', '["당내성 증가", "타액 분비의 증가", "칼슘 흡수의 증가", "위산 분비 저하", "약물 대사 능력 저하"]'::jsonb, 5, NULL, NULL, '{"1": "당내성 증가: 노화로 인해 일반적으로 인슐린 저항성이 증가하나, 분명한 결과라 볼 수 없음.", "2": "타액 분비의 증가: 노화에 따라 오히려 타액 분비는 감소하는 경향이 있음.\n[정답]", "3": "칼슘 흡수의 증가: 노화로 인해 칼슘 흡수는 감소하며, 이는 뼈에 영향을 준다.", "4": "위산 분비 저하: 노화로 위산 분비는 저하되며, 이는 소화에 영향을 준다.", "5": "약물 대사 능력 저하: 노화로 인해 간 기능이 저하되면서 약물 대사 능력이 감소함."}'::jsonb, '[{"term_ko": "노화", "term_vi": "간", "def_ko": "늙음 (lão hóa)", "def_vi": "간 (gan)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (147, '5', '위염증상을 완화하는 데 도움이 되는 방법으로 옳은 것은?', '["복부를 시계 방향으로 마사지한다.", "염장식품의 섭취를 격려한다.", "부드러운 유동식을 제공한다.", "음식을 뜨겁게 하여 제공한다.", "음식 섭취량을 늘리도록 한다."]'::jsonb, 3, NULL, NULL, '{"1": "복부를 시계 방향으로 마사지하는 것은 일반적인 진통 완화 방법이나, 위염 증상 완화와는 직접적인 연관이 없음.\n[정답]", "3": "부드러운 유동식을 제공하는 것은 위염 환자가 소화하기에 용이하며, 증상을 완화하는 데 도움이 된다.", "2": "염장식품의 섭취는 오히려 위염 증상을 악화시킬 수 있기 때문에 권장되지 않는다.", "4": "음식을 뜨겁게 하여 제공하는 것은 위에 자극이 될 수 있어 피해야 한다.", "5": "음식 섭취량을 늘리는 것은 위에 부담을 줄 수 있으므로, 위염 환자에게 바람직하지 않다."}'::jsonb, '[{"term_ko": "위염", "term_vi": "Viêm dạ dày", "def_ko": "위의 염증", "def_vi": "Viêm của dạ dày"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (146, '5', '위궤양 대상자를 돕는 방법으로 옳은 것은?', '["훈연한 음식을 먹게 한다.", "흡연자면 금연하게 한다.", "잠자리에 들기 전에 녹차를 마시게 한다.", "검은색 대변을 보더라도 정상이라고 안심시킨다.", "비스테로이드성 소염진통제를 자주 복용하게 한다."]'::jsonb, 2, NULL, NULL, '{"1": "훈연한 음식을 먹게 하는 것은 위염을 악화시킬 수 있습니다.\n[정답]", "2": "흡연자는 위궤양을 악화시킬 수 있으므로 금연하게 하는 것이 중요합니다.", "3": "녹차는 카페인이 포함되어 있어 잠자기 전에 마시는 것이 좋지 않습니다.", "4": "검은색 대변은 위장 출혈의 징후일 수 있으므로 안심시킬 것이 아니라 진료를 받아야 합니다.", "5": "비스테로이드성 소염진통제는 위 점막을 자극할 수 있으며, 위궤양 환자에게는 사용을 피해야 합니다."}'::jsonb, '[{"term_ko": "위궤양", "term_vi": "Loét dạ dày", "def_ko": "위의 점막에 생기는 염증", "def_vi": "Viêm màng nhầy của dạ dày"}, {"term_ko": "흡연", "term_vi": "Hút thuốc", "def_ko": "담배를 피우는 행위", "def_vi": "Hành động hút thuốc lá"}, {"term_ko": "금연", "term_vi": "Bỏ thuốc", "def_ko": "담배를 끊는 것", "def_vi": "Ngừng hút thuốc"}, {"term_ko": "대변", "term_vi": "Phân", "def_ko": "배설물", "def_vi": "Phân"}, {"term_ko": "비스테로이드성 소염진통제", "term_vi": "Thuốc giảm đau không steroid", "def_ko": "비스테로이드성 소염진통제를 포함한 약물", "def_vi": "Thuốc bao gồm cả thuốc giảm đau không steroid"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (145, '5', '대상자의 장습관의 변화, 선홍색의 혈액과 점액이 섞인 설사와 변비를 반복할 때 나타나는 소화기계 질환으로 옳은 것은?', '["위염", "위궤양", "변비", "대장암", "설사"]'::jsonb, 4, NULL, NULL, '{"1": "위염은 위 점막의 염증으로, 수반되는 증상이 다릅니다.", "2": "위궤양은 위 점막의 결손으로, 혈변이 관찰되는 경우가 드뭅니다.", "3": "변비는 정상적인 배변이 어려운 상태로, 혼합된 혈액과 점액이 나타나지 않습니다.\n[정답]", "4": "대장암은 장의 이상으로 장 습관 변화와 혈액이 섞인 설사를 동반할 수 있습니다.", "5": "설사는 여러 원인으로 발생할 수 있으나, 특정 질환과 직접적인 연관은 약합니다."}'::jsonb, '[{"term_ko": "장습관", "term_vi": "대장암", "def_ko": "배변의 습관(thói quen đại tiện)", "def_vi": "대장의 암(tumor ở đại tràng)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (144, '5', '대장암을 예방하기 위한 식이요법으로 옳은 것은?', '["지방함유량이 많은 음식을 제공한다.", "통곡식으로 만든 음식을 제공한다.", "고칼로리 음식을 제공한다.", "훈연된 동물성 식품을 제공한다.", "야식으로 가공된 음식을 제공한다."]'::jsonb, 2, NULL, NULL, '{"1": "지방함유량이 많은 음식은 대장암 예방에 도움이 되지 않음.\n[정답]", "2": "통곡식으로 만든 음식은 섬유소가 많아 대장암 예방에 효과적임.", "3": "고칼로리 음식은 오히려 대장암 위험을 증가시킬 수 있음.", "4": "훈연된 동물성 식품은 발암 물질을 포함할 수 있어 피해야 함.", "5": "야식으로 가공된 음식은 건강에 좋지 않음."}'::jsonb, '[{"term_ko": "대장암", "term_vi": "Ung thư đại tràng", "def_ko": "큰 창자에서 발생하는 암", "def_vi": "Ung thư xảy ra trong ruột già"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (143, '5', '설사를 하는 대상자를 돕기 위한 방법으로 옳은 것은?', '["시원한 탄산음료를 마시게 한다.", "물을 적게 마시게 한다.", "기생충이 원인일 경우 진정제를 투약한다.", "지사제를 사용한다.", "몸을 따뜻하게 하고 수분 섭취량을 늘린다."]'::jsonb, 5, NULL, NULL, '{"1": "시원한 탄산음료는 위장에 부담을 줄 수 있다.", "2": "물을 적게 마시는 것은 탈수를 유발할 수 있다.", "3": "기생충이 원인일 경우 진정제는 효과적이지 않다.\n[정답]", "5": "몸을 따뜻하게 하고 수분 섭취량을 늘리는 것이 중요하다.", "4": "지사제는 원인에 따라 사용할 수 있으나, 모든 경우에 적합하지 않다."}'::jsonb, '[{"term_ko": "설사", "term_vi": "Tiêu chảy", "def_ko": "배탈(한국어)", "def_vi": "tiêu chảy(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (142, '5', '노인 변비의 유발 요인으로 옳은 것은?', '["식사량의 증가", "수분섭취의 증가", "배변반사의 증가", "마약성 진통제 사용", "고섬유질 음식 섭취의 증가"]'::jsonb, 4, NULL, NULL, '{"1": "식사량의 증가: 일반적으로 식사량의 증가는 변비를 완화할 수 있습니다.", "2": "수분섭취의 증가: 수분은 장 내 수분량을 증가시켜 변비 예방에 도움을 줍니다.", "3": "배변반사의 증가: 배변반사가 증가하면 변이 원활하게 배출될 수 있습니다.\n[정답]", "4": "마약성 진통제 사용: 마약성 진통제는 장의 운동성을 저하시키고 변비를 유발할 수 있습니다.", "5": "고섬유질 음식 섭취의 증가: 고섬유질 음식은 일반적으로 변비를 예방하고 개선하는 데 좋습니다."}'::jsonb, '[{"term_ko": "변비", "term_vi": "Táo bón", "def_ko": "장의 운동이 느려져 배변이 어려운 상태", "def_vi": "Tình trạng khó khăn trong việc đại tiện do sự chậm lại của hoạt động ruột"}, {"term_ko": "수분", "term_vi": "Nước", "def_ko": "물", "def_vi": "Nước"}, {"term_ko": "배변반사", "term_vi": "Phản xạ đại tiện", "def_ko": "대변을 배출하려는 자연스러운 반응", "def_vi": "Phản ứng tự nhiên để thải phân"}, {"term_ko": "마약성 진통제", "term_vi": "Thuốc giảm đau gây nghiện", "def_ko": "통증을 완화하기 위해 사용하는 약물", "def_vi": "Thuốc được sử dụng để giảm đau"}, {"term_ko": "고섬유질", "term_vi": "Giàu chất xơ", "def_ko": "섬유소가 많은 식사", "def_vi": "Bữa ăn nhiều chất xơ"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (141, '5', '시설대상자가 아침에 속이 쓰리다고 말할 때 요양보호사의 반응으로 옳은 것은?', '["\"위염이니 병원에 가야 해요\"", "\"위장약을 먹어야 할 것 같네요\"", "\"괜찮아요, 저는 아침마다 그래요.\"", "\"제가 현재 상태를 간호사에게 전할게요.\"", "\"위가 쉬어야 하니까 아침식사를 거르세요.\""]'::jsonb, 4, NULL, NULL, '{"1": "''위염이니 병원에 가야 해요''는 의료적 판단을 요양보호사가 바로 내리는 것은 부적절합니다.\n[정답]", "4": "''제가 현재 상태를 간호사에게 전할게요''는 적절한 대처로, 전문적인 판단을 간호사에게 맡기며 안전한 방법입니다.", "2": "''위장약을 먹어야 할 것 같네요''는 약물 권장으로, 의사의 처방이 필요한 부분입니다.", "3": "''괜찮아요, 저는 아침마다 그래요.''는 개인적인 경험을 토대로 문제를 간과하는 것입니다.", "5": "''위가 쉬어야 하니까 아침식사를 거르세요.''는 음식 섭취를 무조건 금하는 것이며, 상태에 따라 다를 수 있습니다."}'::jsonb, '[{"term_ko": "시설대상자", "term_vi": "Người nhận chăm sóc", "def_ko": "시설에서 돌봄을 받는 사람", "def_vi": "Người nhận sự chăm sóc tại cơ sở"}, {"term_ko": "위염", "term_vi": "Viêm dạ dày", "def_ko": "위장에 발생하는 염증", "def_vi": "Viêm trong dạ dày"}, {"term_ko": "간호사", "term_vi": "Y tá", "def_ko": "환자를 돌보는 의료 전문인", "def_vi": "Nhân viên chăm sóc bệnh nhân"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (139, '5', '노화와 관련된 호흡기계 특성으로 옳은 것은?', '["폐순환량이 증가하여 숨 쉬기 편하다.", "기침반사가 증가하여 미세 물질을 걸러내기 쉽다.", "콧속 점막에 습기가 증가하여 공기 흡인이 쉽다.", "호흡근육이 약화되어 호흡 증가 시 피로해지기 쉽다.", "기관지 내 분비무리 감소하여 감염 발생 위험이 낮다."]'::jsonb, 4, NULL, NULL, '{"1": "폐순환량이 증가하지 않으며, 노화로 인해 호흡이 편해지지 않습니다.\n[정답]", "4": "노화로 호흡근육이 약해져 호흡 시 피로해지기 쉽습니다.", "2": "기침반사는 감소하며, 미세 물질을 걸러내기 어려워집니다.", "3": "콧속 점막의 습기가 감소하여 공기 흡인에 어려움이 있습니다.", "5": "기관지 내 분비물 증가로 감염 발생 위험이 높아집니다."}'::jsonb, '[{"term_ko": "노화", "term_vi": "Lão hóa", "def_ko": "늙은 상태", "def_vi": "Trạng thái già"}, {"term_ko": "호흡기계", "term_vi": "Hệ hô hấp", "def_ko": "호흡을 담당하는 기관군", "def_vi": "Nhóm cơ quan chịu trách nhiệm hô hấp"}, {"term_ko": "피로", "term_vi": "Mệt mỏi", "def_ko": "에너지가 고갈된 상태", "def_vi": "Trạng thái mất năng lượng"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (138, '5', '인플루엔자 바이러스에 의한 감염병으로 겨울철에 유행하는 질환으로 옳은 것은?', '["독감", "기관지염", "천식", "결핵", "폐렴"]'::jsonb, 1, NULL, NULL, '{"1": "독감은 인플루엔자 바이러스에 의한 대표적인 감염병으로 겨울철에 주로 발생합니다.\n[정답]", "2": "기관지염은 여러 가지 원인에 의해 발생하며 인플루엔자와는 다릅니다.", "3": "천식은 알레르기 반응에 의한 만성 질환으로 인플루엔자와는 관련이 없습니다.", "4": "결핵은 세균 감염에 의한 질환으로 인플루엔자와는 관계가 없습니다.", "5": "폐렴은 여러 감염원에 의해 발생할 수 있지만 인플루엔자와는 다릅니다."}'::jsonb, '[{"term_ko": "인플루엔자", "term_vi": "Virus Influenza", "def_ko": "독감(한국어)", "def_vi": "cúm"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (137, '5', '인플루엔자 대상자를 돕는 방법으로 옳은 것은?', '["사람들이 많은 장소에 출입한다.", "외출할 때는 마스크를 쓰게 한다.", "치료제로 항생제를 복용하게 한다.", "운동 전에 기관지 확장제를 쓰게 한다.", "정기적으로 흉부방사선 검사를 받게 한다."]'::jsonb, 2, NULL, NULL, '{"1": "사람들이 많은 장소에 출입한다는 것은 감염 위험을 증가시키므로 옳지 않습니다.\n[정답]", "2": "외출할 때 마스크를 착용하게 하는 것은 감염 예방에 효과적입니다.", "3": "인플루엔자는 바이러스 감염이므로 항생제는 효과가 없습니다.", "4": "운동 전에 기관지 확장제를 사용해야 하는 경우는 특수 상황에서만 필요합니다.", "5": "정기적인 흉부 방사선 검사는 인플루엔자 예방과 관련이 없습니다."}'::jsonb, '[{"term_ko": "인플루엔자", "term_vi": "Cúm", "def_ko": "독감(한국어)", "def_vi": "Cảm lạnh"}, {"term_ko": "대상자", "term_vi": "Người bệnh", "def_ko": "환자(한국어)", "def_vi": "Người bị bệnh"}, {"term_ko": "마스크", "term_vi": "Khẩu trang", "def_ko": "얼굴 가리개(한국어)", "def_vi": "Đồ che mặt"}, {"term_ko": "항생제", "term_vi": "Kháng sinh", "def_ko": "감염 치료제(한국어)", "def_vi": "Thuốc chữa nhiễm trùng"}, {"term_ko": "기관지", "term_vi": "Phế quản", "def_ko": "호흡기 계통의 일부(한국어)", "def_vi": "Một phần của hệ hô hấp"}, {"term_ko": "정기적", "term_vi": "Định kỳ", "def_ko": "일정한 간격으로(한국어)", "def_vi": "Ở khoảng cách quy định"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (136, '5', '기관지의 만성적 염증으로 기도가 좁아져 숨쉬기 힘든 대상자를 돕는 방법으로 옳은 것은?', '["공기오염이 심한 곳에는 가습기를 설치한다.", "심호흡과 기침을 하여 기관지 내 가래를 배출한다.", "방향제를 사용하여 공기를 정화한다.", "습기가 많은 날씨에 외출을 즐긴다.", "기관지 확장제는 증상이 없을 때만 사용한다."]'::jsonb, 2, NULL, NULL, '{"1": "공기오염이 심한 곳에 가습기를 설치하는 것은 도움이 되지 않는다.\n[정답]", "2": "심호흡과 기침을 통해 기관지 내 가래를 배출하는 것이 중요하다.", "3": "방향제를 사용하는 것은 오히려 자극을 줄 수 있다.", "4": "습기가 많은 날씨에는 외출을 피하는 것이 좋다.", "5": "기관지 확장제는 증상이 있을 때 사용하는 것이 효과적이다."}'::jsonb, '[{"term_ko": "기관지", "term_vi": "Phế quản", "def_ko": "호흡기를 통해 공기가 통과하는 길", "def_vi": "Đường dẫn khí qua phổi"}, {"term_ko": "만성적", "term_vi": "Mãn tính", "def_ko": "오랜 시간 지속되는", "def_vi": "Kéo dài trong thời gian lâu"}, {"term_ko": "염증", "term_vi": "Viêm", "def_ko": "신체의 손상이나 감염에 의해 발생하는 반응", "def_vi": "Phản ứng xảy ra do tổn thương hoặc nhiễm trùng trong cơ thể"}, {"term_ko": "가래", "term_vi": "Đờm", "def_ko": "호흡기에서 배출되는 점액", "def_vi": "Chất nhầy được bài tiết từ đường hô hấp"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (135, '5', '세균, 바이러스에 의한 폐 조직의 염증으로 호흡곤란, 가래, 기침이 나타나는 질병으로 옳은 것은?', '["독감", "결핵", "천식", "만성기관지염", "폐렴"]'::jsonb, 5, NULL, NULL, '{"1": "독감: 인플루엔자 바이러스에 의해 발생하는 질병으로 다양한 증상이 나타날 수 있지만, 주로 발열과 근육통이 특징입니다.\n[정답]", "5": "폐렴: 세균이나 바이러스에 의해 폐 조직에 염증이 생기고, 기침, 가래, 호흡곤란이 주요 증상입니다.", "3": "천식: 주로 알레르기 요인에 의해 발작적으로 발생하는 호흡곤란입니다.", "4": "만성기관지염: 장기간 동안 지속적인 기침과 가래가 특징이며, 염증이 동반됩니다.", "2": "결핵: 결핵균에 의해 폐에 발생하는 만성 감염병으로, 기침, 체중 감소, 야간 발한 등의 증상이 나타납니다."}'::jsonb, '[{"term_ko": "세균", "term_vi": "바이러스", "def_ko": "bacteria", "def_vi": "virus"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (134, '5', '만성기관지염 대상자의 효과적인 가래 배출 방법으로 옳은 것은?', '["항생제를 투여한다.", "수분 섭취를 제한한다.", "심호흡과 기침을 하게 한다.", "똑바로 누워 안정을 취하게 한다.", "실내 공기를 서늘하게 유지한다."]'::jsonb, 3, NULL, NULL, '{"1": "항생제를 투여하여도 가래 배출에는 직접적인 도움이 되지 않는다.\n[정답]", "3": "심호흡과 기침을 통해 가래를 효과적으로 배출할 수 있다.", "2": "수분 섭취를 제한하면 오히려 가래가 더 끈적해질 수 있다.", "4": "똑바로 누워 안정을 취하는 것은 호흡을 방해할 수 있다.", "5": "실내 공기를 서늘하게 유지하면 기관지가 자극을 받을 수 있다."}'::jsonb, '[{"term_ko": "만성기관지염", "term_vi": "가래", "def_ko": "만 tính viêm phế quản", "def_vi": "đờm"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (133, '5', '고양이를 쓰다듬던 대상자가 잠시 후 쌕쌕거리는 호흡음을 내쉬며 가슴이 답답하다고 호소할 때 의심되는 질환으로 옳은 것은?', '["결핵", "비염", "천식", "후두염", "흉막염"]'::jsonb, 3, NULL, NULL, '{"1": "결핵: 결핵은 주로 폐에 영향을 미치지만, 쌕쌕거리는 호흡음과 가슴 답답함과 직접적인 연관은 낮다.\n[정답]", "3": "천식: 천식은 쌕쌕거리는 호흡음과 가슴 답답감을 유발하는 주요 질환입니다.", "2": "비염: 비염은 주로 코와 관련된 증상으로 호흡음과 다소 거리가 있다.", "4": "후두염: 후두염은 목 소리 변화와 관련이 있으며, 일반적으로 호흡음을 이끌어내지 않는다.", "5": "흉막염: 흉막염은 가슴 통증을 유발할 수 있지만 쌕쌕거리는 호흡음과는 연관성이 작다."}'::jsonb, '[{"term_ko": "호흡음", "term_vi": "Âm thanh hô hấp", "def_ko": "소리(한국어)", "def_vi": "Âm thanh liên quan đến hơi thở(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (132, '5', '천식 대상자의 호흡곤란을 예방하는 방법으로 옳은 것은?', '["추운 날씨에 벽난로를 핀다.", "차고 건조한 공기로 환기시킨다.", "뜨거운 물로 침구류를 세탁한다.", "해마다 폐렴구균을 추가 접종한다.", "운동 시작 전에는 기관지 확장제 흡인을 금한다."]'::jsonb, 3, NULL, NULL, '{"1": "추운 날씨는 호흡곤란을 악화시킬 수 있어 벽난로를 피하는 것이 좋다.\n[정답]", "3": "뜨거운 물로 세탁한 침구는 먼지를 제거하고 알레르기 반응을 줄여 호흡곤란 예방에 효과적이다.", "2": "차고 건조한 공기로 환기시키는 것은 천식에 좋지 않다.", "4": "예방접종은 중요하지만, 폐렴구균 접종이 직접적으로 호흡곤란 예방에 기여하지는 않는다.", "5": "운동 전 기관지 확장제 흡인은 실제로 필요할 수 있다."}'::jsonb, '[{"term_ko": "천식", "term_vi": "Hen suyễn", "def_ko": "호흡기 질환의 일종", "def_vi": "Bệnh lý hô hấp"}, {"term_ko": "호흡곤란", "term_vi": "Khó thở", "def_ko": "숨쉬기 어려움", "def_vi": "Khó khăn trong việc thở"}, {"term_ko": "예방", "term_vi": "Phòng ngừa", "def_ko": "미리 방지함", "def_vi": "Ngăn chặn trước"}, {"term_ko": "접종", "term_vi": "Tiêm phòng", "def_ko": "백신을 맞는 것", "def_vi": "Tiêm vacxin"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (131, '5', '천식 대상자가 흡인용 기관지 확장제를 사용할 때의 순서로 옳은 것은?가. 흡인기의 뚜껑을 열고 흔든다. 나. 흡인기를 입으로 문다. 다. 10초간 숨을 참은 후 천천히 내쉰다. 라. 3~5초간 천천히 깊게 숨을 들이쉰다. 마. 입으로 숨을 들이쉬면서 흡인기를 누른다.', '["가 → 나 → 다 → 라 → 마", "가 → 나 → 마 → 라 → 다", "가 → 라 → 나 → 다 → 마", "가 → 다 → 나 → 라 → 마", "가 → 라 → 나 → 마 → 다"]'::jsonb, 2, NULL, NULL, '{"1": "흡인기의 뚜껑을 연 후 흔드는 것은 약물이 고르게 섞이도록 하기 위해서입니다.\n[정답]", "2": "흡인기를 입으로 물고 입안에 약물이 잘 퍼지도록 합니다.", "3": "숨을 참는 것은 약물이 폐에 더 잘 흡수되도록 합니다.", "4": "깊게 숨을 들이쉬며 약물을 폐로 밀어 넣는 과정입니다.", "5": "숨을 들이쉬면서 흡인기를 누르는 것이 올바른 사용법입니다."}'::jsonb, '[{"term_ko": "천식", "term_vi": "Hen suyễn", "def_ko": "호흡기 질환의 일종", "def_vi": "Một loại bệnh hô hấp"}, {"term_ko": "흡인", "term_vi": "Hít", "def_ko": "기구를 사용해 약물을 넣는 행위", "def_vi": "Hành động đưa thuốc vào cơ thể bằng thiết bị"}, {"term_ko": "기관지", "term_vi": "Phế quản", "def_ko": "호흡기를 구성하는 관", "def_vi": "Ống mạch khí trong hệ hô hấp"}, {"term_ko": "확장제", "term_vi": "Thuốc giãn", "def_ko": "기계적으로 확장시키는 물질", "def_vi": "Chất làm giãn nở một cách cơ học"}, {"term_ko": "환자", "term_vi": "Bệnh nhân", "def_ko": "치료가 필요한 사람", "def_vi": "Người cần điều trị"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (130, '5', '요양보호사 결핵이 의심되는 대상자와 접촉했을 때 대처방법으로 옳은 것은?', '["대상자를 병원에 입원시킨다.", "서비스를 중단한다.", "결핵 예방접종을 한다.", "1개월 이후 반드시 의료기관을 찾아 감염 여부를 확인한다.", "대상자에게 마스크와 장갑을 착용하게 한다."]'::jsonb, 4, NULL, NULL, '{"1": "대상자를 병원에 입원시키는 것은 의료진의 판단이 필요하고, 요양보호사의 권한이 아닙니다.\n[정답]", "4": "1개월 이후 의료기관을 방문해 감염 여부를 확인하는 것이 가장 적절한 대처방법입니다.", "2": "서비스를 중단하는 것은 필요하지 않으며, 대처 방법이 아닙니다.", "3": "결핵 예방접종을 하는 것은 일반적인 상황에서 대처방법이 아닙니다.", "5": "대상자에게 마스크와 장갑을 착용하게 하는 것은 좋지만, 감염 여부를 판단하는 것은 의료기관에서 해야 합니다."}'::jsonb, '[{"term_ko": "결핵", "term_vi": "Bệnh lao", "def_ko": "병원체에 의해 발생하는 호흡기 질환", "def_vi": "Bệnh lý hô hấp do vi khuẩn gây ra"}, {"term_ko": "예방접종", "term_vi": "Tiêm phòng", "def_ko": "특정 질병을 예방하기 위해 접종하는 것", "def_vi": "Hành động tiêm để ngăn ngừa một bệnh cụ thể"}, {"term_ko": "의료기관", "term_vi": "Cơ sở y tế", "def_ko": "의료 서비스를 제공하는 조직", "def_vi": "Tổ chức cung cấp dịch vụ y tế"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (129, '5', '항결핵제 복용방법에 관한 설명으로 옳은 것은?', '["평생 동안 복용한다.", "증상이 없으면 복용량을 줄인다.", "약물복용이 끝날 때까지 격리한다.", "주기적으로 간기능 검사를 하면서 복용한다.", "항결핵제 중 한 가지 약물을 복용하는 것이 원칙이다."]'::jsonb, 4, NULL, NULL, '{"1": "평생 동안 복용하지 않습니다. 치료 기간이 정해져 있습니다.\n[정답]", "2": "증상이 없더라도 규칙적으로 복용해야 합니다.", "3": "약물복용이 끝날 때까지 격리하지 않습니다. 격리는 필요하지 않습니다.", "4": "간기능 검사를 주기적으로 하면서 복용하는 것이 중요합니다.", "5": "일반적으로 복합 요법을 사용하며, 한 가지 약물만 복용하는 것이 원칙이 아닙니다."}'::jsonb, '[{"term_ko": "항결핵제", "term_vi": "Thuốc kháng lao", "def_ko": "결핵을 치료하는 약물", "def_vi": "Thuốc dùng để điều trị bệnh lao"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (128, '5', '노화에 따른 심혈관계 특성으로 옳은 것은?', '["최대 심박출량 감소", "심장근육 두께 감소", "심방동수 증가", "심장의 탄력성 증가", "심장으로의 혈액순환 증가"]'::jsonb, 1, NULL, NULL, '{"1": "최대 심박출량 감소는 노화에 따른 일반적인 심혈관계 변화입니다.\n[정답]", "2": "심장근육 두께 감소는 노화와 관련이 있을 수 있지만, 일반적으로는 두꺼워질 수 있습니다.", "3": "심방동수 증가는 노화와 관련된 변화가 아닙니다.", "4": "심장의 탄력성 증가는 노화에 맞지 않는 설명입니다.", "5": "심장으로의 혈액순환 증가는 노화에 따른 변화가 아닙니다."}'::jsonb, '[{"term_ko": "노화", "term_vi": "Lão hóa", "def_ko": "나이에서 오는 변화", "def_vi": "Sự thay đổi do tuổi tác"}, {"term_ko": "심혈관계", "term_vi": "Hệ tim mạch", "def_ko": "심장 및 혈관 시스템", "def_vi": "Hệ thống tim và mạch máu"}, {"term_ko": "최대", "term_vi": "Tối đa", "def_ko": "최대치", "def_vi": "Giá trị tối đa"}, {"term_ko": "심박출량", "term_vi": "Khối lượng máu bơm ra", "def_ko": "심장이 박출하는 혈액의 양", "def_vi": "Lượng máu do tim bơm ra"}, {"term_ko": "심장근육", "term_vi": "Cơ tim", "def_ko": "심장 근육", "def_vi": "Cơ của tim"}, {"term_ko": "탄력성", "term_vi": "Tính đàn hồi", "def_ko": "신축성", "def_vi": "Khả năng đàn hồi"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (127, '5', '고혈압에 관한 설명으로 옳은 것은?', '["혈관이 좁아져 혈압이 낮아진다.", "염장식품은 혈압조절에 도움이 된다.", "심장병이 본태성 고혈압의 원인이 된다.", "이완기 혈압은 심장에서 피를 짜낼 때 압력이다.", "처방된 혈압약은 혈압이 조절되어도 계속 복용한다."]'::jsonb, 5, NULL, NULL, '{"1": "혈관이 좁아지면 혈압이 오히려 높아진다.", "2": "염장식품은 나트륨이 많아 혈압을 높일 수 있으므로 도움이 되지 않는다.\n[정답]", "5": "처방된 혈압약은 증상이 개선되더라도 중단하지 않고 꾸준히 복용해야 한다.", "3": "심장병은 고혈압의 원인이 아니라 고혈압의 합병증일 수 있다.", "4": "이완기 혈압은 심장이 이완될 때의 압력으로, 피를 짜낼 때의 압력은 수축기 혈압이다."}'::jsonb, '[{"term_ko": "고혈압", "term_vi": "Huyết áp cao", "def_ko": "높은 혈압(한국어)", "def_vi": "Huyết áp cao(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (126, '5', '고혈압 대상자의 약물 요법으로 옳은 것은?', '["복용하지 않은 약물은 다음날 2배 복용한다.", "증상이 없어도 혈압이 높으면 치료해야 한다.", "두통 등의 증상이 있을 때만 약을 복용한다.", "혈압 약을 오래 먹으면 몸이 허약해진다.", "혈압이 조절되면 그만 먹어도 된다."]'::jsonb, 2, NULL, NULL, '{"1": "복용하지 않은 약물은 다음날 2배 복용하는 것은 잘못된 방법입니다. \n[정답]", "2": "혈압이 높으면 증상이 없더라도 치료가 필요합니다.", "3": "두통 등의 증상이 있을 때만 약을 복용하는 것은 고혈압 관리에 적절하지 않습니다.", "4": "혈압 약을 오래 먹어도 몸이 허약해진다는 것은 일반적으로 사실이 아닙니다.", "5": "혈압이 조절되면 약 복용을 중단하는 것은 위험할 수 있습니다."}'::jsonb, '[{"term_ko": "고혈압", "term_vi": "Huyết áp cao", "def_ko": "높 혈압(한국어)", "def_vi": "Huyết áp cao(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (125, '5', '고혈압 대상자를 돕는 방법으로 옳은 것은?', '["저지방 유제품을 먹게 한다.", "격렬한 유산소 운동을 하게 한다.", "알코올 섭취로 열량을 보충하게 한다.", "매일 한 잔의 술로 스트레스를 줄이게 한다.", "혈압이 조절되면 약물 복용을 중단하고 운동을 하게 한다."]'::jsonb, 1, NULL, NULL, '{"1": "저지방 유제품은 칼슘이 풍부하고 고혈압 관리에 도움이 됩니다.\n[정답]", "2": "격렬한 유산소 운동은 오히려 혈압을 높일 수 있어 위험합니다.", "3": "알코올 섭취는 고혈압에 부정적인 영향을 줄 수 있습니다.", "4": "매일 술을 마시는 것은 건강에 좋지 않으며 고혈압에 해로울 수 있습니다.", "5": "의사의 지시 없이는 약물 복용을 중단해서는 안 됩니다."}'::jsonb, '[{"term_ko": "고혈압", "term_vi": "유제품", "def_ko": "높은 혈압(압 suất máu cao)", "def_vi": "우유에서 만든 음식(sản phẩm từ sữa)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (124, '5', '동맥혈관 안쪽 벽에 지방이 축적되어 혈관 내부가 좁아지고 혈관벽이 굳어지는 증상으로 옳은 것은?', '["고혈압", "동맥경화증", "신부전", "심부전", "빈혈"]'::jsonb, 2, NULL, NULL, '{"1": "고혈압은 혈압이 비정상적으로 높아진 상태로, 동맥경화증의 결과로 발생할 수 있다.\n[정답]", "2": "동맥경화증은 동맥혈관 안쪽 벽에 지방이 축적되어 혈관 내부가 좁아지고 혈관벽이 굳어지는 증상이다.", "3": "신부전은 신장의 기능이 감소하여 발생하는 상태로, 문제에서 설명하는 증상과는 관련이 없다.", "4": "심부전은 심장이 제대로 기능하지 못하는 상태로, 동맥경화증과는 다른 질환이다.", "5": "빈혈은 혈액 내의 적혈구나 헤모글로빈의 수가 적은 상태를 의미하며, 혈관 관련 증상과는 관련이 없다."}'::jsonb, '[{"term_ko": "동맥혈관", "term_vi": "Mạch máu động mạch", "def_ko": "동맥의 혈관", "def_vi": "Mạch máu của động mạch"}, {"term_ko": "지방", "term_vi": "Chất béo", "def_ko": "지방", "def_vi": "Chất béo"}, {"term_ko": "축적", "term_vi": "Tích tụ", "def_ko": "축적하다", "def_vi": "Tích tụ"}, {"term_ko": "좁아지다", "term_vi": "Hẹp lại", "def_ko": "좁아지다", "def_vi": "Hẹp lại"}, {"term_ko": "굳어지다", "term_vi": "Cứng lại", "def_ko": "굳어지다", "def_vi": "Cứng lại"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (123, '5', '협심증, 심근경색 등 관상동백질환이 있을 때 나타나는 특징적인 증상으로 옳은 것은?', '["뇌혈관 출혈", "흉통", "반신불수", "기억력 저하", "불면증"]'::jsonb, 2, NULL, NULL, '{"1": "뇌혈관 출혈은 관상동맥질환과 관련이 없습니다.\n[정답]", "2": "흉통은 협심증과 심근경색의 대표적인 증상입니다.", "3": "반신불수는 뇌혈관질환의 증상이지 관상동맥질환과 관련이 없습니다.", "4": "기억력 저하는 주로 신경학적 문제와 관련이 있습니다.", "5": "불면증은 정신적 문제와 관련이 있지만, 관상동맥질환의 증상으로는 일반적이지 않습니다."}'::jsonb, '[{"term_ko": "협심증", "term_vi": "Đau thắt ngực", "def_ko": "가슴 통증이 발생하는 질환", "def_vi": "Bệnh gây đau ngực"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (122, '5', '심장의 수축력이 저하되어 나타나는 질환의 주요 증상으로 옳은 것은?', '["복위자세에서의 호흡", "식욕이 좋아짐", "명료한 의식", "지속적인 기침과 객담", "간헐적인 무릎 통증"]'::jsonb, 4, NULL, NULL, '{"1": "복위자세에서의 호흡은 심장의 수축력 저하와 직접적인 관련이 없습니다.\n[정답]", "4": "지속적인 기침과 객담은 심장 기능 저하로 인해 폐혈류가 감소하면서 발생할 수 있는 증상입니다.", "2": "식욕이 좋아짐은 심장 질환과 역행하는 증상으로 부정확합니다.", "3": "명료한 의식은 통상적으로 심장 질환과는 관련이 적습니다.", "5": "간헐적인 무릎 통증은 심장 질환과 관련이 없습니다."}'::jsonb, '[{"term_ko": "심장", "term_vi": "Tim", "def_ko": "심장의 의미(한국어)", "def_vi": "Tim"}, {"term_ko": "수축력", "term_vi": "Sức co bóp", "def_ko": "수축하는 힘(한국어)", "def_vi": "Sức co bóp"}, {"term_ko": "질환", "term_vi": "Bệnh tật", "def_ko": "병의 의미(한국어)", "def_vi": "Bệnh tật"}, {"term_ko": "증상", "term_vi": "Triệu chứng", "def_ko": "나타나는 상태(한국어)", "def_vi": "Triệu chứng"}, {"term_ko": "호흡", "term_vi": "Hô hấp", "def_ko": "숨쉬는 과정(한국어)", "def_vi": "Hô hấp"}, {"term_ko": "기침", "term_vi": "Ho", "def_ko": "기침하는 행위(한국어)", "def_vi": "Ho"}, {"term_ko": "객담", "term_vi": "Đờm", "def_ko": "기침으로 나오는 가래(한국어)", "def_vi": "Đờm"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (121, '5', '심부전 대상자를 돕는 방법으로 옳은 것은?', '["매일 체중을 측정한다.", "식사량을 늘려 제공한다.", "계단 오르기 운동을 격려한다.", "담배와 같은 기호품은 허용한다.", "온 · 냉탕을 오가며 목욕하게 한다."]'::jsonb, 1, NULL, NULL, '{"1": "체중은 심부전 환자의 수분 상태를 체크하는 중요한 지표입니다.\n[정답]", "2": "심부전 환자에게는 식사량을 늘려주는 것이 오히려 증상을 악화시킬 수 있습니다.", "3": "심부전 환자에게는 과도한 운동이 해롭기 때문에 계단 오르기 운동은 권장되지 않습니다.", "4": "담배와 같은 기호품은 심부전에 좋지 않으므로 허용되지 않습니다.", "5": "온 · 냉탕을 오가는 목욕은 심부전 환자에게 위험할 수 있습니다."}'::jsonb, '[{"term_ko": "심부전", "term_vi": "Suy tim", "def_ko": "심장의 기능이 저하된 상태", "def_vi": "Tình trạng chức năng tim giảm"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (120, '5', '적혈구 부족이 원인이 되어 산소운반능력이 저하되는 질환으로 옳은 것은?', '["고혈압", "빈혈", "심부전", "뇌경색", "동맥경화증"]'::jsonb, 2, NULL, NULL, '{"1": "고혈압은 혈압이 상승하는 질환으로, 적혈구와 직접적인 연관이 없습니다.\n[정답]", "2": "빈혈은 적혈구의 부족으로 인해 발생하는 질환으로, 산소운반능력이 저하됩니다.", "3": "심부전은 심장이 제 기능을 하지 못하게 되는 상태로, 적혈구의 수와는 별개의 문제입니다.", "4": "뇌경색은 뇌의 혈류가 차단되어 발생하는 상태로, 적혈구 부족과는 직접적인 연관이 없습니다.", "5": "동맥경화증은 동맥의 경화에 의한 질환으로, 적혈구 수와는 상관이 없습니다."}'::jsonb, '[{"term_ko": "적혈구", "term_vi": "Hồng cầu", "def_ko": "혈액 내 산소를 운반하는 세포", "def_vi": "Tế bào mang oxy trong máu"}, {"term_ko": "빈혈", "term_vi": "Thiếu máu", "def_ko": "적혈구 수가 부족해지는 질환", "def_vi": "Bệnh do thiếu hụt số lượng hồng cầu"}, {"term_ko": "산소", "term_vi": "Oxy", "def_ko": "우리가 숨쉬면서 몸에 필요한 기체", "def_vi": "Khí cần thiết cho cơ thể mà chúng ta hít vào"}, {"term_ko": "질환", "term_vi": "Bệnh", "def_ko": "병이나 상태", "def_vi": "Tình trạng sức khỏe không bình thường"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (119, '5', '심장질환 대상자가 복도를 걷다가 어지럼증을 호소할 때 우선적으로 해야 할 행동으로 옳은 것은?', '["따뜻한 녹차를 마시게 한다.", "바로 그 자리에 앉힌다.", "손가락에 사혈을 한다.", "손으로 입을 가리고 숨을 빨리 쉬라고 한다.", "도움을 요청하러 동료 요양보호사에게 간다."]'::jsonb, 2, NULL, NULL, '{"1": "따뜻한 녹차를 마시게 한다: 이는 어지럼증 상황에서 적절한 응급처치가 아닙니다.\n[정답]", "2": "바로 그 자리에 앉힌다: 어지럼증을 호소하는 환자를 안전하게 앉혀 안정시키는 것이 최우선입니다.", "3": "손가락에 사혈을 한다: 응급처치에서 필요하지 않은 행동입니다.", "4": "손으로 입을 가리고 숨을 빨리 쉬라고 한다: 이는 오히려 상태를 악화시킬 수 있습니다.", "5": "도움을 요청하러 동료 요양보호사에게 간다: 상황을 즉시 처리해야 하므로 적절하지 않습니다."}'::jsonb, '[{"term_ko": "심장질환", "term_vi": "Bệnh tim mạch", "def_ko": "심장과 관련된 질병", "def_vi": "Các bệnh liên quan đến tim"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (118, '5', '노화에 따른 근골격계 변화로 옳은 것은?', '["관절운동의 제한", "허리의 피하지방 감소", "뼈의 질량 증가", "추간판 두께 증가", "근육의 긴장도 증가"]'::jsonb, 1, NULL, NULL, '{"1": "노화에 따라 관절의 운동 범위가 줄어들게 됩니다.\n[정답]", "2": "노화와 함께 허리의 피하지방이 증가하는 경향이 있습니다.", "3": "노화로 인해 뼈의 질량은 감소하게 됩니다.", "4": "추간판의 두께는 일반적으로 나이가 들수록 줄어듭니다.", "5": "근육의 긴장도는 노화에 따라 감소합니다."}'::jsonb, '[{"term_ko": "노화", "term_vi": "Lão hóa", "def_ko": "노화(한국어)", "def_vi": "lão hóa"}, {"term_ko": "근골격계", "term_vi": "Hệ cơ xương", "def_ko": "근골격계(한국어)", "def_vi": "hệ cơ xương"}, {"term_ko": "관절", "term_vi": "Khớp", "def_ko": "관절(한국어)", "def_vi": "khớp"}, {"term_ko": "운동", "term_vi": "Vận động", "def_ko": "운동(한국어)", "def_vi": "vận động"}, {"term_ko": "허리", "term_vi": "Lưng", "def_ko": "허리(한국어)", "def_vi": "lưng"}, {"term_ko": "피하지방", "term_vi": "Mỡ dưới da", "def_ko": "피하지방(한국어)", "def_vi": "mỡ dưới da"}, {"term_ko": "뼈", "term_vi": "Xương", "def_ko": "뼈(한국어)", "def_vi": "xương"}, {"term_ko": "질량", "term_vi": "Khối lượng", "def_ko": "질량(한국어)", "def_vi": "khối lượng"}, {"term_ko": "추간판", "term_vi": "Đĩa đệm", "def_ko": "추간판(한국어)", "def_vi": "đĩa đệm"}, {"term_ko": "두께", "term_vi": "Độ dày", "def_ko": "두께(한국어)", "def_vi": "độ dày"}, {"term_ko": "근육", "term_vi": "Cơ", "def_ko": "근육(한국어)", "def_vi": "cơ"}, {"term_ko": "긴장도", "term_vi": "Độ căng", "def_ko": "긴장도(한국어)", "def_vi": "độ căng"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (117, '5', '다음과 같은 증상을 보이는 질환으로 옳은 것은?• 관절연골의 마모와 관절조직의 퇴화 • 계단을 오르내릴 때 심한 무릎 통증', '["골수염", "골다공증", "골연화증", "고관절 골절", "퇴행성관절염"]'::jsonb, 5, NULL, NULL, '{"1": "골수염: 주로 뼈의 감염으로 인한 염증으로 이 증상과는 관련이 없습니다.", "2": "골다공증: 뼈의 밀도가 감소하는 질환이지만, 관절 통증과 관련이 없습니다.", "3": "골연화증: 뼈가 약해지는 질환으로, 직접적인 관절증상과는 차이가 있습니다.", "4": "고관절 골절: 골절은 특정 상황에서 발생하지만, 만성적인 관절통은 설명하지 않습니다.\n[정답]", "5": "퇴행성관절염: 관절연골의 마모와 통증이 주 증상으로, 보기에서 설명한 내용과 일치합니다."}'::jsonb, '[{"term_ko": "관절", "term_vi": "연골", "def_ko": "관절(관 khớp)", "def_vi": "연골(giải phẫu: sụn)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (116, '5', '퇴행성관절염 예방 및 치료로 옳은 것은?', '["가능한 한 움직임을 삼간다.", "통증 부위에 냉찜질을 한다.", "규칙적인 수영을 한다.", "고칼슘 섭취를 한다.", "통증이 있다면 반드시 수술을 한다."]'::jsonb, 3, NULL, NULL, '{"1": "가능한 한 움직임을 삼간다는 오히려 관절 기능을 악화시킬 수 있습니다.\n[정답]", "3": "규칙적인 수영은 관절에 부담을 덜 주면서 운동 효과를 볼 수 있는 좋은 방법입니다.", "2": "통증 부위에 냉찜질을 하는 것은 일시적으로 통증을 완화할 수 있지만, 장기적 치료법은 아닙니다.", "4": "고칼슘 섭취는 뼈 건강에 좋지만, 퇴행성관절염과는 직접적인 관련이 없습니다.", "5": "통증이 있다고 해서 반드시 수술이 필요한 것은 아닙니다. 비수술적 치료법이 먼저 시도되어야 합니다."}'::jsonb, '[{"term_ko": "퇴행성관절염", "term_vi": "Viêm khớp thoái hóa", "def_ko": "관절의 퇴행성 변화로 인한 질병", "def_vi": "Bệnh do sự thay đổi thoái hóa của khớp"}, {"term_ko": "예방", "term_vi": "Phòng ngừa", "def_ko": "질병이나 사고를 미리 막는 것", "def_vi": "Ngăn chặn bệnh tật hoặc tai nạn trước khi xảy ra"}, {"term_ko": "치료", "term_vi": "Điều trị", "def_ko": "질병이나 상처를 완화하는 것", "def_vi": "Làm giảm bệnh tật hoặc vết thương"}, {"term_ko": "규칙적인", "term_vi": "Đều đặn", "def_ko": "일정한 규칙을 따르는", "def_vi": "Theo một quy tắc nhất định"}, {"term_ko": "수영", "term_vi": "Bơi lội", "def_ko": "물에서 몸을 움직이는 운동", "def_vi": "Cử động cơ thể trong nước"}, {"term_ko": "냉찜질", "term_vi": "Chườm lạnh", "def_ko": "얼음이나 차가운 물체로 치료하는 방법", "def_vi": "Phương pháp điều trị bằng đá hoặc vật lạnh"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (115, '5', '골다공증의 관련 요인으로 옳은 것은?', '["충분한 칼슘 섭취", "잦은 음주", "적당한 체중 유지", "비타민 D 섭취", "오전 10시 ~ 오후 2시까지 자외선 쬐기"]'::jsonb, 2, NULL, NULL, '{"1": "충분한 칼슘 섭취는 골밀도를 유지하는 데 도움이 됩니다.\n[정답]", "2": "잦은 음주는 골다공증의 위험을 증가시킵니다.", "3": "적당한 체중 유지는 골다공증 예방에 긍정적으로 작용합니다.", "4": "비타민 D 섭취는 뼈 건강에 중요한 역할을 합니다.", "5": "오전 10시 ~ 오후 2시까지 자외선 쬐기는 비타민 D 생성에 도움이 됩니다."}'::jsonb, '[{"term_ko": "골다공증", "term_vi": "Loãng xương", "def_ko": "뼈가 약해지는 질환", "def_vi": "Bệnh làm xương trở nên yếu"}, {"term_ko": "칼슘", "term_vi": "Canxi", "def_ko": "뼈를 강화하는 필수 미네랄", "def_vi": "Khoáng chất cần thiết để làm mạnh xương"}, {"term_ko": "비타민 D", "term_vi": "Vitamin D", "def_ko": "뼈 건강에 중요한 비타민", "def_vi": "Vitamin quan trọng cho sức khỏe xương"}, {"term_ko": "자외선", "term_vi": "Tia cực tím", "def_ko": "태양의 광선 중 하나", "def_vi": "Một trong những tia sáng của mặt trời"}, {"term_ko": "체중", "term_vi": "Trọng lượng", "def_ko": "몸무게", "def_vi": "Cân nặng"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (114, '5', '골다공증을 예방하는 방법으로 옳은 것은?', '["자외선 차단", "저체중 유지", "체중부하 운동 제한", "부신피질 호르몬 요법", "비타민 D 함유 음식 섭취"]'::jsonb, 5, NULL, NULL, '{"1": "자외선 차단은 주로 피부암 예방과 관련이 있습니다.\n[정답]", "5": "비타민 D 함유 음식 섭취는 칼슘 흡수를 도와 골다공증 예방에 효과적입니다.", "2": "저체중 유지가 골다공증을 예방한다고 보기 어렵습니다.", "3": "체중부하 운동은 골밀도를 높이는데 도움이 됩니다.", "4": "부신피질 호르몬 요법은 장기 사용 시 오히려 골다공증을 악화시킬 수 있습니다."}'::jsonb, '[{"term_ko": "골다공증", "term_vi": "Bệnh loãng xương", "def_ko": "뼈의 밀도가 감소하여 약해지는 증상", "def_vi": "Tình trạng xương trở nên mỏng và yếu"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (113, '5', '골다공증이 있는 노인이 낙상했을 때 발생할 가능성이 높은 질환으로 옳은 것은?', '["추간판 탈출증", "척추측만증", "고관절골절", "강직척추염", "류마티스관절염"]'::jsonb, 3, NULL, NULL, '{"1": "추간판 탈출증은 주로 젊은 층에서 발생하며 노인의 낙상과는 관련이 적습니다.", "2": "척추측만증은 골다공증과 관련이 없으나 노인에게 흔할 수 있는 질환입니다.\n[정답]", "3": "고관절골절은 골다공증 환자가 낙상했을 때 가장 흔하게 발생하는 부상입니다.", "4": "강직척추염은 염증성 질환으로, 골다공증과 관련이 적습니다.", "5": "류마티스관절염은 관절에 염증을 일으키는 질환이며, 낙상과는 직접적인 연관이 없습니다."}'::jsonb, '[{"term_ko": "골다공증", "term_vi": "Loãng xương", "def_ko": "뼈의 밀도가 감소하여 취약해지는 질환", "def_vi": "Bệnh làm giảm mật độ xương, làm xương yếu"}, {"term_ko": "낙상", "term_vi": "Ngã", "def_ko": "넘어지는 것", "def_vi": "Bị ngã"}, {"term_ko": "고관절", "term_vi": "Khớp hông", "def_ko": "엉덩이 부위의 관절", "def_vi": "Khớp ở vùng đùi"}, {"term_ko": "질환", "term_vi": "Bệnh", "def_ko": "병이나 상태", "def_vi": "Tình trạng bệnh lí"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (112, '5', '노화에 따른 여성 생식기계 변화는?', '["난소의 기능 증가", "질의 윤활작용 감소", "난소 크기 증가", "질의 수축력 증가", "여성호르몬 분비 증가"]'::jsonb, 2, NULL, NULL, '{"1": "난소의 기능이 증가하는 것은 노화 과정에서 발생하지 않습니다.\n[정답]", "2": "여성의 노화에 따라 질의 윤활작용이 감소합니다.", "3": "난소의 크기는 노화로 인해 오히려 감소합니다.", "4": "질의 수축력은 노화로 인해 감소하지 증가하지 않습니다.", "5": "여성호르몬의 분비는 노화와 함께 감소합니다."}'::jsonb, '[{"term_ko": "노화", "term_vi": "Lão hóa", "def_ko": "나이와 함께 신체의 변화가 일어나는 과정", "def_vi": "Quá trình thay đổi cơ thể theo độ tuổi"}, {"term_ko": "여성", "term_vi": "Phụ nữ", "def_ko": "성별이 여성인 사람", "def_vi": "Người có giới tính nữ"}, {"term_ko": "생식기계", "term_vi": "Hệ thống sinh sản", "def_ko": "생식에 관련된 기관들의 시스템", "def_vi": "Hệ thống các cơ quan liên quan đến sinh sản"}, {"term_ko": "윤활작용", "term_vi": "Chất bôi trơn", "def_ko": "매끄럽게 하는 작용", "def_vi": "Hành động làm mượt mà"}, {"term_ko": "여성호르몬", "term_vi": "Hormone nữ", "def_ko": "여성의 신체에서 주로 생성되는 호르몬", "def_vi": "Hormone chủ yếu được tạo ra trong cơ thể phụ nữ"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (111, '5', '남성 노인의 비뇨기계 변화로 옳은 것은?', '["음경이 발기하는 데 시간이 짧게 걸린다.", "대부분의 남성은 전립선 비대를 경험한다.", "잔뇨량이 감소한다.", "방광 용적이 증가한다.", "소변줄기가 굵어진다."]'::jsonb, 2, NULL, NULL, '{"1": "음경의 발기 시간은 노화로 인해 길어질 수 있습니다.\n[정답]", "2": "많은 남성들이 전립선 비대를 경험합니다.", "3": "잔뇨량은 일반적으로 증가하는 경향이 있습니다.", "4": "방광 용적은 나이가 들수록 감소하는 경향이 있습니다.", "5": "소변줄기는 일반적으로 가늘어지는 경향이 있습니다."}'::jsonb, '[{"term_ko": "비뇨기계", "term_vi": "Hệ tiết niệu", "def_ko": "배설 기관", "def_vi": "Cơ quan đào thải"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (110, '5', '여성 노인에게 나타나는 요실금의 주된 요인으로 옳은 것은?', '["복압감소", "골반근육 조절능력 감소", "요도기능 향상", "호르몬 생산 증가", "방광 저장능력 증가"]'::jsonb, 2, NULL, NULL, '{"1": "복압의 감소는 요실금과 관련이 없습니다.\n[정답]", "2": "골반근육의 조절능력 감소는 여성 노인에서 요실금을 유발하는 주요 원인입니다.", "3": "요도기능 향상은 요실금과 반대되는 개념입니다.", "4": "호르몬의 생산 증가가 요실금에 도움이 되지는 않습니다.", "5": "방광의 저장능력 증가는 요실금의 발생과 무관합니다."}'::jsonb, '[{"term_ko": "요실금", "term_vi": "Tiểu không tự chủ", "def_ko": "소변을 참지 못하고 새는 증상(한국어)", "def_vi": "Triệu chứng không thể giữ được nước tiểu(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (109, '5', '복압성 요실금의 치료 및 예방법으로 옳은 것은?', '["골반근육 강화운동", "수분 섭취 제한", "과일 섭취 제한", "복부지방 증가", "고단백 식이 식단"]'::jsonb, 1, NULL, NULL, '{"1": "골반근육 강화운동은 복압성 요실금에 효과적인 치료법입니다. [정답]", "2": "수분 섭취 제한은 요실금을 악화시킬 수 있습니다.", "3": "과일 섭취 제한은 필요하지 않습니다.", "4": "복부지방 증가는 요실금을 악화할 수 있습니다.", "5": "고단백 식이 식단은 요실금과 관련이 없습니다."}'::jsonb, '[{"term_ko": "복압성", "term_vi": "Béo phì chức năng", "def_ko": "압력이 복부에서 발생하는 상태", "def_vi": "Tình trạng áp lực xảy ra trong bụng"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (108, '5', '절박성 요실금이 있는 대상자를 돕는 방법으로 옳은 것은?', '["낮 동안 기저귀를 채워준다.", "골반근육 강화운동을 한다.", "웃음요법 프로그램에 참여하게 한다.", "식이섬유가 적은 음식을 제공한다.", "따뜻한 녹차를 자주 마시게 한다."]'::jsonb, 2, NULL, NULL, '{"1": "기저귀는 일시적인 대처일 뿐, 요실금 치료에 도움이 되지 않는다.\n[정답]", "2": "골반근육 강화운동은 요실금 증상을 완화하는 데 효과적이다.", "3": "웃음요법은 일반적인 스트레스 해소에는 좋지만, 요실금에 직접적인 효과는 없다.", "4": "식이섬유가 적은 음식은 오히려 변비를 유발할 수 있다.", "5": "따뜻한 녹차는 이뇨작용을 촉진할 수 있으므로 요실금에 도움이 되지 않는다."}'::jsonb, '[{"term_ko": "절박성 요실금", "term_vi": "Tiểu không tự chủ cấp bách", "def_ko": "긴급하게 소변이 마려운 상태", "def_vi": "Tình trạng muốn đi tiểu gấp"}, {"term_ko": "골반근육", "term_vi": "Cơ vùng chậu", "def_ko": "골반 부위의 근육", "def_vi": "Các cơ ở vùng chậu"}, {"term_ko": "기저귀", "term_vi": "Tã", "def_ko": "소변을 흡수하도록 만든 위생용품", "def_vi": "Sản phẩm vệ sinh dùng để hấp thụ nước tiểu"}, {"term_ko": "식이섬유", "term_vi": "Chất xơ", "def_ko": "장의 건강에 좋은 섬유질", "def_vi": "Chất dinh dưỡng tốt cho sức khỏe ruột"}, {"term_ko": "이뇨작용", "term_vi": "Tác dụng lợi tiểu", "def_ko": "체내의 소변 배출을 촉진하는 작용", "def_vi": "Tác động thúc đẩy việc bài tiết nước tiểu"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (107, '5', '전립선비대증의 발생 원인으로 옳은 것은?', '["여성호르몬의 증가", "상행성 요로감염", "복압상승", "방광의 저장능력 감소", "골반근육 조절능력의 약화"]'::jsonb, 1, NULL, NULL, '{"1": "여성호르몬의 증가가 전립선비대증과 관련이 있어 옳은 설명입니다.\n[정답]", "2": "상행성 요로감염은 전립선비대증의 직접적인 원인과는 관련이 적습니다.", "3": "복압상승은 다른 증상과 관련될 수 있으나 전립선비대증의 원인은 아닙니다.", "4": "방광의 저장능력 감소는 결과적으로 나타날 수 있지만 직접적인 원인은 아닙니다.", "5": "골반근육 조절능력의 약화는 관련이 있을 수 있지만 전립선비대증의 주요 원인으로 보기는 어렵습니다."}'::jsonb, '[{"term_ko": "전립선비대증", "term_vi": "Phì đại tuyến tiền liệt", "def_ko": "전립선이 비대해지는 질병", "def_vi": "Bệnh tuyến tiền liệt phì đại"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (106, '5', '전립선비대증의 증상에 해당하는 것으로 옳은 것은?', '["소변줄기가 굵어진다.", "배뇨 횟수가 감소한다.", "배뇨 후 잔뇨감이 없다.", "힘을 주어야 소변이 나온다.", "배뇨 후 4시간 이내 소변이 마렵다."]'::jsonb, 4, NULL, NULL, '{"1": "전립선비대증에서는 소변줄기가 굵어지지 않습니다.\n[정답]", "2": "전립선비대증에서는 배뇨 횟수가 일반적으로 증가합니다.", "3": "배뇨 후 잔뇨감이 느껴지는 것이 전립선비대증의 증상입니다.", "4": "힘을 주어야만 소변이 나오는 것이 전립선비대증의 증상입니다.", "5": "배뇨 후 4시간 이내 소변이 마렵다는 증상은 전립선비대증과는 관련이 없습니다."}'::jsonb, '[{"term_ko": "전립선비대증", "term_vi": "BPH", "def_ko": "전립선의 크기가 커지는 상태", "def_vi": "Tình trạng kích thước tuyến tiền liệt bị phình to"}, {"term_ko": "배뇨", "term_vi": "Đi tiểu", "def_ko": "소변을 보는 행위", "def_vi": "Hành động đi vệ sinh"}, {"term_ko": "잉여", "term_vi": "Dư", "def_ko": "남은 것", "def_vi": "Cái còn lại"}, {"term_ko": "소변줄기", "term_vi": "Dòng nước tiểu", "def_ko": "소변의 흐름", "def_vi": "Dòng chảy của nước tiểu"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (105, '5', '전립선비대증을 관리하는 방법으로 옳은 것은?', '["노화현상이므로 약물은 사용하지 않는다.", "소변량을 증가시키기 위해 맥주를 마신다.", "고지방과 고콜레스테롤 음식 섭취를 피한다.", "소변을 참을 수 있을 때까지 참는다.", "약화된 근육을 강화하기 위해 체중을 늘린다."]'::jsonb, 3, NULL, NULL, '{"1": "전립선비대증 관리에 있어 약물 치료는 일반적이지 않다고 할 수 없으며, 필요에 따라 사용해야 한다.\n[정답]", "3": "고지방 및 고콜레스테롤 음식은 전립선 건강에 좋지 않으므로 피해야 한다.", "2": "맥주는 오히려 소변을 자극할 수 있어 바람직하지 않다.", "4": "소변을 지나치게 참는 것은 방광에 해롭고 전립선에 좋지 않다.", "5": "체중을 늘리는 것은 오히려 근육을 약화시킬 수 있으며 건강에 좋지 않다."}'::jsonb, '[{"term_ko": "전립선비대증", "term_vi": "Bệnh phì đại tuyến tiền liệt", "def_ko": "남성의 전립선이 비대해지는 질환", "def_vi": "Bệnh tuyến tiền liệt to lên ở nam giới"}, {"term_ko": "약물", "term_vi": "Thuốc", "def_ko": "약을 의미하는 용어", "def_vi": "Từ ngữ dùng để chỉ thuốc"}, {"term_ko": "고지방", "term_vi": "Chất béo cao", "def_ko": "지방이 많은 것", "def_vi": "Đồ ăn giàu chất béo"}, {"term_ko": "고콜레스테롤", "term_vi": "Cholesterol cao", "def_ko": "콜레스테롤이 많은 것", "def_vi": "Đồ ăn chứa nhiều cholesterol"}, {"term_ko": "소변", "term_vi": "Nước tiểu", "def_ko": "인간의 배설물", "def_vi": "Chất thải của cơ thể con người"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (104, '5', '노화에 따른 피부질환의 특성으로 옳은 것은?', '["표피가 얇아져 탄력성이 증가한다.", "상처회복이 지연되고 궤양이 생기기 쉽다.", "손톱과 발톰이 얇아진다.", "피하지방의 증가로 기온에 둔감해진다.", "각질층의 수분함량의 증가로 소양증이 증가한다."]'::jsonb, 2, NULL, NULL, '{"1": "표피가 얇아지면 탄력성이 감소합니다.\n[정답]", "2": "노화로 인해 상처회복이 지연되고 궤양이 생기기 쉬워집니다.", "3": "손톱과 발톱이 얇아지는 것은 맞지만, 지문과는 관계가 적습니다.", "4": "피하지방의 감소로 기온에 둔감해지는 것이 더 일반적입니다.", "5": "각질층의 수분함량이 감소하여 소양증이 증가합니다."}'::jsonb, '[{"term_ko": "노화", "term_vi": "Lão hóa", "def_ko": "나이가 들면서 신체나 정신의 변화", "def_vi": "Sự thay đổi về thể chất hoặc tâm lý theo độ tuổi"}, {"term_ko": "피부질환", "term_vi": "Bệnh da", "def_ko": "피부에서 발생하는 질환", "def_vi": "Các bệnh xảy ra ở da"}, {"term_ko": "상처", "term_vi": "Vết thương", "def_ko": "피부의 손상", "def_vi": "Sự tổn thương trên da"}, {"term_ko": "궤양", "term_vi": "Loét", "def_ko": "깊은 피부 손상", "def_vi": "Tổn thương sâu trên da"}, {"term_ko": "염증", "term_vi": "Viêm", "def_ko": "몸의 방어 반응", "def_vi": "Phản ứng bảo vệ của cơ thể"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (103, '5', '욕창의 위험성이 높은 대상자로 옳은 것은?', '["영양 부족으로 피하지방이 감소한 대상자", "침상에서 뒤척이는 대상자", "체중을 잘 유지하는 대상자", "요실금이나 변실금이 없는 대상자", "침상 이동시 밀림이 없는 대상자"]'::jsonb, 1, NULL, NULL, '{"1": "영양 부족은 피부의 건강에 영향을 미쳐 욕창 위험을 높입니다.\n[정답]", "2": "침상에서 뒤척이는 것은 욕창 위험을 낮추는 요소입니다.", "3": "체중을 잘 유지하는 경우 욕창 발생 위험이 낮습니다.", "4": "요실금이나 변실금이 없는 경우 욕창 위험이 낮습니다.", "5": "침상 이동 시 밀림이 없으면 욕창 위험이 낮아집니다."}'::jsonb, '[{"term_ko": "욕창", "term_vi": "Nguyên nhân gây loét", "def_ko": "압력에 의해 피부가 손상되는 상태(pressure ulcer)", "def_vi": "Nguyên nhân gây ra loét do nằm lâu"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (102, '5', '대상자에게 욕창을 발생시킬 가능성이 높은 요양보호사의 행동은?', '["체위를 자주 변경해준다.", "침상 시트의 주름을 펴준다.", "무릎 사이에 베개는 제거한다.", "천골 부위에 도넛 베개 사용을 삼간다.", "목욕 후에 피부를 완전히 말려준다."]'::jsonb, 3, NULL, NULL, '{"1": "체위를 자주 변경해주는 것은 욕창 예방에 도움이 된다.", "2": "침상 시트의 주름을 펴주는 것은 편안함을 제공하고 피부 손상을 예방하는 데 기여한다.\n[정답]", "3": "무릎 사이에 베개는 제거해야 한다. 무릎 사이에 베개가 있으면 압력이 증가해 욕창 발생 가능성이 높아진다.", "4": "천골 부위에 도넛 베개 사용을 삼가는 것은 압력을 분산시켜 욕창 예방에 기여한다.", "5": "목욕 후에 피부를 완전히 말려주는 것은 피부 건강을 유지하는 데 중요하다."}'::jsonb, '[{"term_ko": "욕창", "term_vi": "Loét do tì đè", "def_ko": "피부가 오랫동안 압력을 받아 손상되는 상태", "def_vi": "Tình trạng da bị tổn thương do áp lực kéo dài"}, {"term_ko": "체위", "term_vi": "Tư thế", "def_ko": "몸의 자세", "def_vi": "Tư thế của cơ thể"}, {"term_ko": "베개", "term_vi": "Gối", "def_ko": "머리를 받치는 물건", "def_vi": "Đồ vật dùng để đỡ đầu"}, {"term_ko": "천골", "term_vi": "Xương cùng", "def_ko": "척추의 아래쪽 부분", "def_vi": "Phần dưới cùng của cột sống"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (101, '5', '욕창을 예방하는 방법으로 옳은 것은?', '["천골부위에 도넛 베개를 대어준다.", "정해진 시간에 자세변경을 한다.", "단백질을 충분히 보충한다.", "목욕 후 파우더를 사용한다.", "오염물질은 알코올로 닦아낸다."]'::jsonb, 3, NULL, NULL, '{"1": "천골부위에 도넛 베개를 대는 것은 도움이 될 수 있지만 반드시 필요하지는 않습니다. \n[정답]", "2": "정해진 시간에 자세변경을 하는 것은 욕창 예방에 매우 중요합니다.", "3": "단백질을 충분히 보충하는 것은 피부 재생에 도움이 되어 욕창 예방에 기여할 수 있습니다.", "4": "목욕 후 파우더를 사용하는 것은 피부를 보호할 수 있지만 욕창 예방의 직접적인 방법은 아닙니다.", "5": "오염물질은 알코올로 닦아내는 것보다 적절한 방법으로 씻어내는 것이 좋습니다."}'::jsonb, '[{"term_ko": "욕창", "term_vi": "Loét", "def_ko": "압력으로 인한 피부 손상", "def_vi": "Tổn thương da do áp lực"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (100, '5', '노인에게 흔한 피부건조증을 예방하기 위한 생활 습관으로 옳은 것은?', '["수분섭취를 줄인다.", "알코올이 함유된 세정제를 사용한다.", "겨울철 실내 제습기를 사용한다.", "때를 밀어 피부의 청결을 유지한다.", "목욕 후 몸에 물기가 마르기 전에 보습제를 바른다."]'::jsonb, 5, NULL, NULL, '{"1": "수분섭취를 줄이면 피부건조증이 악화된다. 이는 잘못된 선택이다.\n[정답]", "5": "목욕 후 몸에 물기가 마르기 전에 보습제를 바르는 것은 피부의 수분을 유지하는 좋은 방법이다.", "2": "알코올이 함유된 세정제는 피부를 더욱 건조하게 하므로 잘못된 선택이다.", "3": "겨울철 실내 제습기는 습도가 낮아져 피부건조증이 악화될 수 있으므로 잘못된 선택이다.", "4": "때를 밀리면 피부의 보호막이 손상될 수 있으므로 잘못된 선택이다."}'::jsonb, '[{"term_ko": "노인", "term_vi": "Người cao tuổi", "def_ko": "어르신(한국어)", "def_vi": "Người già"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (99, '5', '수두를 일으키는 바이러스에 의해 피부와 신경에 ㅇ염증이 생기는 질환으로 옳은 것은?', '["욕창", "피부 건조증", "대상포진", "옴", "머릿니"]'::jsonb, 3, NULL, NULL, '{"1": "욕창: 주로 장시간 눕거나 앉은 자세로 인해 피부 손상이 발생하는 것이므로 정답이 아닙니다.", "2": "피부 건조증: 피부 수분 부족으로 인해 생기는 문제로 염증과는 관련이 없습니다.\n[정답]", "3": "대상포진: 수두 바이러스가 재활성화되어 피부와 신경에 염증을 일으키는 질환입니다.", "4": "옴: 피부 기생충에 의한 질환으로 수두와는 관련이 없습니다.", "5": "머릿니: 두피에 기생하는 이로 인한 감염으로, 수두와는 관계가 없습니다."}'::jsonb, '[{"term_ko": "수두", "term_vi": "Thủy đậu", "def_ko": "물집이 생기는 감염병(한국어)", "def_vi": "Bệnh lây nhiễm có mụn nước"}, {"term_ko": "염증", "term_vi": "Viêm", "def_ko": "상처나 감염으로 인해 생기는 부풀어 오른 상태(한국어)", "def_vi": "Tình trạng sưng tấy xảy ra do vết thương hoặc nhiễm trùng"}, {"term_ko": "대상포진", "term_vi": "Zona", "def_ko": "수두 바이러스 재활성화에 따른 피부와 신경염증(한국어)", "def_vi": "Viêm da và thần kinh do virus gây thuỷ đậu tái hoạt động"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (98, '5', '대상포진의 주요 증상으로 옳은 것은?', '["작열감을 포함한 발진이 생긴다.", "전신에 수포가 생긴다.", "혈관성 질환이다.", "인플루엔자 바이러스가 원인이다.", "물집이 나타난 이후 통증이 발생한다."]'::jsonb, 1, NULL, NULL, '{"1": "작열감을 포함한 발진이 나타나는 것이 맞습니다.\n[정답]", "2": "전신에 수포가 생기지는 않으며, 특정 피부에 발생합니다.", "3": "혈관성 질환이 아니라 바이러스 감염에 의한 질환입니다.", "4": "인플루엔자 바이러스가 아닌 수두 대상포진 바이러스가 원인입니다.", "5": "물집이 나타난 이후에는 통증이 있을 수 있으나, 초기부터 통증이 발생할 수 있습니다."}'::jsonb, '[{"term_ko": "대상포진", "term_vi": "Zona", "def_ko": "질병명(한국어)", "def_vi": "Tên bệnh"}, {"term_ko": "증상", "term_vi": "Triệu chứng", "def_ko": "증상(한국어)", "def_vi": "Triệu chứng"}, {"term_ko": "발진", "term_vi": "Phát ban", "def_ko": "발진(한국어)", "def_vi": "Phát ban"}, {"term_ko": "수포", "term_vi": "Bọng nước", "def_ko": "물집(한국어)", "def_vi": "Bọng nước"}, {"term_ko": "통증", "term_vi": "Đau", "def_ko": "통증(한국어)", "def_vi": "Đau"}, {"term_ko": "바이러스", "term_vi": "Virus", "def_ko": "바이러스(한국어)", "def_vi": "Virus"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (97, '5', '옴에 감염된 대상자를 돕는 방법으로 옳은 것은?', '["음식 섭취로 인한 알레르기 증상이다.", "가려운 부위에만 연고를 도포한다.", "아침에 약을 바르고 잠자기 전에 씻어낸다.", "감염 부위를 만져서 열감이 있는지 확인한다.", "대상자의 동거 가족은 증상이 없어도 함께 치료 받는다."]'::jsonb, 5, NULL, NULL, '{"1": "음식 섭취로 인한 알레르기 증상이 아니다. 따라서 옳지 않다.\n[정답]", "5": "대상자의 동거 가족도 증상이 없어도 함께 치료 받아야 한다. 이는 전염성을 고려한 접근이다.", "2": "가려운 부위에만 연고를 도포하는 것은 불완전한 접근법이다. 따라서 옳지 않다.", "3": "아침에 약을 바르고 잠자기 전에 씻어내는 것은 올바른 방식이 아니다. 따라서 옳지 않다.", "4": "감염 부위를 만져서 열감이 있는지 확인하는 것은 감염 확인의 방법이지만, 옳은 치료 방법이 아니다. 따라서 옳지 않다."}'::jsonb, '[{"term_ko": "옴", "term_vi": "Bệnh ghẻ", "def_ko": "병(한국어)", "def_vi": "Bệnh ghẻ"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (96, '5', '머릿니에 감염된 대상자의 돕기 방법으로 옳은 것은?', '["1달 간격으로 2회 약물치료를 한다.", "대상자가 사용했던 침구류는 함께 사용한다.", "침구류는 찬물에 5시간 이상 담갔다 세탁한다.", "머리는 대상자가 원할 때 감긴다.", "진공청소기로 방안을 꼼꼼히 청소한다."]'::jsonb, 5, NULL, NULL, '{"1": "1달 간격으로 약물치료를 하는 것은 적절한 방법이 아니다. 머릿니 제거는 즉각적으로 이루어져야 한다.\n[정답]", "5": "진공청소기로 방안을 청소하는 것은 머릿니와 그 알을 효과적으로 제거하는 방법으로 옳다.", "3": "침구류를 찬물에 5시간 이상 담가 세탁하는 것은 효과적이지 않다. 높은 온도의 물에서 세탁해야 한다.", "4": "머리는 대상자의 원할 때가 아니라 정해진 주기로 세척해야 한다.", "2": "대상자가 사용했던 침구류는 따로 사용해야 한다."}'::jsonb, '[{"term_ko": "머릿니", "term_vi": "Chí đầu", "def_ko": "머리에 감염되는 곤충", "def_vi": "Côn trùng ký sinh trên đầu"}, {"term_ko": "약물치료", "term_vi": "Điều trị bằng thuốc", "def_ko": "약으로 치료하는 방법", "def_vi": "Phương pháp điều trị bằng thuốc"}, {"term_ko": "진공청소기", "term_vi": "Máy hút bụi", "def_ko": "먼지를 빨아들이는 기계", "def_vi": "Thiết bị hút bụi"}, {"term_ko": "침구류", "term_vi": "Đồ dùng giường", "def_ko": "침대에서 사용하는 물품", "def_vi": "Vật phẩm sử dụng trên giường"}, {"term_ko": "세탁", "term_vi": "Giặt", "def_ko": "빨래를 하는 것", "def_vi": "Hành động giặt giũ"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (95, '5', '기저귀피부염이 있는 대상자의 돕기 방법으로 옳은 것은?', '["회음부 접촉 부위에 생긴다.", "경계가 분명한 병변이 있다.", "멍 자국 같은 푸른 병변이다.", "기저귀를 자주 갈아준다.", "항생제를 처방받아 바른다."]'::jsonb, 4, NULL, NULL, '{"1": "기저귀 피부염은 주로 회음부 접촉 부위에서 발생할 수 있지만, 이 보기는 도움 방법이 아니다.\n[정답]", "4": "기저귀 피부염의 예방과 관리를 위해 기저귀를 자주 갈아주는 것이 중요하다.", "2": "경계가 분명한 병변을 나타낼 수 있으나, 이는 도움 방법이 아니다.", "3": "멍 자국 같은 푸른 병변은 기저귀 피부염의 증상이 아니다.", "5": "항생제는 일반적으로 기저귀 피부염에 대한 치료 방법이 아니다."}'::jsonb, '[{"term_ko": "기저귀", "term_vi": "Tã", "def_ko": "아기나 노인이 사용하는 보호용 기구", "def_vi": "vật dụng bảo vệ được sử dụng cho trẻ em hoặc người già"}, {"term_ko": "피부염", "term_vi": "Viêm da", "def_ko": "피부의 염증", "def_vi": "viêm nhiễm da"}, {"term_ko": "돕기", "term_vi": "Giúp đỡ", "def_ko": "지원하다, 도와주다", "def_vi": "trợ giúp, giúp đỡ"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (94, '5', '다음과 같은 특성이 있을 때 의심할 수 있는 질환으로 옳은 것은?• 과도한 자극, 자외선 노출 등 스테로이드 연고 도포에 의해 생긴 출혈 • 손등, 팔에 경계가 뚜렷한 다양한 크기와 모양', '["건선", "기저귀 습진", "노인성 자반", "대상포진", "우정문신"]'::jsonb, 3, NULL, NULL, '{"1": "건선: 만성적인 염증성 피부질환으로, 가려움증과 함께 인설이 생기기 때문에 제외됩니다.", "2": "기저귀 습진: 주로 아기에게 발생하며, 자극과 관련된 질환이지만 해당 특성과는 거리가 멉니다.\n[정답]", "3": "노인성 자반: 노인에게 흔한 피부출혈로, 경계가 뚜렷하고 여러 모양이 나타나는 특성과 일치합니다.", "4": "대상포진: 신경에 의한 통증과 물집이 특징이며, 질문의 해당 특성과는 적합하지 않습니다.", "5": "우정문신: 특정한 문양이나 문신과 관계된 것이므로 해당 증상과는 관련이 없습니다."}'::jsonb, '[{"term_ko": "특성", "term_vi": "Đặc tính", "def_ko": "특점(한국어)", "def_vi": "đặc điểm(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (93, '5', '노화에 따른 신경계 변화로 옳은 것은?', '["신경세포기능의 향상", "근긴장 반응성 향상", "정서 조절의 안정", "운동부족으로 인한 숙면", "단기기억의 감퇴"]'::jsonb, 5, NULL, NULL, '{"1": "신경세포기능의 향상은 일반적으로 노화와 관련해 옳지 않다.\n[정답]", "5": "단기기억의 감퇴가 노화와 관련된 신경계 변화로 맞다.", "2": "근긴장 반응성 향상은 나이가 들면서 오히려 감소하는 경향이 있다.", "3": "정서 조절의 안정은 노화에 따라 오히려 어려워질 수 있다.", "4": "운동부족으로 인한 숙면은 노화와 관계없이 일반적인 현상이다."}'::jsonb, '[{"term_ko": "노화", "term_vi": "Lão hóa", "def_ko": "나이가 많아짐(한국어)", "def_vi": "Sự tăng tuổi"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (92, '5', '노화에 따른 시각의 변화로 옳은 것은?', '["눈물 양의 증가", "각막반사의 증가", "색의 식별능력 증가", "눈부심의 증가", "결막 두께의 증가"]'::jsonb, 4, NULL, NULL, '{"1": "눈물 양의 증가는 노화와 관련해 일반적이지 않습니다.\n[정답]", "4": "눈부심의 증가는 노화로 인해 발생할 수 있는 시각적 변화입니다.", "2": "각막반사의 증가는 노화와 관계가 없습니다.", "3": "색의 식별능력은 노화에 따라 감소하는 경향이 있습니다.", "5": "결막 두께는 노화에 따라 변하지 않거나 감소할 수 있습니다."}'::jsonb, '[{"term_ko": "노화", "term_vi": "Lão hóa", "def_ko": "늙다(한국어)", "def_vi": "Già đi(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (91, '5', '노화에 따른 청각계 변화에 대한 설명으로 옳은 것은?', '["고막이 얇아진다.", "이관이 좁아진다.", "외이도가 습해진다.", "평형감각이 향상된다.", "난청은 여성에게 흔하다."]'::jsonb, 2, NULL, NULL, '{"1": "고막이 얇아지는 것이 아니라 두꺼워질 수 있습니다.\n[정답]", "2": "노화에 따라 이관(귀와 목을 연결하는 관)이 좁아지는 것이 일반적입니다.", "3": "외이도가 습해지는 것이 아니라 건조해질 수 있습니다.", "4": "평형감각은 노화에 따라 저하될 수 있습니다.", "5": "난청은 남성에게 더 흔하게 발생합니다."}'::jsonb, '[{"term_ko": "노화", "term_vi": "청각계", "def_ko": "나이듦(già hóa)", "def_vi": "듣는 시스템(hệ thống thính giác)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (90, '5', '노화에 따른 미각의 변화로 옳은 것은?', '["미뢰의 기능 증가", "혀의 유두 돌기 증가", "입술 근육의 탄력성 증가", "구강건조 증상 감소", "구강 점막의 재생 능력 감소"]'::jsonb, 5, NULL, NULL, '{"1": "미뢰의 기능은 노화에 따라 감소하며, 증가하지 않는다.", "2": "혀의 유두 돌기도 노화로 인해 감소하거나 변화한다.", "3": "입술 근육의 탄력성은 노화에 따라 감소한다.", "4": "구강건조 증상은 노화와 관련하여 증가할 수 있다.\n[정답]", "5": "구강 점막의 재생 능력은 노화에 따라 감소하게 된다."}'::jsonb, '[{"term_ko": "미각", "term_vi": "Vị giác", "def_ko": "맛을 느끼는 능력(한국어)", "def_vi": "Khả năng cảm nhận vị"}, {"term_ko": "노화", "term_vi": "Lão hóa", "def_ko": "나이가 많아지는 것(한국어)", "def_vi": "Sự gia tăng tuổi tác"}, {"term_ko": "미뢰", "term_vi": "Nụ vị giác", "def_ko": "맛을 느끼는 기관(한국어)", "def_vi": "Cơ quan cảm nhận vị"}, {"term_ko": "구강", "term_vi": "Khoang miệng", "def_ko": "입과 관련된 부분(한국어)", "def_vi": "Phần liên quan đến miệng"}, {"term_ko": "점막", "term_vi": "Niêm mạc", "def_ko": "내장기관을 덮고 있는 얇은 막(한국어)", "def_vi": "Màng mỏng bao phủ cơ quan nội tạng"}, {"term_ko": "재생", "term_vi": "Tái sinh", "def_ko": "다시 살아나는 것(한국어)", "def_vi": "Sự sống lại"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (89, '5', '노화에 따른 감각기계 변화로 옳은 것은?', '["맛에 대한 감지능력이 예민해진다.", "후각세포의 감소로 둔화가 나타난다.", "접촉의 강도가 낮아야 접촉감을 느낄 수 있다.", "통증에 대한 민감성이 증가한다.", "넓은 홀에서는 큰 소리로 소통을 한다."]'::jsonb, 2, NULL, NULL, '{"1": "노화로 인해 맛에 대한 감지능력은 일반적으로 둔화됩니다.\n[정답]", "2": "후각세포가 감소함에 따라 후각의 둔화가 나타납니다.", "3": "노화로 인해 접촉에 대한 민감성이 떨어지므로, 접촉의 강도가 높아야 감지를 할 수 있습니다.", "4": "통증에 대한 민감성은 노화와 함께 감소하는 경향이 있습니다.", "5": "큰 소리로 소통할 필요가 있는 것은 일반적인 상황이 아닙니다."}'::jsonb, '[{"term_ko": "노화", "term_vi": "Lão hóa", "def_ko": "나이 때문에 신체의 기능이 퇴화되어 가는 과정", "def_vi": "Quá trình chức năng cơ thể suy giảm do tuổi tác"}, {"term_ko": "감각기계", "term_vi": "Hệ thống cảm giác", "def_ko": "신체에서 감각 정보를 처리하는 시스템", "def_vi": "Hệ thống xử lý thông tin cảm giác trong cơ thể"}, {"term_ko": "후각세포", "term_vi": "Tế bào khứu giác", "def_ko": "냄새를 감지하는 세포", "def_vi": "Tế bào phát hiện mùi"}, {"term_ko": "둔화", "term_vi": "Giảm nhạy cảm", "def_ko": "감각의 반응 속도나 강도가 줄어드는 것", "def_vi": "Sự giảm tốc độ hoặc cường độ phản ứng cảm giác"}, {"term_ko": "민감성", "term_vi": "Độ nhạy cảm", "def_ko": "특정 자극에 반응하는 정도", "def_vi": "Mức độ phản ứng với một kích thích"}, {"term_ko": "소통", "term_vi": "Giao tiếp", "def_ko": "의사 소통을 하는 행위", "def_vi": "Hành động trao đổi thông tin"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (88, '5', '눈의 압력 상승으로 인한 시신경이 손상되어 시력이 점차 약해지고, 안구에 통증이 있는 질환으로 옳은 것은?', '["결막염", "황반변성", "백내장", "녹내장", "수정체 황화현상"]'::jsonb, 4, NULL, NULL, '{"1": "결막염은 눈의 결막에 염증이 생기는 질환으로, 압력 상승과는 관련이 없습니다.", "2": "황반변성은 시력의 중심 부위인 황반에 문제가 발생하는 질환으로, 통증을伴わ나 눈의 압력 상승과 관련은 없습니다.", "3": "백내장은 수정체가 혼탁해져 시력이 저하되는 질환으로, 눈의 압력 상승과는 관련이 없습니다.\n[정답]", "4": "녹내장은 눈의 압력이 상승하여 시신경이 손상되고 시력이 약해지는 질환으로, 통증이 동반될 수 있습니다.", "5": "수정체 황화현상은 노화로 인한 수정체의 변화로 시력에 영향을 줄 수 있으나 압력 상승과는 직접적인 연관이 없습니다."}'::jsonb, '[{"term_ko": "압력", "term_vi": "Áp suất", "def_ko": "압력(한국어)", "def_vi": "Áp lực(베트남어)"}, {"term_ko": "시신경", "term_vi": "Dây thần kinh thị giác", "def_ko": "시각을 전달하는 신경(한국어)", "def_vi": "Dây dẫn truyền thị giác(베트남어)"}, {"term_ko": "통증", "term_vi": "Đau", "def_ko": "아픔(한국어)", "def_vi": "Cảm giác đau(베트남어)"}, {"term_ko": "황반", "term_vi": "Điểm vàng", "def_ko": "시각의 중심부(한국어)", "def_vi": "Điểm trung tâm của thị lực(베트남어)"}, {"term_ko": "녹내장", "term_vi": "Glôcôm", "def_ko": "눈의 질환(한국어)", "def_vi": "Bệnh mắt(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (87, '5', '녹내장 대상자의 바람직한 일상생활 습관으로 옳은 것은?', '["겨울철에 스키를 즐긴다.", "무거운 물건 드는 것을 피한다.", "물구나무 서기로 상체 순환을 돕는다.", "머리를 숙인 자세에서 독서를 한다.", "몸에 꽉 끼는 옷을 입어 체온을 유지한다."]'::jsonb, 2, NULL, NULL, '{"1": "겨울철에 스키를 즐기는 것은 시각에 부담을 줄 수 있어 바람직하지 않습니다.\n[정답]", "2": "무거운 물건 드는 것을 피하는 것은 눈에 부담을 줄일 수 있는 좋은 습관입니다.", "3": "물구나무 서기는 혈압에 영향을 줄 수 있어 추천되지 않습니다.", "4": "머리를 숙인 자세에서 독서는 시야에 부담을 주므로 바람직하지 않습니다.", "5": "몸에 꽉 끼는 옷을 입는 것은 체온을 유지하는 데 도움이 되지 않으며 불편함을 초래할 수 있습니다."}'::jsonb, '[{"term_ko": "녹내장", "term_vi": "Glaucom", "def_ko": "눈의 압력이 높아지는 질환(병)", "def_vi": "Bệnh tăng áp lực mắt"}, {"term_ko": "바람직한", "term_vi": "Thích hợp", "def_ko": "좋은, 바람직한", "def_vi": "Tốt, phù hợp"}, {"term_ko": "물구나무서기", "term_vi": "Đứng bằng đầu", "def_ko": "머리를 아래로 하고 서 있는 자세", "def_vi": "Tư thế đứng ngược"}, {"term_ko": "머리를 숙인 자세", "term_vi": "Tư thế cúi đầu", "def_ko": "머리가 아래로 기울어진 자세", "def_vi": "Tư thế nghiêng đầu xuống"}, {"term_ko": "체온", "term_vi": "Nhiệt độ cơ thể", "def_ko": "몸의 온도", "def_vi": "Nhiệt độ của cơ thể"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (86, '5', '백내장은 ☐ 이(가) 혼탁해져서 빛이 드러가지 못하여 시력장애가 발생하는 질환이다. ☐안에 들어갈 부위로 옳은 것은?', '["각막", "결막", "공막", "수정체", "홍채"]'::jsonb, 4, NULL, NULL, '{"1": "각막: 외부에서 들어오는 빛을 투과시키는 역할을 하지만 백내장과는 관련이 없습니다.", "2": "결막: 눈꺼풀 안쪽과 안구 표면을 덮고 있는 점막으로, 백내장과 관련이 없습니다.", "3": "공막: 안구의 외벽으로, 백내장과는 관련이 없습니다.\n[정답]", "4": "수정체: 백내장은 수정체가 혼탁해지는 질환으로, 시력장애를 유발합니다.", "5": "홍채: 눈의 색을 결정하고 빛의 양을 조절하지만, 백내장과는 관련이 없습니다."}'::jsonb, '[{"term_ko": "백내장", "term_vi": "혼탁", "def_ko": "질환(병) / bệnh đục thủy tinh thể", "def_vi": "흐림(먼지나 얼룩) / mờ đục"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (85, '5', '백내장의 주요 증상으로 옳은 것은?', '["뿌옇게 혼탁한 각막", "안구의 통증", "두통, 구역질", "심하면 실명됨", "통증이 없으면서 점차 흐려지는 시력"]'::jsonb, 5, NULL, NULL, '{"1": "뿌옇게 혼탁한 각막은 백내장과 관련이 없으며 주로 각막 질환과 연관이 있습니다.", "2": "안구의 통증은 백내장으로 인한 주요 증상이 아닙니다.", "3": "두통과 구역질은 백내장과 직접적인 관련이 없습니다.\n[정답]", "4": "심하면 실명됨은 백내장이 심해질 경우의 결과를 설명하나 주요 증상으로는 적합하지 않습니다.", "5": "통증이 없으면서 점차 흐려지는 시력은 백내장의 일반적인 증상으로 맞습니다."}'::jsonb, '[{"term_ko": "백내장", "term_vi": "Thủy tinh thể", "def_ko": "노안의 주요 원인으로 시력이 흐릿해지는 상태", "def_vi": "Trạng thái thị lực bị mờ do nguyên nhân chủ yếu là thoái hóa"}, {"term_ko": "증상", "term_vi": "Triệu chứng", "def_ko": "증상, dấu hiệu", "def_vi": "Dấu hiệu"}, {"term_ko": "실명", "term_vi": "Mù", "def_ko": "시력을 잃는 상태", "def_vi": "Trạng thái mất thị lực"}, {"term_ko": "혼탁", "term_vi": "Mờ đục", "def_ko": "깨끗하지 않음, 흐림", "def_vi": "Không rõ ràng, bị đục"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (84, '5', '노화로 나타날 수 있는 내분비계 변화로 옳은 것은?', '["공복 혈당이 감소한다.", "인슐린에 대한 민감성이 감소한다.", "기초대사율이 증가한다.", "근육의 질량이 증가한다.", "갑상선호르몬 분비가 증가한다."]'::jsonb, 2, NULL, NULL, '{"1": "공복 혈당은 노화로 인해 증가하는 경향이 있습니다.\n[정답]", "2": "노화가 진행됨에 따라 인슐린에 대한 민감성이 감소합니다.", "3": "기초대사율은 대개 노화에 따라 감소합니다.", "4": "근육의 질량은 노화에 따라 감소하는 경향이 있습니다.", "5": "갑상선호르몬의 분비는 일반적으로 노화와 함께 감소합니다."}'::jsonb, '[{"term_ko": "노화", "term_vi": "Lão hóa", "def_ko": "늙음(한국어)", "def_vi": "Sự già đi(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (83, '5', '당뇨병의 주요 증상으로 옳은 것은?', '["음식 섭취량 감소", "감각 민감성 증가", "갈증 감소", "소변 배설량 증가", "수분 섭취량 감소"]'::jsonb, 4, NULL, NULL, '{"1": "음식 섭취량 감소: 당뇨병 환자들은 일반적으로 음식 섭취량이 감소하지 않습니다.\n[정답]", "4": "소변 배설량 증가: 당뇨병의 주요 증상 중 하나로, 혈당 수치가 높아지면 소변으로 배설되는 당분이 많아져 소변 배설량이 증가하게 됩니다.", "2": "감각 민감성 증가: 당뇨병 환자들은 오히려 감각이 둔해질 수 있습니다.", "3": "갈증 감소: 당뇨병 환자는 갈증이 증가하는 것이 일반적입니다.", "5": "수분 섭취량 감소: 당뇨병 환자는 수분 섭취가 늘어나는 경향이 있습니다."}'::jsonb, '[{"term_ko": "당뇨병", "term_vi": "Bệnh tiểu đường", "def_ko": "질병의 일종으로 인슐린의 분비 이상 또는 인슐린 저항성으로 혈당 조절이 안 되는 상태", "def_vi": "Một loại bệnh do sự rối loạn tiết insulin hoặc kháng insulin dẫn đến không kiểm soát được mức đường trong máu"}, {"term_ko": "갈증", "term_vi": "Cảm giác khát", "def_ko": "목이 마르다는 느낌", "def_vi": "Cảm giác muốn uống nước"}, {"term_ko": "소변", "term_vi": "Nước tiểu", "def_ko": "신장에서 만들어지는 액체", "def_vi": "Chất lỏng được sản xuất bởi thận"}, {"term_ko": "수분", "term_vi": "Thành phần nước", "def_ko": "물의 양", "def_vi": "Lượng nước"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (82, '5', '당뇨병 대상자가 인슐린 주사를 맞고 식사를 하지 않았을 때 증상으로 옳은 것은?', '["땀을 많이 흘림", "배뇨 증가", "식욕 증가", "체온 상승", "피로감"]'::jsonb, 1, NULL, NULL, '{"1": "땀을 많이 흘림: 인슐린을 맞고 식사를 하지 않으면 저혈당증이 발생할 수 있으며, 이때 땀을 많이 흘리는 증상이 나타날 수 있습니다.\n[정답]", "2": "배뇨 증가: 식사와 관련이 적고, 저혈당과는 관련이 적습니다.", "3": "식욕 증가: 저혈당 상태에서는 대개 식욕이 증가하기 보다는 감소할 수 있습니다.", "4": "체온 상승: 저혈당 시 체온이 상승하지 않습니다.", "5": "피로감: 피로감은 나타날 수 있지만, 주로 저혈당의 특정 증상으로는 땀을 많이 흘리는 것이 더 적합합니다."}'::jsonb, '[{"term_ko": "당뇨병", "term_vi": "Bệnh tiểu đường", "def_ko": "혈당 조절이 필요한 질환", "def_vi": "Bệnh cần kiểm soát đường huyết"}, {"term_ko": "인슐린", "term_vi": "Insulin", "def_ko": "혈당을 조절하는 호르몬", "def_vi": "Hormone điều chỉnh đường huyết"}, {"term_ko": "저혈당", "term_vi": "Hạ đường huyết", "def_ko": "혈당이 비정상적으로 낮은 상태", "def_vi": "Tình trạng đường huyết thấp bất thường"}, {"term_ko": "증상", "term_vi": "Triệu chứng", "def_ko": "질병에 의해 나타나는 신체의 변화", "def_vi": "Sự biến đổi cơ thể do bệnh tật gây ra"}, {"term_ko": "피로감", "term_vi": "Cảm giác mệt mỏi", "def_ko": "피곤한 상태", "def_vi": "Tình trạng mệt mỏi"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (81, '5', '당뇨 환자의 운동 요법으로 옳은 것은?', '["식후 30분에서 1시간경에 시작한다.", "일주일에 2일 운동한다.", "10분 이내로 짧게 운동한다.", "혈당이 300mg/dl 이상인 경우에 운동한다.", "공복에 운동한다."]'::jsonb, 1, NULL, NULL, '{"1": "식사 후 30분에서 1시간 경에 시작하는 것이 좋습니다.\n[정답]", "2": "일주일에 2일 운동하는 것은 부족합니다.", "3": "10분 이내로 짧게 운동하는 것은 운동 효과가 적습니다.", "4": "혈당이 300mg/dl 이상인 경우는 운동을 피해야 합니다.", "5": "공복에 운동하는 것은 혈당에 위험할 수 있습니다."}'::jsonb, '[{"term_ko": "당뇨", "term_vi": "Tiểu đường", "def_ko": "통치 증상", "def_vi": "Triệu chứng quản lý"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (80, '5', '당뇨병 대상자의 발 관리 방법으로 옳은 것은?', '["발톱을 일자로 자른다.", "꼭 끼는 신발을 신는다.", "양말을 벗고 맨발로 다닌다.", "발은 건조하게 관리한다.", "바레 열 패드를 대어주어 보온한다."]'::jsonb, 1, NULL, NULL, '{"1": "발톱을 일자로 자르는 것은 안전하고 일반적인 발 관리 방법이다.\n[정답]", "2": "꼭 끼는 신발을 신는 것은 혈액 순환을 방해할 수 있어 옳지 않다.", "3": "양말을 벗고 맨발로 다니는 것은 발을 보호하지 못하므로 바람직하지 않다.", "4": "발은 항상 건조하게 유지해야 하지만 관리할 때는 적절한 수분도 필요하다.", "5": "바레 열 패드를 대어 보온하는 것은 직접적인 열로 인해 화상을 입을 수 있어 주의해야 한다."}'::jsonb, '[{"term_ko": "발톱", "term_vi": "Móng chân", "def_ko": "손톱(한국어)", "def_vi": "Móng ở chân"}, {"term_ko": "신발", "term_vi": "Giày", "def_ko": "발을 보호하는 도구(한국어)", "def_vi": "Công cụ bảo vệ chân"}, {"term_ko": "양말", "term_vi": "Socks", "def_ko": "발을 보호하는 직물(한국어)", "def_vi": "Vải bảo vệ chân"}, {"term_ko": "건조", "term_vi": "Khô", "def_ko": "수분이 없는 상태(한국어)", "def_vi": "Tình trạng không có độ ẩm"}, {"term_ko": "보온", "term_vi": "Giữ ấm", "def_ko": "체온을 유지하는 것(한국어)", "def_vi": "Giữ nhiệt độ cơ thể"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (79, '5', '본인 스스로 자각하기 어렵고, 과거 정신과적 병력이 있으며, 두통, 소화불량과 같은 신체적 증상을 호소하는 질환으로 옳은 것은?', '["우울증", "치매", "섬망", "뇌졸증", "파킨슨질환"]'::jsonb, 1, NULL, NULL, '{"1": "우울증은 자각하기 어려운 증상과 함께 신체적 증상을 동반하기 때문에 정답입니다.\n[정답]", "2": "치매는 기억력 저하가 주요 증상으로, 자각하기 어려운 경우가 많지만 주된 증상은 아닙니다.", "3": "섬망은 일시적인 인지장애로 신체적 증상보다 인지 상태의 변화를 주로 나타냅니다.", "4": "뇌졸증은 신체적 증상이 두드러지며 정신적 병력과는 관련이 적습니다.", "5": "파킨슨질환은 운동장애가 주요 증상이며, 우울증처럼 자각이 어려운 경우가 있을 수 있지만 일반적으로는 정신과적 병리와 병행됩니다."}'::jsonb, '[{"term_ko": "자각", "term_vi": "Nhận thức", "def_ko": "인식(한국어)", "def_vi": "nhận biết(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (78, '5', '우울증 발생 가능성이 높은 대상자의 상황으로 옳은 것은?', '["사회활동을 활발히 하고 있다.", "경로당 프로그램에 참여한다.", "낮에 햇빛을 쐬며 운동을 한다.", "최근 갑상샘기능저하증을 진단받았다.", "식욕과 체중이 변화 없이 유지되고 있다."]'::jsonb, 4, NULL, NULL, '{"1": "사회활동을 활발히 하고 있다: 사회적 활동은 보통 긍정적인 기여를 하므로 우울증 발생 가능성을 낮출 수 있음.", "2": "경로당 프로그램에 참여한다: 프로그램 참여는 사회적 연대감을 강화하고 우울증 가능성을 줄임.", "3": "낮에 햇빛을 쐬며 운동을 한다: 햇빛과 운동은 기분 개선에 도움이 되므로 우울증 발생 가능성을 낮출 수 있음.\n[정답]", "4": "최근 갑상샘기능저하증을 진단받았다: 갑상샘기능저하증은 우울증 발생 위험을 증가시킬 수 있는 신체적 질환임.", "5": "식욕과 체중이 변화 없이 유지되고 있다: 변화가 없는 것은 일반적으로 우울증과 관련이 없거나 낮은 가능성을 나타냄."}'::jsonb, '[{"term_ko": "우울증", "term_vi": "Trầm cảm", "def_ko": "정신적 질환의 일종", "def_vi": "Một loại bệnh tâm thần"}, {"term_ko": "사회활동", "term_vi": "Hoạt động xã hội", "def_ko": "사람들과의 상호작용이나 활동", "def_vi": "Sự tương tác hoặc hoạt động với mọi người"}, {"term_ko": "갑상샘기능저하증", "term_vi": "Suy giảm chức năng tuyến giáp", "def_ko": "갑상샘의 호르몬 생산이 부족한 상태", "def_vi": "Tình trạng hormone của tuyến giáp không đủ"}, {"term_ko": "식욕", "term_vi": "Khẩu vị", "def_ko": "음식을 먹고 싶은 욕구", "def_vi": "Mong muốn ăn uống"}, {"term_ko": "체중", "term_vi": "Cân nặng", "def_ko": "몸의 무게", "def_vi": "Trọng lượng cơ thể"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (77, '5', '우울증 대상자를 돕는 방법으로 옳은 것은?', '["사회적 활동을 줄이게 한다.", "햇볕을 쬐며 걷기 운동을 하게 한다.", "곧 괜찮아질 것이라고 위로한다.", "대상자의 분노 감정을 인정하지 않는다.", "항우울제 용량을 늘려야 한다고 말한다."]'::jsonb, 2, NULL, NULL, '{"1": "사회적 활동을 줄이는 것은 우울증을 악화시킬 수 있습니다.\n[정답]", "2": "햇볕을 쬐며 걷기 운동은 기분 개선에 도움을 줄 수 있습니다.", "3": "단순한 위로는 대상자의 상태를 오히려 좋지 않게 만들 수 있습니다.", "4": "대상자의 감정을 인정하지 않으면 신뢰를 잃게 됩니다.", "5": "항우울제의 용량 조정은 전문가의 판단이 필요합니다."}'::jsonb, '[{"term_ko": "우울증", "term_vi": "Trầm cảm", "def_ko": "심리적 장애로 지속적인 슬픔", "def_vi": "Rối loạn tâm lý gây ra sự buồn bã kéo dài"}, {"term_ko": "사회적 활동", "term_vi": "Hoạt động xã hội", "def_ko": "사람들이 함께 어울리는 활동", "def_vi": "Hoạt động mà mọi người tham gia cùng nhau"}, {"term_ko": "햇볕", "term_vi": "Ánh nắng mặt trời", "def_ko": "태양에서 방출되는 빛", "def_vi": "Ánh sáng phát ra từ mặt trời"}, {"term_ko": "걷기 운동", "term_vi": "Đi bộ", "def_ko": "걷기를 포함한 운동 형태", "def_vi": "Hình thức tập thể dục bao gồm việc đi bộ"}, {"term_ko": "전문가", "term_vi": "Chuyên gia", "def_ko": "특정 분야의 지식이 있는 사람", "def_vi": "Người có kiến thức trong một lĩnh vực cụ thể"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (76, '5', '다음에서 설명하는 질병으로 옳은 것은?• 주의력 저하와 인지기능 전반에 장애와 정신병적 증상이 나타날 수 있다. • 수 시간 내지 수일에 걸쳐 급격히 발생한다. • 증상의 기복이 심한 것이 특징이다.', '["섬망", "파킨슨병", "척추질환", "추간판탈출", "알츠하이머병"]'::jsonb, 1, NULL, NULL, '{"1": "섬망은 주의력 저하와 인지 기능 저하, 정신병적 증상이 갑작스럽게 나타나는 것이 특징입니다.\n[정답]", "2": "파킨슨병은 주로 운동 기능에 영향을 주며, 급성 발병과는 거리가 멉니다.", "3": "척추질환은 주의력 저하 및 정신병적 증상과 직접 연관이 없습니다.", "4": "추간판탈출은 통증과 관련된 질병이며, 인지 기능 저하와는 관련이 없습니다.", "5": "알츠하이머병은 점진적으로 증상이 진행되므로 급작스러운 발생과는 다릅니다."}'::jsonb, '[{"term_ko": "주의력", "term_vi": "Chú ý", "def_ko": "집중력(한국어)", "def_vi": "Sự tập trung(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (75, '5', '섬망이 있는 대상자의 치료 및 예방으로 옳은 것은?', '["대상자와 접촉하는 사람의 수를 늘린다.", "텥레비전을 크게 틀어 놓는다.", "주변 환경을 새롭게 바꿔준다.", "낮 동안 커튼을 쳐서 빛을 차단한다.", "가족사진과 달력을 대상자 가까이에 둔다."]'::jsonb, 5, NULL, NULL, '{"1": "대상자와 접촉하는 사람의 수를 늘린다. - 이는 섬망 증상을 악화시킬 수 있습니다.\n[정답]", "5": "가족사진과 달력을 대상자 가까이에 둔다. - 이는 정서적 안정과 방향 감각을 돕는 효과가 있습니다.", "2": "텥레비전을 크게 틀어 놓는다. - 이는 자극이 과해져 증상을 악화시킬 수 있습니다.", "3": "주변 환경을 새롭게 바꿔준다. - 이는 대상자에게 혼란을 줄 수 있습니다.", "4": "낮 동안 커튼을 쳐서 빛을 차단한다. - 이는 일주기 리듬을 방해할 수 있습니다."}'::jsonb, '[{"term_ko": "섬망", "term_vi": "Mê sảng", "def_ko": "혼란을 동반한 의식의 장애", "def_vi": "Rối loạn ý thức đi kèm với sự nhầm lẫn"}, {"term_ko": "예방", "term_vi": "Phòng ngừa", "def_ko": "미연에 막음", "def_vi": "Ngăn chặn trước"}, {"term_ko": "정서적 안정", "term_vi": "Ổn định cảm xúc", "def_ko": "감정을 안정시키는 것", "def_vi": "Làm cho cảm xúc ổn định"}, {"term_ko": "치료", "term_vi": "Điều trị", "def_ko": "병을 고침", "def_vi": "Chữa bệnh"}, {"term_ko": "환경", "term_vi": "Môi trường", "def_ko": "주변의 상황", "def_vi": "Tình huống xung quanh"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (74, '5', '섬망 대상자의 치료 및 대처 방법으로 옳은 것은?', '["안정을 위해 가족이 방문하지 않도록 한다.", "절대 안정을 위해 능동적인 관절운동은 피한다.", "낮 동안에 커튼을 닫아 외부 환경을 차단한다.", "밤에는 커튼을 치고 방안을 어둡게 한다.", "야간 섬망에는 방을 밝게 하고 따뜻하게 한다."]'::jsonb, 5, NULL, NULL, '{"1": "섬망 환자를 위한 환경은 가족이 함께 할 수 있도록 하여 안정감을 주는 것이 좋습니다.\n[정답]", "5": "야간 섬망 환자는 방을 밝고 따뜻하게 하여 안정감을 주고 혼란을 줄이는 것이 중요합니다.", "2": "능동적인 관절운동은 환자의 상태에 따라 다를 수 있으나, 섬망 상태에서는 신중해야 합니다.", "3": "외부 환경의 차단은 이 환자에게 오히려 혼란을 증가시킬 수 있습니다.", "4": "방 안을 어둡게 하는 것은 섬망을 악화시킬 수 있습니다."}'::jsonb, '[{"term_ko": "섬망", "term_vi": "Hội chứng lú lẫn", "def_ko": "혼란 상태(한국어)", "def_vi": "Trạng thái nhầm lẫn(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (73, '5', '섬망 대상자의 지남력을 유지하는 방법으로 옳은 것은?', '["낮에 커튼을 쳐 어둡게 한다.", "새 친구를 사귀게 한다.", "가족의 방문을 제한한다.", "식사할 때 시간을 알려준다.", "창문이 없는 밀폐된 공간에서 지낸다."]'::jsonb, 4, NULL, NULL, '{"1": "낮에 커튼을 쳐 어둡게 한다: 지남력 유지에 도움이 되지 않음.\n[정답]", "4": "식사할 때 시간을 알려준다: 지남력을 유지하는 데 효과적이다.", "2": "새 친구를 사귀게 한다: 불안감을 줄이지 못할 수 있다.", "3": "가족의 방문을 제한한다: 고립감을 유발할 수 있어 좋지 않다.", "5": "창문이 없는 밀폐된 공간에서 지낸다: 이는 지남력에 부정적 영향을 미침."}'::jsonb, '[{"term_ko": "지남력", "term_vi": "Định hướng", "def_ko": "방향감각(한국어)", "def_vi": "nhận thức về phương hướng(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (72, '5', '노쇠증후군에 공통된 특징으로 옳은 것은?', '["만성질환자들에게 많이 생긴다.", "삶의 질에 영향을 끼치지 않는다.", "특정 질환의 원인이 된다.", "요로감염 등이 섬망을 유발하기도 한다.", "심리적인 원인이 주요인이 된다."]'::jsonb, 4, NULL, NULL, '{"1": "노쇠증후군은 만성질환자에게 많이 발병하는 경향이 있습니다.\n[정답]", "2": "노쇠증후군은 삶의 질에 부정적인 영향을 미칠 수 있습니다.", "3": "노쇠증후군은 특정 질환의 원인이 되지 않습니다.", "4": "요로감염은 섬망을 유발할 수 있는 중요한 요소입니다.", "5": "심리적인 원인보다 신체적인 원인이 더 큰 요인이 됩니다."}'::jsonb, '[{"term_ko": "노쇠증후군", "term_vi": "Hội chứng suy giảm cơ thể", "def_ko": "노쇠가 진행되는 상태", "def_vi": "Tình trạng suy giảm thể lực"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (71, '6', '치매에 관한 설명으로 옳은 것은?', '["시공간을 파악하는 능력은 정상이다.", "언어소통의 능력에는 변화가 없다.", "혈관성 치매 비율이 가장 높다.", "근래의 일보다 먼 과거의 일을 잘 기억해내지 못한다.", "운동기능은 정상인데 운동활동 수행능력이 손상되는 실행중이 나타난다."]'::jsonb, 5, NULL, NULL, '{"1": "치매 환자는 시공간을 파악하는 능력이 저하됩니다.", "2": "언어소통 능력은 치매 초기에는 상대적으로 정상이나 진행됨에 따라 변화가 생깁니다.\n[정답]", "3": "혈관성 치매는 비율이 높지만, 알츠하이머병이 가장 흔한 형태입니다.", "4": "치매 환자는 근래의 일은 잘 기억하지 못하고 먼 과거의 일이 더 잘 기억납니다.", "5": "운동기능은 정상일 수 있으나, 수행능력에는 문제가 생길 수 있습니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí", "def_ko": "기억력과 인지기능의 저하로 인한 상태", "def_vi": "Tình trạng giảm khả năng nhớ và nhận thức"}, {"term_ko": "혈관성", "term_vi": "Mạch máu", "def_ko": "혈관과 관련된 형태", "def_vi": "Liên quan đến mạch máu"}, {"term_ko": "언어소통", "term_vi": "Giao tiếp ngôn ngữ", "def_ko": "의사소통을 위한 언어 사용", "def_vi": "Sử dụng ngôn ngữ để giao tiếp"}, {"term_ko": "운동기능", "term_vi": "Chức năng vận động", "def_ko": "신체를 움직이는 능력", "def_vi": "Khả năng di chuyển cơ thể"}, {"term_ko": "수행능력", "term_vi": "Khả năng thực hiện", "def_ko": "특정 작업을 수행하는 능력", "def_vi": "Khả năng thực hiện một nhiệm vụ"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (70, '6', '알츠하이머병에 관한 설명으로 옳은 것은?', '["중기에는 가족을 알아보지 못한다.", "초기에는 독립적인 생활을 할 수 있다.", "초기부터 장기기억력 저하가 나타난다.", "말기에 새로 외우는 것은 거의 불가능하다.", "말기에는 과거에 대해 힌트를 주면 기억해낸다."]'::jsonb, 2, NULL, NULL, '{"1": "중기에는 가족을 알아보지 못하는 경우가 많지만, 모든 환자에게 해당되는 것은 아닙니다.\n[정답]", "2": "초기에는 독립적인 생활을 할 수 있습니다. 이는 알츠하이머병 초기의 특징입니다.", "3": "초기부터 장기기억력 저하가 나타나는 것이 아니라 단기기억력에서 먼저 저하가 나타납니다.", "4": "말기에는 새로 외우는 것이 거의 불가능한 것이 맞습니다.", "5": "과거에 대해 힌트를 주면 기억해내는 경우가 많지만, 말기의 경우에는 그 정도가 심각하게 저하될 수 있습니다."}'::jsonb, '[{"term_ko": "알츠하이머병", "term_vi": "기억력", "def_ko": "질병(병 Alzheimer)", "def_vi": "기억력(Trí nhớ)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (69, '6', '뇌졸중은 뇌혈관이 막힌 경우를 (A)(이)라고 하고, 뇌혈관이 터진 경우를 (B)(이)라고 한다. () 안에 들어갈 질환으로 옳은 것은?', '["뇌경색 뇌출혈", "뇌출혈 뇌경색", "중풍 뇌출혈", "동맥경화 중풍", "동맥경화 뇌출혈"]'::jsonb, 1, NULL, NULL, '{"1": "뇌졸중은 뇌혈관이 막힌 경우를 뇌경색이라고 하고, 뇌혈관이 터진 경우를 뇌출혈이라고 합니다.\n[정답]", "2": "뇌출혈은 뇌혈관이 터진 경우를 의미하지만, 막힌 경우는 잘못된 설명입니다.", "3": "중풍은 일반적으로 뇌졸중을 지칭하지만, 구체적인 질환명이 아니므로 옳지 않습니다.", "4": "동맥경화는 뇌졸중의 원인으로 작용할 수 있지만, 뇌졸중의 세부 유형이 아닙니다.", "5": "동맥경화 역시 뇌졸중의 원인이 될 수 있으나 정확한 설명이 아닙니다."}'::jsonb, '[{"term_ko": "뇌졸중", "term_vi": "Đột quỵ", "def_ko": "뇌의 혈관이 막히거나 터지는 질환", "def_vi": "Bệnh có liên quan đến mạch máu não"}, {"term_ko": "뇌경색", "term_vi": "Đột quỵ não do tắc mạch", "def_ko": "뇌혈관이 막혀 발생하는 뇌졸중", "def_vi": "Đột quỵ não xảy ra do mạch máu bị tắc"}, {"term_ko": "뇌출혈", "term_vi": "Xuất huyết não", "def_ko": "뇌혈관이 터져 발생하는 뇌졸중", "def_vi": "Đột quỵ não xảy ra do mạch máu bị vỡ"}, {"term_ko": "동맥경화", "term_vi": "Xơ vữa động mạch", "def_ko": "동맥 벽이 두꺼워지는 질환", "def_vi": "Bệnh làm dày thành mạch"}, {"term_ko": "중풍", "term_vi": "Liệt", "def_ko": "뇌졸중을 통칭하는 용어", "def_vi": "Thuật ngữ chung chỉ đột quỵ"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (68, '6', '뇌졸중의 증상 중 손상된 뇌의 반대쪽 팔다리, 갑작스런 안면하부의 마비가 오는 후유증으로 옳은 것은?', '["반신마비", "전신마비", "반신감각장애", "언어장애", "운동실조증"]'::jsonb, 1, NULL, NULL, '{"1": "반신마비는 뇌의 반대쪽 팔다리에 나타나는 마비 증상을 의미합니다.\n[정답]", "2": "전신마비는 모든 팔다리에 마비가 오는 상태로 뇌졸중과는 관련이 없습니다.", "3": "반신감각장애는 뇌졸중 후 부가적으로 나타날 수 있으나, 문제에서 묻는 것은 직접적인 후유증입니다.", "4": "언어장애는 뇌졸중에 의해 발생할 수 있으나, 마비와는 직접적인 관련성이 떨어집니다.", "5": "운동실조증은 조정 능력에서 문제가 생기는 것이며, 뇌졸중의 직접적인 마비와는 다릅니다."}'::jsonb, '[{"term_ko": "뇌졸중", "term_vi": "Đột quỵ", "def_ko": "뇌에 혈액 공급이 차단되어 발생하는 질환", "def_vi": "Bệnh xảy ra khi cung cấp máu đến não bị ngắt quãng"}, {"term_ko": "반신마비", "term_vi": "Bại nửa người", "def_ko": "신체의 한 쪽 절반에 마비가 오는 증상", "def_vi": "Triệu chứng liệt ở một nửa cơ thể"}, {"term_ko": "전신마비", "term_vi": "Liệt toàn thân", "def_ko": "신체의 전부에 마비가 오는 상태", "def_vi": "Trạng thái liệt ở toàn bộ cơ thể"}, {"term_ko": "운동실조증", "term_vi": "Rối loạn vận động", "def_ko": "운동의 조정이 어려운 증상", "def_vi": "Triệu chứng khó khăn trong việc điều chỉnh vận động"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (67, '6', '뇌졸중의 증상 중 손상된 뇌의 반대쪽의 시각, 촉각, 청각 등의 장애, 남의 살 같은 불쾌한 느낌의 후유증을 남기는 것으로 옳은 것은?', '["반신마비", "전신마비", "반신감각장애", "언어장애", "운동실조증"]'::jsonb, 3, NULL, NULL, '{"1": "반신마비는 한쪽 팔과 다리에 힘이 약해지거나 마비되는 증상입니다.\n[정답]", "3": "반신감각장애는 손상된 뇌의 반대쪽에서 시각, 촉각, 청각 등의 장애와 불쾌한 느낌이 나타나는 현상입니다.", "2": "전신마비는 전체적으로 마비되는 상태를 나타냅니다.", "4": "언어장애는 의사소통에 어려움을 겪는 증상입니다.", "5": "운동실조증은 운동의 조정이 어려워지는 증상입니다."}'::jsonb, '[{"term_ko": "뇌졸중", "term_vi": "Đột quỵ", "def_ko": "중풍(한국어)", "def_vi": "Bệnh đột quỵ"}, {"term_ko": "손상", "term_vi": "Tổn thương", "def_ko": "피해(한국어)", "def_vi": "Tổn thương"}, {"term_ko": "반신", "term_vi": "Nửa người", "def_ko": "반쪽 몸(한국어)", "def_vi": "Nửa người"}, {"term_ko": "감각", "term_vi": "Cảm giác", "def_ko": "느낌(한국어)", "def_vi": "Cảm giác"}, {"term_ko": "장애", "term_vi": "Khuyết tật", "def_ko": "문제(한국어)", "def_vi": "Khuyết tật"}, {"term_ko": "불쾌한", "term_vi": "Khó chịu", "def_ko": "기분이 나쁜(한국어)", "def_vi": "Khó chịu"}, {"term_ko": "후유증", "term_vi": "Di chứng", "def_ko": "후유증(한국어)", "def_vi": "Di chứng"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (66, '6', '좌측뇌가 손상되어 우측마비와 함께 말을 못하거나 남의 말을 이해하지 못하는 실어증의 후유증으로 옳은 것은?', '["반신마비", "전신마비", "반신감각장애", "언어장애", "운동실조증"]'::jsonb, 4, NULL, NULL, '{"1": "반신마비: 좌측뇌 손상으로 인해 우측신체가 마비될 수 있으나, 질문은 언어장애에 초점을 맞추고 있다.\n[정답]", "4": "언어장애: 좌측뇌 손상의 대표적인 후유증 중 하나로, 말을 못하거나 이해하지 못하는 증상이 나타난다.", "3": "반신감각장애: 감각의 문제일 수 있으나, 언어장애가 중심 주제가 아니다.", "2": "전신마비: 좌측뇌 손상이 전신마비로 이어지지는 않는다.", "5": "운동실조증: 운동을 조정하는 문제이나, 언어장애와는 관련성이 적다."}'::jsonb, '[{"term_ko": "좌측뇌", "term_vi": "Não trái", "def_ko": "왼쪽 뇌(부위)", "def_vi": "Phần não bên trái"}, {"term_ko": "우측", "term_vi": "Bên phải", "def_ko": "오른쪽", "def_vi": "Bên phải"}, {"term_ko": "마비", "term_vi": "Liệt", "def_ko": "마비/충혈", "def_vi": "Tê liệt"}, {"term_ko": "실어증", "term_vi": "Rối loạn ngôn ngữ", "def_ko": "언어장애", "def_vi": "Rối loạn ngôn ngữ"}, {"term_ko": "후유증", "term_vi": "Di chứng", "def_ko": "후유증", "def_vi": "Hậu quả"}, {"term_ko": "언어", "term_vi": "Ngôn ngữ", "def_ko": "언어", "def_vi": "Ngôn ngữ"}, {"term_ko": "이해", "term_vi": "Hiểu", "def_ko": "이해하다", "def_vi": "Hiểu"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (65, '6', '대상자에게 소뇌 손상이 발생했을 때 나타나는 특징적인 증상으로 옳은 것은?', '["시각장애로 사물을 인지하지 못한다.", "인지기능의 저하가 나타난다.", "말의 내용을 이해하지 못한다.", "한 개의 물체가 두 개로 보인다.", "자세의 균형을 유지하지 못한다."]'::jsonb, 5, NULL, NULL, '{"1": "시각장애는 주로 대뇌와 관련된 증상입니다.", "2": "인지기능 저하는 대뇌 손상에서 흔히 나타나는 증상입니다.", "3": "말의 내용을 이해하지 못하는 것은 주로 언어 중추와 관련된 문제입니다.", "4": "한 개의 물체가 두 개로 보이는 현상은 복시로, 주로 시각 신경과 관련이 있습니다.\n[정답]", "5": "자세의 균형을 유지하지 못하는 것은 소뇌의 주요 기능 중 하나로, 손상이 있으면 나타날 수 있는 증상입니다."}'::jsonb, '[{"term_ko": "소뇌", "term_vi": "Tiểu não", "def_ko": "뇌의 일부분으로 균형과 운동 조절을 담당하는 기관", "def_vi": "Một phần của não chịu trách nhiệm điều chỉnh thăng bằng và chuyển động"}, {"term_ko": "균형", "term_vi": "Thăng bằng", "def_ko": "물체의 중력을 잘 유지하는 상태", "def_vi": "Trạng thái duy trì trọng lực của một vật"}, {"term_ko": "인지기능", "term_vi": "Chức năng nhận thức", "def_ko": "정보를 이해하고 해석하는 능력", "def_vi": "Khả năng hiểu và giải thích thông tin"}, {"term_ko": "자세", "term_vi": "Tư thế", "def_ko": "몸의 위치나 태세", "def_vi": "Vị trí hoặc dáng vẻ của cơ thể"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (64, '6', '술에 취한 사람처럼 비틀거리고, 자꾸 한쪽으로 쓰러질 때 의심할 수 있는 뇌졸중의 주요 증상으로 옳은 것은?', '["언어장애", "운동실조증", "반신마비", "어지럼증", "평형감각장애"]'::jsonb, 2, NULL, NULL, '{"1": "언어장애는 뇌졸중의 증상 중 하나지만, 비틀거리며 한쪽으로 쓰러지기보다는 언어적 문제에 관련됩니다.\n[정답]", "2": "운동실조증은 비틀거리며 한쪽으로 쓰러지는 증상을 직접적으로 나타냅니다.", "3": "반신마비는 몸의 한쪽만 마비되는 증상으로, 비틀거림과 다소 관련이 있지만 결정적인 증상은 아닙니다.", "4": "어지럼증도 뇌졸중 증상일 수 있으나, 주로 비틀거림의 원인으로 운동실조증이 더 적합합니다.", "5": "평형감각장애 역시 관련이 있지만 비틀거림을 주된 표현으로 보기에는 운동실조증이 더 직접적입니다."}'::jsonb, '[{"term_ko": "뇌졸중", "term_vi": "Đột quỵ", "def_ko": "뇌에서 발생하는 혈류 장애로 인한 증상", "def_vi": "Triệu chứng do rối loạn lưu thông máu ở não"}, {"term_ko": "운동실조증", "term_vi": "Rối loạn vận động", "def_ko": "근육의 협응이 잘 되지 않아 비틀거림", "def_vi": "Sự mất phối hợp của cơ bắp dẫn đến đi không vững"}, {"term_ko": "언어장애", "term_vi": "Khó khăn về ngôn ngữ", "def_ko": "언어 표현이 힘든 상태", "def_vi": "Tình trạng khó khăn trong việc biểu đạt ngôn ngữ"}, {"term_ko": "반신마비", "term_vi": "Liệt nửa người", "def_ko": "몸의 한쪽이 마비된 상태", "def_vi": "Tình trạng một bên cơ thể bị liệt"}, {"term_ko": "어지럼증", "term_vi": "Chóng mặt", "def_ko": "머리가 아찔한 증상", "def_vi": "Triệu chứng đầu óc quay cuồng"}, {"term_ko": "평형감각장애", "term_vi": "Khó khăn về cảm giác thăng bằng", "def_ko": "균형을 잡기 힘든 상태", "def_vi": "Tình trạng khó khăn trong việc duy trì cân bằng"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (63, '6', '뇌졸중으로 갑자기 발생하며 갑자기 동작이 서툴러지고, 대소변을 못가리고, 감정조절에 이상이 생길 때 의심해봐야 하는 질환으로 옳은 것은?', '["알츠하이머", "혈관성 치매", "파킨슨병", "섬망", "균형감각장애"]'::jsonb, 2, NULL, NULL, '{"1": "알츠하이머: 주로 기억력 감退에 관련된 질환으로, 동작 서툴렷과는 관련이 적습니다.\n[정답]", "2": "혈관성 치매: 뇌졸중과 관련된 증상들이 나타나므로, 이 질환이 정답입니다.", "3": "파킨슨병: 움직임의 느려짐과 함께 특징적인 증상이 있지만, 뇌졸중과 직접 연관되지는 않습니다.", "4": "섬망: 급성 정신상태 변화로, 갑작스러운 증상은 있으나 뇌졸중과의 직접적인 연관은 적습니다.", "5": "균형감각장애: 뇌졸중으로 인해 발생할 수 있지만, 주요 증상은 아닙니다."}'::jsonb, '[{"term_ko": "뇌졸중", "term_vi": "Đột quỵ", "def_ko": "뇌의 혈액 공급이 차단되어 발생하는 질환", "def_vi": "Bệnh xảy ra do cung cấp máu đến não bị chặn"}, {"term_ko": "동작", "term_vi": "Động tác", "def_ko": "움직임", "def_vi": "Sự chuyển động"}, {"term_ko": "서툴러지다", "term_vi": "Trở nên vụng về", "def_ko": "행동이 정확하지 않다", "def_vi": "Hành động không chính xác"}, {"term_ko": "대소변", "term_vi": "Tiểu tiện và đại tiện", "def_ko": "소변과 대변", "def_vi": "Nước tiểu và phân"}, {"term_ko": "감정조절", "term_vi": "Kiểm soát cảm xúc", "def_ko": "감정의 통제가 이루어지다", "def_vi": "Hoạt động điều khiển cảm xúc"}, {"term_ko": "질환", "term_vi": "Bệnh", "def_ko": "병", "def_vi": "Bệnh tật"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (62, '6', '뇌졸중을 의심할 수 있는 전구증상은?', '["가만히 있을 때 떨림증상이 있다.", "가슴이 조이는 흉통이 있다.", "새벽에 속쓰림 증상이 있다.", "한 개의 물체가 둘로 보인다.", "목이 말라서 물을 자주 마신다."]'::jsonb, 4, NULL, NULL, '{"1": "가만히 있을 때 떨림증상은 뇌졸중의 전구증상과 관련이 없다.\n[정답]", "4": "한 개의 물체가 둘로 보이는 것은 뇌졸중의 전구증상으로 나타날 수 있다.", "2": "가슴이 조이는 흉통은 심혈관계의 문제일 수 있다.", "3": "새벽에 속쓰림 증상은 소화계의 문제일 가능성이 높다.", "5": "목이 마르는 것은 일반적인 생리적 현상으로, 뇌졸중과는 관련이 없다."}'::jsonb, '[{"term_ko": "뇌졸중", "term_vi": "Đột quỵ", "def_ko": "뇌의 혈액 공급이 중단되어 발생하는 질병", "def_vi": "Bệnh xảy ra khi cung cấp máu lên não bị ngừng lại"}, {"term_ko": "전구증상", "term_vi": "Triệu chứng tiền triệu", "def_ko": "증상이 나타나기 전의 신호", "def_vi": "Dấu hiệu trước khi triệu chứng xuất hiện"}, {"term_ko": "흉통", "term_vi": "Đau ngực", "def_ko": "가슴에 통증이 있는 상태", "def_vi": "Tình trạng đau ở ngực"}, {"term_ko": "속쓰림", "term_vi": "Cảm giác nôn", "def_ko": "위장에 불편을 느끼는 증상", "def_vi": "Triệu chứng cảm giác khó chịu trong dạ dày"}, {"term_ko": "물체", "term_vi": "Vật thể", "def_ko": "물건", "def_vi": "Đồ vật"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (61, '6', '혈관성 치매 대상자를 돕기 위한 요양보호사의 활동으로 옳은 것은?', '["망상장애가 왔다며 가족과 상의하여 병원에 입원시킨다.", "이상행동을 보일 시 부정, 설득보다 보호, 수용, 지지한다.", "가능한 재활치료보다 침상에서 안정을 취하게 한다.", "보호자의 정서적 지도 및 상담비용을 청구한다.", "적절한 의사소통이 불가능하므로 인내심을 가지고 지도한다."]'::jsonb, 2, NULL, NULL, '{"1": "망상장애가 있는 경우, 입원이 필요할 수 있으나 가족과 상의하여 결정하는 것은 요양보호사의 역할이 아니다.\n[정답]", "2": "치매 환자가 이상행동을 보일 경우, 보호적이고 수용적인 태도를 통해 환자의 안정감을 증진시키는 것이 중요하다.", "3": "침상에서 안정하는 것보다는 가능한 재활치료를 통해 기능 회복을 도모하는 것이 바람직하다.", "4": "보호자의 정서적 지도 및 상담은 중요하지만, 요양보호사가 비용을 청구하는 것은 적절하지 않다.", "5": "의사소통이 어려운 경우 인내심을 가지고 대하는 것은 중요하지만, 이를 지도하는 것은 요양보호사의 주된 역할이 아니다."}'::jsonb, '[{"term_ko": "혈관성 치매", "term_vi": "Giảm trí nhớ mạch máu", "def_ko": "혈관에 의한 치매(vascular dementia)", "def_vi": "Suy giảm trí nhớ do các vấn đề liên quan đến mạch máu"}, {"term_ko": "요양보호사", "term_vi": "Nhân viên chăm sóc", "def_ko": "노인이나 환자를 돌보는 사람", "def_vi": "Người chăm sóc người già hoặc người bệnh"}, {"term_ko": "이상행동", "term_vi": "Hành vi thái quá", "def_ko": "부적절한 행동", "def_vi": "Hành vi không phù hợp"}, {"term_ko": "재활치료", "term_vi": "Điều trị phục hồi", "def_ko": "기능 회복을 위한 치료", "def_vi": "Sự điều trị nhằm phục hồi chức năng"}, {"term_ko": "정서적", "term_vi": "Cảm xúc", "def_ko": "감정과 관련된", "def_vi": "Liên quan đến cảm xúc"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (60, '6', '다음에서 설명하는 신경계 질환으로 옳은 것은?• 도파민이라는 물질의 분비 장애로 발생한다. • 떨림 증상으로 움직일 때보다 가만히 있을 때 주로 나타난다. • 행동이 느려지는 것으로 서서히 나타난다.', '["혈관성 치매", "알츠하이머병", "파킨슨병", "뇌졸중", "건망증"]'::jsonb, 3, NULL, NULL, '{"1": "혈관성 치매: 주로 혈관의 문제로 인한 인지 저하를 의미하며, 도파민과 관련이 없습니다.", "2": "알츠하이머병: 기억력 감퇴가 주 증상이며, 도파민의 문제와는 무관합니다.\n[정답]", "3": "파킨슨병: 도파민의 분비 장애로 인해 발생하며, 떨림과 행동의 느려짐이 주요 증상입니다.", "4": "뇌졸중: 뇌의 혈액 공급 부족으로 발생하는 질환이며, 도파민과 관련이 없습니다.", "5": "건망증: 기억력을 잃는 상태이며, 신경계 질환과는 다릅니다."}'::jsonb, '[{"term_ko": "신경계", "term_vi": "Hệ thần kinh", "def_ko": "신체의 신경과 관련된 시스템", "def_vi": "Hệ thống liên quan đến dây thần kinh"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (59, '6', '파킨슨질환의 운동 증상으로 옳은 것은?', '["얼굴 등에서 떨림이 보이고 움직이면 사라진다.", "불안, 피로, 환각, 망상 등 증상이 발생한다.", "과도한 주간 졸림, 기면증이 발생한다.", "통증이나 후각 기능 저하가 발생한다.", "변비, 피로 등의 증상이 나타난다."]'::jsonb, 1, NULL, NULL, '{"1": "파킨슨질환의 특징적인 운동 증상인 떨림은 정지 시 나타나고, 움직이면 사라지는 경향이 있습니다.\n[정답]", "2": "이것은 비운동 증상에 해당하며, 파킨슨질환의 주요 운동 증상은 아닙니다.", "3": "기면증이나 주간 졸림은 파킨슨환자에게 나타날 수 있지만 운동 증상과는 관련이 없습니다.", "4": "후각 기능 저하는 비운동 증상으로 분류되며, 운동 증상과는 관계가 없습니다.", "5": "변비와 피로 또한 비운동 증상이며, 운동 증상으로 보기는 어렵습니다."}'::jsonb, '[{"term_ko": "파킨슨질환", "term_vi": "Bệnh Parkinson", "def_ko": "파킨슨병(한국어)", "def_vi": "Bệnh Parkinson"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (58, '6', '파킨슨질환의 주요 증상으로 옳은 것은?', '["진전 (떨림)은 가만히 있으면 사라진다.", "행동의 느려짐은 급박하게 진행된다.", "엉거주춤한 자세로 쉽게 넘어져 골절의 원인이 된다.", "밤낮으로 과도한 깊은 수면현상이 나타난다.", "기억력에는 문제가 없다."]'::jsonb, 3, NULL, NULL, '{"1": "진전(떨림)은 일반적으로 가만히 있을 때 나타나므로 잘못된 진술입니다.\n[정답]", "3": "엉거주춤한 자세로 쉽게 넘어져 골절의 원인이 될 수 있습니다.", "2": "행동의 느려짐은 서서히 진행되는 특징이 있으므로 잘못된 진술입니다.", "4": "과도한 깊은 수면현상은 파킨슨질환과 관련이 있지만, 일반적인 증상으로 나타나지는 않습니다.", "5": "기억력 문제는 흔히 발생할 수 있습니다."}'::jsonb, '[{"term_ko": "파킨슨질환", "term_vi": "Bệnh Parkinson", "def_ko": "파킨슨병(한국어)", "def_vi": "Bệnh Parkinson (베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (57, '6', '파킨슨질환자의 치료 및 관리 방법으로 옳은 것은?', '["대상자가 원하는 시간에 약물복용을 한다.", "서있는 것이 불안정하다면 지팡이를 짚게 한다.", "서있는 자세가 불안정하므로 운동은 삼간다.", "약물흡수를 위해 단백질 식품과 함께 복용한다.", "변비 예방을 위해 과일, 수분 섭취를 한다."]'::jsonb, 5, NULL, NULL, '{"1": "대상자가 원하는 시간에 약물복용을 한다는 것은 비규칙적인 복용이 될 수 있어 좋지 않다.\n[정답]", "5": "변비 예방을 위해 과일과 수분 섭취를 권장하는 것은 적절한 치료 방법이다.", "2": "서 있는 것이 불안정할 경우 지팡이를 짚게 하는 것은 안전을 위해 중요하지만, 그 자체가 치료 방법은 아니다.", "3": "서 있는 자세가 불안정하다고 해서 운동을 삼가는 것은 오히려 해로운 경우가 많다.", "4": "약물 흡수를 위해 단백질 식품과 함께 복용하는 것은 약물의 효과를 저해할 수 있다."}'::jsonb, '[{"term_ko": "파킨슨질환", "term_vi": null, "def_ko": "파킨슨 병(Parkinson''s disease)", "def_vi": null}, {"term_ko": "치료", "term_vi": null, "def_ko": "치료 (Điều trị)", "def_vi": null}, {"term_ko": "관리", "term_vi": null, "def_ko": "관리 (Quản lý)", "def_vi": null}, {"term_ko": "변비", "term_vi": null, "def_ko": "변비 (Táo bón)", "def_vi": null}, {"term_ko": "과일", "term_vi": null, "def_ko": "과일 (Trái cây)", "def_vi": null}, {"term_ko": "수분", "term_vi": null, "def_ko": "수분 (Nước)", "def_vi": null}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (56, '7', '노화에 따른 수분량의 감소와 탈수의 원인으로 옳은 것은?', '["갈증에 대한 반응 저하", "염분 섭취의 증가", "타액 분비 증가", "소화액의 증가", "칼슘 흡수 감소"]'::jsonb, 1, NULL, NULL, '{"1": "갈증에 대한 반응 저하: 노화와 함께 갈증을 느끼는 능력이 저하되어 수분 섭취가 줄어든다.\n[정답]", "2": "염분 섭취의 증가: 염분 섭취 증가가 탈수에 직접적인 영향을 미치지는 않는다.", "3": "타액 분비 증가: 노화로 인해 타액 분비가 증가하지 않는다.", "4": "소화액의 증가: 노화로 인해 소화액이 증가하는 것이 아니다.", "5": "칼슘 흡수 감소: 칼슘 흡수는 수분과 관련이 적다."}'::jsonb, '[{"term_ko": "노화", "term_vi": "Lão hóa", "def_ko": "나이 들어감", "def_vi": "Già đi"}, {"term_ko": "수분량", "term_vi": "Lượng nước", "def_ko": "체내 물의 양", "def_vi": "Lượng nước trong cơ thể"}, {"term_ko": "탈수", "term_vi": "Mất nước", "def_ko": "수분 부족 상태", "def_vi": "Tình trạng thiếu nước"}, {"term_ko": "갈증", "term_vi": "Khát", "def_ko": "목마름", "def_vi": "Cảm giác khát"}, {"term_ko": "반응", "term_vi": "Phản ứng", "def_ko": "반응하다", "def_vi": "Phản ứng"}, {"term_ko": "저하", "term_vi": "Giảm", "def_ko": "감소", "def_vi": "Giảm"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (55, '7', '영양 문제 발생 위험이 가장 높은 대상자로 옳은 것은?', '["인지기능이 저하된 대상자", "배변활동이 양호한 대상자", "거동에 문제가 없는 대상자", "잇몸에 맞는 틀니를 낀 대상자", "시력 교정용 안경을 쓴 대상자"]'::jsonb, 1, NULL, NULL, '{"1": "인지기능이 저하된 대상자는 영양 문제 발생 위험이 높습니다.\n[정답]", "2": "배변활동이 양호한 대상자는 영양 문제와 직접적인 관련이 없습니다.", "3": "거동에 문제가 없는 대상자는 보통 영양 문제가 덜 발생합니다.", "4": "잇몸에 맞는 틀니를 낀 대상자는 씹는데 문제가 없을 수 있어 영양 문제와는 거리가 있습니다.", "5": "시력 교정용 안경을 쓴 대상자는 영양 문제 발생 위험에 영향을 미치지 않습니다."}'::jsonb, '[{"term_ko": "영양", "term_vi": "Dinh dưỡng", "def_ko": "영양(한국어)", "def_vi": "Dinh dưỡng(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (54, '7', '노인이 운동을 꺼리는 이유로 옳은 것은?', '["복부지방 감소", "폐활량 감소", "관절의 운동범위 증가", "자극에 대한 반응 증가", "폐활량 증가"]'::jsonb, 2, NULL, NULL, '{"1": "복부지방 감소는 운동을 통해 일어날 수 있는 긍정적인 효과입니다.\n[정답]", "2": "폐활량 감소는 노인이 운동을 꺼리는 이유 중 하나입니다.", "3": "관절의 운동범위 증가도 운동의 긍정적인 효과입니다.", "4": "자극에 대한 반응 증가는 운동의 효과가 아닙니다.", "5": "폐활량 증가는 운동이 이루어질 때의 효과입니다."}'::jsonb, '[{"term_ko": "노인", "term_vi": "Người cao tuổi", "def_ko": "나이가 많은 사람", "def_vi": "Người có tuổi cao"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (53, '7', '대상자의 건강증진을 위한 운동 방법으로 옳은 것은?', '["빠르게 방향을 바꾸는 운동을 한다.", "개인의 신체능력에 맞는 운동을 한다.", "고강도에서 중강도 운동으로 진행한다.", "준비 운동은 2 ~ 3분 이내로 짧게 한다.", "호흡곤란, 부정맥, 혈압이 있을 때는 고강도 운동을 한다."]'::jsonb, 2, NULL, NULL, '{"1": "빠르게 방향을 바꾸는 운동은 부상을 유발할 수 있어 건강증진에 적합하지 않다.\n[정답]", "2": "개인의 신체능력에 맞는 운동은 안전하고 효과적으로 건강증진에 기여할 수 있다.", "3": "고강도에서 중강도 운동으로 진행하는 것은 개인의 체력이 허락할 경우에 적절하더라도 무조건적인 진행은 문제가 될 수 있다.", "4": "준비 운동은 최소 5분 이상이 권장되므로 2~3분은 적절하지 않다.", "5": "호흡곤란, 부정맥, 혈압이 있는 경우에는 고강도 운동을 하면 위험할 수 있다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người bệnh", "def_ko": "환자", "def_vi": "Người được chăm sóc"}, {"term_ko": "건강증진", "term_vi": "Cải thiện sức khỏe", "def_ko": "건강의 개선", "def_vi": "Sự nâng cao sức khỏe"}, {"term_ko": "운동 방법", "term_vi": "Phương pháp tập luyện", "def_ko": "운동이 이루어지는 방식", "def_vi": "Cách thức tập luyện"}, {"term_ko": "신체능력", "term_vi": "Khả năng thể chất", "def_ko": "신체의 능력", "def_vi": "Năng lực của cơ thể"}, {"term_ko": "고강도", "term_vi": "Cường độ cao", "def_ko": "높은 강도의 운동", "def_vi": "Mức độ cao"}, {"term_ko": "호흡곤란", "term_vi": "Khó thở", "def_ko": "호흡에 어려움을 겪는 것", "def_vi": "Gặp khó khăn trong việc thở"}, {"term_ko": "부정맥", "term_vi": "Rối loạn nhịp tim", "def_ko": "심장 박동이 불규칙한 상태", "def_vi": "Tình trạng nhịp tim không đều"}, {"term_ko": "혈압", "term_vi": "Huyết áp", "def_ko": "혈액 압력", "def_vi": "Áp lực máu"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (52, '7', '노화로 인한 수면양상의 변화로 옳은 것은?', '["수면 중에 자주 깬다.", "수면시간이 늘어난다.", "잠드는 데 시간이 줄어든다.", "낮 동안 졸림 증상이 줄어든다.", "아침에 늦게 일어난다."]'::jsonb, 1, NULL, NULL, '{"1": "노화가 진행되면 수면의 질이 저하되어 자주 깨어나는 현상이 나타납니다.\n[정답]", "2": "일반적으로 수면 시간은 감소하는 경향이 있습니다.", "3": "수면의 시작 시간은 오히려 길어질 수 있습니다.", "4": "낮 동안 졸림 증상은 증가하는 경향이 있습니다.", "5": "아침에 일어나는 시간은 오히려 빨라질 수 있습니다."}'::jsonb, '[{"term_ko": "노화", "term_vi": "Lão hóa", "def_ko": "나이가 들다(한국어)", "def_vi": "Trở nên già"}, {"term_ko": "수면", "term_vi": "Giấc ngủ", "def_ko": "잠자다(한국어)", "def_vi": "Ngủ"}, {"term_ko": "자주", "term_vi": "Thường xuyên", "def_ko": "자주(한국어)", "def_vi": "Thường xuyên"}, {"term_ko": "깬다", "term_vi": "Thức dậy", "def_ko": "깨다(한국어)", "def_vi": "Thức dậy"}, {"term_ko": "증상", "term_vi": "Triệu chứng", "def_ko": "증상(한국어)", "def_vi": "Triệu chứng"}, {"term_ko": "일어난다", "term_vi": "Dậy", "def_ko": "일어나다(한국어)", "def_vi": "Dậy"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (51, '7', '밤에 잠이 들기까지 시간이 오래 걸리고 자주 깨는 대상자의 수면을 돕는 방법으로 옳은 것은?', '["저녁에 과식하지 않는다.", "가습기를 이용하여 습도를 80%로 맞춘다.", "밤에 땀 흘리는 운동을 하게 한다.", "저녁 식사 후 따뜻한 홍차를 마시게 한다.", "취침 전에 집중할 수 있는 놀이를 함께 한다."]'::jsonb, 1, NULL, NULL, '{"1": "저녁에 과식하지 않는 것은 소화에 도움을 주어 수면의 질을 개선한다.\n[정답]", "2": "가습기를 이용하여 습도를 80%로 맞추는 것은 과도한 습도로 인해 오히려 불편함을 줄 수 있다.", "3": "밤에 땀 흘리는 운동을 하게 하는 것은 오히려 신체의 에너지를 활성화시켜 수면을 방해할 수 있다.", "4": "저녁 식사 후 따뜻한 홍차를 마시는 것은 카페인이 포함되어 있어 수면에 방해가 될 수 있다.", "5": "취침 전에 집중할 수 있는 놀이를 함께 하는 것은 오히려 긴장을 높여 수면을 방해할 수 있다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Đối tượng", "def_ko": "환자(한국어)", "def_vi": "Bệnh nhân"}, {"term_ko": "수면", "term_vi": "Giấc ngủ", "def_ko": "잠(한국어)", "def_vi": "Ngủ"}, {"term_ko": "가습기", "term_vi": "Máy tạo độ ẩm", "def_ko": "습도를 조절하는 기기(한국어)", "def_vi": "Thiết bị điều chỉnh độ ẩm"}, {"term_ko": "과식", "term_vi": "Ăn quá no", "def_ko": "너무 많이 먹는 것(한국어)", "def_vi": "Ăn nhiều"}, {"term_ko": "적당한", "term_vi": "Thích hợp", "def_ko": "적절한(한국어)", "def_vi": "Phù hợp"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (50, '7', '여성노인의 성적 변화에 관한 설명으로 옳은 것은?', '["질 분비물 증가로 성교 시 통증이 없다.", "유방절제술을 받으면 성기능이 감소한다.", "항 염증성 약물을 복용하면 성기능이 증가한다.", "전립선 절세술은 발기하는 데 문제를 유발한다.", "유방절제술은 성기능에 영향을 주지 않는다."]'::jsonb, 5, NULL, NULL, '{"1": "질 분비물의 증가가 성교 시 통증의 원인이 되는 경우가 많기 때문에 이 설명은 잘못되었습니다.\n[정답]", "5": "유방절제술이 성기능에 영향을 미치지 않는다는 것은 연구에 의해 지지받는 내용을 반영한 것입니다.", "2": "유방절제술 후 일부 여성은 성기능 변화가 있을 수 있으나, 이는 개인에 따라 다릅니다.", "3": "항 염증성 약물이 성기능을 증가시키는 것은 일반적으로 알려진 바가 아닙니다.", "4": "전립선 절세술은 남성의 성기능에 영향을 줄 수 있지만, 여성의 경우에는 관계가 없습니다."}'::jsonb, '[{"term_ko": "여성", "term_vi": "Phụ nữ", "def_ko": "여자(한국어)", "def_vi": "Nữ giới(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (49, '7', '뇌졸중 대상자가 성생활에 대해 고민할 때 요양보호사의 반응으로 옳은 것은?', '["\"성생활은 뇌졸중 재발의 원인이 돼요.\"", "\"성생활로 뇌졸중이 악화되지 않아요.\"", "\"윤활제는 사용하지 않는 것이 좋아요.\"", "\"뇌졸중 치료제를 드시면 성기능이 좋아져요.\"", "\"체위 변화를 위한 기구는 성생활에 도움이 되지 않아요.\""]'::jsonb, 2, NULL, NULL, '{"1": "성생활이 뇌졸중 재발의 원인이 된다는 것은 과학적 증거가 부족하다. \n[정답]", "2": "성생활은 뇌졸중 환자에게 특별한 주의만 기울이면 안전하게 할 수 있다.", "3": "윤활제 사용은 성생활의 질을 향상시킬 수 있다.", "4": "뇌졸중 치료제는 성기능에 영향이 있을 수 있으나, 반드시 좋게 작용하지는 않는다.", "5": "체위 변화를 위한 기구는 성생활에 도움이 될 수 있다."}'::jsonb, '[{"term_ko": "뇌졸중", "term_vi": "Đột quỵ", "def_ko": "뇌의 혈류가 방해받아 발생하는 질환", "def_vi": "Bệnh xảy ra khi máu đến não bị cản trở"}, {"term_ko": "성생활", "term_vi": "Đời sống tình dục", "def_ko": "성적인 활동", "def_vi": "Hoạt động tình dục"}, {"term_ko": "윤활제", "term_vi": "Chất bôi trơn", "def_ko": "성행위 시 마찰을 줄이기 위해 사용하는 물질", "def_vi": "Chất được sử dụng để giảm ma sát trong quan hệ tình dục"}, {"term_ko": "체위", "term_vi": "Tư thế", "def_ko": "몸의 자세", "def_vi": "Địa điểm hoặc chiều hướng của cơ thể"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (48, '7', '시설에서의 노인의 성생활과 관련된 권리로 옳은 것은?', '["노인도 성적 존재임을 인정한다.", "부부라도 한방을 쓸 수 없도록 한다.", "자신의 성을 인식하고 표현하지 않도록 한다.", "노인부부의 성생활을 흥밋거리로 다룬다.", "노인 개인의 성과 관련된 상담은 하지 않는다."]'::jsonb, 1, NULL, NULL, '{"1": "노인은 성적 존재로 인식되어야 하며, 그 권리가 존중받아야 합니다.\n[정답]", "2": "부부는 개인의 사생활을 존중받아야 하므로 한 방을 함께 사용할 수 있어야 합니다.", "3": "노인은 자신의 성을 인식하고 표현할 권리가 있습니다.", "4": "노인의 성생활은 사생활이므로 비하하거나 흥미거리로 삼아서는 안 됩니다.", "5": "노인 개인의 성과 관련된 상담은 그들의 권리를 존중하기 위해 필요할 수 있습니다."}'::jsonb, '[{"term_ko": "성생활", "term_vi": "Cuộc sống tình dục", "def_ko": "성적 활동(한국어)", "def_vi": "Hoạt động tình dục"}, {"term_ko": "권리", "term_vi": "Quyền lợi", "def_ko": "법적으로 보장된 특정한 이점(한국어)", "def_vi": "Lợi ích cụ thể được đảm bảo theo pháp luật"}, {"term_ko": "인식", "term_vi": "Nhận thức", "def_ko": "알고 이해하거나 받아들이는 것(한국어)", "def_vi": "Biết, hiểu hoặc chấp nhận"}, {"term_ko": "상담", "term_vi": "Tư vấn", "def_ko": "전문가와 이야기를 나누는 것(한국어)", "def_vi": "Nói chuyện với chuyên gia"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (47, '7', '편의점에서 구입 가능한 상비약으로 옳은 것은?', '["해열진통제, 소화제, 파스", "감기약, 수면제", "소화제, 항생제", "파스, 스테로이드 연고", "해열제, 혈압약"]'::jsonb, 1, NULL, NULL, '{"1": "해열진통제, 소화제, 파스는 일반적으로 편의점에서 구입할 수 있는 상비약입니다.\n[정답]", "2": "감기약, 수면제는 일반적으로 편의점에서 구입할 수 없는 약입니다.", "3": "소화제, 항생제는 항생제는 처방이 필요하므로 편의점에서 구입할 수 없습니다.", "4": "파스, 스테로이드 연고는 스테로이드 연고는 일반적으로 전문 약국에서 처방받아야 합니다.", "5": "해열제, 혈압약은 혈압약은 처방전이 필요한 약이므로 편의점에서 구매할 수 없습니다."}'::jsonb, '[{"term_ko": "편의점", "term_vi": "Cửa hàng tiện lợi", "def_ko": "소형 매점", "def_vi": "Cửa hàng nhỏ gọn"}, {"term_ko": "상비약", "term_vi": "Thuốc cơ bản", "def_ko": "기본적인 의약품", "def_vi": "Thuốc y tế cơ bản"}, {"term_ko": "해열진통제", "term_vi": "Thuốc giảm đau hạ sốt", "def_ko": "열을 내리고 통증을 완화하는 약", "def_vi": "Thuốc giảm sốt và đau"}, {"term_ko": "소화제", "term_vi": "Thuốc tiêu hóa", "def_ko": "소화불량을 치료하는 약", "def_vi": "Thuốc điều trị rối loạn tiêu hóa"}, {"term_ko": "파스", "term_vi": "Cao dán", "def_ko": "붙이는 약", "def_vi": "Thuốc dán"}, {"term_ko": "감기약", "term_vi": "Thuốc cảm", "def_ko": "감기를 치료하는 약", "def_vi": "Thuốc điều trị cảm cúm"}, {"term_ko": "수면제", "term_vi": "Thuốc ngủ", "def_ko": "잠이 오게 하는 약", "def_vi": "Thuốc giúp ngủ"}, {"term_ko": "항생제", "term_vi": "Kháng sinh", "def_ko": "세균 감염을 치료하는 약", "def_vi": "Thuốc điều trị nhiễm trùng"}, {"term_ko": "스테로이드 연고", "term_vi": "Thuốc mỡ steroid", "def_ko": "피부 질환 치료용 연고", "def_vi": "Thuốc mỡ điều trị bệnh ngoài da"}, {"term_ko": "혈압약", "term_vi": "Thuốc huyết áp", "def_ko": "고혈압 치료약", "def_vi": "Thuốc điều trị huyết áp cao"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (46, '7', '노인 대상자의 약물 복용 방법으로 옳은 것은?', '["위장 장애가 있을 때에는 약의 용량을 줄인다.", "코팅된 약을 삼키기 힘들 때는 분쇄하여 복용한다.", "약이 효과가 없을 때에는 임의로 복용을 중단한다.", "복용 약이 있는 경우 건강기능식품 섭취는 의사와 상의한다.", "약이 없으면 증상이 비슷한 다른 대상자의 약을 먹는다."]'::jsonb, 4, NULL, NULL, '{"1": "위장 장애가 있을 때에는 의사의 처방에 따라 용량 조절이 필요합니다. 따라서 단순히 줄이는 것은 올바른 방법이 아닙니다.", "2": "코팅된 약물을 분쇄하여 복용하는 것은 약물의 효과에 영향을 줄 수 있어 권장되지 않습니다.\n[정답]", "3": "약물이 효과가 없다고 해서 임의로 중단하는 것은 위험한 행동입니다.", "4": "복용 중인 약물이 있을 경우 건강기능식품 섭취는 반드시 의사와 상의해야 하는 것이 맞습니다.", "5": "약이 없다고 다른 대상자의 약을 복용하는 것은 매우 위험한 행동입니다."}'::jsonb, '[{"term_ko": "약물", "term_vi": "Thuốc", "def_ko": "약(한국어)", "def_vi": "Thuốc"}, {"term_ko": "복용", "term_vi": "Uống thuốc", "def_ko": "복용하다(한국어)", "def_vi": "Uống thuốc"}, {"term_ko": "이상", "term_vi": "Triệu chứng", "def_ko": "이상(한국어)", "def_vi": "Triệu chứng"}, {"term_ko": "중단", "term_vi": "Ngừng", "def_ko": "중단하다(한국어)", "def_vi": "Ngừng"}, {"term_ko": "확인", "term_vi": "Kiểm tra", "def_ko": "확인하다(한국어)", "def_vi": "Kiểm tra"}, {"term_ko": "상담", "term_vi": "Tư vấn", "def_ko": "상담하다(한국어)", "def_vi": "Tư vấn"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (45, '7', '관절염, 근육통 약으로, 노인에서는 위염, 위궤양, 속쓰림 등의 부작용이 나타나는 약물로 옳은 것은?', '["당뇨병 약", "스테로이드제", "수면제", "소염진통제", "고지혈증 약"]'::jsonb, 4, NULL, NULL, '{"1": "당뇨병 약: 당뇨병 약물은 주로 혈당 조절을 위한 약물로, 위염이나 위궤양과 관련된 부작용이 일반적이지 않습니다.\n[정답]", "2": "스테로이드제: 스테로이드제는 장기적으로 사용 시 위염, 위궤양과 같은 부작용이 나타날 수 있습니다.", "3": "수면제: 수면제는 주로 수면을 유도하는 약물로, 위장관 부작용이 주가 아닙니다.", "4": "소염진통제: 소염진통제는 관절염 및 근육통 치료에 사용되며, 노인에게 위염과 위궤양을 유발할 수 있습니다.", "5": "고지혈증 약: 고지혈증 약물은 주로 혈중 지방을 조절하지만, 위장관 부작용은 드물게 나타납니다."}'::jsonb, '[{"term_ko": "관절염", "term_vi": "Viêm khớp", "def_ko": "관절의 염증 및 통증(한국어)", "def_vi": "Viêm và đau tại khớp"}, {"term_ko": "근육통", "term_vi": "Đau cơ", "def_ko": "근육의 통증(한국어)", "def_vi": "Đau ở cơ"}, {"term_ko": "위염", "term_vi": "Viêm dạ dày", "def_ko": "위의 염증(한국어)", "def_vi": "Viêm ở dạ dày"}, {"term_ko": "위궤양", "term_vi": "Loét dạ dày", "def_ko": "위에 생기는 궤양(한국어)", "def_vi": "Hình thành loét ở dạ dày"}, {"term_ko": "소염진통제", "term_vi": "Thuốc giảm đau kháng viêm", "def_ko": "염증과 통증을 완화하는 약물(한국어)", "def_vi": "Thuốc giúp giảm viêm và đau"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (44, '7', '와파린고 함께 먹었을 때 약의 효과를 줄일 수 있어 과량 섭취하지 않는 음식으로 옳은 것은?', '["인삼", "시금치", "프로바이오틱스", "알로에", "감마리놀레산"]'::jsonb, 2, NULL, NULL, '{"1": "인삼은 혈액 응고에 영향을 줄 수 있어 주의해야 합니다.\n[정답]", "2": "시금치는 와파린과 함께 섭취해도 안전하며, 과량 섭취하지 않아야 하는 음식입니다.", "3": "프로바이오틱스는 일반적으로 와파린에 영향을 주지 않습니다.", "4": "알로에는 항응고 효과가 있어 주의가 필요합니다.", "5": "감마리놀레산은 혈액 응고에 영향을 미칠 수 있는 물질입니다."}'::jsonb, '[{"term_ko": "와파린", "term_vi": "인삼", "def_ko": "항응고제(thuốc chống đông máu)", "def_vi": "한약재(thuốc đông y)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (43, '7', '약물 복용 방법으로 옳은 것은?', '["쓴 약은 커피우유와 함께 복용한다.", "약이 없으면 증상이 비슷한 다른 사람의 약을 복용한다.", "약 복용 시간을 놓친 경우 용량을 2배 용량으로 복용한다.", "처방이 바뀌면 이전 약을 모두 복용한 후 바뀐 약을 복용한다.", "삼키기 힘든 약이 분할할 수 없는 약이라면 처방을 변경해달라고 한다."]'::jsonb, 5, NULL, NULL, '{"1": "쓴 약은 다른 음료와 함께 복용하는 것이 도움이 될 수 있으나, 반드시 커피우유와 함께 복용해야 하는 것은 아닙니다.\n[정답]", "5": "삼키기 힘든 약은 분할할 수 없으므로 의사에게 처방 변경을 요청하는 것이 바람직합니다.", "2": "타인의 약을 복용하는 것은 안전하지 않으며, 반드시 본인의 처방 약을 복용해야 합니다.", "3": "약 복용 시간을 놓쳤을 경우, 용량을 두 배로 복용하는 것은 위험할 수 있습니다.", "4": "처방이 바뀌더라도 이전 약을 모두 복용한 후 바뀐 약을 복용하는 것은 잘못된 방법입니다."}'::jsonb, '[{"term_ko": "약물", "term_vi": "Thuốc", "def_ko": "약(한국어)", "def_vi": "thuốc(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (42, '7', '흡연과 금연에 관한 설명으로 옳은 것은?', '["흡연은 중독성이 없다.", "금연 시기를 놓치면 금연 효과가 없다.", "일시적 금연은 폐기능을 악화시킨다.", "간접흡연도 직접흡연을 하는 경우와 마찬가지다.", "금연 시 혈중 일산화탄소 수치가 증가한다."]'::jsonb, 4, NULL, NULL, '{"1": "흡연은 중독성이 없다. 이는 잘못된 설명입니다.\n[정답]", "4": "간접흡연도 직접흡연을 하는 경우와 마찬가지다. 간접흡연은 직접흡연처럼 건강에 해롭습니다.", "2": "금연 시기를 놓치면 금연 효과가 없다. 이는 부정확한 설명입니다.", "3": "일시적 금연은 폐기능을 악화시킨다. 이는 올바른 설명이 아닙니다.", "5": "금연 시 혈중 일산화탄소 수치가 증가한다. 이는 잘못된 설명입니다."}'::jsonb, '[{"term_ko": "흡연", "term_vi": "Hút thuốc", "def_ko": "담배를 피우는 것", "def_vi": "Hành động hút thuốc lá"}, {"term_ko": "금연", "term_vi": "Bỏ thuốc", "def_ko": "담배를 끊는 것", "def_vi": "Ngừng hút thuốc lá"}, {"term_ko": "중독성", "term_vi": "Tính gây nghiện", "def_ko": "중독의 성질", "def_vi": "Tính chất của sự nghiện"}, {"term_ko": "일시적", "term_vi": "Tạm thời", "def_ko": "잠깐 동안", "def_vi": "Trong một khoảng thời gian ngắn"}, {"term_ko": "간접흡연", "term_vi": "Hút thuốc thụ động", "def_ko": "다른 사람이 피우는 담배 연기를 흡입", "def_vi": "Hít khói thuốc từ người khác"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (41, '7', '금연 후 나타나는 변화로 옳은 것은?', '["정자 수가 감소한다.", "기대수명이 감소한다.", "혈액순환이 감소한다.", "심장병 발생 위험이 감소한다.", "혈중 산소량이 정상보다 감소한다."]'::jsonb, 4, NULL, NULL, '{"1": "금연 후 정자 수는 오히려 증가하는 경향이 있습니다.", "2": "금연은 기대수명을 증가시키는 효과가 있습니다.", "3": "혈액순환은 금연 후 개선됩니다.\n[정답]", "4": "금연 후 심장병 발생 위험이 감소하는 것이 정확한 설명입니다.", "5": "혈중 산소량은 정상으로 회복됩니다."}'::jsonb, '[{"term_ko": "금연", "term_vi": "Bỏ thuốc lá", "def_ko": "담배를 끊는 것", "def_vi": "Ngừng hút thuốc"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (40, '7', '음주를 매일 하는 대상자의 절주를 돕는 방법으로 옳은 것은?', '["알코올 도수가 높은 술을 마신다.", "권유받았을 때만 술을 마신다.", "일주일에 술 마시는 날을 정한다.", "절주 의지를 주변 사람들에게 알리게 한다.", "암 예방을 위해 하루 한두 잔의 술을 허용한다."]'::jsonb, 4, NULL, NULL, '{"1": "알코올 도수가 높은 술을 마신다.", "2": "권유받았을 때만 술을 마신다.", "3": "일주일에 술 마시는 날을 정한다.\n[정답]", "4": "절주 의지를 주변 사람들에게 알리게 한다.", "5": "암 예방을 위해 하루 한두 잔의 술을 허용한다."}'::jsonb, '[{"term_ko": "음주", "term_vi": "Uống rượu", "def_ko": "술을 마시는 것", "def_vi": "Uống rượu"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (39, '7', '금연과 흡연의 금단 증상 대처 및 스트레스 관리로 옳은 것은?', '["적절한 식단보다 영양제를 중심으로 공급한다.", "금단증상이 심하더라도 약물치료는 피한다.", "술 생각이 유발되는 상황을 피한다.", "스트레스 받는 상황에서 적당한 음주와 흡연을 한다.", "불규칙한 생활습관을 통해 스트레스를 관리한다."]'::jsonb, 3, NULL, NULL, '{"1": "적절한 식단보다는 영양제를 공급하는 것은 금연의 도움에 비효율적입니다.\n[정답]", "3": "술 생각이 유발되는 상황을 피하는 것은 금연을 지속하는 데 도움이 됩니다.", "2": "금단증상이 심하더라도 약물치료는 필요할 수 있으므로 피하는 것이 옳지 않습니다.", "4": "스트레스를 받는 상황에서 음주와 흡연은 오히려 위험합니다.", "5": "불규칙한 생활습관은 스트레스를 오히려 악화시킬 수 있습니다."}'::jsonb, '[{"term_ko": "금연", "term_vi": "Bỏ thuốc lá", "def_ko": "담배를 끊는 것", "def_vi": "Ngừng hút thuốc"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (38, '7', '60세 이상 노인에게 권장되는 예방접종에 관한 설명으로 옳은 것은?', '["폐렴구균은 매년 1회 접종한다.", "인플루엔자는 10년마다 1회 접종한다.", "백일해는 10년마다 접종한다.", "파상풍은 1회 접종했다면 10년마다 추갈 접종한다.", "대상포진은 과거에 홍역을 앓았다면 접종할 필요가 없다."]'::jsonb, 4, NULL, NULL, '{"1": "폐렴구균은 매년 1회 접종하는 것이 아니라, 일정한 기준에 따라 접종합니다.\n[정답]", "4": "파상풍은 1회 접종 후 10년마다 추가 접종이 필요합니다.", "2": "인플루엔자는 매년 접종해야 합니다.", "3": "백일해는 성인이 경우 10년마다 접종할 필요가 없습니다.", "5": "대상포진은 홍역 이력과는 관계없이 접종이 권장됩니다."}'::jsonb, '[{"term_ko": "예방접종", "term_vi": "Tiêm vắc xin", "def_ko": "예방을 위한 백신 접종", "def_vi": "Tiêm phòng để ngăn ngừa"}, {"term_ko": "노인", "term_vi": "Người cao tuổi", "def_ko": "60세 이상의 성인", "def_vi": "Người trên 60 tuổi"}, {"term_ko": "폐렴구균", "term_vi": "Phế cầu khuẩn", "def_ko": "폐렴을 일으키는 세균", "def_vi": "Vi khuẩn gây bệnh viêm phổi"}, {"term_ko": "인플루엔자", "term_vi": "Cúm", "def_ko": "독감", "def_vi": "Bệnh cúm"}, {"term_ko": "대상포진", "term_vi": "Zona", "def_ko": "수두의 바이러스가 재활성화되어 발생", "def_vi": "Bệnh zona (Herpes zoster)"}, {"term_ko": "파상풍", "term_vi": "Uốn ván", "def_ko": "상처로 인한 세균 감염", "def_vi": "Nhiễm khuẩn do vết thương"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (37, '7', '60세 이상 노인에게 매년 1회 권장되는 예방접종으로 옳은 것은?', '["디프테리아", "백일해", "대상포진", "폐렴구균", "인플루엔자"]'::jsonb, 5, NULL, NULL, '{"1": "디프테리아: 노인에게 권장되지만 매년 접종할 필요는 없음.", "2": "백일해: 노인에게 권장되지만 매년 접종할 필요는 없음.\n[정답]", "3": "인플루엔자: 60세 이상 노인은 매년 예방접종을 권장받는 중요한 예방접종입니다.", "4": "폐렴구균: 노인에게 권장되지만 매년 접종할 필요는 없음.", "5": "대상포진: 노인에게 권장되지만 매년 접종할 필요는 없음."}'::jsonb, '[{"term_ko": "예방접종", "term_vi": "Tiêm phòng", "def_ko": "예방접종(한국어)", "def_vi": "Tiêm phòng(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (36, '7', '10년마다 추가 접종해야 하는 것으로 옳은 것은?', '["폐렴구균 - 백일해", "파상풍 - 디프테리아", "인플루엔자 - 백일해", "폐렴구균 - 디프테리아", "대상포진 - 인플루엔자"]'::jsonb, 2, NULL, NULL, '{"1": "폐렴구균 - 백일해: 폐렴구균 백신은 10년마다 접종해야 하는 것이 아닙니다.\n[정답]", "2": "파상풍 - 디프테리아: 파상풍과 디프테리아 백신은 10년마다 추가 접종을 권장합니다.", "3": "인플루엔자 - 백일해: 인플루엔자는 매년 접종이 권장되며, 백일해는 추가 접종 대상이 아닙니다.", "4": "폐렴구균 - 디프테리아: 폐렴구균 백신은 10년마다 접종해야 하는 것이 아닙니다.", "5": "대상포진 - 인플루엔자: 대상포진 백신은 1회 접종으로 충분하며, 인플루엔자는 매년 접종이 필요합니다."}'::jsonb, '[{"term_ko": "파상풍", "term_vi": "Uốn ván", "def_ko": "질병명(한국어)", "def_vi": "bệnh"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (35, '7', '여름철 폭염에 대응하는 안전수칙으로 옳은 것은?', '["물을 평소보다 많이 마신다.", "지방이 많은 음식을 섭취한다.", "실내보다 실외에서 운동한다.", "외출 시 챙이 좁은 모자를 쓴다.", "두통이 있으면 뜨거운 차를 마신다."]'::jsonb, 1, NULL, NULL, '{"1": "물을 충분히 마시는 것은 여름철 열사병 예방에 중요하다.\n[정답]", "2": "지방이 많은 음식은 체온 상승을 유발할 수 있으므로 적절하지 않다.", "3": "실외에서 운동하는 것은 폭염 시 위험할 수 있다.", "4": "챙이 좁은 모자는 햇빛을 충분히 막지 못해 보호효과가 낮다.", "5": "두통이 있을 때 뜨거운 차를 마시는 것은 추천되지 않는다."}'::jsonb, '[{"term_ko": "폭염", "term_vi": "Nắng nóng", "def_ko": "극심한 더위(한국어)", "def_vi": "Nhiệt độ cao cực độ (베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (34, '7', '열사병이 있을 때 대응하는 안전수칙으로 옳은 것은?', '["심한 갈증, 피로감을 호소한다.", "근육경련이 2~3분 동안 지속한다.", "젖은 수건으로 몸을 적신 후 선풍기 바람을 씌워준다.", "땀을 많이 흘린 뒤 발생한다.", "염분과 수분을 보충하도록 한다."]'::jsonb, 3, NULL, NULL, '{"1": "심한 갈증과 피로감은 열사병의 증상 중 하나이지만 대응 방법이 아닙니다.", "2": "근육 경련이 지속되는 것은 열사병의 증상이나, 이에 대한 대처법은 아닙니다.\n[정답]", "3": "젖은 수건으로 몸을 적신 후 선풍기 바람을 씌워주는 것은 열사병의 적절한 응급처치 방법입니다.", "4": "땀을 많이 흘린 후 발생할 수 있지만, 이는 대응 방법은 아닙니다.", "5": "염분과 수분 보충은 필요하지만, 응급조치로는 젖은 수건과 선풍기 사용이 더 중요합니다."}'::jsonb, '[{"term_ko": "열사병", "term_vi": "Bệnh say nắng", "def_ko": "고온 상태에서 발생하는 질병", "def_vi": "Bệnh xảy ra khi ở nhiệt độ cao"}, {"term_ko": "안전수칙", "term_vi": "Quy tắc an toàn", "def_ko": "사고를 예방하기 위한 규칙", "def_vi": "Quy tắc để ngăn ngừa tai nạn"}, {"term_ko": "응급처치", "term_vi": "Cấp cứu", "def_ko": "긴급 상황에서의 치료", "def_vi": "Điều trị trong tình huống khẩn cấp"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (33, '7', '겨울철 안전수칙으로 옳은 것은?', '["실내운동을 삼가고 실외운동으로 바꾼다.", "운동은 새벽보다는 낮 시간을 이용한다.", "술을 마신 다음날 아침에는 가급적 운동을 한다.", "동상 예방을 위해 손은 주머니에 넣고 다닌다.", "움직임이 둔한 옷으로 보온을 한다."]'::jsonb, 2, NULL, NULL, '{"1": "실내운동은 겨울철 안전을 위해 추천되지 않으며, 실외운동의 위험이 큽니다.\n[정답]", "2": "낮 시간대에는 햇볕이 있어 체온 유지에 도움이 되므로 운동하기에 적합합니다.", "3": "술의 영향으로 반응속도가 떨어지므로 다음날 아침 운동하는 것은 안전하지 않습니다.", "4": "손을 주머니에 넣고 다니는 것은 동상 예방에 도움이 되지 않으며, 장갑을 착용하는 것이 좋습니다.", "5": "보온을 위해서는 활동적인 움직임을 유지하는 것이 중요하므로 둔한 옷은 피해야 합니다."}'::jsonb, '[{"term_ko": "겨울철", "term_vi": "Mùa đông", "def_ko": "올 겨울", "def_vi": "Mùa đông sắp đến"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (32, '7', '저체온과 같은 한랭질환이 있을 때 대응하는 안전수칙으로 옳은 것은?', '["의식이 있다면 따뜻한 초콜릿 같은 단 음식을 섭취하게 한다.", "젖은 옷 위에 담요로 감싸는 것이 좋다.", "피부색이 창백하고 누런 회색으로 변하면 따뜻한 물에 담그는 것이 좋다.", "대상자를 시원한 곳으로 옮기고 미지근한 물에 담근다.", "의식이 없더라도 따뜻한 차를 마시게 한다."]'::jsonb, 1, NULL, NULL, '{"1": "의식이 있다면 따뜻한 초콜릿 같은 단 음식을 섭취하게 한다. - 저체온증 환자가 의식이 있을 때 따뜻한 음식을 제공하는 것은 중요한 조치입니다.\n[정답]", "2": "젖은 옷 위에 담요로 감싸는 것이 좋다. - 젖은 옷은 체온 유지에 방해가 되므로 즉시 벗기고 담요로 덮어주는 것이 올바른 대처가 아닙니다.", "3": "피부색이 창백하고 누런 회색으로 변하면 따뜻한 물에 담그는 것이 좋다. - 따뜻한 물에 담그는 것은 부적절하며, 급격한 온도 변화는 위험할 수 있습니다.", "4": "대상자를 시원한 곳으로 옮기고 미지근한 물에 담근다. - 시원한 곳으로 옮기는 것은 잘못된 행동입니다. 적절한 온도로 보존해야 합니다.", "5": "의식이 없더라도 따뜻한 차를 마시게 한다. - 의식이 없는 환자에게 음료를 제공하는 것은 위험할 수 있습니다."}'::jsonb, '[{"term_ko": "저체온", "term_vi": "Hạ thân nhiệt", "def_ko": "저체온증(한국어)", "def_vi": "Bệnh hạ thân nhiệt"}, {"term_ko": "한랭질환", "term_vi": "Bệnh lạnh", "def_ko": "차가운 질병(한국어)", "def_vi": "Bệnh do lạnh"}, {"term_ko": "의식", "term_vi": "Ý thức", "def_ko": "인지 상태(한국어)", "def_vi": "Tình trạng nhận thức"}, {"term_ko": "담요", "term_vi": "Chăn", "def_ko": "덮개(한국어)", "def_vi": "Chiếc chăn"}, {"term_ko": "섭취", "term_vi": "Tiêu thụ", "def_ko": "먹다(한국어)", "def_vi": "Tiêu thụ"}, {"term_ko": "온도", "term_vi": "Nhiệt độ", "def_ko": "기온(한국어)", "def_vi": "Nhiệt độ"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (31, '8', '대상자와 의사소통하는 방법으로 옳은 것은?', '["대상자와 눈을 마주하기를 피한다.", "호칭을 할 때에는 대상자의 성명을 부른다.", "요양보호사가 알고 있는 전문 용어를 표현한다.", "상황에 맞지 않는 말을 하면 즉시 지적해 준다.", "개인정보 보호를 위해 요양보호사의 소속은 비밀로 한다."]'::jsonb, 2, NULL, NULL, '{"1": "대상자와 눈을 마주하기를 피하는 것은 올바른 의사소통 방법이 아니다.\n[정답]", "2": "호칭을 할 때 대상자의 성명을 부르는 것은 존중의 표현으로 적절하다.", "3": "요양보호사가 알고 있는 전문 용어를 표현하는 것은 대상자가 이해하지 못할 수 있으므로 피해야 한다.", "4": "상황에 맞지 않는 말을 하면 즉시 지적하는 것은 관계를 악화시킬 수 있다.", "5": "개인정보 보호를 위해 요양보호사의 소속은 당연히 공개되어야 한다."}'::jsonb, '[{"term_ko": "의사소통", "term_vi": "Giao tiếp", "def_ko": "소통, 교류(한국어)", "def_vi": "sự trao đổi, giao lưu(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (30, '8', '바람직한 비언어적 의사소통 기법으로 옳은 것은?', '["생각할 수 있는 긴 침묵", "대상자보다 높은 눈높이", "대상자로부터 비껴 앉은 자세", "간간히 적절하게 미소 짓기", "적절한 희미한 미소"]'::jsonb, 4, NULL, NULL, '{"1": "생각할 수 있는 긴 침묵은 소통에 도움이 되지 않을 수 있으며, 바람직한 기법이 아니다.\n[정답]", "4": "간간히 적절하게 미소 짓기는 긍정적인 비언어적 의사소통 기법이다.", "2": "대상자보다 높은 눈높이는 상대방에게 위압감을 줄 수 있으므로 바람직하지 않다.", "3": "대상자로부터 비껴 앉은 자세는 상대방과의 직접적인 소통을 방해할 수 있다.", "5": "적절한 희미한 미소는 비언어적 의사소통으로 효과를 줄 수 있지만, 간간히 미소 짓는 것이 더 효과적이다."}'::jsonb, '[{"term_ko": "비언어적", "term_vi": "Giao tiếp phi ngôn ngữ", "def_ko": "비언어적 의사소통", "def_vi": "Giao tiếp không dùng từ ngữ"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (29, '8', '장기요양서비스에서 의사소통의 원칙으로 옳은 것은?', '["대상자를 개별화하여 파악한다.", "대상자의 감정을 억제하도록 한다.", "요양보호사의 편견에 따라 대상자를 파악한다.", "대상자의 부적절한 행동에 대해 심판적 태도로 대한다.", "장기요양기관의 결정에 따르도록 한다."]'::jsonb, 1, NULL, NULL, '{"1": "대상자를 개별화하여 파악한다는 것은 의사소통의 핵심 원칙 중 하나로, 개인의 특성에 맞춘 접근이 필요하다.\n[정답]", "2": "대상자의 감정을 억제하도록 한다는 것은 잘못된 원칙으로, 감정 표현의 중요성을 무시한다.", "3": "요양보호사의 편견에 따라 대상자를 파악한다는 것은 부적절한 의사소통을 초래할 수 있다.", "4": "대상자의 부적절한 행동에 대해 심판적 태도로 대한다는 것은 신뢰를 저해할 수 있다.", "5": "장기요양기관의 결정에 따르도록 한다는 것은 상황에 따라 유연성이 필요하다."}'::jsonb, '[{"term_ko": "장기요양서비스", "term_vi": "Dịch vụ chăm sóc dài hạn", "def_ko": "장기적인 요양을 제공하는 서비스", "def_vi": "Dịch vụ chăm sóc kéo dài"}, {"term_ko": "의사소통", "term_vi": "Giao tiếp", "def_ko": "서로 정보를 주고받는 과정", "def_vi": "quá trình truyền đạt thông tin cho nhau"}, {"term_ko": "개별화", "term_vi": "Cá nhân hóa", "def_ko": "개인의 특성에 맞추어 조정하는 것", "def_vi": "điều chỉnh theo đặc điểm cá nhân"}, {"term_ko": "편견", "term_vi": "Thành kiến", "def_ko": "어떤 대상을 공정하지 않게 판단하는 사고", "def_vi": "suy nghĩ đánh giá sai lệch về một đối tượng"}, {"term_ko": "부적절한", "term_vi": "Không phù hợp", "def_ko": "적합하지 않은 상태", "def_vi": "trạng thái không thích hợp"}, {"term_ko": "심판적", "term_vi": "Thái độ phán xét", "def_ko": "판단하고 평가하는 태도", "def_vi": "thái độ đánh giá và quyết định"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (28, '8', '다음의 대화에서 요양보호사의 반응으로 옳은 것은?• 대상자 : 내 스웨터 어디 있어? 왜 자꾸 숨겨 놔! • 요양보호사 : ( )', '["\"제가 스웨터 숨기지 않았어요. 함부로 의심하지 마세요.\"", "\"오늘은 스웨터가 없어서 밖에 못 나가시겠네요.\"", "\"새로 구입한 더 예쁜 스웨터가 있어요. 대신 이걸로 입으세요.\"", "\"잘 안 입으셔서 지난번에 제가 딸에게 보냈어요.\"", "\"스웨터가 입고 싶으신가 봐요. 우리 가지러 가요.\""]'::jsonb, 5, NULL, NULL, '{"1": "너무 방어적인 태도로, 대상자의 감정을 이해하지 못하고 있습니다.\n[정답]", "5": "대상자의 요구를 수용하고, 함께 행동하자는 긍정적인 반응입니다.", "3": "대상자의 불만을 해소하지 못하고 있으며, 새로운 것을 제안하고 있습니다.", "4": "대상자의 감정에 대한 공감이 부족하고, 자신의 행동을 설명하고 있습니다.", "2": "대상자의 감정을 무시하며, 기분이 좋지 않게 만들 수 있는 응답입니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người được chăm sóc", "def_ko": "환자, 간병을 받는 사람", "def_vi": "Người nhận chăm sóc"}, {"term_ko": "요양보호사", "term_vi": "Nhân viên chăm sóc", "def_ko": "환자를 돌보는 사람", "def_vi": "Người chăm sóc bệnh nhân"}, {"term_ko": "반응", "term_vi": "Phản ứng", "def_ko": "응답", "def_vi": "Phản hồi"}, {"term_ko": "스웨터", "term_vi": "Áo len", "def_ko": "겉옷", "def_vi": "Áo khoác"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (27, '8', '의사소통할 때 라포가 형성되엇다고 볼 수 있는 대상자의 반응은?', '["눈은 먼 곳을 응시한다.", "시선을 한 곳에 고정한다.", "몸을 뒤로 젖혀 앉는다.", "무슨 일이라도 털어놓고 말한다.", "마음에 들지 않으면 슬쩍 넘어가 피한다."]'::jsonb, 4, NULL, NULL, '{"1": "눈은 멀리 쳐다보는 것은 거리감을 나타내기 때문에 라포가 형성되었다고 볼 수 없습니다.", "2": "시선을 한 곳에 고정하는 것은 불안감을 나타낼 수 있어 긍정적인 라포 형성을 의미하지 않습니다.", "3": "몸을 뒤로 젖히며 앉는 것은 거리를 두는 모습으로 보일 수 있습니다.\n[정답]", "4": "무슨 일이든 털어놓고 말하는 것은 신뢰가 형성된 상태로 라포가 형성되었다고 볼 수 있습니다.", "5": "마음에 들지 않으면 피하는 것은 라포가 형성되지 않았음을 나타냅니다."}'::jsonb, '[{"term_ko": "의사소통", "term_vi": "Giao tiếp", "def_ko": "소통의 과정", "def_vi": "Quá trình truyền đạt"}, {"term_ko": "라포", "term_vi": "Rapport", "def_ko": "신뢰 관계", "def_vi": "Mối quan hệ tin cậy"}, {"term_ko": "대상자", "term_vi": "Người tham gia", "def_ko": "도움을 받는 사람", "def_vi": "Người nhận sự giúp đỡ"}, {"term_ko": "반응", "term_vi": "Phản ứng", "def_ko": "응답", "def_vi": "Phản hồi"}, {"term_ko": "형성되다", "term_vi": "Hình thành", "def_ko": "만들어지다", "def_vi": "Được hình thành"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (26, '8', '대상자가 오늘따라 여기저기 안 아픈 데가 없네. 갈수록 더 아픈 것 같아.라고 할 때 공감적 표혐으로 옳은 것은?', '["\"연세가 있으신데 당연하지요.\"", "\"어디가 아프세요? 병원에 갈까요?\"", "\"어르신만 아픈 게 아니에요. 저도 아파요.\"", "\"건강하고 싶으신데 아프니까 힘드시죠?\"", "\"드시는 약 잘 챙겨 드셔야 해요.\""]'::jsonb, 4, NULL, NULL, '{"1": "''연세가 있으신데 당연하지요.''는 대상자의 감정을 충분히 이해하지 못하는 표현입니다.\n[정답]", "2": "''어디가 아프세요? 병원에 갈까요?''는 공감은 있지만 적극적인 대처가 필요한 상황에서 덜 적절한 반응입니다.", "3": "''어르신만 아픈 게 아니에요. 저도 아파요.''는 공감적 표현이지만 자신을 지나치게 강조하는 반응입니다.", "4": "''건강하고 싶으신데 아프니까 힘드시죠?''는 대상자의 감정을 잘 표현한 것입니다.", "5": "''드시는 약 잘 챙겨 드셔야 해요.''는 조언 성격이 강하고 공감적 표현이 아닙니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Đối tượng", "def_ko": "환자 또는 돌봄을 받는 사람", "def_vi": "Người bệnh hoặc người nhận chăm sóc"}, {"term_ko": "공감", "term_vi": "Đồng cảm", "def_ko": "다른 사람의 감정을 이해하고 공유하는 것", "def_vi": "Hiểu và chia sẻ cảm xúc của người khác"}, {"term_ko": "표현", "term_vi": "Biểu hiện", "def_ko": "감정을 나타내는 방식", "def_vi": "Cách thể hiện cảm xúc"}, {"term_ko": "건강", "term_vi": "Sức khỏe", "def_ko": "신체적 상태가 좋음", "def_vi": "Tình trạng cơ thể tốt"}, {"term_ko": "아픔", "term_vi": "Đau", "def_ko": "고통의 느낌", "def_vi": "Cảm giác đau đớn"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (25, '8', '대상자가 요즘은 세월이 어떻게 가는지... 삶의 의미를 모르겠어.라고 할 때 공감의 표현으로 옳은 것은?', '["\"요즘 많이 힘들고 외로우신가 봐요.\"", "\"아드님께 전화라도 드릴까요?\"", "\"나이 먹으면 시간이 빨리 간대요.\"", "\"날씨도 좋은데 산책 가실래요?\"", "\"저도 요즘 그래요.\""]'::jsonb, 1, NULL, NULL, '{"1": "''요즘 많이 힘들고 외로우신가 봐요.''는 대상자의 감정을 정확히 이해하고 표현한 공감의 예입니다.\n[정답]", "2": "''아드님께 전화라도 드릴까요?''는 공감보다는 해결책을 제안하는 것으로, 감정적 지지를 줄 수 없습니다.", "3": "''나이 먹으면 시간이 빨리 간대요.''는 일반화된 말로, 대상자의 감정에 대한 공감이 부족합니다.", "4": "''날씨도 좋은데 산책 가실래요?''는 행동을 제안하는 것이며 감정을 잘 품어주지 못합니다.", "5": "''저도 요즘 그래요.''는 자신의 경험을 이야기하는 것으로, 대상자의 감정을 소홀히 여기는 느낌을 줍니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người được chăm sóc", "def_ko": "환자 또는 보살펴야 할 사람", "def_vi": "Bệnh nhân hoặc người cần được chăm sóc"}, {"term_ko": "공감", "term_vi": "Đồng cảm", "def_ko": "상대방의 감정을 이해하고 함께 느끼는 것", "def_vi": "Hiểu và cảm nhận cảm xúc của người khác"}, {"term_ko": "감정", "term_vi": "Cảm xúc", "def_ko": "마음의 상태", "def_vi": "Tình trạng của tâm trí"}, {"term_ko": "의미", "term_vi": "Ý nghĩa", "def_ko": "어떤 것의 가치나 중요성", "def_vi": "Giá trị hoặc tầm quan trọng của một điều"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (24, '8', '다음의 대화를 읽고 요양보호사의 공감적 반응으로 옳은 것은?• 대상자 : 맨날 양치질해라. 속옷 갈아입어라. 머리 빗어라 명령하고, 내가 어린애도 아니고, 귀찮아 죽겠네. • 요양보호사 : _________________', '["\"그런 식으로 말씀하지 마세요. 어린애처럼 스스로 못 책기시잖아요.\"", "\"어르신 말씀하시는 게 맞아요. 그럼 가족들에게 부탁하세요.\"", "\"깨끗하게 지내시라고 챙겨 드리는 거예요.\"", "\"사실은 저도 이렇게까지 챙기기 힘들었어요.\"", "\"어르신의 개인위생에 대해 일일이 간섭하는 것 같아 성가시고 화가 나셨나 봐요.\""]'::jsonb, 5, NULL, NULL, '{"1": "그런 식으로 말씀하지 말라는 반응은 공감이 결여되어 있습니다.\n[정답]", "5": "어르신의 개인위생에 대한 간섭이 성가시고 화가 났다는 감정을 공감하며 반응하고 있습니다.", "2": "가족에게 부탁하라는 제안은 공감적이지 않습니다.", "3": "챙겨 드리는 이유를 설명하는 것은 공감이 아닙니다.", "4": "자신의 경험을 이야기하는 것은 공감이 아닌 자기 중심적인 반응입니다."}'::jsonb, '[{"term_ko": "공감", "term_vi": "Sự đồng cảm", "def_ko": "다른 사람의 감정을 이해하고 받아들이는 것", "def_vi": "Hiểu và chấp nhận cảm xúc của người khác"}, {"term_ko": "반응", "term_vi": "Phản ứng", "def_ko": "특정 상황에 대한 반응이나 행동", "def_vi": "Hành động hoặc phản ứng đối với một tình huống nhất định"}, {"term_ko": "개인위생", "term_vi": "Vệ sinh cá nhân", "def_ko": "개인의 청결과 위생을 유지하는 것", "def_vi": "Duy trì sự sạch sẽ và vệ sinh cá nhân"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (23, '8', '다음의 대화에서 요양보호사의 공감적 반응으로 옳은 것은?• 대상자 : 나를 도와주던 요양보호사는 그만두었습니다? 그 사람이 참 잘했는데...... • 요양보호사 : _________________', '["\"그렇게 그 요양보호사가 잘했으면 그분 모셔다 드려요?\"", "\"그렇게 말씀하시니 기분이 참 나쁘네요.\"", "\"제가 그 사람보다 경력이 많아 더 잘할 수 있어요.\"", "\"제가 맘에 들지 않으시면 다른 사람을 소개해 드릴까요?\"", "\"지난번 요양보호사님이 일을 참 잘하셨나 봐요. 저도 열심히 할게요.\""]'::jsonb, 5, NULL, NULL, '{"1": "대상자의 감정을 존중하지 않는 반응입니다.\n[정답]", "5": "대상자의 긍정적인 경험을 인정하고, 계속해서 노력하겠다는 의지를 나타냅니다.", "2": "부정적인 감정을 드러내며 대화의 흐름을 방해합니다.", "3": "자신의 경력을 강조하여 대상자의 감정에 공감하지 않습니다.", "4": "대상자의 감정에 대한 이해 없이 다른 선택지를 제안하는 것입니다."}'::jsonb, '[{"term_ko": "요양보호사", "term_vi": "Nhân viên chăm sóc", "def_ko": "환자를 돌보는 전문직", "def_vi": "Người chăm sóc bệnh nhân"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (22, '8', '다음의 대화에서 요양보호사의 적절한 반응으로 옳은 것은?• 딸 : 엄마, 이제 요리하지 마세요. 맛이 예전 같지 않아요. • 대상자 : (화를 내면서 방으로 들어가며) 그러면 이제 네가 알아서 해 먹든지, 난 안 먹어. • 요양보호사 : (대상자에게 다가가) _________________', '["\"앞으로 음식은 제가 만들어 드릴게요.\"", "\"요리솜씨가 예전 같지 않다고 하니 속상하시지요.\"", "\"이런 일로 식사를 안 하시면 건강만 나빠지세요.\"", "\"이제 음식은 따님한테 하라고 하고 편히 쉬세요.\"", "\"엄마가 음식하기 힘드실까 봐 해 본 말일 거예요.\""]'::jsonb, 2, NULL, NULL, '{"1": "''앞으로 음식은 제가 만들어 드릴게요.'' - 이는 대화에 적절하지 않습니다. 간섭으로 비춰질 수 있습니다.\n[정답]", "2": "''요리솜씨가 예전 같지 않다고 하니 속상하시지요.'' - 이는 대상자의 감정을 인정하고 공감하는 반응입니다.", "3": "''이런 일로 식사를 안 하시면 건강만 나빠지세요.'' - 이는 대상자를 압박하는 듯한 표현으로 바람직하지 않습니다.", "4": "''이제 음식은 따님한테 하라고 하고 편히 쉬세요.'' - 이는 대상자의 자존심을 상하게 할 수 있습니다.", "5": "''엄마가 음식하기 힘드실까 봐 해 본 말일 거예요.'' - 이 또한 대상자의 감정을 고려하지 않은 반응입니다."}'::jsonb, '[{"term_ko": "요양보호사", "term_vi": "Người chăm sóc", "def_ko": "돌보는 사람", "def_vi": "Người chăm sóc"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (21, '8', '실금한 대상자가 옷 갈아입기를 거부할 때 ''나-전달법'' 표현으로 옳은 것은?', '["\"벗지 않으면 서비스를 더 이상 진행할 수 없어요.\"", "\"갈아입지 않으면 피부에 발진이 생길까 봐 염려가 돼요.\"", "\"왜 고집을 피우세요. 빨리 당장 벗으세요.\"", "\"왜 갈아입기가 싫으신데요?\"", "\"옷을 벗지 않으면 며느님께 연락드릴 거예요.\""]'::jsonb, 2, NULL, NULL, '{"1": "대상자의 의사를 존중하지 않고 서비스 제공을 중단하겠다는 위협적 표현이다.\n[정답]", "2": "대상자의 건강과 안전을 염려하는 표현으로, 나-전달법에 부합한다.", "3": "상대방을 무시하는 듯한 명령조 표현이다.", "4": "질문으로 의사를 물어보지만, 나-전달법의 긍정적인 요소가 부족하다.", "5": "협박처럼 들리는 표현으로, 적절하지 않다."}'::jsonb, '[{"term_ko": "실금", "term_vi": "Tiểu không tự chủ", "def_ko": "소변이나 대변을 의도치 않게 누는 것", "def_vi": "Tiểu tiện hoặc đại tiện không tự chủ"}, {"term_ko": "옷 갈아입기", "term_vi": "Thay đồ", "def_ko": "옷을 바꾸는 과정", "def_vi": "Quá trình thay đổi quần áo"}, {"term_ko": "나-전달법", "term_vi": "Phương pháp truyền đạt ‘Tôi’", "def_ko": "자신의 감정을 표현하는 방법", "def_vi": "Phương pháp diễn đạt cảm xúc của bản thân"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (20, '8', '다음의 상황에서 ''나-전달법''을 활용한 요양보호사의 반응으로 옳은 것은?• 요양보호사 : 요즘 식사량이 줄어서 몸무게도 줄어든 것 같아요. 좋아하시는 음식을 준비했으니 좀 맛 좀 보세요. • 대상자 : (조금 먹더니) 입맛이 없어서 더 못 먹겠어요... 미안해요. • 요양보호사 : _________________', '["\"집에서 좋아하는 음식을 만들어 오라고 할까요?\"", "\"드시고 싶은 음식은 따로 없으세요?\"", "\"잘 못 드시는 것 같은데 무슨 걱정이라도 있으세요?\"", "\"위염이 있으신가 봐요. 병원진료를 받으셔야겠어요.\"", "\"식사량이 줄어서 건강이 나빠질까 봐 걱정되네요.\""]'::jsonb, 5, NULL, NULL, '{"1": "''집에서 좋아하는 음식을 만들어 오라고 할까요?'' - 대상자의 상황을 직접적으로 이해하지 못하는 제안이다.\n[정답]", "5": "''식사량이 줄어서 건강이 나빠질까 봐 걱정되네요.'' - 대상자의 현재 상황에 공감하며 걱정하는 반응이다.", "3": "''잘 못 드시는 것 같은데 무슨 걱정이라도 있으세요?'' - 이는 대화의 초점을 흐릴 수 있다.", "4": "''위염이 있으신가 봐요. 병원진료를 받으셔야겠어요.'' - 가능한 상황에 대한 주장을 하여 부담을 줄 수 있다.", "2": "''드시고 싶은 음식은 따로 없으세요?'' - 공감보다 질문으로 대화를 이끄는 방식이다."}'::jsonb, '[{"term_ko": "식사량", "term_vi": "입맛", "def_ko": "양 thức ăn (khối lượng thức ăn)", "def_vi": "khẩu vị (vị giác)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (19, '8', '재가대상자가 식탁 위에 밥 먹은 그릇을 그대로 두어 밥풀이 말라붙어 있을 때 ''나-전달법''으로 적절하게 반응한 것은?', '["\"식사를 하신 지 오래되었나 봐요.\"", "\"밥풀이 하나도 안 남게 깨끗이 좀 드세요.\"", "\"그릇이 그대로 있네요. 어디가 불편하세요?\"", "\"밥풀이 말라붙어 있는 것을 보니 맛있게 드셨군요.\"", "\"밥풀이 말라붙어서 설거지하기가 힘들어요. 다 드신 그릇은 싱크대 물에 담가 두셨으면 좋겠어요.\""]'::jsonb, 5, NULL, NULL, '{"1": "식사 시간이 오래 지났다며 수동적인 반응을 보이는 것은 부적절합니다.\n[정답]", "5": "밥풀이 말라붙은 상황을 설명하며 부탁하는 것으로 적절한 반응입니다.", "3": "불편함을 묻는 것은 상황을 해결하는데 도움이 되지 않습니다.", "2": "강압적인 표현으로 요양보호사가 아닌 접근입니다.", "4": "긍정적인 해석이지만, 요청을 하지 않아 상황을 개선하지 못합니다."}'::jsonb, '[{"term_ko": "재가대상자", "term_vi": "Người được chăm sóc tại nhà", "def_ko": "가정에서 요양을 받는 사람", "def_vi": "Người nhận sự chăm sóc tại nhà"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (18, '8', '재가 어르신이 업무시간 이외의 시간에 자주 전화를 하여 푸념을 할 때 ''나-전달법''으로 반응한 것은?', '["\"외로우셔서 자꾸 저한테 전화하시는 거예요?\"", "\"저보다는 가족분들에게 전화하시는 게 좋을 것 같아요.\"", "\"자꾸 전화하시니 제가 찾아봬도 되는지 센터장님에게 물어보고 갈게요.\"", "\"요새 스트레스가 많으신가 봐요. 제가 해결해 드릴 수 있는 일이라면 좋을 텐데...\"", "\"업무 시간 외에 전화하시면 제 일을 못 해서 힘들어요. 업무 시간에 말씀해 주시면 좋겠어요.\""]'::jsonb, 5, NULL, NULL, '{"1": "재가 어르신의 심리적 상태를 이해하려는 긍정적인 접근이지만, ''나-전달법''의 요구에 부합하지 않습니다.\n[정답]", "5": "자신의 입장을 명확히 전달하며 업무 시간을 구분하는 것은 ''나-전달법''의 전형적인 예시입니다.", "2": "가족 권유는 긍정적인 의도로 보이나 본인의 경계를 설정하지 않습니다.", "3": "자신의 경계를 설정하고 대안을 제시했지만 ''나-전달법''의 직접적인 표현이 아닙니다.", "4": "상대방의 심리를 파악하려는 접근은 좋지만 직접적인 ''나-전달법''이 아닙니다."}'::jsonb, '[{"term_ko": "재가", "term_vi": "Tại gia", "def_ko": "방문하여 돌보는 것(한국어)", "def_vi": "Chăm sóc tại nhà"}, {"term_ko": "업무시간", "term_vi": "Thời gian làm việc", "def_ko": "일하는 시간(한국어)", "def_vi": "Thời gian làm việc"}, {"term_ko": "푸념", "term_vi": "Than phiền", "def_ko": "불평하는 것(한국어)", "def_vi": "Phàn nàn"}, {"term_ko": "전달법", "term_vi": "Phương pháp truyền đạt", "def_ko": "의사소통 방법(한국어)", "def_vi": "Phương pháp giao tiếp"}, {"term_ko": "가족", "term_vi": "Gia đình", "def_ko": "가까운 친인척(한국어)", "def_vi": "Người thân"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (17, '8', '다음 상황에서 요양보호사의 공감적 반응으로 적절한 것은?• 대상자 : 나이를 먹을수록 후회되는 일도 많고, 사는 게 재미도 없고, 외롭네...... • 요양보호사 : _________________', '["\"우울증인 것 같으니 검사를 받으셔야겠어요.\"", "\"요즘 많이 외롭고 힘드신가 봐요.\"", "\"재미있는 프로그램에 참여하시겠어요?\"", "\"부정적인 감성은 건강에 해로워요.\"", "\"나이가 들면 대부분 다 그렇게 느껴요.\""]'::jsonb, 2, NULL, NULL, '{"1": "우울증을 언급하며 검사받자고 하는 것은 공감적 반응이라기보다는 진단적인 접근으로 비춰질 수 있습니다.\n[정답]", "2": "대상자의 외로움과 힘듦을 인정하며 공감하는 반응입니다.", "3": "즐거운 활동 참여를 묻는 것은 대상자의 감정에 대한 반응이 아니라 해결책을 제시하는 것입니다.", "4": "부정적인 감성이 건강에 해롭다는 일반적인 진술로, 대상자의 감정을 존중하지 않습니다.", "5": "나이가 들면 공감이 되더라도, 듣는 이의 감정을 적절히 반영하지 않는 일반화된 답변입니다."}'::jsonb, '[{"term_ko": "공감적", "term_vi": "Đồng cảm", "def_ko": "감정이나 느낌을 이해하고 함께 느끼는 것", "def_vi": "Hiểu và cảm nhận cùng cảm xúc"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (16, '8', '난청인 대상자와 의사소통하는 방법으로 옳은 것은?', '["고음의 큰소리로 말한다.", "입력은 작게, 출력은 크게 한다.", "손으로 입을 가리고 말한다.", "밝은 장소에서 입을 크게 벌리며 말한다.", "실물, 그림판, 문자판을 이용하여 설명한다."]'::jsonb, 4, NULL, NULL, '{"1": "고음의 큰소리로 말하는 것은 난청인에게 효과적이지 않음.\n[정답]", "4": "밝은 장소에서 입을 크게 벌리며 말하는 것은 난청인이 이야기를 이해하는 데 도움이 됨.", "2": "입력은 작게, 출력은 크게 하는 것은 기본적인 의사소통 방식에서 벗어남.", "3": "손으로 입을 가리고 말하면 난청인이 입 모양을 보지 못해 의사소통에 방해가 됨.", "5": "실물, 그림판, 문자판을 이용하여 설명하는 것은 좋은 방법이지만, 보기 중에서는 4번이 더 적절함."}'::jsonb, '[{"term_ko": "난청인", "term_vi": "Người khiếm thính", "def_ko": "청력이 떨어진 사람", "def_vi": "Người có thính lực kém"}, {"term_ko": "의사소통", "term_vi": "Giao tiếp", "def_ko": "서로의 생각이나 정보를 주고받는 것", "def_vi": "Trao đổi thông tin hoặc ý tưởng giữa các cá nhân"}, {"term_ko": "입 모양", "term_vi": "Hình dáng môi", "def_ko": "말할 때 입의 모양", "def_vi": "Hình dạng miệng khi nói"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (15, '8', '시각장애 대상자와 이야기하는 방법으로 옳은 것은?', '["몸짓과 얼굴표정을 사용하여 대화한다.", "대상자를 만났을 때 신체접촉 후 말을 건넨다.", "대상자와 반걸음 떨어져 보행한다.", "대상자 중심으로 오른쪽, 왼쪽을 설명하여 원칙을 정해둔다.", "''이쪽'', ''저쪽''과 같은 지시대명사를 많이 사용한다."]'::jsonb, 4, NULL, NULL, '{"1": "몸짓과 얼굴표정을 사용하여 대화한다: 시각장애인에게는 시각적 신호가 부족하므로 비언어적 의사소통 방법이 전통적으로 사용되지만, 주된 의사소통 방식은 아님.\n[정답]", "4": "대상자 중심으로 오른쪽, 왼쪽을 설명하여 원칙을 정해둔다: 방향을 알려주는 것은 시각장애인이 공간을 인식하는 데 도움이 된다.", "2": "대상자를 만났을 때 신체접촉 후 말을 건넨다: 신체접촉은 예기치 않게 이루어질 경우 불안감을 유발할 수 있다.", "3": "대상자와 반걸음 떨어져 보행한다: 너무 간격을 두면 친밀감이 떨어질 수 있으며, 시각장애인에게는 도움이 되지 않는다.", "5": "''이쪽'', ''저쪽''과 같은 지시대명사를 많이 사용한다: 명확한 지시가 필요하기 때문에 이 방법은 적절하지 않다."}'::jsonb, '[{"term_ko": "시각장애", "term_vi": "Khiếm thị", "def_ko": "시각 기능이 제한되거나 상실된 상태", "def_vi": "Trạng thái giảm hoặc mất khả năng thị giác"}, {"term_ko": "대상자", "term_vi": "Người nhận chăm sóc", "def_ko": "돌봄을 받는 사람", "def_vi": "Người được chăm sóc"}, {"term_ko": "신체접촉", "term_vi": "Tiếp xúc cơ thể", "def_ko": "신체를_touch하는 행위", "def_vi": "Hành động chạm vào cơ thể"}, {"term_ko": "보행", "term_vi": "Đi bộ", "def_ko": "걷는 것", "def_vi": "Hành động đi lại"}, {"term_ko": "지시대명사", "term_vi": "Đại từ chỉ định", "def_ko": "방향을 나타내는 대명사", "def_vi": "Đại từ chỉ ra hướng"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (14, '8', '알아듣기는 하나 말을 할 수 없는 대상자와 의사소통하는 방법으로 옳은 것은?', '["몸짓과 얼굴표정을 사용하여 대화한다.", "대상자를 만났을 때 신체접촉 후 말을 건넨다.", "대상자와 반걸음 떨어져 보행한다.", "대상자 중심으로 오른쪽, 왼쪽을 설명하여 원칙을 정해둔다.", "''이쪽'', ''저쪽''과 같은 지시대명사를 많이 사용한다."]'::jsonb, 4, NULL, NULL, '{"1": "몸짓과 얼굴표정을 사용하여 대화한다. (신체 언어는 의사소통에 도움이 되지만, 단순히 그것만으로는 부족할 수 있다.)\n[정답]", "4": "대상자 중심으로 오른쪽, 왼쪽을 설명하여 원칙을 정해둔다. (대상자가 이해할 수 있도록 방향을 명확히 할 수 있다.)", "3": "대상자와 반걸음 떨어져 보행한다. (거리 유지가 중요한데, 너무 멀어지면 의사소통이 어렵다.)", "2": "대상자를 만났을 때 신체접촉 후 말을 건넨다. (신체 접촉이 항상 좋은 의사소통 방법은 아니다.)", "5": "''이쪽'', ''저쪽''과 같은 지시대명사를 많이 사용한다. (모호한 지시대명사는 이해를 저해할 수 있다.)"}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người bệnh", "def_ko": "환자나 돌보아야 할 사람", "def_vi": "Bệnh nhân hoặc người cần chăm sóc"}, {"term_ko": "의사소통", "term_vi": "Giao tiếp", "def_ko": "소통이나 정보를 교환하는 과정", "def_vi": "Quá trình trao đổi thông tin"}, {"term_ko": "신체접촉", "term_vi": "Tiếp xúc thể chất", "def_ko": "몸이 서로 맞닿는 것", "def_vi": "Khi cơ thể chạm vào nhau"}, {"term_ko": "지시대명사", "term_vi": "Đại từ chỉ hướng", "def_ko": "사람이나 사물을 지시하는 대명사", "def_vi": "Đại từ chỉ người hoặc vật"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (13, '8', '알아듣기는 하나 말을 할 수 없는 대상자와 의사소통하는 방법으로 옳은 것은?', '["친근감 있게 유아어를 쓴다.", "대상자의 옆에서 귀에 대고 말한다.", "긴장하지 않게 음악을 틀어 놓고 말한다.", "그림판, 문자판을 이용하여 의사를 표현하게 한다.", "요양보호사를 중심으로 오른쪽, 왼쪽 방향을 정하여 설명한다."]'::jsonb, 4, NULL, NULL, '{"1": "친근감 있게 유아어를 쓴다. - 유아어 사용은 적절하지 않으며 상황을 혼란스럽게 할 수 있습니다.\n[정답]", "4": "그림판, 문자판을 이용하여 의사를 표현하게 한다. - 시각적 도구를 사용하여 의사소통하는 것은 효과적인 방법입니다.", "3": "긴장하지 않게 음악을 틀어 놓고 말한다. - 음악이 의사소통에 도움이 되지 않을 수 있습니다.", "2": "대상자의 옆에서 귀에 대고 말한다. - 이렇게 하는 것은 대상을 불편하게 할 수 있습니다.", "5": "요양보호사를 중심으로 오른쪽, 왼쪽 방향을 정하여 설명한다. - 방향지시가 필요하지 않은 경우 오히려 혼동을 줄 수 있습니다."}'::jsonb, '[{"term_ko": "의사소통", "term_vi": "Giao tiếp", "def_ko": "교류(감정, 생각 등)를 하는 것", "def_vi": "Sự trao đổi (cảm xúc, suy nghĩ, v.v.)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (12, '8', '다음과 같은 방법으로 의사소통해야 하는 대상자로 옳은 것은?• 실물, 그림판, 문자판을 이용한다. • 눈을 깜빡이거나 손짓, 고개를 끄덕이는 등으로 의사표현하게 한다. • 말로 잘 표현했을 때 칭찬과 더불어 긍정적 공감을 비언어적으로 표현해 준다.', '["청각장애", "언어장애", "시각장애", "지남력장애", "주의력결핍"]'::jsonb, 2, NULL, NULL, '{"1": "청각장애는 주로 청각적 정보에 대한 이해가 어려운 경우로, 실물이나 그림판을 사용할 수 없다.\n[정답]", "2": "언어장애는 언어적 표현에 어려움이 있는 상황으로, 비언어적 의사소통 방법을 통해 소통할 수 있다.", "3": "시각장애는 시각적 정보를 인식할 수 없는 경우로, 실물과 그림판을 사용할 수 없다.", "4": "지남력장애는 시간과 장소에 대한 인지 문제로, 의사소통 방법과 관련이 없다.", "5": "주의력결핍은 집중력 문제로, 의사소통의 방법과는 관련이 적다."}'::jsonb, '[{"term_ko": "의사소통", "term_vi": "Giao tiếp", "def_ko": "소통, 나누기", "def_vi": "Truyền đạt, giao tiếp"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (11, '8', '치매 대상자와 의사소통할 때 기본 원칙을 지켜 반응한 것으로 옳은 것은?', '["\"왜 과일을 안 드셨어요?\"", "\"아침 8시예요. 약 드실 시간이에요.\"", "\"아까 그 사람은 누구예요?\"", "\"어디 불편한 곳은 없으세요?\"", "\"점심 드시고 나서 바나나를 간식으로 드세요.\""]'::jsonb, 2, NULL, NULL, '{"1": "''왜 과일을 안 드셨어요?''는 치매 대상자에게 부정적인 감정을 유발할 수 있습니다.\n[정답]", "2": "''아침 8시예요. 약 드실 시간이에요.''는 치매 대상자의 일상 스케줄을 지원하는 긍정적인 의사소통입니다.", "3": "''아까 그 사람은 누구예요?''는 혼란을 줄 수 있는 질문입니다.", "4": "''어디 불편한 곳은 없으세요?''는 직접적인 질문으로 혼동을 줄 수 있습니다.", "5": "''점심 드시고 나서 바나나를 간식으로 드세요.''는 지시적인 언급으로 불편감을 초래할 수 있습니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "치매(이해력과 기억력이 감소하는 병)", "def_vi": "Bệnh mất khả năng hiểu và ghi nhớ."}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (10, '8', '치매로 인한 이해력장애 대상자와의 이야기하는 방법으로 옳은 것은?', '["실물이나 그림판, 문자판 등은 생략한다.", "요양보호사의 속도에 맞추어 이야기한다.", "친근함을 위해 반말로 이야기한다.", "전문적인 용어를 사용한다.", "짧은 문장으로 천천히 이야기한다."]'::jsonb, 5, NULL, NULL, '{"1": "실물이나 그림판, 문자판 등은 생략한다. 이 방법은 이해력장애가 있는 대상자에게 도움이 되지 않습니다.\n[정답]", "5": "짧은 문장으로 천천히 이야기한다. 이는 이해를 돕고 소통을 원활하게 합니다.", "2": "요양보호사의 속도에 맞추어 이야기한다. 이는 대상자의 이해를 고려하지 않는 방법입니다.", "3": "친근함을 위해 반말로 이야기한다. 이는 대상자와의 관계를 악화시킬 수 있습니다.", "4": "전문적인 용어를 사용한다. 이해력장애가 있는 대상자에게는 적합하지 않습니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Mất trí nhớ", "def_ko": "기억과 사고 능력이 저하되는 상태", "def_vi": "Tình trạng suy giảm trí nhớ và khả năng suy nghĩ"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (9, '8', '치매로 인한 주의력 결핍장애 대상자와 의사소통방법으로 옳은 것은?', '["대상자와 눈을 피한다.", "정확하고 자세하게 설명한다.", "환경적 자극을 최대한 줄인다.", "내용을 빠르고 반복적으로 말한다.", "복잡한 활동을 먼저 제시한다."]'::jsonb, 3, NULL, NULL, '{"1": "대상자와 눈을 피하는 것은 의사소통에 비협조적이다.\n[정답]", "2": "정확하고 자세하게 설명하는 것은 좋지만 청취할 준비가 되어 있지 않을 수 있다.", "3": "환경적 자극을 최대한 줄이는 것은 집중력 향상에 도움이 된다.", "4": "내용을 빠르고 반복적으로 말하는 것은 오히려 혼란을 줄 수 있다.", "5": "복잡한 활동을 먼저 제시하는 것은 주의력이 결핍된 대상자에게 불리하다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí", "def_ko": "기억력과 사고력을 저하시키는 질병", "def_vi": "Bệnh làm suy giảm trí nhớ và khả năng tư duy"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (8, '8', '치매로 인한 지남력장애 대상자와 의사소통방법으로 옳은 것은?', '["전문용어로 자세히 설명한다.", "대상자의 미래 계획을 함께 세운다.", "대중 매체에 나오는 신조어를 사용한다.", "장소, 날짜, 시간에 대해 자주 인식시킨다.", "친밀감을 표현하기 위해 별명을 사용한다."]'::jsonb, 4, NULL, NULL, '{"1": "전문용어로 설명하면 혼란을 초래할 수 있습니다.\n[정답]", "4": "장소, 날짜, 시간에 대한 인식은 지남력장애 대상자에게 매우 중요합니다.", "2": "미래 계획을 세우는 것은 어렵고 혼란을 초래할 수 있습니다.", "3": "신조어 사용은 이해를 더욱 어렵게 만듭니다.", "5": "별명 사용은 친밀감을 줄 수 있지만 신뢰를 구축하는 데 한계가 있을 수 있습니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh Alzheimer", "def_ko": "알츠하이머(한국어)", "def_vi": "Bệnh mất trí nhớ"}, {"term_ko": "지남력장애", "term_vi": "Rối loạn định hướng", "def_ko": "방향감각 상실(한국어)", "def_vi": "Mất khả năng nhận thức thời gian và không gian"}, {"term_ko": "의사소통", "term_vi": "Giao tiếp", "def_ko": "커뮤니케이션(한국어)", "def_vi": "Hình thức trao đổi thông tin"}, {"term_ko": "전문용어", "term_vi": "Thuật ngữ chuyên môn", "def_ko": "전문적 용어(한국어)", "def_vi": "Thuật ngữ trong lĩnh vực nhất định"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (7, '8', '다음과 같은 대화를 읽고 지남력 증진을 위한 요양보호사의 표현으로 옳은 것은?• 대상자 : (눈 내리는 창밖을 보며) 벚꽃이 지기 전에 빨리 벚꽃 구경하러 갑시다. • 요양보호사 : _________________', '["\"눈이 와서 미끄러워요. 다음에 가요.\"", "\"놀러가고 싶으신가 봐요?\", \"밖에 나가고 싶으신가 봐요.\"", "\"지금은 져울이에요. 벚꽃 구경은 봅에 가요.\"", "\"지금은 꽃이 핀 데가 없어요.\"", "\"화전이 드시고 싶으신가 봐요.\""]'::jsonb, 3, NULL, NULL, '{"1": "눈이 와서 미끄러워서 외출을 권하지 않는 표현으로 대상자의 감정을 무시합니다.\n[정답]", "2": "대상자의 희망을 물어보며 긍정적인 반응을 보입니다.", "3": "현재 상황에 대한 사실을 전달하였으나, 대상자의 감정을 고려하지 않았습니다.", "4": "만약 벚꽃이 핀 곳이 없다는 부정적 표현입니다.", "5": "''화전''이란 언급은 적절하지 않습니다."}'::jsonb, '[{"term_ko": "지남력", "term_vi": null, "def_ko": "인식하여 길을 잘 찾아가는 능력(한국어)", "def_vi": null}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (6, '8', '다음과 같은 상황에서 효과적으로 의사소통하는 방법으로 옳은 것은?• 치매 대상자 : 아이고, 나 죽네...... 배 아파 죽겠어. • 요양보호사 : _________________', '["\"어디가 불편하세요?\"", "(배를 짚으며) \"여기가 아프세요?\"", "\"많이 아프시군요. 장염인가 봐요?\"", "\"간식으로 무엇을 먹었는지 말해보세요.\"", "\"속이 쓰리세요? 더부룩하세요? 콕콕 쑤시나요?\""]'::jsonb, 2, NULL, NULL, '{"1": "''어디가 불편하세요?''는 다소 추상적인 질문으로, 추가적인 정보를 얻기 어렵습니다.\n[정답]", "2": "''(배를 짚으며) 여기가 아프세요?''는 환자의 불편한 부위를 명확히 파악하는 데 도움을 줍니다.", "3": "''많이 아프시군요. 장염인가 봐요?''라는 질문은 정확한 진단이 아닌 추측성 대답으로, 환자의 불안감을 초래할 수 있습니다.", "4": "''간식으로 무엇을 먹었는지 말해보세요.''는 증상과의 직접 연결이 없어, 효과적인 대화로 이어지지 않습니다.", "5": "''속이 쓰리세요? 더부룩하세요? 콕콕 쑤시나요?''와 같은 질문은 복잡하고, 환자가 이해하기 어려울 수 있습니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Mất trí nhớ", "def_ko": "기억력을 상실하는 질병(한국어)", "def_vi": "Bệnh mất khả năng nhớ"}, {"term_ko": "의사소통", "term_vi": "Giao tiếp", "def_ko": "정보를 주고받는 것(한국어)", "def_vi": "Hành động trao đổi thông tin"}, {"term_ko": "대상자", "term_vi": "Người nhận", "def_ko": "도움을 받는 사람(한국어)", "def_vi": "Người nhận sự giúp đỡ"}, {"term_ko": "불편하다", "term_vi": "Không thoải mái", "def_ko": "편하지 않다(한국어)", "def_vi": "Không dễ chịu"}, {"term_ko": "증상", "term_vi": "Triệu chứng", "def_ko": "질병의 나타나는 조짐(한국어)", "def_vi": "Dấu hiệu của bệnh"}, {"term_ko": "요양보호사", "term_vi": "Người chăm sóc", "def_ko": "노인이나 환자의 돌보는 전문가(한국어)", "def_vi": "Người chăm sóc cho người già hoặc bệnh nhân"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (5, '8', '치매 대상자가 환각증상을 보이며 문밖에 우리 딸이 와 있어. 딸한테 가야겠어.라고 할 때 요양보호사의 의사소통 방법으로 옳은 것은?', '["\"문밖에 아무도 없는데요.\"", "\"따님이 많이 그리우신가 봐요.\"", "\"식사하시면 따님께 연락드릴게요.\"", "\"거짓말 하시면 간식 안 드릴 거예요.\"", "\"원래 따님 없으시잖아요?\""]'::jsonb, 2, NULL, NULL, '{"1": "환각 증상에 대해 부정하는 접근 방식은 대상자의 정서를 더욱 상하게 할 수 있다.\n[정답]", "2": "대상자가 느끼는 감정을 인정하고 공감하는 방식으로, 환자가 안심할 수 있도록 돕는다.", "3": "식사 후 연락하겠다고 하는 것은 즉각적인 감정이나 불안에 대한 반응이 아니다.", "4": "협박적인 말투는 대상자의 불안을 더욱 증폭시킬 수 있다.", "5": "사실 확인을 통한 부정적인 반응은 대상자의 정신적 상태에 도움이 되지 않는다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh Alzheimer", "def_ko": "기억력 및 사고 능력 저하를 동반한 질환", "def_vi": "Bệnh lý giảm trí nhớ và khả năng tư duy"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (4, '8', '다음을 읽고 요양보호사가 추천하는 여가활동 유형으로 옳은 것은?• 대상자 : 내가 예전에는 글쓰기를 좋아해서 일기를 매일 썼는데...... • 요양보호사 : 글짓기 프로그램이 있는데 참여해 보시는 건 어떠세요?', '["자기계발 활동", "가족중심 활동", "사교오락 활동", "운동 활동", "소일 활동"]'::jsonb, 1, NULL, NULL, '{"1": "자기계발 활동: 글쓰기와 같은 활동은 자기계발의 일환으로 볼 수 있습니다.\n[정답]", "2": "가족중심 활동: 가족과 함께하는 활동이 아니므로 부적절합니다.", "3": "사교오락 활동: 글짓기는 사교와는 거리가 먼 개인적인 활동입니다.", "4": "운동 활동: 운동과 관련된 활동이 아니므로 맞지 않습니다.", "5": "소일 활동: 글쓰기는 소일의 범주에 포함될 수 있으나, 자기계발 활동이 더 적합합니다."}'::jsonb, '[{"term_ko": "여가활동", "term_vi": "Hoạt động giải trí", "def_ko": "여가를 활용하는 활동", "def_vi": "Các hoạt động sử dụng thời gian rảnh"}, {"term_ko": "자기계발", "term_vi": "Phát triển bản thân", "def_ko": "자신을 발전시키는 활동", "def_vi": "Các hoạt động để phát triển bản thân"}, {"term_ko": "사교오락", "term_vi": "Giao lưu vui chơi", "def_ko": "서로 만나 즐기는 활동", "def_vi": "Các hoạt động để gặp gỡ và vui chơi"}, {"term_ko": "소일", "term_vi": "Tiêu khiển", "def_ko": "시간을 보내는 개인적인 활동", "def_vi": "Các hoạt động cá nhân để tiêu thời gian"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (3, '8', '다음의 대화에서 요양보호사가 제안하는 여가활동의 유형으로 옳은 것은?• 대상자 : 문화생활? 그런 게 어디 있어? 하루 종일 텔레비전 보는 게 다야...... • 요양보호사 : 어르신, 우리 재미있는 영화 보러 영화관에 갈까요?', '["자기계발 활동", "가족중심 활동", "사교오락 활동", "운동 활동", "소일 활동"]'::jsonb, 3, NULL, NULL, '{"1": "자기계발 활동은 개인의 능력을 향상시키기 위한 활동이며, 영화 관람과는 관계가 없다.\n[정답]", "3": "사교오락 활동은 친구나 가족과 함께 즐기는 놀이 또는 오락을 포함하며, 영화 관람이 이에 해당한다.", "2": "가족중심 활동은 가족과 함께 하는 활동을 의미하며, 여기서는 어르신과 요양보호사 간의 활동이다.", "4": "운동 활동은 신체 활동을 포함하며, 영화 관람과는 관련이 없다.", "5": "소일 활동은 취미나 소소한 일을 의미하므로 영화 관람과는 적합하지 않다."}'::jsonb, '[{"term_ko": "요양보호사", "term_vi": "Người chăm sóc", "def_ko": "노인이나 장애인을 돌보는 전문가", "def_vi": "Chuyên gia chăm sóc người già hoặc người khuyết tật"}, {"term_ko": "여가활동", "term_vi": "Hoạt động giải trí", "def_ko": "여가 시간에 하는 활동", "def_vi": "Hoạt động thực hiện trong thời gian rảnh"}, {"term_ko": "사교오락", "term_vi": "Giải trí xã hội", "def_ko": "친구나 가족과 함께 즐기는 놀이 또는 오락", "def_vi": "Vui chơi hoặc giải trí cùng bạn bè hoặc gia đình"}, {"term_ko": "자기계발", "term_vi": "Phát triển bản thân", "def_ko": "개인의 능력 향상", "def_vi": "Nâng cao khả năng cá nhân"}, {"term_ko": "소일 활동", "term_vi": "Hoạt động tiêu khiển", "def_ko": "취미나 소소한 일", "def_vi": "Sở thích hoặc công việc nhỏ"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (2, '8', '다음의 대화에서 요양보호사가 제안하는 여가활동의 유형으로 옳은 것은?• 대상자 : (지팡이로 이동하며) 하루 종일 갇혀 있는 것 같아. 밖에 나가지도 못하고...... • 요양보호사 : 예전에 농사일 지으셨다면서요. 옥상 텃밭에서 상추를 가꾸어 보시는 건 어떠세요?', '["자기계발 활동", "가족중심 활동", "사교오락 활동", "운동 활동", "소일 활동"]'::jsonb, 5, NULL, NULL, '{"1": "자기계발 활동: 본인의 능력을 개발하는 활동으로, 제안된 내용과는 무관함.", "2": "가족중심 활동: 가족과의 관계를 증진시키는 활동으로, 이 경우에 적합하지 않음.", "3": "사교오락 활동: 사람들과의 교류 및 오락을 포함하는 활동이나, 옥상 텃밭 가꾸기는 그와는 다름.", "4": "운동 활동: 신체 활동을 포함하지만 텃밭 가꾸기는 운동보다는 정원 가꾸기에 더 중점을 둠.\n[정답]", "5": "소일 활동: 제안된 옥상 텃밭에서 상추를 가꾸는 활동은 소일 활동으로서, 적절한 여가활동의 예시이다."}'::jsonb, '[{"term_ko": "여가활동", "term_vi": "Hoạt động giải trí", "def_ko": "여가 시간을 활용하는 활동(한국어)", "def_vi": "hoạt động tận dụng thời gian rảnh (베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1, '8', '거동이 불편하고 인지기능이 저하된 대상자의 여가활동으로 옳은 것은?', '["가족의 의견을 중심으로 프로그램을 지원한다.", "낙상의 위험이 있으므로 활동에서 배재한다.", "움직임이 빠르고 활동적인 프로그램을 제공한다.", "어렵지 않고 단순하고 흥미로운 활동으로 진행한다.", "개인보다 단체를 위한 집단 프로그램을 제공한다."]'::jsonb, 4, NULL, NULL, '{"1": "가족의 의견을 반영하되, 대상자의 개인적 선호도 고려가 필요합니다.\n[정답]", "4": "대상자의 능력과 흥미를 고려하여 어렵지 않고 단순한 활동이 적합합니다.", "3": "거동이 불편한 대상자에게는 활동적인 프로그램이 적합하지 않습니다.", "5": "개인의 선호에 따라 단체 활동보다는 개인에 맞춘 활동이 필요할 수 있습니다.", "2": "대상자는 적절한 여가활동을 통해서도 활동성을 유지할 수 있습니다."}'::jsonb, '[{"term_ko": "거동", "term_vi": "Di chuyển", "def_ko": "움직임, 행위", "def_vi": "chuyển động, hành vi"}, {"term_ko": "인지기능", "term_vi": "Chức năng nhận thức", "def_ko": "인지 능력", "def_vi": "khả năng nhận biết"}, {"term_ko": "여가활동", "term_vi": "Hoạt động giải trí", "def_ko": "여가 시간에 하는 활동", "def_vi": "hoạt động trong thời gian rảnh"}, {"term_ko": "낙상", "term_vi": "Ngã", "def_ko": "넘어짐", "def_vi": "sự ngã"}, {"term_ko": "프로그램", "term_vi": "Chương trình", "def_ko": "계획된 활동", "def_vi": "hoạt động đã được lập kế hoạch"}, {"term_ko": "단체", "term_vi": "Nhóm", "def_ko": "집단", "def_vi": "tập thể"}, {"term_ko": "개인", "term_vi": "Cá nhân", "def_ko": "개인", "def_vi": "cá nhân"}]'::jsonb);
